window.HADITH_CACHE = window.HADITH_CACHE || {};
window.HADITH_CACHE["nasai_1"] = {"501":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي الزُّهْرِيُّ وَإِسْحَقُ بْنُ عَبْدِ اللَّهِ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الْعَصْرَ ثُمَّ يَذْهَبُ الذَّاهِبُ إِلَى قُبَاءٍ فَقَالَ أَحَدُهُمَا فَيَأْتِيهِمْ وَهُمْ يُصَلُّونَ وَقَالَ الْآخَرُ وَالشَّمْسُ مُرْتَفِعَةٌ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Malik] dia berkata; Telah menceritakan kepadaku [Az Zuhri] dan [Ishaq bin Abdullah] dari [Anas] bahwa Rasulullah Shallallahu'alaihi wasallam shalat Ashar, dan kemudian seseorang pergi ke Quba.' -Salah seorang perawi- berkata; Lalu dia sampai ke Masjid Quba' dan ia dapati mereka (orang di masjid Quba) sedang mengerjakan shalat. Dan --perawi yang satunya lagi- berkata;..dan matahari masih meninggi."},"502":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي الْعَصْرَ وَالشَّمْسُ مُرْتَفِعَةٌ حَيَّةٌ وَيَذْهَبُ الذَّاهِبُ إِلَى الْعَوَالِي وَالشَّمْسُ مُرْتَفِعَةٌ","id":"Telah mengabarkan kepada kami [Qutaibah] Telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Anas bin Malik] bahwa Rasulullah Shallallahu'alaihi wasallam shalat Ashar dan matahari masih tinggi dan bersinar, lalu seseorang pergi ke sekitar Madinah sedangkan matahari masih tinggi."},"503":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ أَبِي الْأَبْيَضِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِنَا الْعَصْرَ وَالشَّمْسُ بَيْضَاءُ مُحَلِّقَةٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Rib'i bin Hirasy] dari [Abu Al Abyadl] dari [Anas bin Malik], bahwa Rasulullah Shallallahu'alaihi wasallam shalat Ashar bersama kami saat matahari masih cerah dan bulat."},"504":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ أَبِي بَكْرِ بْنِ عُثْمَانَ بْنِ سَهْلِ بْنِ حُنَيْفٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ بْنَ سَهْلٍ يَقُولُصَلَّيْنَا مَعَ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ الظُّهْرَ ثُمَّ خَرَجْنَا حَتَّى دَخَلْنَا عَلَى أَنَسِ بْنِ مَالِكٍ فَوَجَدْنَاهُ يُصَلِّي الْعَصْرَ قُلْتُ يَا عَمِّ مَا هَذِهِ الصَّلَاةُ الَّتِي صَلَّيْتَ قَالَ الْعَصْرَ وَهَذِهِ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي كُنَّا نُصَلِّي","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah] dari [Abu Bakar bin Utsman bin Sahal bin Hanif] dia berkata; Saya mendengar [Abu Umamah bin Sahal] berkata; \"Kami mengerjakan shalat Zhuhur bersama Umar bin Abdul Aziz. Kemudian kami pergi untuk menemui [Anas bin Malik], dan ternyata ia sedang shalat Ashar. Aku berkata kepadanya, 'Wahai paman! Shalat apakah yang kamu kerjakan ini? ' dia menjawab, 'Shalat Ashar'. Inilah Shalat Rasulullah Shallallahu'alaihi wasallam bersama kami.\""},"505":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو عَلْقَمَةَ الْمَدَنِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ قَالَصَلَّيْنَا فِي زَمَانِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ ثُمَّ انْصَرَفْنَا إِلَى أَنَسِ بْنِ مَالِكٍ فَوَجَدْنَاهُ يُصَلِّي فَلَمَّا انْصَرَفَ قَالَ لَنَا صَلَّيْتُمْ قُلْنَا صَلَّيْنَا الظُّهْرَ قَالَ إِنِّي صَلَّيْتُ الْعَصْرَ فَقَوَّلُوا لَهُ عَجَّلْتَ فَقَالَ إِنَّمَا أُصَلِّي كَمَا رَأَيْتُ أَصْحَابِي يُصَلُّونَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Abu Al Qamah Al Madani] dia berkata; Telah menceritakan kepada kami [Muhammad bin Amr] dari [Abu Salamah] dia berkata; \"Kami shalat pada masa Umar bin Abdul Aziz, kemudian kami pergi menemui [Anas bin Malik], dan ternyata dia sedang shalat. Setelah selesai dia berkata kepada kami, \"Kalian sudah shalat?\" Kami menjawab, \"Ya, sudah shalat Dzuhur\". Dia berkata, \"Aku shalat Ashar.\". Mereka bertanya kepadanya, 'engkau menyegerakannya'. Dia menjawab, ' Aku hanya shalat sebagaimana aku melihat para sahabatku melakukan shalat\"."},"506":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرِ بْنِ إِيَاسِ بْنِ مُقَاتِلِ بْنِ مُشَمْرِجِ بْنِ خَالِدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا الْعَلَاءُأَنَّهُ دَخَلَ عَلَى أَنَسِ بْنِ مَالِكٍ فِي دَارِهِ بِالْبَصْرَةِ حِينَ انْصَرَفَ مِنْ الظُّهْرِ وَدَارُهُ بِجَنْبِ الْمَسْجِدِ فَلَمَّا دَخَلْنَا عَلَيْهِ قَالَ أَصَلَّيْتُمْ الْعَصْرَ قُلْنَا لَا إِنَّمَا انْصَرَفْنَا السَّاعَةَ مِنْ الظُّهْرِ قَالَ فَصَلُّوا الْعَصْرَ قَالَ فَقُمْنَا فَصَلَّيْنَا فَلَمَّا انْصَرَفْنَا قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تِلْكَ صَلَاةُ الْمُنَافِقِ جَلَسَ يَرْقُبُ صَلَاةَ الْعَصْرِ حَتَّى إِذَا كَانَتْ بَيْنَ قَرْنَيْ الشَّيْطَانِ قَامَ فَنَقَرَ أَرْبَعًا لَا يَذْكُرُ اللَّهَ عَزَّ وَجَلَّ فِيهَا إِلَّا قَلِيلًا","id":"Telah mengabarkan kepada kami [Ali bin Hujr bin Iyas bin Muqatil Musamrij bin Khalid] dia berkata; Telah menceritakan kepada kami [Ismail] berkata; Telah menceritakan kepada kami [Al 'Alla] bahwa dia pernah masuk ke rumah [Anas bin Malik] di Basrah ketika dia selesai shalat Zhuhur, dan rumahnya di samping Masjid. Ketika kami sudah masuk, beliau berkata kepada kami, \"Apakah kalian sudah shalat Ashar?\" Kami menjawab. Belum, kami baru saja selesai dari waktu shalat Zhuhur.\" dia berkata, \"Kerjakanlah shalat Ashar.\"Kemudian kami shalat Ashar, dan setelah kami selesai, dia berkata; \"Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Itulah shalatnya orang munafik, duduk menunggu waktu shalat Ashar, hingga apabila telah berada pada dua tanduk setan, maka dia berdiri lalu mematuk-matuk empat kali (Shalat empat rakaat dengan cepat) tanpa berdzikir kepada -Allah Azza wa Jalla- kecuali sedikit.\""},"507":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الَّذِي تَفُوتُهُ صَلَاةُ الْعَصْرِ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Bapaknya] dari Rasulullah Shallallahu'alaihi wasallam beliau bersabda: \"Orang yang kehilangan shalat Ashar seolah-olah dia kehilangan (dirampas) keluarga dan hartanya.\""},"508":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الَّذِي تَفُوتُهُ صَلَاةُ الْعَصْرِ فَكَأَنَّمَا وُتِرَ أَهْلَهُ وَمَالَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibnu Umar Radliyallahu'anhu], dari Rasulullah Shallallahu'alaihi wasallam, beliau bersabda: \"Orang yang kehilangan shalat Ashar maka seolah-olah kehilangan (dirampas) keluarga dan hartanya.\""},"509":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ وَاضِحٍ قَالَ حَدَّثَنَا قُدَامَةُ يَعْنِي ابْنَ شِهَابٍ عَنْ بُرْدٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ جِبْرِيلَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُهُ مَوَاقِيتَ الصَّلَاةِ فَتَقَدَّمَ جِبْرِيلُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَهُ وَالنَّاسُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى الظُّهْرَ حِينَ زَالَتْ الشَّمْسُ وَأَتَاهُ حِينَ كَانَ الظِّلُّ مِثْلَ شَخْصِهِ فَصَنَعَ كَمَا صَنَعَ فَتَقَدَّمَ جِبْرِيلُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَهُ وَالنَّاسُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى الْعَصْرَ ثُمَّ أَتَاهُ حِينَ وَجَبَتْ الشَّمْسُ فَتَقَدَّمَ جِبْرِيلُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَهُ وَالنَّاسُ خَلَفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى الْمَغْرِبَ ثُمَّ أَتَاهُ حِينَ غَابَ الشَّفَقُ فَتَقَدَّمَ جِبْرِيلُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَهُ وَالنَّاسُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى الْعِشَاءَ ثُمَّ أَتَاهُ حِينَ انْشَقَّ الْفَجْرُ فَتَقَدَّمَ جِبْرِيلُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَهُ وَالنَّاسُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى الْغَدَاةَ ثُمَّ أَتَاهُ الْيَوْمَ الثَّانِيَ حِينَ كَانَ ظِلُّ الرَّجُلِ مِثْلَ شَخْصِهِ فَصَنَعَ مِثْلَ مَا صَنَعَ بِالْأَمْسِ فَصَلَّى الظُّهْرَ ثُمَّ أَتَاهُ حِينَ كَانَ ظِلُّ الرَّجُلِ مِثْلَ شَخْصَيْهِ فَصَنَعَ كَمَا صَنَعَ بِالْأَمْسِ فَصَلَّى الْعَصْرَ ثُمَّ أَتَاهُ حِينَ وَجَبَتْ الشَّمْسُ فَصَنَعَ كَمَا صَنَعَ بِالْأَمْسِ فَصَلَّى الْمَغْرِبَ فَنِمْنَا ثُمَّ قُمْنَا ثُمَّ نِمْنَا ثُمَّ قُمْنَا فَأَتَاهُ فَصَنَعَ كَمَا صَنَعَ بِالْأَمْسِ فَصَلَّى الْعِشَاءَ ثُمَّ أَتَاهُ حِينَ امْتَدَّ الْفَجْرُ وَأَصْبَحَ وَالنُّجُومُ بَادِيَةٌ مُشْتَبِكَةٌ فَصَنَعَ كَمَا صَنَعَ بِالْأَمْسِ فَصَلَّى الْغَدَاةَ ثُمَّ قَالَ مَا بَيْنَ هَاتَيْنِ الصَّلَاتَيْنِ وَقْتٌ","id":"Telah mengabarkan kepada kami [Yusuf bin Wadlih] dia berkata; Telah menceritakan kepada kami [Qudamah yaitu Ibnu Syihab] dari [Burad] dari [Atha bin Abu Rabah] dari [Jabir bin Abdullah], bahwa Jibril datang kepada Nabi Shallallahu'alaihi wasallam untuk mengajari waktu-waktu shalat. Jibril maju dan Rasulullah Shallallahu'alaihi wasallam di belakangnya, sedangkan manusia berada di belakang Rasullah Shallallahu'alaihi wasallam. Lalu Jibril shalat Zhuhur ketika matahari telah tergelincir, dan datang kembali ketika bayangan sudah seperti aslinya, lalu melakukan seperti yang dilakukan pertama kali, Jibril maju dan Rasullah Shallallahu'alaihi wasallam di belakangnya, sedangkan manusia dibelakang Rasulullah Shallallahu'alaihi wasallam, lalu jibril shalat Maghrib tatkala mega merah telah hilang, Jibril datang lagi, lalu Jibril maju dan Rasulullah Shallallahu'alaihi wasallam di belakangnya, sedangkan manusia di belakang Rasulullah Shallallahu'alaihi wasallam, lantas Jibril segera shalat Isya. Saat fajar mulai terbit, Jibril datang lagi, lalu Jibril maju dan Rasulullah Shallallahu'alaihi wasallam di belakangnya, sedangkan manusia di belakang Rasulullah Shallallahu'alaihi wasallam, lalu Jibril shalat Subuh. Pada hari kedua, Jibril datang ketika bayangan seseorang seperti aslinya dan berbuat sebagaimana yang diperbuat kemarin, yakni melaksanakan shalat Zhuhur. Kemudian datang lagi saat bayangan seseorang seperti dua kali aslinya dan berbuat seperti yang diperbuat kemarin dan segera shalat Ashar. Lalu datang lagi saat matahari terbenam, dan melakukan seperti yang dilakukan kemarin dan shalat Maghrib kemudian kami tidur. Kemudian bangun, kemudian tidur, kemudian bangun lagi, dan datanglah Jibril dan berbuat seperti yang diperbuat kemarin, lalu shalat Isya'. Besoknya, ketika fajar telah terbentang dan waktu sudah pagi, Jibril datang sedangkan bintang sangat terang. Ia segera berbuat seperti kemarin, lalu ia shalat Subuh. Kemudian ia berkata, \"Waktu shalat ada diantara dua shalat tadi.\""},"510":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ مَعْمَرًا عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ رَكْعَتَيْنِ مِنْ صَلَاةِ الْعَصْرِ قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ أَوْ رَكْعَةً مِنْ صَلَاةِ الصُّبْحِ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Mu'tamir] dia berkata; Saya mendengar [Ma'mar] dari [Ibnu Thawus] dari [Bapaknya] dari [Ibnu Abbas] dari [Abu Hurairah] dari Nabi Shallallahu'alaihi wasallam, beliau Shallallahu'alaihi wasallam bersabda: \"Barangsiapa mendapatkan dua rakaat shalat Ashar sebelum terbenamnya matahari - atau satu rakaat shalat Subuh sebelum matahari terbit - maka ia mendapatkan shalat tersebut.\""},"511":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ مَعْمَرًا عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ رَكْعَةً مِنْ صَلَاةِ الْعَصْرِ قَبْلَ أَنْ تَغِيبَ الشَّمْسُ أَوْ أَدْرَكَ رَكْعَةً مِنْ الْفَجْرِ قَبْلَ طُلُوعِ الشَّمْسِ فَقَدْ أَدْرَكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Mu'tamir] dia berkata; Saya mendengar [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi Shallallahu'alaihi wasallam, beliau bersabda: \"Barangsiapa mendapatkan satu rakaat shalat Ashar sebelum matahari terbenam - atau mendapatkan satu rakaat shalat Subuh sebelum matahari terbit - maka ia telah mendapatkan shalat tersebut.\""},"512":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَدْرَكَ أَحَدُكُمْ أَوَّلَ سَجْدَةٍ مِنْ صَلَاةِ الْعَصْرِ قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَلْيُتِمَّ صَلَاتَهُ وَإِذَا أَدْرَكَ أَوَّلَ سَجْدَةٍ مِنْ صَلَاةِ الصُّبْحِ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَلْيُتِمَّ صَلَاتَهُ","id":"Telah mengabarkan kepada kami [Amr bin Manshur] dia berkata; Telah menceritakan kepada kami [Al Fadhl bin Dukain] dia berkata; Telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi Shallallahu'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian mendapatkan permulaan sujud dari shalat Ashar sebelum matahari terbenam, maka hendaklah menyempurnakan shalatnya. Jika ia mendapatkan permulaan sujud dari shalat Subuh sebelum matahari terbit, maka hendaklah menyempurnakan shalatnya.\""},"513":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ وَعَنْ بُسْرِ بْنِ سَعِيدٍ وَعَنْ الْأَعْرَجِ يُحَدِّثُونَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ رَكْعَةً مِنْ صَلَاةِ الصُّبْحِ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَ الصُّبْحَ وَمَنْ أَدْرَكَ رَكْعَةً مِنْ الْعَصْرِ قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَقَدْ أَدْرَكَ الْعَصْرَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Zaid bin Aslam] dari ['Atha bin Yasar], dan dari [Busr bin Sa'id] dari [Al A'raj] mereka berkata; dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian mendapatkan satu rakaat dari shalat Subuh sebelum matahari terbit, maka ia mendapatkan shalat Subuh dan barangsiapa mendapatkan satu rakaat dari shalat Ashar sebelum matahari terbenam, maka ia telah mendapatkan shalat Ashar.\""},"514":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ نَصْرِ بْنِ عَبْدِ الرَّحْمَنِعَنْ جَدِّهِ مُعَاذٍ أَنَّهُ طَافَ مَعَ مُعَاذِ ابْنِ عَفْرَاءَ فَلَمْ يُصَلِّ فَقُلْتُ أَلَا تُصَلِّي فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ بَعْدَ الْعَصْرِ حَتَّى تَغِيبَ الشَّمْسُ وَلَا بَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah mengabarkan kepada kami [Abu Daud] dia berkata; Telah menceritakan kepada kami [Sa'id bin Amir] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Sa'ad bin Ibrahim] dari [Nashr bin Abdurrahman] dari Kakeknya - [Mu'adz] - bahwa dia berkeliling bersama Mu'adz bin 'Afra dan dia belum shalat, maka aku tanyakan kepadanya; apakah engkau tidak shalat? Dia menjawab: Rasulullah Shallallahu'alaihi wasallam bersabda: \"Tidak ada shalat setelah shalat Ashar hingga matahari terbenam, dan tidak ada shalat setelah shalat shubuh hingga matahari terbit.\""},"515":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ هِشَامٍ قَالَ حَدَّثَنَا مَخْلَدُ بْنُ يَزِيدَ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ وَقْتِ الصَّلَاةِ فَقَالَ أَقِمْ مَعَنَا هَذَيْنِ الْيَوْمَيْنِ فَأَمَرَ بِلَالًا فَأَقَامَ عِنْدَ الْفَجْرِ فَصَلَّى الْفَجْرَ ثُمَّ أَمَرَهُ حِينَ زَالَتْ الشَّمْسُ فَصَلَّى الظُّهْرَ ثُمَّ أَمَرَهُ حِينَ رَأَى الشَّمْسَ بَيْضَاءَ فَأَقَامَ الْعَصْرَ ثُمَّ أَمَرَهُ حِينَ وَقَعَ حَاجِبُ الشَّمْسِ فَأَقَامَ الْمَغْرِبَ ثُمَّ أَمَرَهُ حِينَ غَابَ الشَّفَقُ فَأَقَامَ الْعِشَاءَ ثُمَّ أَمَرَهُ مِنْ الْغَدِ فَنَوَّرَ بِالْفَجْرِ ثُمَّ أَبْرَدَ بِالظُّهْرِ وَأَنْعَمَ أَنْ يُبْرِدَ ثُمَّ صَلَّى الْعَصْرَ وَالشَّمْسُ بَيْضَاءُ وَأَخَّرَ عَنْ ذَلِكَ ثُمَّ صَلَّى الْمَغْرِبَ قَبْلَ أَنْ يَغِيبَ الشَّفَقُ ثُمَّ أَمَرَهُ فَأَقَامَ الْعِشَاءَ حِينَ ذَهَبَ ثُلُثُ اللَّيْلِ فَصَلَّاهَا ثُمَّ قَالَ أَيْنَ السَّائِلُ عَنْ وَقْتِ الصَّلَاةِ وَقْتُ صَلَاتِكُمْ مَا بَيْنَ مَا رَأَيْتُمْ","id":"Telah mengabarkan kepada kami [Amr bin Hisyam] dia berkata; Telah menceritakan kepada kami [Makhlad bin Yazid] dari [Sufyan Ats Tsauri] dari [Al Qamah bin Martsad] dari [Sulaiman bin Buraidah] dari [Bapaknya] dia berkata; Seorang laki-laki datang kepada Rasulullah Shallallahu'alaihi wasallam dan bertanya tentang waktu shalat. Beliau Shallallahu'alaihi wasallam menjawab, \"Ikutlah shalat bersama kami dalam dua hari ini'. Beliau Shallallahu'alaihi wasallam lalu memerintahkan Bilal untuk mengumandangkan i iqamat ketika fajar, kemudian mereka mengerjakan shalat Fajar (Subuh). Kemudian beliau Shallallahu'alaihi wasallam memerintahkan Bilal (untuk i iqamat) ketika matahari tergelincir lalu mengerjakan shalat Zhuhur. Lalu beliau memerintahkannya untuk i iqamat ketika melihat matahari sudah putih lalu mengejar shalat Ashar. Beliau juga memerintahkan i iqamat ketika matahari terbenam, lalu beliau shalat Maghrib. Kemudian beliau memerintahkannya untuk i iqamat ketika megah merah telah hilang, lalu mengerjakan shalat Isya'. Besoknya beliau memeintahkannya untuk i iqamat, mengakhirkan shalat Subuh hingga cahaya pagi menyebar. Kemudian beliau menunda shalat Zhuhur sampai cuaca dingin dan alangkah nikmatnya penundaan - cuaca dingin - ini. Lalu shalat Ashar tatkala matahari putih dan beliau juga mengakhirkan hal itu sampai kemudian shalat Maghrib sebelum hilangnya mega merah, kemudian memerintahkan lagi i iqamat shalat Isya' ketika lewat sepertiganya, lalu beliau shalat Isya. Kemudian beliau Shallallahu'alaihi wasallam berkata; \"Mana orang yang bertanya tentang waktu shalat. Waktu shalat kalian adalah sebagaimana yang telah kalian lihat. "},"516":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ قَالَ سَمِعْتُ حَسَّانَ بْنَ بِلَالٍ عَنْ رَجُلٍ مِنْ أَسْلَمَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّهُمْ كَانُوا يُصَلُّونَ مَعَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَغْرِبَ ثُمَّ يَرْجِعُونَ إِلَى أَهَالِيهِمْ إِلَى أَقْصَى الْمَدِينَةِ يَرْمُونَ وَيُبْصِرُونَ مَوَاقِعَ سِهَامِهِمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah menceritakan kepada kami [Muhammad] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyir] dia berkata; Saya mendengar [Hasan bin Bilal] dari [seorang Bani Aslam] -dari kalangan sahabat Nabi Shallallahu'alaihi wasallam- bahwa mereka shalat Maghrib bersama Nabi Shallallahu'alaihi wasallam kemudian mereka pulang ke keluarga mereka di ujung Madinah, mereka melempar anak panah mereka dan mereka masih melihat tempat jatuhnya anak panah itu. "},"517":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ خَيْرِ بْنِ نُعَيْمٍ الْحَضْرَمِيِّ عَنْ ابْنِ هُبَيْرَةَ عَنْ أَبِي تَمِيمٍ الْجَيْشَانِيِّ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ بِالْمُخَمَّصِ قَالَ إِنَّ هَذِهِ الصَّلَاةَ عُرِضَتْ عَلَى مَنْ كَانَ قَبْلَكُمْ فَضَيَّعُوهَا وَمَنْ حَافَظَ عَلَيْهَا كَانَ لَهُ أَجْرُهُ مَرَّتَيْنِ وَلَا صَلَاةَ بَعْدَهَا حَتَّى يَطْلُعَ الشَّاهِدُ وَالشَّاهِدُ النَّجْمُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Al Laits] dari [Khair bin Nu'aim Al Hadlrami] dari [Ibnu Hubairah] dari [Abu Tamim Al Jaisyani] dari [Abu Bashrah Al Ghifari] dia berkata; \"Kami shalat Ashar bersama 'Rasulullah Shallallahu'alaihi wasallam di Mukhammash, lalu beliau Shallallahu'alaihi wasallam bersabda: \"Shalat ini diwajibkan kepada umat-umat sebelum kalian, tetapi mereka menyia-nyiakan. Barangsiapa menjaganya maka dia mendapat pahala dua kali, dan tidak ada shalat setelahnya sehingga munculnya bintang.\""},"518":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَبَا أَيُّوبَ الْأَزْدِيَّ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ شُعْبَةُ كَانَ قَتَادَةُ يَرْفَعُهُ أَحْيَانًا وَأَحْيَانًا لَا يَرْفَعُهُقَالَ وَقْتُ صَلَاةِ الظُّهْرِ مَا لَمْ تَحْضُرْ الْعَصْرُ وَوَقْتُ صَلَاةِ الْعَصْرِ مَا لَمْ تَصْفَرَّ الشَّمْسُ وَوَقْتُ الْمَغْرِبِ مَا لَمْ يَسْقُطْ ثَوْرُ الشَّفَقِ وَوَقْتُ الْعِشَاءِ مَا لَمْ يَنْتَصِفْ اللَّيْلُ وَوَقْتُ الصُّبْحِ مَا لَمْ تَطْلُعْ الشَّمْسُ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Abu Daud] Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; Saya mendengar [Abu Ayyub Al Azdi] berkata; dari [Abdullah bin Amru] -Syu'bah bertutur; Qatadah kadang menyandarkannya kepada Nabi Shallallahu'alaihi wasallam, dan kadang juga tidak- dia berkata; \"Waktu shalat Zhuhur adalah sebelum datangya Ashar. Dan waktu shalat Ashar adalah selama matahari belum menguning, waktu shalat Maghrib adalah selagi mega merah belum hilang, waktu shalat Isya' adalah selama malam belum lewat setengahnya, dan waktu shalat Subuh adalah sebelum matahari terbit.\""},"519":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ وَأَحْمَدُ بْنُ سُلَيْمَانَ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا أَبُو دَاوُدَ عَنْ بَدْرِ بْنِ عُثْمَانَ قَالَ إِمْلَاءً عَلَيَّ حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي مُوسَى عَنْ أَبِيهِ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَائِلٌ يَسْأَلُهُ عَنْ مَوَاقِيتِ الصَّلَاةِ فَلَمْ يَرُدَّ عَلَيْهِ شَيْئًا فَأَمَرَ بِلَالًا فَأَقَامَ بِالْفَجْرِ حِينَ انْشَقَّ ثُمَّ أَمَرَهُ فَأَقَامَ بِالظُّهْرِ حِينَ زَالَتْ الشَّمْسُ وَالْقَائِلُ يَقُولُ انْتَصَفَ النَّهَارُ وَهُوَ أَعْلَمُ ثُمَّ أَمَرَهُ فَأَقَامَ بِالْعَصْرِ وَالشَّمْسُ مُرْتَفِعَةٌ ثُمَّ أَمَرَهُ فَأَقَامَ بِالْمَغْرِبِ حِينَ غَرَبَتْ الشَّمْسُ ثُمَّ أَمَرَهُ فَأَقَامَ بِالْعِشَاءِ حِينَ غَابَ الشَّفَقُ ثُمَّ أَخَّرَ الْفَجْرَ مِنْ الْغَدِ حِينَ انْصَرَفَ وَالْقَائِلُ يَقُولُ طَلَعَتْ الشَّمْسُ ثُمَّ أَخَّرَ الظُّهْرَ إِلَى قَرِيبٍ مِنْ وَقْتِ الْعَصْرِ بِالْأَمْسِ ثُمَّ أَخَّرَ الْعَصْرَ حَتَّى انْصَرَفَ وَالْقَائِلُ يَقُولُ احْمَرَّتْ الشَّمْسُ ثُمَّ أَخَّرَ الْمَغْرِبَ حَتَّى كَانَ عِنْدَ سُقُوطِ الشَّفَقِ ثُمَّ أَخَّرَ الْعِشَاءَ إِلَى ثُلُثِ اللَّيْلِ ثُمَّ قَالَ الْوَقْتُ فِيمَا بَيْنَ هَذَيْنِ","id":"Telah mengabarkan kepada kami [Abdah bin Abdullah] dan [Ahmad bin Sulaiman] keduanya berkata; telah menceritakan kepada kami [Abu Daud] dari [Badar bin Utsman] berkata; telah menceritakan kepada kami [Abu Bakar bin Abu Musa] dari [Bapaknya] dia berkata; \"Seorang laki-laki datang kepada nabi Shallallahu'alaihi wasallam dan bertanya tantang waktu shalat, namun beliau tidak menjawabnya sedikitpun. Tetapi beliau Shallallahu'alaihi wasallam menyuruh Bilal untuk iqamat lalu beliau mengerjakan shalat Subuh ketika Fajar terbit. Kemudian beliau menyuruh Bilal untuk iqamat ketika matahari sudah tergelincir, lalu mengerjakan shalat Zhuhur - perawi berkata, \"Ketika tengah hari\" Bilal lebih tahu -. Kemudian beliau menyuruh bilal untuk iqamat tatkala matahari masih tinggi untuk shalat Ashar. Kemudian menyuruh bilal untuk iqamat ketika matahari telah terbenam untuk shalat Maghrib. Kemudian menyuruhnya untuk iqamat lalu shalat Isya ketika mega merah telah lenyap. Kemudian beliau mengakhirkan shalat Fajar pada esoknya ketika beliau selesai - perawi berkata, \"matahari menjelang terbit\"-.Kemudian beliau juga mengakhirkan Zhuhur hingga menjelang shalat Ashar hingga beliau selesai shalat-perawi berkata, \"matahari sudah memerah\"-. Kemudian beliau Shallallahu'alaihi wasallam shalat maghrib hingga hampir hilangnya mega merah, dan beliau mengakhirkan shalat Isya sampai sepertiga malam. Lalu beliau Shallallahu'alaihi wasallam bersabda: 'Waktu shalat adalah yang ada di antara keduanya'."},"520":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنَا خَارِجَةُ بْنُ عَبْدِ اللَّهِ بْنِ سُلَيْمَانَ بْنِ زَيْدِ بْنِ ثَابِتٍ قَالَ حَدَّثَنِي الْحُسَيْنُ بْنُ بَشِيرِ بْنِ سَلَّامٍ عَنْ أَبِيهِ قَالَدَخَلْتُ أَنَا وَمُحَمَّدُ بْنُ عَلِيٍّ عَلَى جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ فَقُلْنَا لَهُ أَخْبِرْنَا عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَاكَ زَمَنَ الْحَجَّاجِ بْنِ يُوسُفَ قَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى الظُّهْرَ حِينَ زَالَتْ الشَّمْسُ وَكَانَ الْفَيْءُ قَدْرَ الشِّرَاكِ ثُمَّ صَلَّى الْعَصْرَ حِينَ كَانَ الْفَيْءُ قَدْرَ الشِّرَاكِ وَظِلِّ الرَّجُلِ ثُمَّ صَلَّى الْمَغْرِبَ حِينَ غَابَتْ الشَّمْسُ ثُمَّ صَلَّى الْعِشَاءَ حِينَ غَابَ الشَّفَقُ ثُمَّ صَلَّى الْفَجْرَ حِينَ طَلَعَ الْفَجْرُ ثُمَّ صَلَّى مِنْ الْغَدِ الظُّهْرَ حِينَ كَانَ الظِّلُّ طُولَ الرَّجُلِ ثُمَّ صَلَّى الْعَصْرَ حِينَ كَانَ ظِلُّ الرَّجُلِ مِثْلَيْهِ قَدْرَ مَا يَسِيرُ الرَّاكِبُ سَيْرَ الْعَنَقِ إِلَى ذِي الْحُلَيْفَةِ ثُمَّ صَلَّى الْمَغْرِبَ حِينَ غَابَتْ الشَّمْسُ ثُمَّ صَلَّى الْعِشَاءَ إِلَى ثُلُثِ اللَّيْلِ أَوْ نِصْفِ اللَّيْلِ شَكَّ زَيْدٌ ثُمَّ صَلَّى الْفَجْرَ فَأَسْفَرَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] dia berkata; telah menceritakan kepada kami [Kharijah bin Abdullah bin Sulaiman bin Zaid bin Tsabit] dia berkata; telah menceritakan kepadaku [Al Husain bin Basyir bin Salam] dari [bapaknya], dia berkata; \"Aku dan Muhammad bin Ali masuk ke rumah [Jabir bin Abdullah Al Anshari] lalu kami berkata kepadanya, 'kabarkanlah kepada kami tentang shalat Rasulullah Shallallahu'alaihi wasallam -saat itu masa pemerintahan Hajjaj bin Yusuf-' Ia menjawab, 'Rasulullah Shallallahu'alaihi wasallam pernah keluar lalu shalat Zhuhur ketika matahari telah tergelincir dan bayangannya saat itu seukuran tali sandal. Kemudian beliau shalat Ashar ketika bayangan telah menjadi seukuran tali sandal dan bayangan orang. Kemudian beliau shalat Maghrib ketika matahari telah terbenam, lalu beliau shalat Isya ketika mega merah telah lenyap. Selanjutnya beliau Shalat Subuh ketika terbit fajar. Kemudian besoknya beliau shalat Zhuhur ketika bayangan setinggi orang, kemudian shalat Ashar ketika bayangan seseorang menjadi dua kali lipatnya, seukuran perjalanan pengendara yang berlalu dengan cepat ke Dzul Hulaifah. Kemudian shalat Maghrib ketika matahari terbenam dan shalat Isya sampai sepertiga malam atau pertengahan malam. Lalu shalat subuh ketika sudah kelihatan agak menguning'."},"521":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عَوْفٌ قَالَ حَدَّثَنِي سَيَّارُ بْنُ سَلَامَةَ قَالَدَخَلْتُ عَلَى أَبِي بَرْزَةَ فَسَأَلَهُ أَبِي كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْمَكْتُوبَةَ قَالَ كَانَ يُصَلِّي الْهَجِيرَ الَّتِي تَدْعُونَهَا الْأُولَى حِينَ تَدْحَضُ الشَّمْسُ وَكَانَ يُصَلِّي الْعَصْرَ حِينَ يَرْجِعُ أَحَدُنَا إِلَى رَحْلِهِ فِي أَقْصَى الْمَدِينَةِ وَالشَّمْسُ حَيَّةٌ وَنَسِيتُ مَا قَالَ فِي الْمَغْرِبِ وَكَانَ يَسْتَحِبُّ أَنْ يُؤَخِّرَ الْعِشَاءَ الَّتِي تَدْعُونَهَا الْعَتَمَةَ وَكَانَ يَكْرَهُ النَّوْمَ قَبْلَهَا وَالْحَدِيثَ بَعْدَهَا وَكَانَ يَنْفَتِلُ مِنْ صَلَاةِ الْغَدَاةِ حِينَ يَعْرِفُ الرَّجُلُ جَلِيسَهُ وَكَانَ يَقْرَأُ بِالسِّتِّينَ إِلَى الْمِائَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami ['Auf] dia berkata; telah menceritakan kepada kami [Sayyar bin Salamah] berkata; \"Aku datang ke [Abu Barzah] lalu bertanya kepadanya. Bagaimana cara Rasulullah Shallallahu'alaihi wasallam mengerjakan shalat wajib? Ia (Sayyar) menjawab, 'Rasulullah Shallallahu'alaihi wasallam shalat ketika cuaca sangat panas-kalian menyebutnya shalat yang pertama-ketika matahari condong ke barat, dan beliau shalat Ashar ketika salah seorang dari kita pulang kerumahnya di ujung madinah dan matahari masih bersinar. Aku lupa apa yang dikatakan pada shalat Maghrib. Beliau suka menangguhkan shalat Isya-yang biasa kalian sebut shalat 'atamah-. Beliau tidak suka tidur sebelum Isya dan bercakap-cakap sesudahnya. Beliau shalat Subuh ketika seseorang bisa mengenali orang yang duduk di sebelahnya, dan beliau biasa membaca enam puluh sampai seratus ayat'. "},"522":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حُسَيْنِ بْنِ عَلِيِّ بْنِ حُسَيْنٍ قَالَ أَخْبَرَنِي وَهْبُ بْنُ كَيْسَانَ قَالَ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَجَاءَ جِبْرِيلُ عَلَيْهِ السَّلَام إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ زَالَتْ الشَّمْسُ فَقَالَ قُمْ يَا مُحَمَّدُ فَصَلِّ الظُّهْرَ حِينَ مَالَتْ الشَّمْسُ ثُمَّ مَكَثَ حَتَّى إِذَا كَانَ فَيْءُ الرَّجُلِ مِثْلَهُ جَاءَهُ لِلْعَصْرِ فَقَالَ قُمْ يَا مُحَمَّدُ فَصَلِّ الْعَصْرَ ثُمَّ مَكَثَ حَتَّى إِذَا غَابَتْ الشَّمْسُ جَاءَهُ فَقَالَ قُمْ فَصَلِّ الْمَغْرِبَ فَقَامَ فَصَلَّاهَا حِينَ غَابَتْ الشَّمْسُ سَوَاءً ثُمَّ مَكَثَ حَتَّى إِذَا ذَهَبَ الشَّفَقُ جَاءَهُ فَقَالَ قُمْ فَصَلِّ الْعِشَاءَ فَقَامَ فَصَلَّاهَا ثُمَّ جَاءَهُ حِينَ سَطَعَ الْفَجْرُ فِي الصُّبْحِ فَقَالَ قُمْ يَا مُحَمَّدُ فَصَلِّ فَقَامَ فَصَلَّى الصُّبْحَ ثُمَّ جَاءَهُ مِنْ الْغَدِ حِينَ كَانَ فَيْءُ الرَّجُلِ مِثْلَهُ فَقَالَ قُمْ يَا مُحَمَّدُ فَصَلِّ فَصَلَّى الظُّهْرَ ثُمَّ جَاءَهُ جِبْرِيلُ عَلَيْهِ السَّلَام حِينَ كَانَ فَيْءُ الرَّجُلِ مِثْلَيْهِ فَقَالَ قُمْ يَا مُحَمَّدُ فَصَلِّ فَصَلَّى الْعَصْرَ ثُمَّ جَاءَهُ لِلْمَغْرِبِ حِينَ غَابَتْ الشَّمْسُ وَقْتًا وَاحِدًا لَمْ يَزُلْ عَنْهُ فَقَالَ قُمْ فَصَلِّ فَصَلَّى الْمَغْرِبَ ثُمَّ جَاءَهُ لِلْعِشَاءِ حِينَ ذَهَبَ ثُلُثُ اللَّيْلِ الْأَوَّلُ فَقَالَ قُمْ فَصَلِّ فَصَلَّى الْعِشَاءَ ثُمَّ جَاءَهُ لِلصُّبْحِ حِينَ أَسْفَرَ جِدًّا فَقَالَ قُمْ فَصَلِّ فَصَلَّى الصُّبْحَ فَقَالَ مَا بَيْنَ هَذَيْنِ وَقْتٌ كُلُّهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Husain bin Ali bin Husain] dia berkata; Telah mengabarkan kepadaku [Wahab bin Kaisan] dia berkata; telah menceritakan kepada kami [Jabir bin Abdullah] dia berkata, \"Jibril 'alaihissalam datang kepada Rasulullah Shallallahu'alaihi wasallam ketika matahari telah condong ke barat, ia berkata.'Wahai Muhammad, bangkitlah dan tegakkanlah shalat! ' Lalu beliau shalat Zhuhur-ketika matahari condong ke barat-. Kemudian dia menetap hingga tatkala bayangan seseorang seperti aslinya. Ia datang pada waktu Ashar, lantas berkata, 'Wahai Muhammad, bangkitlah dan tegakkanlah shalat! ' Lalu beliau shalat Ashar, Kemudian dia menetap. Ia datang lagi ketika matahari telah terbenam dan berkata, 'Bangkit dan tegakkan shalat Maghrib! ' lalu beliau shalat Maghrib ketika matahari terbenam. Kemudian dia menetap dan tatkala awan merah telah hilang Jibril datang dan berkata 'bangkitlah dan tegakkan shalat Isya! ' Lalu beliau shalat Isya, dan saat fajar terbit pada waktu pagi, ia berkata, 'Bangkitlah dan tegakkan shalat! 'Lalu beliau shalat Subuh. Kemudian besoknya ia datang lagi ketika bayangan orang sama seperti aslinya dan berkata, 'Wahai Muhammad, bangkitlah dan tegakkanlah shalat!, lalu beliau shalat Zhuhur. Kemudian Jibril datang lagi tatkala bayangan (benda) seperti dua kali lipatnya, ia berkata, 'Wahai Muhammad, tagakkanlah shalat! lalu beliau shalat Ashar. Kemudian Jibril datang lagi untuk shalat saat matahari terbenam dan hanya satu waktu. Ia berkata, 'Wahai Muhammad, tegakkanlah shalat! 'Lalu beliau shalat Maghrib. Ia juga datang untuk shalat Isya ketika sepertiga malam berlalu, 'Wahai Muhammad, tegakkanlah shalat!, lalu beliau shalat Isya. Kemudian Jibril datang untuk shalat Subuh ketika sudah terang sekali, ia berkata, 'Wahai Muhammad, tegakkanlah shalat! lalu beliau shalat subuh. Lalu beliau Shallallahu'alaihi wasallam bersabda: \"Semua waktu shalat adalah diantara dua waktu ini.\""},"523":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَسَنٍ قَالَقَدِمَ الْحَجَّاجُ فَسَأَلْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الظُّهْرَ بِالْهَاجِرَةِ وَالْعَصْرَ وَالشَّمْسُ بَيْضَاءُ نَقِيَّةٌ وَالْمَغْرِبَ إِذَا وَجَبَتْ الشَّمْسُ وَالْعِشَاءَ أَحْيَانًا كَانَ إِذَا رَآهُمْ قَدْ اجْتَمَعُوا عَجَّلَ وَإِذَا رَآهُمْ قَدْ أَبْطَئُوا أَخَّرَ","id":"Telah mengabarkan kepada kami [Amru bin Mas'adah] dan [Muhammad bin Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sa'ad bin Ibrahim] dari [Muhammad bin Amru bin Hasan] dia berkata, \"Hajjaj datang, lalu kami bertanya kepada [Jabir bin Abdullah]. Ia berkata, 'Rasullulah Shallallahu'alaihi wasallam shalat Zhuhur pada tengah hari, shalat Ashar tatkala matahari masih putih bersih, shalat Maghrib saat matahari telah terbenam, dan shalat Isya kadang-kadang bila beliau Shallallahu'alaihi wasallam melihat para sahabat sudah berkumpul beliau menyegerakan, dan bila melihat mereka terlambat maka beliau Shallallahu'alaihi wasallam mengakhirkannya'."},"524":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ رَقَبَةَ عَنْ جَعْفَرِ بْنِ إِيَاسٍ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَأَنَا أَعْلَمُ النَّاسِ بِمِيقَاتِ هَذِهِ الصَّلَاةِ عِشَاءِ الْآخِرَةِ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهَا لِسُقُوطِ الْقَمَرِ لِثَالِثَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Raqabah] dari [Ja'far bin Iyas] dari [Habib bin Salim] dari [Nu'man bin Basyir] dia berkata; \"Aku orang yang paling tahu tentang waktu shalat ini, yakni shalat Isya yang terakhir, Rasulullah Shallallahu'alaihi wasallam biasa mengerjakan shalat Isya saat tenggelamnya bulan pada sepertiga malam yang pertama.\""},"525":{"ar":"أَخْبَرَنَا عُثْمَانُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ بَشِيرِ بْنِ ثَابِتٍ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَوَاللَّهِ إِنِّي لَأَعْلَمُ النَّاسِ بِوَقْتِ هَذِهِ الصَّلَاةِ صَلَاةِ الْعِشَاءِ الْآخِرَةِ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهَا لِسُقُوطِ الْقَمَرِ لِثَالِثَةٍ","id":"Telah mengabarkan kepada kami [Usman bin Abdullah] dia berkata; telah menceritakan kepada kami ['Affan] dia berkata; telah menceritakan kepada kami [Abu Awanah] dari [Abu Bisyr] dari [Basyir bin Tsabit] dari [Habib bin Salim] dari [An Nu'man bin Basyir] dia berkata; \"Aku orang yang paling tahu tentang waktu shalat ini, yakni shalat Isya yang terakhir, Rasulullah Shallallahu'alaihi wasallam biasa mengerjakan shalat Isya saat tenggelamnya bulan pada sepertiga malam yang pertama.\""},"526":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ عَوْفٍ عَنْ سَيَّارِ بْنِ سَلَامَةَ قَالَدَخَلْتُ أَنَا وَأَبِي عَلَى أَبِي بَرْزَةَ الْأَسْلَمِيِّ فَقَالَ لَهُ أَبِي أَخْبِرْنَا كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْمَكْتُوبَةَ قَالَ كَانَ يُصَلِّي الْهَجِيرَ الَّتِي تَدْعُونَهَا الْأُولَى حِينَ تَدْحَضُ الشَّمْسُ وَكَانَ يُصَلِّي الْعَصْرَ ثُمَّ يَرْجِعُ أَحَدُنَا إِلَى رَحْلِهِ فِي أَقْصَى الْمَدِينَةِ وَالشَّمْسُ حَيَّةٌ قَالَ وَنَسِيتُ مَا قَالَ فِي الْمَغْرِبِ قَالَ وَكَانَ يَسْتَحِبُّ أَنْ تُؤَخَّرَ صَلَاةُ الْعِشَاءِ الَّتِي تَدْعُونَهَا الْعَتَمَةَ قَالَ وَكَانَ يَكْرَهُ النَّوْمَ قَبْلَهَا وَالْحَدِيثَ بَعْدَهَا وَكَانَ يَنْفَتِلُ مِنْ صَلَاةِ الْغَدَاةِ حِينَ يَعْرِفُ الرَّجُلُ جَلِيسَهُ وَكَانَ يَقْرَأُ بِالسِّتِّينَ إِلَى الْمِائَةِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah] dari [Auf] dari [Sayyar bin Salamah] dia berkata; \"Aku dan bapakku menemui [Abu Barzah Al Aslami] lalu bapakku bertanya kepadanya, 'Bagaimana cara Rasulullah Shallallahu'alaihi wasallam mengerjakan shalat wajib?, dia (Sayyar) menjawab, 'Rasulullah Shallallahu'alaihi wasallam shalat Zhuhur -kalian menyebutnya pertama- ketika matahari bergeser ke barat, dan beliau shalat Ashar ketika salah seorang dari kita pulang ke rumahnya diujung madinah dan matahari masih bersinar. -Aku lupa apa yang dikatakan shalat Maghrib- dan beliau suka mengakhirkan shalat Isya -shalat ini biasa kalian sebut shalat 'Atamah-. Beliau tidak suka tidur sebelum shalat Isya dan bercakap-cakap sesudahnya, dan beliau selesai shalat Subuh ketika seseorang bisa mengenali orang yang duduk di sebelahnya. Beliau biasanya membaca enam puluh sampai seratus ayat'."},"527":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ وَيُوسُفُ بْنُ سَعِيدٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ قُلْتُ لِعَطَاءٍأَيُّ حِينٍ أَحَبُّ إِلَيْكَ أَنْ أُصَلِّيَ الْعَتَمَةَ إِمَامًا أَوْ خِلْوًا قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ أَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ بِالْعَتَمَةِ حَتَّى رَقَدَ النَّاسُ وَاسْتَيْقَظُوا وَرَقَدُوا وَاسْتَيْقَظُوا فَقَامَ عُمَرُ فَقَالَ الصَّلَاةَ الصَّلَاةَ قَالَ عَطَاءٌ قَالَ ابْنُ عَبَّاسٍ خَرَجَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنِّي أَنْظُرُ إِلَيْهِ الْآنَ يَقْطُرُ رَأْسُهُ مَاءً وَاضِعًا يَدَهُ عَلَى شِقِّ رَأْسِهِ قَالَ وَأَشَارَ فَاسْتَثْبَتُّ عَطَاءً كَيْفَ وَضَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَى رَأْسِهِ فَأَوْمَأَ إِلَيَّ كَمَا أَشَارَ ابْنُ عَبَّاسٍ فَبَدَّدَ لِي عَطَاءٌ بَيْنَ أَصَابِعِهِ بِشَيْءٍ مِنْ تَبْدِيدٍ ثُمَّ وَضَعَهَا فَانْتَهَى أَطْرَافُ أَصَابِعِهِ إِلَى مُقَدَّمِ الرَّأْسِ ثُمَّ ضَمَّهَا يَمُرُّ بِهَا كَذَلِكَ عَلَى الرَّأْسِ حَتَّى مَسَّتْ إِبْهَامَاهُ طَرَفَ الْأُذُنِ مِمَّا يَلِي الْوَجْهَ ثُمَّ عَلَى الصُّدْغِ وَنَاحِيَةِ الْجَبِينِ لَا يُقَصِّرُ وَلَا يَبْطُشُ شَيْئًا إِلَّا كَذَلِكَ ثُمَّ قَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ أَنْ لَا يُصَلُّوهَا إِلَّا هَكَذَا","id":"Telah mengabarkan kepada kami [Ibrahim bin Hasan] dan [Yusuf bin Sa'id] keduanya berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij], dia berkata; \"Aku berkata kepada [Atha], \"kapan waktu yang paling engkau sukai untuk mengerjakan shalat Atamah (Isya) baik berjamaah maupun sendiri? ' dia menjawab, 'Aku mendengar [Ibnu Abbas] berkata, \"Rasulullah Shallallahu'alaihi wasallam shalat Isya pada malam itu setelah lewat sepertiganya, hingga orang-orang telah tidur dan terbangun kembali kemudian tidur lagi dan bangun lagi, lalu Umar bangun dan meneriakkan, 'shalat, shalat! Atha mengatakan bahwa Ibnu Abbas berkata, 'Lalu Nabi Shallallahu'alaihi wasallam Keluar, dan saat itu aku seolah-olah melihat kepala Nabi Shallallahu'alaihi wasallam meneteskan air dengan meletakkan tangannya di atas kepalanya'. Ibnu Abbas mengisyaratkan, \" Lalu Ibnu Juraij berkata; \"Lantas aku memastikan kepada Atha dengan berkata, 'Bagaimana cara Rasulullah Shallallahu'alaihi wasallam meletakkan tangannya dibagian kepalanya? ' Ia mengisyaratkan kepadaku sebagaimana yang dilakukan oleh Ibnu Abbas; Atha meletakkan sesuatu di antara celah-celah jarinya, kemudian meletakkan telapak tangannya di atas ubun-ubun kepala, membasahi kepalanya dan menyapu tangannya di atas kepala, wajah seterusnya menyapu pelipis, yaitu bagian di antara mata dan telinga, serta menyapu bagian janggut, tidak lebih dan tidak kurang sedikitpun, melainkan beginilah caranya.\" Rasulullah Shallallahu'alaihi wasallam bersabda, \"Seandainya aku tidak khawatir akan memberatkan umatku, maka aku pasti menyuruh mereka mengerjakan shalat Isya seperti pada waktu ini.\" "},"528":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ الْمَكِّيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ وَعَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَخَّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِشَاءَ ذَاتَ لَيْلَةٍ حَتَّى ذَهَبَ مِنْ اللَّيْلِ فَقَامَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَنَادَى الصَّلَاةَ يَا رَسُولَ اللَّهِ رَقَدَ النِّسَاءُ وَالْوِلْدَانُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمَاءُ يَقْطُرُ مِنْ رَأْسِهِ وَهُوَ يَقُولُ إِنَّهُ الْوَقْتُ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur Al Makki] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Amr] dari [Atha] dari [Ibnu Abbas] dan dari [Ibnu Juraij] dari [Atha] dari [Ibnu Abbas] dia berkata; \"Nabi Shallallahu'alaihi wasallam pada suatu malam mengakhirkan shalat Isya hingga sebagian malam lewat, lalu Umar bin Khaththab Radliyallahu'anhu bangkit dan memanggil, 'shalat wahai Rasulullah Shallallahu'alaihi wasallam, para wanita dan anak-anak telah tidur! ' kemudian Rasulullah Shallallahu'alaihi wasallam keluar sedangkan air menetes dari kepalanya, lalu bersabda: \"Inilah waktunya (shalat Isya) kalau saja aku tidak khawatir akan mamberatkan umatku\". "},"529":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤَخِّرُ الْعِشَاءَ الْآخِرَةَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari [Jabir bin Samurah], dia berkata; \"Rasulullah Shallallahu'alaihi wasallam mengakhirkan shalat Isya.\""},"530":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَأَمَرْتُهُمْ بِتَأْخِيرِ الْعِشَاءِ عِنْدَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; Telah menceritakan kepada kami [Sufyan] dia berkata; Telah menceritakan kepada kami [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Seandainya aku tidak khawatir akan memberatkan umatku, maka pasti aku menyuruh mereka untuk mengakhirkan shalat Isya pada setiap kali shalat\"."},"531":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا ابْنُ حِمْيَرٍ قَالَ حَدَّثَنَا ابْنُ أَبِي عَبْلَةَ عَنْ الزُّهْرِيِّ وَأَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنِي أَبِي عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْأَعْتَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً بِالْعَتَمَةِ فَنَادَاهُ عُمَرُ رَضِيَ اللَّهُ عَنْهُ نَامَ النِّسَاءُ وَالصِّبْيَانُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مَا يَنْتَظِرُهَا غَيْرُكُمْ وَلَمْ يَكُنْ يُصَلِّي يَوْمَئِذٍ إِلَّا بِالْمَدِينَةِ ثُمَّ قَالَ صَلُّوهَا فِيمَا بَيْنَ أَنْ يَغِيبَ الشَّفَقُ إِلَى ثُلُثِ اللَّيْلِوَاللَّفْظُ لِابْنِ حِمْيَرٍ","id":"Telah mengabarkan kepada kami [Amr bin Utsman] dia berkata; Telah menceritakan kepada kami [Ibnu Himyar] dia berkata; Telah menceritakan kepada kami [Ibnu Abu 'Ablah] dari [Az Zuhri] dan Telah mengabarkan kepadaku [Amr bin Utsman] dia berkata; Telah menceritakan kepadaku [Bapakku] dari [Syu'aib] dari [Az Zuhri] dari [Urwah] dari [Aisyah] Radliyallahu'anha, dia berkata; \"Rasulullah Shallallahu'alaihi wasallam pada suatu malam mengakhirkan shalat Isya, lalu Umar Radliyallahu'anhu memanggil beliau, para wanita dan anak-anak telah tidur'. Lalu keluarlah Rasulullah Shallallahu'alaihi wasallam dan bersabda: \"Tidak ada yang menunggunya selain kalian\". Rasulullah Shallallahu'alaihi wasallam tidak melakukan shalat yang demikian, kecuali di Madinah. Kemudian beliau bersabda: \"Kerjakanlah shalat Isya di antara lenyapnya mega merah sampai sepertiga malam.\" lafazh ini dari Ibnu Himyar."},"532":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ ح و أَخْبَرَنِي يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي الْمُغِيرَةُ بْنُ حَكِيمٍ عَنْ أُمِّ كُلْثُومِ ابْنَةِ أَبِي بَكْرٍ أَنَّهَا أَخْبَرَتْهُ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ قَالَتْأَعْتَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ حَتَّى ذَهَبَ عَامَّةُ اللَّيْلِ وَحَتَّى نَامَ أَهْلُ الْمَسْجِدِ ثُمَّ خَرَجَ فَصَلَّى وَقَالَ إِنَّهُ لَوَقْتُهَا لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan] dia berkata; Telah menceritakan kepada kami [Hajaj] dia berkata; [Ibnu Juiraj] berkata; dari jalur lain, Telah mengabarkan kepadaku [Yusuf bin Sa'id] dia berkata; Telah menceritakan kepada kami [Hajaj] dari [Ibnu Juraij] dia berkata; Telah mengabarkan kepadaku [Al Mughirah bin Hakim] dari [Ummu Kultsum] -putri Abu Bakar- bahwa dia telah mengabarkan kepadanya dari [Aisyah] Radliyallahu'anha -Ummul Mukminin- dia berkata; \"Suatu malam Rasulullah Shallallahu'alaihi wasallam mengerjakan shalat Isya hingga malam hampir habis dan hingga orang-orang masjid telah tidur. Kemudian beliau keluar lalu shalat, lalu bersabda: \"Inilah waktunya shalat Isya', kalau saja tidak memberatkan umatku.\""},"533":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَمَكَثْنَا ذَاتَ لَيْلَةٍ نَنْتَظِرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعِشَاءِ الْآخِرَةِ فَخَرَجَ عَلَيْنَا حِينَ ذَهَبَ ثُلُثُ اللَّيْلِ أَوْ بَعْدَهُ فَقَالَ حِينَ خَرَجَ إِنَّكُمْ تَنْتَظِرُونَ صَلَاةً مَا يَنْتَظِرُهَا أَهْلُ دِينٍ غَيْرُكُمْ وَلَوْلَا أَنْ يَثْقُلَ عَلَى أُمَّتِي لَصَلَّيْتُ بِهِمْ هَذِهِ السَّاعَةَ ثُمَّ أَمَرَ الْمُؤَذِّنَ فَأَقَامَ ثُمَّ صَلَّى","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Al Hakam] dari [Nafi'] dari [Ibnu Umar] dia berkata; \"Suatu malam kami berdiam (di masjid) menunggu Rasulullah Shallallahu'alaihi wasallam untuk shalat Isya yang terakhir, lalu beliau keluar kepada kami ketika telah lewat sepertiga malam atau lebih. Beliau keluar sambil bersabda: \"Kalian menunggu shalat yang tidak menunggunya orang yang memeluk agama ini selain kalian. Kalau saja tidak memberatkan umatku, maka aku pasti shalat bersama mereka pada waktu seperti ini.\" Kemudian beliau menyuruh Muadzin untuk iqamat, lantas shalat."},"534":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا دَاوُدُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْمَغْرِبِ ثُمَّ لَمْ يَخْرُجْ إِلَيْنَا حَتَّى ذَهَبَ شَطْرُ اللَّيْلِ فَخَرَجَ فَصَلَّى بِهِمْ ثُمَّ قَالَ إِنَّ النَّاسَ قَدْ صَلَّوْا وَنَامُوا وَأَنْتُمْ لَمْ تَزَالُوا فِي صَلَاةٍ مَا انْتَظَرْتُمْ الصَّلَاةَ وَلَوْلَا ضَعْفُ الضَّعِيفِ وَسَقَمُ السَّقِيمِ لَأَمَرْتُ بِهَذِهِ الصَّلَاةِ أَنْ تُؤَخَّرَ إِلَى شَطْرِ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Imran bin Musa] dia berkata; Telah menceritakan kepada kami [Abdul Warits] dia berkata; Telah menceritakan kepada kami [Daud] dari [Abu Nadlrah] dari [Abu Sa'id Al Khudri] dia berkata; \"Kami shalat Maghrib bersama Rasulullah Shallallahu'alaihi wasallam, kemudian beliau Shallallahu'alaihi wasallam keluar kepada kami hingga telah lewat separuh malam. Lalu beliau keluar dan shalat bersama mereka, lantas bersabda: \"Orang-orang sudah shalat dan mereka telah tidur dan kalian selalu dalam keadaan orang yang shalat selama masih menunggu shalat. Seandainya tidak menambah lemah orang yang lemah dan tidak menambah sakit orang yang sakit, maka aku pasti memerintahkan mereka untuk mengakhirkan shalat ini sampai pertengahan malam.\""},"535":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا خَالِدٌ قَالَا حَدَّثَنَا حُمَيْدٌ قَالَسُئِلَ أَنَسٌ هَلْ اتَّخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاتَمًا قَالَ نَعَمْ أَخَّرَ لَيْلَةً صَلَاةَ الْعِشَاءِ الْآخِرَةِ إِلَى قَرِيبٍ مِنْ شَطْرِ اللَّيْلِ فَلَمَّا أَنْ صَلَّى أَقْبَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا بِوَجْهِهِ ثُمَّ قَالَ إِنَّكُمْ لَنْ تَزَالُوا فِي صَلَاةٍ مَا انْتَظَرْتُمُوهَا قَالَ أَنَسٌ كَأَنِّي أَنْظُرُ إِلَى وَبِيصِ خَاتَمِهِ فِي حَدِيثِ عَلِيٍّ إِلَى شَطْرِ اللَّيْلِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah menceritakan kepada kami [Ismail]. Dari jalur lain, Telah memberitakan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Khalid] keduanya berkata; Telah menceritakan kepada kami [Humaid] dia berkata; \"Anas pernah ditanya, 'Apakah Nabi Shallallahu'alaihi wasallam memakai cincin? [Anas] menjawab, 'ya, beliau Shallallahu'alaihi wasallam pernah mengakhirkan shalat Isya sampai menjelang tengah malam, dan setelah selesai shalat beliau menghadap kepada kami dengan wajahnya, lalu bersabda: \"Kalian senantiasa dalam keadaan shalat selagi kalian menunggu shalat.\" Anas berkata; 'Seolah-olah aku melihat kilauan cincin beliau Shallallahu'alaihi wasallam '. Pada lafazh lain: Sampai pertengahan malam. "},"536":{"ar":"أَخْبَرَنَا عُتْبَةُ بْنُ عَبْدِ اللَّهِ قَالَ قَرَأْتُ عَلَى مَالِكِ بْنِ أَنَسٍ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ يَعْلَمُ النَّاسُ مَا فِي النِّدَاءِ وَالصَّفِّ الْأَوَّلِ ثُمَّ لَمْ يَجِدُوا إِلَّا أَنْ يَسْتَهِمُوا عَلَيْهِ لَاسْتَهَمُوا وَلَوْ يَعْلَمُ النَّاسُ مَا فِي التَّهْجِيرِ لَاسْتَبَقُوا إِلَيْهِ وَلَوْ عَلِمُوا مَا فِي الْعَتَمَةِ وَالصُّبْحِ لَأَتَوْهُمَا وَلَوْ حَبْوًا","id":"Telah mengabarkan kepada kami ['Utbah bin Abdullah] dia berkata; saya telah membacakan kepada [Malik bin Anas] dan [Al Harits bin Miskin] sebuah hadist yang saya dengar dari [Ibnu Al Qasim] dia berkata; Telah menceritakan kepadaku [Malik] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda; \"Kalau saja manusia mengetahui apa yang ada didalam panggilan adzan dan shaf pertama. Kemudian mereka tidak bisa mendapatkannya kecuali dengan cara mengundi di antara mereka, maka mereka pasti akan mengundinya. Seandainya mereka mengetahui keutamaan menyegerakan shalat maka mereka pasti berlomba-lomba mendapatkannya. Seandainya mereka mengetahui keutamaan yang terdapat di dalam shalat Isya dan Subuh, maka mereka pasti akan mendatanginya, meskipun dengan cara merangkak.\""},"537":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ هُوَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي لَبِيدٍ عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَغْلِبَنَّكُمْ الْأَعْرَابُ عَلَى اسْمِ صَلَاتِكُمْ هَذِهِ فَإِنَّهُمْ يُعْتِمُونَ عَلَى الْإِبِلِ وَإِنَّهَا الْعِشَاءُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Abu Daud -yaitu Al Hafari] dari [Sufyan] dari [Abdullah bin Abu Labid] dari [Abu Salamah] dari [Ibnu Umar] dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda; \"Janganlah kalian di kalahkan oleh orang badui dalam memberi istilah shalat kalian. Mereka istilahkan shalat isyak dengan 'atamah, mereka namakan demikian karena mereka mengandangkan unta tengah malam dan memerah susunya, padahal itu adalah Isya.\" "},"538":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ ابْنِ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي لَبِيدٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى الْمِنْبَرِ لَا تَغْلِبَنَّكُمْ الْأَعْرَابُ عَلَى اسْمِ صَلَاتِكُمْ أَلَا إِنَّهَا الْعِشَاءُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Ibnu Uyainah] dari [Abdullah bin Abu Labid] dari [Abu Salamah bin Abdurrahman] dari [Ibnu Umar] dia berkata; \"Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda di atas mimbar; Janganlah kalian di kalahkan oleh orang badui dalam penamaan shalat kalian, itu adalah Isya\". "},"539":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ هَارُونَ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدِ بْنِ عَلِيِّ بْنِ الْحُسَيْنِ عَنْ أَبِيهِ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ حِينَ تَبَيَّنَ لَهُ الصُّبْحُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Harun] dia berkata; Telah menceritakan kepada kami [Hatim bin Ismail] dia berkata; Telah menceritakan kepada kami [Ja'far bin Muhammad bin Ali bin Al Husain] dari [Bapaknya] bahwa [Jabir bin Abdullah] berkata, \"Rasulullah Shallallahu'alaihi wasallam shalat Subuh ketika pagi sudah sangat jelas.\""},"540":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ وَقْتِ صَلَاةِ الْغَدَاةِ فَلَمَّا أَصْبَحْنَا مِنْ الْغَدِ أَمَرَ حِينَ انْشَقَّ الْفَجْرُ أَنْ تُقَامَ الصَّلَاةُ فَصَلَّى بِنَا فَلَمَّا كَانَ مِنْ الْغَدِ أَسْفَرَ ثُمَّ أَمَرَ فَأُقِيمَتْ الصَّلَاةُ فَصَلَّى بِنَا ثُمَّ قَالَ أَيْنَ السَّائِلُ عَنْ وَقْتِ الصَّلَاةِ مَا بَيْنَ هَذَيْنِ وَقْتٌ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah menceritakan kepada kami [Ismail] dia berkata; Telah menceritakan kepada kami [Humaid] dari [Anas] bahwa ada seorang laki-laki yang datang kepada Nabi Shallallahu'alaihi wasallam untuk bertanya waktu shalat subuh. Pada keesokan harinya ketika Fajar, Rasulullah Shallallahu'alaihi wasallam memerintahkan untuk iqamat, lantas beliau shalat Subuh bersama kami. Lalu beliau bersabda: \"Mana orang yang bertanya tentang waktu shalat? Waktu shalat ada diantara dua shalat ini\"."},"541":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُصَلِّي الصُّبْحَ فَيَنْصَرِفُ النِّسَاءُ مُتَلَفِّعَاتٍ بِمُرُوطِهِنَّ مَا يُعْرَفْنَ مِنْ الْغَلَسِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Yahya bin Sa'id] dari ['Amrah] dari [Aisyah] Radliyallahu'anha berkata; \"Jika Rasulullah Shallallahu'alaihi wasallam selesai shalat Subuh, maka para wanita pulang dengan menyelimutkan kain ke tubuh mereka dan mereka tidak saling mengenal karena hari masih gelap\"."},"542":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكُنَّ النِّسَاءُ يُصَلِّينَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ مُتَلَفِّعَاتٍ بِمُرُوطِهِنَّ فَيَرْجِعْنَ فَمَا يَعْرِفُهُنَّ أَحَدٌ مِنْ الْغَلَسِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Urwah] dari [Aisyah] Radliyallahu'anha dia berkata; \"Para wanita shalat Subuh bersama Rasulullah dengan menyelimutkan kain ke tubuh mereka, lalu mereka kembali, dan tidak saling mengenal karena hari masih gelap\"."},"543":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ صَلَاةَ الصُّبْحِ بِغَلَسٍ وَهُوَ قَرِيبٌ مِنْهُمْ فَأَغَارَ عَلَيْهِمْ وَقَالَ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ مَرَّتَيْنِ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Sulaiman bin Harb] dia berkata; Telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] dia berkata, \"Rasulullah Shallallahu'alaihi wasallam shalat Subuh saat perang Khaibar dan beliau Shallallahu'alaihi wasallam dekat dengan penduduk khaibar, lalu Rasulullah Shallallahu'alaihi wasallam menyerang mereka (di pagi hari). Lalu beliau bersabda: Allahu akbar, hancurlah Khaibar -Beliau ucapkan sebanyak dua kali-, sesungguhnya jika kami telah singgah di pemukiman suatu kaum, berakibat buruklah pagi hari orang-orang yang diberi peringatan itu.\" "},"544":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ قَالَ حَدَّثَنِي عَاصِمُ بْنُ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ رَافِعِ بْنِ خَدِيجٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَسْفِرُوا بِالْفَجْرِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Ibnu 'Ajlan] dia berkata; Telah menceritakan kepadaku ['Ashim bin 'Umar bin Qatadah] dari [Mahmud bin Labid] dari [Rafi' bin Khadij] dari Rasulullah Shallallahu'alaihi wasallam beliau bersabda: \"Laksanakanlah shalat Subuh sampai hari agak terang.\" "},"545":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ أَخْبَرَنَا أَبُو غَسَّانَ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ رِجَالٍ مِنْ قَوْمِهِ مِنْ الْأَنْصَارِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَسْفَرْتُمْ بِالْفَجْرِ فَإِنَّهُ أَعْظَمُ بِالْأَجْرِ","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub] dia berkata; Telah menceritakan kepada kami [Ibnu Abu Maryam] dia berkata; Telah menceritakan kepada kami [Abu Ghassan] dia berkata; Telah menceritakan kepadaku [Zaid bin Aslam] dari [Ashim bin Umar bin Qatadah] dari [Mahmud bin Lubid], dari [orang-orang Anshar], bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: 'Selagi kalian masih melaksanakan shalat Subuh Sampai agak terang, maka itulah pahala yang besar.\""},"546":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ الْأَعْرَجُ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ سَجْدَةً مِنْ الصُّبْحِ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَهَا وَمَنْ أَدْرَكَ سَجْدَةً مِنْ الْعَصْرِ قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَقَدْ أَدْرَكَهَا","id":"Telah mengabarkan kepada kami [Ibrahim bin Muhammad] dan [Muhammad bin Al Mutsanna] lafazh ini miliknya, keduanya berkata; Telah menceritakan kepada kami [Yahya] [Abdullah bin Sa'id] dia berkata; Telah menceritakan kepadaku [Abdurrahman Al A'raj] dari [Abu Hurairah] dari Nabi Shallallahu'alaihi wasallam, beliau bersabda: \"Barang siapa mendapatkan satu rakaaat shalat Subuh sebelum matahari terbit, maka dia telah mendapatkan shalat Subuh.\""},"547":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ قَالَ أَنْبَأَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ رَكْعَةً مِنْ الْفَجْرِ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَهَا وَمَنْ أَدْرَكَ رَكْعَةً مِنْ الْعَصْرِ قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَقَدْ أَدْرَكَهَا وَمَنْ أَدْرَكَ رَكْعَةً مِنْ الْفَجْرِ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ فَقَدْ أَدْرَكَهَا وَمَنْ أَدْرَكَ رَكْعَةً مِنْ الْعَصْرِ قَبْلَ أَنْ تَغْرُبَ الشَّمْسُ فَقَدْ أَدْرَكَهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; Telah menceritakan kepada kami [Zakaria bin Adi] dia berkata; Telah memberitakan kepada kami [Ibnu Al Mubarak] dari [Yunus bin Yazid] dari [Az Zuhri] dari [Urwah] dari [Aisyah] Radliyallahu'anha dari Nabi Shallallahu'alaihi wasallam, beliau bersabda: \"Barang siapa mendapatkan satu rakaat shalat Subuh sebelum matahari terbit, dia telah mendapatkan shalat subuh. Barang siapa hanya mendapatkan satu rakaat dari shalat Ashar sebelum matahari terbenam, dia telah mendapatkan shalat Ashar. Barang siapa mendapat satu rakaat shalat Subuh sebelum matahari terbit, dia telah mendapatkan shalat Subuh. Barang siapa hanya mendapatkan satu rakaat dari shalat Ashar sebelum matahari terbenam, dia telah mendapatkan shalat Ashar.\""},"548":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ أَبِي صَدَقَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الظُّهْرَ إِذَا زَالَتْ الشَّمْسُ وَيُصَلِّي الْعَصْرَ بَيْنَ صَلَاتَيْكُمْ هَاتَيْنِ وَيُصَلِّي الْمَغْرِبَ إِذَا غَرَبَتْ الشَّمْسُ وَيُصَلِّي الْعِشَاءَ إِذَا غَابَ الشَّفَقُ ثُمَّ قَالَ عَلَى إِثْرِهِ وَيُصَلِّي الصُّبْحَ إِلَى أَنْ يَنْفَسِحَ الْبَصَرُ","id":"Telah mengabarkan kepada kami [Ismail bin Mas'ud] dan [Muhammad bin Abdul A'la] keduanya berkata; Telah menceritakan kepada kami [Khalid] dia berkata; [Syu'bah] dari [Abu Shadaqah] dari [Anas bin Malik], dia berkata; \"Rasulullah Shallallahu'alaihi wasallam Shalat Zhuhur ketika matahari telah condong, dan shalat Ashar diantara dua shalat kalian ini. Lalu shalat Maghrib ketika matahari terbenam dan shalat Isya ketika mega merah sudah tidak nampak.\""},"549":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الصَّلَاةِ رَكْعَةً فَقَدْ أَدْرَكَ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barang siapa mendapatkan satu rakaat dalam suatu shalat, ia telah mendapatkan shalat itu.\""},"550":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الصَّلَاةِ رَكْعَةً فَقَدْ أَدْرَكَهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Abdullah bin Idris] dia berkata; Telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Rasulullah Shallallahu'alaihi wasallam Beliau bersabda: \"Barang siapa mendapatkan satu rakaat dalam suatu shalat, ia telah mendapatkan shalat.\""},"551":{"ar":"أَخْبَرَنِي يَزِيدُ بْنُ مُحَمَّدِ بْنِ عَبْدِ الصَّمَدِ قَالَ حَدَّثَنَا هِشَامٌ الْعَطَّارُ قَالَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ سَمَاعَةَ عَنْ مُوسَى بْنِ أَعْيَنَ عَنْ أَبِي عَمْرٍو الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ الصَّلَاةِ رَكْعَةً فَقَدْ أَدْرَكَ الصَّلَاةَ","id":"Telah mengabarkan kepadaku [Yazid bin Muhammad bin Abdus Shamad] dia berkata; Telah menceritakan kepada kami [Hisyam Al Athar] dia berkata; Telah menceritakan kepada kami [Ismail yaitu Ibnu Sama'ah] dari [Musa bin A'yan] dari [Abu Amr Al Auza'i] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Nabi Shallallahu'alaihi wasallam bersabda: \"Barang siapa mendapatkan satu rakaat dalam suatu shalat, ia telah mendapatkan shalat itu.\""},"552":{"ar":"أَخْبَرَنِي شُعَيْبُ بْنُ شُعَيْبِ بْنِ إِسْحَقَ قَالَ حَدَّثَنَا أَبُو الْمُغِيرَةِ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَ مِنْ الصَّلَاةِ رَكْعَةً فَقَدْ أَدْرَكَهَا","id":"Telah mengabarkan kepada kami [Syu'aib bin Syu'aib bin Ishaq] dia berkata; Telah menceritakan kepada kami [Abu Al Mughirah] dia berkata; Telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barang sipa mendapatkan satu rakaat shalat, ia telah mendapatkan shalat.\""},"553":{"ar":"أَخْبَرَنِي مُوسَى بْنُ سُلَيْمَانَ بْنِ إِسْمَعِيلَ بْنِ الْقَاسِمِ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ يُونُسَ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ رَكْعَةً مِنْ الْجُمُعَةِ أَوْ غَيْرِهَا فَقَدْ تَمَّتْ صَلَاتُهُ","id":"Telah mengabarkan kepada kami [Musa bin Sulaiman bin Ismail bin Al Qasim] dia berkata; Telah menceritakan kepada kami [Baqiyyah] dari [Yunus] dia berkata; Telah menceritakan kepadaku [Az Zuhri] dari [Salim] dari [Bapaknya] dari Nabi Shallallahu'alaihi wasallam, beliau bersabda: \"Barang siapa mendapatkan satu rakaat shalat jum'at atau selainnya maka telah sempurna shalatnya.\""},"554":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ التِّرْمِذِيُّ قَالَ حَدَّثَنَا أَيُّوبُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ رَكْعَةً مِنْ صَلَاةٍ مِنْ الصَّلَوَاتِ فَقَدْ أَدْرَكَهَا إِلَّا أَنَّهُ يَقْضِي مَا فَاتَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ismail At-Tirmidzi] dia berkata; Telah menceritakan kepada kami [Ayyub bin Sulaiman] dia berkata; Telah menceritakan kepada kami [Abu Bakr] dari [Sulaiman bin Bilal] dari [Yunus] dari [Ibnu Syihab] dari [Salim] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barang siapa mendapatkan satu raka'at dari shalat lima waktu, ia telah mendapatkannya, tetapi dia harus memyempurnakan sisanya.\""},"555":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ الصُّنَابِحِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشَّمْسُ تَطْلُعُ وَمَعَهَا قَرْنُ الشَّيْطَانِ فَإِذَا ارْتَفَعَتْ فَارَقَهَا فَإِذَا اسْتَوَتْ قَارَنَهَا فَإِذَا زَالَتْ فَارَقَهَا فَإِذَا دَنَتْ لِلْغُرُوبِ قَارَنَهَا فَإِذَا غَرَبَتْ فَارَقَهَا وَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّلَاةِ فِي تِلْكَ السَّاعَاتِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Zaid bin Aslam] dari [Atha bin Yasar] dari [Abdullah Ash-Shunabihi] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Matahari terbit dan bersamanya tanduk setan. Bila matahari itu meninggi maka tanduk setan berpisah, dan jika (matahari) sampai ke tengah-tengah maka tanduk setan tersebut bersamanya lagi. Bila matahari condong maka tanduk setan berpisah, jika mulai dekat waktu terbenam maka tanduk setan bersamanya lagi\". Dan Rasulullah Shallallahu'alaihi wasallam melarang shalat pada waktu-waktu tersebut. "},"556":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ مُوسَى بْنِ عَلِيِّ بْنِ رَبَاحٍ قَالَ سَمِعْتُ أَبِي يَقُولُ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يَقُولُثَلَاثُ سَاعَاتٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا أَنْ نُصَلِّيَ فِيهِنَّ أَوْ نَقْبُرَ فِيهِنَّ مَوْتَانَا حِينَ تَطْلُعُ الشَّمْسُ بَازِغَةً حَتَّى تَرْتَفِعَ وَحِينَ يَقُومُ قَائِمُ الظَّهِيرَةِ حَتَّى تَمِيلَ وَحِينَ تَضَيَّفُ الشَّمْسُ لِلْغُرُوبِ حَتَّى تَغْرُبَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; Telah menceritakan kepada kami [Abdullah] dari [Musa bin Ali bin Rabah] dia berkata; Saya mendengar [Bapakku] berkata; Saya mendengar [Uqbah bin Amir Al Juhaini] berkata; \"Tiga waktu yang Rasulullah Shallallahu'alaihi wasallam melarang kita untuk mengerjakan shalat atau mengubur mayit yaitu: ketika matahari terbit hingga meninggi, ketika bayangan orang sama persis hingga matahari condong ke Barat, serta ketika matahari hendak terbenam sampai terbenamnya.\""},"557":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَعَنْ الصَّلَاةِ بَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Muhammad bin Yahya bin Habban] dari [Al A'raj] dari [Abu Hurairah] bahwa Nabi Shallallahu'alaihi wasallam melarang shalat setelah Ashar hingga matahari terbenam dan melarang shalat setelah Subuh hingga matahari terbit."},"558":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مَنِيعٍ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا مَنْصُورٌ عَنْ قَتَادَةَ قَالَ حَدَّثَنَا أَبُو الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَ سَمِعْتُ غَيْرَ وَاحِدٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ عُمَرُوَكَانَ مِنْ أَحَبِّهِمْ إِلَيَّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ وَعَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ","id":"Telah mengabarkan kepada kami [Ahmad bin Mani'] dia berkata; Telah menceritakan kepada kami [Husyaim] dia berkata; Telah memberitakan kepada kami [Manshur] dari [Qatadah] dia berkata; Telah menceritakan kepada kami [Abu Al 'Aliyah] dari [Ibnu Abbas] dia berkata: \"Aku mendengar tidak hanya dari satu orang sahabat Nabi Shallallahu'alaihi wasallam diantara mereka adalah [Umar bin Khaththab], dan dia termasuk orang yang sangat kucintai bahwa Rasulullah Shallallahu'alaihi wasallam melarang shalat setelah Subuh hingga matahari terbit dan melarang shalat setelah Ashar hingga matahari terbenam.\""},"559":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَحَرَّ أَحَدُكُمْ فَيُصَلِّيَ عِنْدَ طُلُوعِ الشَّمْسِ وَعِنْدَ غُرُوبِهَا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jangan salah seorang dari kalian berkehendak dan shalat ketika matahari saat terbit dan juga ketika matahari terbenam.\""},"560":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ أَنْبَأَنَا خَالِدٌ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُصَلَّى مَعَ طُلُوعِ الشَّمْسِ أَوْ غُرُوبِهَا","id":"Telah mengabarkan kepada kami [Ismail bin Mas'ud] Telah memberitakan kepada kami [Khalid] Telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah Shallallahu'alaihi wasallam melarang shalat bertepatan dengan terbit atau terbenamnya matahari."},"561":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا سُفْيَانُ وَهُوَ ابْنُ حَبِيبٍ عَنْ مُوسَى بْنِ عَلِيٍّ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ يَقُولُثَلَاثُ سَاعَاتٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا أَنْ نُصَلِّيَ فِيهِنَّ أَوْ نَقْبُرَ فِيهِنَّ مَوْتَانَا حِينَ تَطْلُعُ الشَّمْسُ بَازِغَةً حَتَّى تَرْتَفِعَ وَحِي��َ يَقُومُ قَائِمُ الظَّهِيرَةِ حَتَّى تَمِيلَ وَحِينَ تَضَيَّفُ لِلْغُرُوبِ حَتَّى تَغْرُبَ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dia berkata; Telah menceritakan kepada kami [Sufyan yaitu Ibnu Habib] dari [Musa bin Ali] dari [Bapaknya] dia berkata; Saya mendengar [Uqbah bin Amir] berkata; \"Ada tiga waktu yang Rasulullah Shallallahu'alaihi wasallam melarang kami untuk shalat atau menguburkan mayit pada waktu tersebut, yaitu saat matahari baru terbit hingga meninggi, saat bayangan seseorang sama dengan badannya (matahari sepenggal) hingga matahari tergelincir, serta saat matahari menjelang terbenam hingga terbenam.\""},"562":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّلَاةِ بَعْدَ الصُّبْحِ حَتَّى الطُّلُوعِ وَعَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ حَتَّى الْغُرُوبِ","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] dia berkata; Telah menceritakan kepada kami [Ibnu Uyainah] dari [Dlamrah bin Sa'id] bahwa dia mendengar [Abu Sa'id Al Khudri] berkata; \"Rasulullah Shallallahu'alaihi wasallam melarang shalat setelah shalat Subuh hingga matahari terbit dan melarang shalat setelah Ashar hingga matahari terbenam.\""},"563":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا صَلَاةَ بَعْدَ الْفَجْرِ حَتَّى تَبْزُغَ الشَّمْسُ وَلَا صَلَاةَ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُأَخْبَرَنِي مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا الْوَلِيدُ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ نَمِرٍ عَنْ ابْنِ شِهَابٍ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad] dia berkata; Telah menceritakan kepada kami [Makhlad] dari [Ibnu Juraij] dari [Ibnu Syihab] dari [Atha bin Yazid] bahwa dia mendengar [Abu Sa'id Al Khudri] berkata; \"Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Tidak ada shalat setelah shalat Subuh hingga matahari terbit sampai meninggi dan tidak ada shalat setelah Ashar hingga matahari terbenam.\" Telah mengabarkan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Al Walid] dia berkata, telah mengabarkan kepada kami [Abdurrahman bin Namir] dari [Ibnu Syihab] dari ['Atho bin Yazid] dari [Abu Sa'id Al Khudri] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda seperti yang telah disebutkan."},"564":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ حُجَيْرٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Hisyam bin Hujair] dari [Thawus] dari [Ibnu Abbas] bahwa Nabi Shallallahu'alaihi wasallam melarang shalat setelah Ashar. "},"565":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ عَنْبَسَةَ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ قَالَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاأَوْهَمَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ إِنَّمَا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتَحَرَّوْا بِصَلَاتِكُمْ طُلُوعَ الشَّمْسِ وَلَا غُرُوبَهَا فَإِنَّهَا تَطْلُعُ بَيْنَ قَرْنَيْ شَيْطَانٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Mubarak Al Makhrami] dia berkata; Telah menceritakan kepada kami [Al Fadhl bin 'Anbasah] dia berkata; Telah menceritakan kepada kami [Wuhaib] dari [Ibnu Thawus] dari [Bapaknya] dia berkata; [Aisyah] Radliyallahu'anha berkata; \"Umar Radliyallahu'anhu menyangka bahwa Rasulullah Shallallahu'alaihi wasallam melarang dengan sabdanya: \"Janganlah kalian berkehendak dan shalat saat terbit dan terbenamnya matahari. Sesungguhnya matahari terbit di antara dua tanduk setan.\""},"566":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي قَالَ أَخْبَرَنِي ابْنُ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا طَلَعَ حَاجِبُ الشَّمْسِ فَأَخِّرُوا الصَّلَاةَ حَتَّى تُشْرِقَ وَإِذَا غَابَ حَاجِبُ الشَّمْسِ فَأَخِّرُوا الصَّلَاةَ حَتَّى تَغْرُبَ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; Telah menceritakan kepada kami [Hisyam bin Urwah] dia berkata; Telah mengabarkan kepadaku [Bapakku] dia berkata; Telah mengabarkan kepadaku [Ibnu Umar] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Apabila terbit sebagian matahari maka tangguhkanlah shalat hingga matahari memancar, dan jika telah terbenam sebagian (bola) matahari maka akhirkanlah shalat hingga matahari terbenam.\""},"567":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ قَالَ أَخْبَرَنِي أَبُو يَحْيَى سُلَيْمُ بْنُ عَامِرٍ وَضَمْرَةُ بْنُ حَبِيبٍ وَأَبُو طَلْحَةَ نُعَيْمُ بْنُ زِيَادٍ قَالُوا سَمِعْنَا أَبَا أُمَامَةَ الْبَاهِلِيَّ يَقُولُ سَمِعْتُ عَمْرَو بْنَ عَبَسَةَ يَقُولُقُلْتُ يَا رَسُولَ اللَّهِ هَلْ مِنْ سَاعَةٍ أَقْرَبُ مِنْ الْأُخْرَى أَوْ هَلْ مِنْ سَاعَةٍ يُبْتَغَى ذِكْرُهَا قَالَ نَعَمْ إِنَّ أَقْرَبَ مَا يَكُونُ الرَّبُّ عَزَّ وَجَلَّ مِنْ الْعَبْدِ جَوْفَ اللَّيْلِ الْآخِرَ فَإِنْ اسْتَطَعْتَ أَنْ تَكُونَ مِمَّنْ يَذْكُرُ اللَّهَ عَزَّ وَجَلَّ فِي تِلْكَ السَّاعَةِ فَكُنْ فَإِنَّ الصَّلَاةَ مَحْضُورَةٌ مَشْهُودَةٌ إِلَى طُلُوعِ الشَّمْسِ فَإِنَّهَا تَطْلُعُ بَيْنَ قَرْنَيْ الشَّيْطَانِ وَهِيَ سَاعَةُ صَلَاةِ الْكُفَّارِ فَدَعْ الصَّلَاةَ حَتَّى تَرْتَفِعَ قِيدَ رُمْحٍ وَيَذْهَبَ شُعَاعُهَا ثُمَّ الصَّلَاةُ مَحْضُورَةٌ مَشْهُودَةٌ حَتَّى تَعْتَدِلَ الشَّمْسُ اعْتِدَالَ الرُّمْحِ بِنِصْفِ النَّهَارِ فَإِنَّهَا سَاعَةٌ تُفْتَحُ فِيهَا أَبْوَابُ جَهَنَّمَ وَتُسْجَرُ فَدَعْ الصَّلَاةَ حَتَّى يَفِيءَ الْفَيْءُ ثُمَّ الصَّلَاةُ مَحْضُورَةٌ مَشْهُودَةٌ حَتَّى تَغِيبَ الشَّمْسُ فَإِنَّهَا تَغِيبُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَهِيَ صَلَاةُ الْكُفَّارِ","id":"Telah mengabarkan kepada kami [Amr bin Manshur] dia berkata; Telah memberitakan kepada kami [Adam bin Abu Iyyas] dia berkata; Telah menceritakan kepada kami [Al Laits bin Sa'ad] dia berkata; Telah menceritakan kepada kami [Mu'awiyah bin Shalih] dia berkata; Telah mengabarkan kepadaku [Abu Yahya Sulaim bin Amir] dan [Dlamrah bin Habib] dan [Abu Thalhah Nu'aim bin Ziyad] mereka berkata; Kami mendengar [Abu Umamah Al Bahili] berkata; Saya mendengar [Amr bin Abasah] berkata; \"Wahai Rasulullah Shallallahu'alaihi wasallam, apakah ada waktu yang lebih dekat (kepada Allah) dari pada yang lain? Atau apakah ada waktu yang lebih baik untuk berdzikir kepadanya?\" Beliau Shallallahu'alaihi wasallam menjawab; \"Ya, waktu yang paling dekat antara Allah Azza wa Jalla dengan hambanya adalah pertengahan malam yang terakhir. Jika engkau mampu menjadi bagian dari orang yang berdzikir kepada Allah pada waktu itu, lakukanlah, karena ketika itu dihadiri dan disaksikan (oleh para malaikat) sampai matahari terbit. Dan matahari terbit diantara dua tanduk setan dan itulah waktu ibadahnya orang-orang kafir, maka tinggalkanlah shalat hingga matahari mulai meninggi seukuran tombak dan sinarnya mulai menyebar. Kemudian shalat saat itu dihadiri dan disaksikan (oleh para malaikat) hingga matahari tegak seperti tegaknya tombak pada pertengahan hari, karena saat itulah pintu-pintu neraka Jahannam dibuka dan dinyalakan apinya, maka tinggalkanlah shalat hingga terlihat bayangan (suatu benda), kemudian shalat saat itu dihadiri dan disaksikan (oleh para malaikat) hingga matahari terbenam, karena matahari terbenam diantara dua tanduk setan dan itulah waktu ibadahnya orang-orang kafir.\""},"568":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ وَهْبِ بْنِ الْأَجْدَعِ عَنْ عَلِيٍّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ إِلَّا أَنْ تَكُونَ الشَّمْسُ بَيْضَاءَ نَقِيَّةً مُرْتَفِعَةً","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Hilal bin Yasaf] dari [Wahab bin Al Ajda'] dari [Ali] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam melarang shalat setelah Ashar kecuali matahari masih putih jernih dan tinggi.\""},"569":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي قَالَ قَالَتْ عَائِشَةُمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّجْدَتَيْنِ بَعْدَ الْعَصْرِ عِنْدِي قَطُّ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; Telah menceritakan kepada kami [Yahya] dari [Hisyam] dia berkata; Telah mengabarkan kepadaku [Bapakku] dia berkata; [Aisyah] Radliyallahu'anha berkata: \"Rasulullah Shallallahu'alaihi wasallam sama sekali tidak pernah meninggalkan dua rakaat setelah Ashar di sampingku.\""},"570":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَامَا دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ الْعَصْرِ إِلَّا صَلَّاهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; Telah menceritakan kepada kami [Jarir] dari [Mughirah] dari [Ibrahim] dari [Al Aswad] dia berkata; [Aisyah] Radliyallahu'anha berkata; \"Rasulullah Shallallahu'alaihi wasallam tidak pernah menemuiku setelah Ashar kecuali setelah mengerjakan shalat dua rakaat (ba'da ashar).\""},"571":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ خَالِدِ بْنِ الْحَارِثِ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ مَسْرُوقًا وَالْأَسْوَدَ قَالَانَشْهَدُ عَلَى عَائِشَةَ أَنَّهَا قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ عِنْدِي بَعْدَ الْعَصْرِ صَلَّاهُمَا","id":"Telah mengabarkan kepada kami [Ismail bin Mas'ud] dari [Khalid bin Al Harits] dari [Syu'bah] dari [Abu Ishaq] dia berkata; Aku mendengar [Masruq] dan [Al Aswad] mereka berkata; \"Kami bersaksi bahwa [Aisyah] pernah berkata, 'Rasulullah Shallallahu'alaihi wasallam jika berada di sampingku (di rumahku) setelah Ashar, beliau mengerjakan shalat dua rakaat.\""},"572":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْصَلَاتَانِ مَا تَرَكَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي سِرًّا وَلَا عَلَانِيَةً رَكْعَتَانِ قَبْلَ الْفَجْرِ وَرَكْعَتَانِ بَعْدَ الْعَصْرِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah memberitakan kepadaku [Ali bin Mushir] dari [Abu Ishaq] dari [Abdurrahman bin Al Aswad] dari [Bapaknya] dari [Aisyah] Radliyallahu'anha berkata; \"Ada dua shalat yang tidak pernah ditinggalkan oleh Rasulullah Shallallahu'alaihi wasallam, baik secara sembunyi-sembunyi maupun terang-terangan, yaitu shalat dua rakaat sebelum Fajar (Subuh) dan dua rakaat setelah Ashar.\""},"573":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حَرْمَلَةَ عَنْ أَبِي سَلَمَةَأَنَّهُ سَأَلَ عَائِشَةَ عَنْ السَّجْدَتَيْنِ اللَّتَيْنِ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهِمَا بَعْدَ الْعَصْرِ فَقَالَتْ إِنَّهُ كَانَ يُصَلِّيهِمَا قَبْلَ الْعَصْرِ ثُمَّ إِنَّهُ شُغِلَ عَنْهُمَا أَوْ نَسِيَهُمَا فَصَلَّاهُمَا بَعْدَ الْعَصْرِ وَكَانَ إِذَا صَلَّى صَلَاةً أَثْبَتَهَا","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; Telah menceritakan kepada kami [Ismail] dia berkata; Telah menceritakan kepada kami [Muhammad bin Abu Harmalah] dari [Abu Salamah] bahwa dia pernah bertanya kepada Aisyah tentang dua rakaat yang dilakukan oleh Rasulullah Shallallahu'alaihi wasallam setelah Ashar. Maka [Aisyah] menjawab, \"Rasulullah Shallallahu'alaihi wasallam awal mulanya mengerjakan sebelum Ashar, lalu beliau sibuk atau lupa, maka beliau shalat setelah Ashar. Beliau jika telah mengerjakan shalat maka beliau mengerjakannya terus-menerus.\""},"574":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ مَعْمَرًا عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي بَيْتِهَا بَعْدَ الْعَصْرِ رَكْعَتَيْنِ مَرَّةً وَاحِدَةً وَأَنَّهَا ذَكَرَتْ ذَلِكَ لَهُ فَقَالَ هُمَا رَكْعَتَانِ كُنْتُ أُصَلِّيهِمَا بَعْدَ الظُّهْرِ فَشُغِلْتُ عَنْهُمَا حَتَّى صَلَّيْتُ الْعَصْرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Al Mu'tamir] dia berkata; Aku mendengar [Ma'mar] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin Abdurrahman] dari [Ummu Salamah] bahwa Nabi Shallallahu'alaihi wasallam mengerjakan shalat dua rakaat setelah Ashar di rumahnya hanya sekali, dan Ummu Salamah pernah mengingatkannya. Rasulullah Shallallahu'alaihi wasallam lalu bersabda kepadanya, \"Dua rakaat tersebut dulunya aku kerjakan setelah Zhuhur, lalu aku disibukkan dengan seseuatu sehingga aku mengerjakannva setelah Ashar.\""},"575":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْشُغِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّكْعَتَيْنِ قَبْلَ الْعَصْرِ فَصَلَّاهُمَا بَعْدَ الْعَصْرِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Waki'] dia berkata; Telah menceritakan kepada kami [Thalhah bin Yahya] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ummu Salamah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam pernah disibukkan oleh sesuatu sehingga tidak sempat shalat dua rakaat sebelum Ashar, maka beliau mengerjakannya setelah Ashar.\""},"576":{"ar":"أَخْبَرَنَا عُثْمَانُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ قَالَ أَنْبَأَنَا أَبِي قَالَ حَدَّثَنَا عِمْرَانُ بْنُ حُدَيْرٍ قَالَسَأَلْتُ لَاحِقًا عَنْ الرَّكْعَتَيْنِ قَبْلَ غُرُوبِ الشَّمْسِ فَقَالَ كَانَ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ يُصَلِّيهِمَا فَأَرْسَلَ إِلَيْهِ مُعَاوِيَةُ مَا هَاتَانِ الرَّكْعَتَانِ عِنْدَ غُرُوبِ الشَّمْسِ فَاضْطَرَّ الْحَدِيثَ إِلَى أُمِّ سَلَمَةَ فَقَالَتْ أُمُّ سَلَمَةَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي رَكْعَتَيْنِ قَبْلَ الْعَصْرِ فَشُغِلَ عَنْهُمَا فَرَكَعَهُمَا حِينَ غَابَتْ الشَّمْسُ فَلَمْ أَرَهُ يُصَلِّيهِمَا قَبْلُ وَلَا بَعْدُ","id":"Telah mengabarkan kepada kami [Utsman bin Abdullah] dia berkata; Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] dia berkata; Telah memberitakan kepada kami [Bapakku] dia berkata; Telah menceritakan kepada kami [Imran bin Hudair] dia berkata; Aku bertanya kepada [Lahiq] tentang seseorang yang mengerjakan shalat dua rakaat sebelum matahari terbenam, maka dia mengatakan bahwa Abdullah bin Zubair mengerjakan dua rakaat ini. Lalu Muawiyah mengutus seseorang kepada Abdullah bin Zubair dan berkata, \"Apakah shalat dua rakaat ketika matahari terbenam?\" Abdullah bin Zubair mengembalikan hadis tersebut kepada [Ummu Salamah], maka dia berkata, \"Rasulullah Shallallahu'alaihi wasallam shalat dua rakaat sebelum Ashar, lalu beliau sibuk sehingga akhirnya beliau mengerjakannya ketika matahari terbenam. Aku tidak pernah melihat beliau mengerjakan shalat dua rakaat sebelum dan sesudah ini.\""},"577":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ عُثْمَانَ بْنِ مُحَمَّدِ بْنِ سَعِيدِ بْنِ عَبْدِ اللَّهِ بْنِ نُفَيْلٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عِيسَى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّ أَبَا الْخَيْرِ حَدَّثَهُأَنَّ أَبَا تَمِيمٍ الْجَيْشَانِيَّ قَامَ لِيَرْكَعَ رَكْعَتَيْنِ قَبْلَ الْمَغْرِبِ فَقُلْتُ لِعُقْبَةَ بْنِ عَامِرٍ انْظُرْ إِلَى هَذَا أَيَّ صَلَاةٍ يُصَلِّي فَالْتَفَتَ إِلَيْهِ فَرَآهُ فَقَالَ هَذِهِ صَلَاةٌ كُنَّا نُصَلِّيهَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ali bin Utsman bin Muhammad bin Sa'id bin Abdullah bin Nufail] dia berkata; Telah menceritakan kepada kami [Sa'id bin Isa] dia berkata; Telah menceritakan kepada kami [Abdurrahman bin Al Qasim] dia berkata; Telah menceritakan kepada kami [Bakr bin Mudlar] dari [Amr bin Al Harits] dari [Yazid bin Abu Habib] bahwa [Abu Al Khair] Telah menceritakan kepadanya, sesungguhnya Abu Tamim Al Jaisyani bangkit untuk mengerjakan shalat dua rakaat sebelum Maghrib. Abu Al Khair lalu berkata kepada Uqbah bin Amir, \"Lihat ini, shalat apa yang dia kerjakan?\" Lalu [Uqbah bin Amir] menoleh kepadanya dan melihatnya, lantas berkata; \"Ini shalat yang dulu biasa kami kerjakan pada zaman Rasulullah Shallallahu'alaihi wasallam.\""},"578":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ زِيْدِ بْنِ مُحَمَّدٍ قَالَ سَمِعْتُ نَافِعًا يُحَدِّثُ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ أَنَّهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا طَلَعَ الْفَجْرُ لَا يُصَلِّي إِلَّا رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam] dia berkata; Telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Zaid bin Muhammad] dia berkata; Aku mendengar [Nafi'] berkata; dari [Ibnu Umar] dari [Hafshah] dia berkata; \"Apabila Fajar telah terbit maka Rasulullah Shallallahu'alaihi wasallam tidak mengerjakan shalat kecuali dua rakaat yang ringan.\""},"579":{"ar":"أَخْبَرَنِي الْحَسَنُ بْنُ إِسْمَعِيلَ بْنِ سُلَيْمَانَ وَأَيَّوبُ بْنُ مُحَمَّدٍ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ أَيُّوبُ حَدَّثَنَا وَقَالَ حَسَنٌ أَخْبَرَنِي شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ يَزِيدَ بْنِ طَلْقٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْبَيْلَمَانِيِّ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ مَنْ أَسْلَمَ مَعَكَ قَالَ حُرٌّ وَعَبْدٌ قُلْتُ هَلْ مِنْ سَاعَةٍ أَقْرَبُ إِلَى اللَّهِ عَزَّ وَجَلَّ مِنْ أُخْرَى قَالَ نَعَمْ جَوْفُ اللَّيْلِ الْآخِرُ فَصَلِّ مَا بَدَا لَكَ حَتَّى تُصَلِّيَ الصُّبْحَ ثُمَّ انْتَهِ حَتَّى تَطْلُعَ الشَّمْسُ وَمَا دَامَتْ وَقَالَ أَيُّوبُ فَمَا دَامَتْ كَأَنَّهَا حَجَفَةٌ حَتَّى تَنْتَشِرَ ثُمَّ صَلِّ مَا بَدَا لَكَ حَتَّى يَقُومَ الْعَمُودُ عَلَى ظِلِّهِ ثُمَّ انْتَهِ حَتَّى تَزُولَ الشَّمْسُ فَإِنَّ جَهَنَّمَ تُسْجَرُ نِصْفَ النَّهَارِ ثُمَّ صَلِّ مَا بَدَا لَكَ حَتَّى تُصَلِّيَ الْعَصْرَ ثُمَّ انْتَهِ حَتَّى تَغْرُبَ الشَّمْسُ فَإِنَّهَا تَغْرُبُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَتَطْلُعُ بَيْنَ قَرْنَيْ شَيْطَانٍ","id":"Telah mengabarkan kepada kami [Al Hasan bin Ismail bin Sulaiman] dan [Ayyub bin Muhammad] mereka berkata; Telah menceritakan kepada kami [Hajjaj bin Muhammad]. [Ayyub] berkata; Telah menceritakan kepada kami, dan [Hasan] berkata; Telah mengabarkan kepadaku [Syu'bah] dari [Ya'la bin Atha] dari [Yazid bin Thalq] dari [Abdurrahman bin Al Bailamani] dari [Amru bin Abasah] dia berkata; \"Aku datang kepada Rasulullah Shallallahu'alaihi wasallam lalu kukatakan kepada beliau, 'Wahai Rasulullah Shallallahu'alaihi wasallam, siapakan yang masuk Islam bersama engkau? ' Beliau Shallallahu'alaihi wasallam menjawab, 'Orang merdeka dan budak'. Kemudian aku bertanya lagi, 'Apakah ada waktu yang sangat dekat dengan Allah Azza wa Jalla dibanding yang lain? ' Beliau Shallallahu'alaihi wasallam menjawab, 'Ya, pada pertengahan malam yang terakhir. Shalatlah yang kamu kehendaki sampai engkau shalat Subuh, kemudian berhentilah ketika matahari terbit dan selagi matahari laksana perisai hingga memancar sinarnya. Kemudian shalatlah sekehendakmu sampai bayangan tongkat sama dengan aslinya, kemudian berhentilah sampai matahari condong ke arah Barat, karena neraka Jahannam dinyalakan pada pertengahan hari. Kemudian shalatlah sekehendakmu hingga shalat Ashar. lalu berhentilah hingga matahari terbenam, karena matahari terbenam diantara dua tanduk setan dan terbit diantara dua tanduk setan '.\""},"580":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ مِنْ أَبِي الزُّبَيْرِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ بَابَاهَ يُحَدِّثُ عَنْ جُبَيْرِ بْنِ مُطْعِمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا بَنِي عَبْدِ مَنَافٍ لَا تَمْنَعُوا أَحَدًا طَافَ بِهَذَا الْبَيْتِ وَصَلَّى أَيَّةَ سَاعَةٍ شَاءَ مِنْ لَيْلٍ أَوْ نَهَارٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; Telah menceritakan kepada kami [Sufyan] dia berkata; Aku mendengar dari [Abu Zubair] dia berkata; Aku mendengar [Abdullah bin Babah] dia bercerita dari [Jubair bin Muth'im] bahwa Nabi Shallallahu'alaihi wasallam bersabda: \"Wahai Bani Abdi Manaf, Janganlah kalian mencegah seorang pun yang thawaf di Ka'bah ini, dan siapapun yang shalat kapan pun waktunya, baik waktu siang dan malam yang dia kehendaki.\""},"581":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مُفَضَّلٌ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ارْتَحَلَ قَبْلَ أَنْ تَزِيغَ الشَّمْسُ أَخَّرَ الظُّهْرَ إِلَى وَقْتِ الْعَصْرِ ثُمَّ نَزَلَ فَجَمَعَ بَيْنَهُمَا فَإِنْ زَاغَتْ الشَّمْسُ قَبْلَ أَنْ يَرْتَحِلَ صَلَّى الظُّهْرَ ثُمَّ رَكِبَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Mufadlal] dari [Uqail] dari [Ibnu Syihab] dari [Anas bin Malik], dia berkata; \"Rasulullah Shallallahu'alaihi wasallam bila hendak melakukan perjalanan sebelum matahari condong ke barat beliau mengakhirkan Zhuhur sampai waktu shalat Ashar, kemudian singgah dan shalat dengan menjama' (menggabungkan) dua shalat tersebut. Jika matahari telah condong ke barat sebelum berangkat beliau shalat Zhuhur dulu, baru kemudian berangkat.\""},"582":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزُّبَيْرِ الْمَكِّيِّ عَنْ أَبِي الطُّفَيْلِ عَامِرِ بْنِ وَاثِلَةَ أَنَّ مُعَاذَ بْنَ جَبَلٍ أَخْبَرَهُأَنَّهُمْ خَرَجُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ تَبُوكَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْمَعُ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ فَأَخَّرَ الصَّلَاةَ يَوْمًا ثُمَّ خَرَجَ فَصَلَّى الظُّهْرَ وَالْعَصْرَ جَمِيعًا ثُمَّ دَخَلَ ثُمَّ خَرَجَ فَصَلَّى الْمَغْرِبَ وَالْعِشَاءَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan aku mendengarnya, lafazh ini miliknya. Dari [Ibnu Al Qasim] dia berkata; Telah menceritakan kepadaku [Malik] dari [Abu Zubair Al Makki] dari [Abu Thufail Amir bin Watsilah] Telah mengabarkan kepadanya [Mu'adz bin Jabal] bahwa para sahabat keluar bersama Rasulullah Shallallahu'alaihi wasallam pada tahun terjadinya perang Tabuk, maka Rasulullah Shallallahu'alaihi wasallam menjama' antara shalat Zuhur dan shalat Ashar, juga antara Maghrib dan Isya'. Beliau mengakhirkan shalat pada suatu hari kemudian keluar, lalu shalat Zhuhur dan Ashar dengan menjama'nya. Kemudian beliau masuk dan keluar, kemudian shalat Maghrib dan Isya' dengan menjama'nya pula. "},"583":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا كَثِيرُ بْنُ قَارَوَنْدَا قَالَ سَأَلْتُ سَالِمَ بْنَ عَبْدِ اللَّهِعَنْ صَلَاةِ أَبِيهِ فِي السَّفَرِ وَسَأَلْنَاهُ هَلْ كَانَ يَجْمَعُ بَيْنَ شَيْءٍ مِنْ صَلَاتِهِ فِي سَفَرِهِ فَذَكَرَ أَنَّ صَفِيَّةَ بِنْتَ أَبِي عُبَيْدٍ كَانَتْ تَحْتَهُ فَكَتَبَتْ إِلَيْهِ وَهُوَ فِي زَرَّاعَةٍ لَهُ أَنِّي فِي آخِرِ يَوْمٍ مِنْ أَيَّامِ الدُّنْيَا وَأَوَّلِ يَوْمٍ مِنْ الْآخِرَةِ فَرَكِبَ فَأَسْرَعَ السَّيْرَ إِلَيْهَا حَتَّى إِذَا حَانَتْ صَلَاةُ الظُّهْرِ قَالَ لَهُ الْمُؤَذِّنُ الصَّلَاةَ يَا أَبَا عَبْدِ الرَّحْمَنِ فَلَمْ يَلْتَفِتْ حَتَّى إِذَا كَانَ بَيْنَ الصَّلَاتَيْنِ نَزَلَ فَقَالَ أَقِمْ فَإِذَا سَلَّمْتُ فَأَقِمْ فَصَلَّى ثُمَّ رَكِبَ حَتَّى إِذَا غَابَتْ الشَّمْسُ قَالَ لَهُ الْمُؤَذِّنُ الصَّلَاةَ فَقَالَ كَفِعْلِكَ فِي صَلَاةِ الظُّهْرِ وَالْعَصْرِ ثُمَّ سَارَ حَتَّى إِذَا اشْتَبَكَتْ النُّجُومُ نَزَلَ ثُمَّ قَالَ لِلْمُؤَذِّنِ أَقِمْ فَإِذَا سَلَّمْتُ فَأَقِمْ فَصَلَّى ثُمَّ انْصَرَفَ فَالْتَفَتَ إِلَيْنَا فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَضَرَ أَحَدَكُمْ الْأَمْرُ الَّذِي يَخَافُ فَوْتَهُ فَلْيُصَلِّ هَذِهِ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'] dia berkata; Telah menceritakan kepada kami [Yazid bin Zura'i] berkata; Telah menceritakan kepada kami [Katsir bin Qarawanda] dia berkata; \"Aku bertanya kepada [Salim bin Abdullah] tentang shalat [ayahnya] dalam perjalanan, \"Apakah beliau menjama' diantara dua shalat dalam perjalanan\" Lalu Salim menyebutkan bahwa Shafiyyah binti Abu Ubaid -dia adalah istrinya- menulis surat kepadanya saat dia berada di ladangnya. Dia (Shafiyah) berkata, \"Aku berada pada hari-hari terakhir di dunia dan permulaan hari-hari di akhirat.\" Lalu Salim segera menaiki kendaraannya dan cepat-cepat pergi menuju Shafiyah hingga waktu shalat Zhuhur tiba berkatalah muadzin kepadanya, \"Shalat wahai Abu Abdurahman\" namun beliau tidak menoleh, hingga sampai saatnya antara dua (waktu) shalat beliau turun dan berkata, \"Kumandangkan iqamat, dan jika aku sudah mengucapkan salam (selesai shalat) maka (ia berkata) kumandangkan lagi iqamat.\" Lalu beliau shalat. Kemudian naik kendaraannya lagi, hingga tatkala matahari terbenam muadzin berkata, \"Shalat!\", Salim berkata, \"Kerjakanlah seperti yang kamu kerjakan saat shalat Zhuhur dan Ashar.\" Kemudian Salim berjalan lagi dan ketika bintang mulai bertaburan (telah beranjak malam) dia singgah. Kemudian dia berkata kepada muadzin, \"Kumandangkanlah iqamat dan jika aku telah salam (selesai shalat) (ia berkata) maka kumandangkanlah iqamat lagi, lalu dia shalat.\" Kemudian setelah selesai shalat ia menoleh kepada kami dan berkata, \"Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bila salah seorang dari kalian menghadapi suatu perkara yang kalian khawatir kehilangannya maka shalat lah seperti ini' (Jamak takdim).\""},"584":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ ثَمَانِيًا جَمِيعًا وَسَبْعًا جَمِيعًا أَخَّرَ الظُّهْرَ وَعَجَّلَ الْعَصْرَ وَأَخَّرَ الْمَغْرِبَ وَعَجَّلَ الْعِشَاءَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Amr] dari [Jabir bin Zaid] dari [Ibnu Abbas] dia berkata; \"Aku shalat bersama Nabi Shallallahu'alaihi wasallam di Madinah delapan rakaat dengan menjama'nya, dan tujuh rakaat dengan menjama'nya, menyegerakan Ashar dan mengakhirkan Maghrib, serta menyegerakan Isya'.\" "},"585":{"ar":"أَخْبَرَنِي أَبُو عَاصِمٍ خُشَيْشُ بْنُ أَصْرَمَ قَالَ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا حَبِيبٌ وَهُوَ ابْنُ أَبِي حَبِيبٍ عَنْ عَمْرِو بْنِ هَرِمٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍأَنَّهُ صَلَّى بِالْبَصْرَةِ الْأُولَى وَالْعَصْرَ لَيْسَ بَيْنَهُمَا شَيْءٌ وَالْمَغْرِبَ وَالْعِشَاءَ لَيْسَ بَيْنَهُمَا شَيْءٌ فَعَلَ ذَلِكَ مِنْ شُغْلٍ وَزَعَمَ ابْنُ عَبَّاسٍ أَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ الْأُولَى وَالْعَصْرَ ثَمَانِ سَجَدَاتٍ لَيْسَ بَيْنَهُمَا شَيْءٌ","id":"Telah mengabarkan kepadaku [Abu 'Ashim Khusyaisy bin Ashram] dia berkata; Telah menceritakan kepada kami [Habban bin Hilal] Telah menceritakan kepada kami [Habib yaitu Ibnu Abu Habib] dari [Amr bin Haram] dari [Jabir bin Zaid] dari [Ibnu Abbas], bahwa dia shalat Zhuhur dan Ashar di Bashrah tanpa ada sesuatupun diantara keduanya, juga shalat Maghrib dan Isya tanpa ada sesuatupun diantara keduanya. Dia melakukan hal tersebut karena sibuk. Ibnu Abbas menyangka bahwa dia shalat Zhuhur dan Ashar di Madinah bersama Rasulullah Shallallahu'alaihi wasallam delapan rakaat, tanpa ada sesuatu diantara keduanya."},"586":{"ar":"أَخْبَرَنِي إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ إِسْمَعِيلَ بْنِ عَبْدِ الرَّحْمَنِ شَيْخٍ مِنْ قُرَيْشٍ قَالَصَحِبْتُ ابْنَ عُمَرَ إِلَى الْحِمَى فَلَمَّا غَرَبَتْ الشَّمْسُ هِبْتُ أَنْ أَقُولَ لَهُ الصَّلَاةَ فَسَارَ حَتَّى ذَهَبَ بَيَاضُ الْأُفُقِ وَفَحْمَةُ الْعِشَاءِ ثُمَّ نَزَلَ فَصَلَّى الْمَغْرِبَ ثَلَاثَ رَكَعَاتٍ ثُمَّ صَلَّى رَكْعَتَيْنِ عَلَى إِثْرِهَا ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah mengabarkan kepadaku [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Ismail bin Abdurahman] -pemuka Quraisy- dia berkata, \"Aku menemani [Ibnu Umar] ke perbatasan, dan tatkala matahari terbenam aku berkata kepadanya, \"Shalat dulu\". Namun beliau tetap berjalan hingga lenyap cahaya putih di ufuk dan kegelapan Isya'. Kemudian beliau singgah dan mengerjakan shalat Maghrib tiga rakaat. Lalu shalat dua rakaat setelahnya dan berkata; 'Dulu aku melihat Rasulullah Shallallahu'alaihi wasallam melakukannya seperti ini'.\""},"587":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ ابْنِ أَبِي حَمْزَةَ ح وَأَنْبَأَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عُثْمَانُ وَاللَّفْظُ لَهُ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمٌ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا عَجِلَهُ السَّيْرُ فِي السَّفَرِ يُؤَخِّرُ صَلَاةَ الْمَغْرِبِ حَتَّى يَجْمَعَ بَيْنَهَا وَبَيْنَ الْعِشَاءِ","id":"Telah mengabarkan kepada kami [Amr bin Utsman] dia berkata; Telah menceritakan kepada kami [Baqiyyah] dari [Ibnu Abu Hamzah] dan Telah memberitakan kepada kami [Ahmad bin Muhammad bin Al Mughirah] dia berkata; Telah menceritakan kepada kami [Utsman] dan lafazh ini darinya, dari [Syu'aib] dari [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Salim] dari [Bapaknya] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam bila tergesa-gesa dalam perjalanannya, beliau mengakhirkan shalat Maghrib hingga menjama' antara Maghrib dan Isya'.\""},"588":{"ar":"أَخْبَرَنَا الْمُؤَمَّلُ بْنُ إِهَابٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ مُحَمَّدٍ الْجَارِيُّ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَغَابَتْ الشَّمْسُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ فَجَمَعَ بَيْنَ الصَّلَاتَيْنِ بِسَرِفَ","id":"Telah mengabarkan kepada kami [Al Mu'ammal bin Ihab] dia berkata; Telah menceritakan kepadaku [Yahya bin Muhammad Al Jari] dia berkata; Telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Malik bin Anas] dari [Abu Zubair] dari [Jabir] dia berkata; Rasulullah Shallallahu'alaihi wasallam sedang berada di Makkah, dan matahari telah terbenam, maka beliau Shallallahu'alaihi wasallam menjama' Shalatnya di Sarif."},"589":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنَا جَابِرُ بْنُ إِسْمَعِيلَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا عَجِلَ بِهِ السَّيْرُ يُؤَخِّرُ الظُّهْرَ إِلَى وَقْتِ الْعَصْرِ فَيَجْمَعُ بَيْنَهُمَا وَيُؤَخِّرُ الْمَغْرِبَ حَتَّى يَجْمَعَ بَيْنَهَا وَبَيْنَ الْعِشَاءِ حَتَّى يَغِيبَ الشَّفَقُ","id":"Telah mengabarkan kepada kami [Amr bin Sawwad bin Al Aswad bin Amr] dia berkata; Telah memberitakan kepada kami [Ibnu Wahab] dia berkata; Telah menceritakan kepada kami [Jabir bin Ismail] dari [Uqail] dari [Ibnu Syihab] dari [Anas] dari Rasulullah Shallallahu'alaihi wasallam bahwa apabila Beliau Shallallahu'alaihi wasallam sedang tergesa-gesa dalam perjalanannya maka beliau mengakhirkan Zhuhur sampai waktu shalat Ashar, lalu menjama' keduanya. Beliau juga mengakhirkan shalat Maghrib hingga beliau menjama' antara Maghrib dan Isya' hingga mega merah menghilang."},"590":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ حَدَّثَنَا ابْنُ جَابِرٍ قَالَ حَدَّثَنِي نَافِعٌ قَالَخَرَجْتُ مَعَ عَبْدِ اللَّهِ بْنِ عُمَرَ فِي سَفَرٍ يُرِيدُ أَرْضًا فَأَتَاهُ آتٍ فَقَالَ إِنَّ صَفِيَّةَ بِنْتَ أَبِي عُبَيْدٍ لِمَا بِهَا فَانْظُرْ أَنْ تُدْرِكَهَا فَخَرَجَ مُسْرِعًا وَمَعَهُ رَجُلٌ مِنْ قُرَيْشٍ يُسَايِرُهُ وَغَابَتْ الشَّمْسُ فَلَمْ يُصَلِّ الصَّلَاةَ وَكَانَ عَهْدِي بِهِ وَهُوَ يُحَافِظُ عَلَى الصَّلَاةِ فَلَمَّا أَبْطَأَ قُلْتُ الصَّلَاةَ يَرْحَمُكَ اللَّهُ فَالْتَفَتَ إِلَيَّ وَمَضَى حَتَّى إِذَا كَانَ فِي آخِرِ الشَّفَقِ نَزَلَ فَصَلَّى الْمَغْرِبَ ثُمَّ أَقَامَ الْعِشَاءَ وَقَدْ تَوَارَى الشَّفَقُ فَصَلَّى بِنَا ثُمَّ أَقْبَلَ عَلَيْنَا فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا عَجِلَ بِهِ السَّيْرُ صَنَعَ هَكَذَا","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] dia berkata; Telah menceritakan kepada kami [Al Walid] dia berkata; Telah menceritakan kepada kami [Ibnu Jabir] dia berkata; Telah menceritakan kepadaku [Nafi'] dia berkata; \"Aku keluar bersama [Abdullah bin Umar] dalam suatu perjalanan menuju suatu daerah, lalu datanglah seseorang yang berkata, 'Shafiyyah binti Abu Ubaid ada masalah, maka tolong temuilah, semoga kamu dapat sampai padanya'. Lalu dia keluar dengan cepat bersama seorang laki-laki Quraisy. Matahari sudah terbenam, namun beliau tidak mengerjakan shalat, padahal aku tahu dia orang yang sangat menjaga shalat (pada waktunya), maka setelah agak lambat aku berkata kepadanya, 'Shalat dulu, semoga Allah merahmatimu! ' Dia menoleh kepadaku dan terus berlalu hingga tatkala sampai akhir mega merah, beliau singgah dan shalat Maghrib kemudian shalat Isya', sedangkan mega merah telah lenyap. Beliau shalat bersama kami, dan setelah selesai beliau menghadap ke kami dan mengatakan bahwa Rasulullah Shallallahu'alaihi wasallam bila tergesa-gesa dalam suatu perjalanan beliau berbuat seperti itu.\""},"591":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْعَطَّافُ عَنْ نَافِعٍ قَالَأَقْبَلْنَا مَعَ ابْنِ عُمَرَ مِنْ مَكَّةَ فَلَمَّا كَانَ تِلْكَ اللَّيْلَةُ سَارَ بِنَا حَتَّى أَمْسَيْنَا فَظَنَنَّا أَنَّهُ نَسِيَ الصَّلَاةَ فَقُلْنَا لَهُ الصَّلَاةَ فَسَكَتَ وَسَارَ حَتَّى كَادَ الشَّفَقُ أَنْ يَغِيبَ ثُمَّ نَزَلَ فَصَلَّى وَغَابَ الشَّفَقُ فَصَلَّى الْعِشَاءَ ثُمَّ أَقْبَلَ عَلَيْنَا فَقَالَ هَكَذَا كُنَّا نَصْنَعُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَدَّ بِهِ السَّيْرُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Al Athaf] dari [Nafi'], dia berkata, \"Kami datang dari Makkah bersama [Ibnu Umar], malam itu kami berjalan hingga masuk waktu sore hari dan kami menyangka bahwa beliau telah lupa shalat, maka kami berkata, 'Shalat dulu'. Namun beliau diam saja dan terus berjalan hingga mega merah hampir lenyap. Kemudian kami singgah lalu shalat, dan hilanglah mega merah tersebut. Kemudian shalat Isya dan setelah selesai ia menghadap kepada kami sambil berkata, 'Beginilah kami dahulu berbuat bersama Rasulullah Shallallahu'alaihi wasallam bila sedang tergesa-gesa dalam perjalanan'.\""},"592":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنَا ابْنُ شُمَيْلٍ قَالَ حَدَّثَنَا كَثِيرُ ب��نُ قَارَوَنْدَا قَالَسَأَلْنَا سَالِمَ بْنَ عَبْدِ اللَّهِ عَنْ الصَّلَاة فِي السِّفْر فَقُلْنَا أَكَانَ عَبْدُ اللَّهِ يَجْمَعُ بَيْنَ شَيْءٍ مِنْ الصَّلَوَاتِ فِي السَّفَرِ فَقَالَ لَا إِلَّا بِجَمْعٍ ثُمَّ أَتَيْتُهُ فَقَالَ كَانَتْ عِنْدَهُ صَفِيَّةُ فَأَرْسَلَتْ إِلَيْهِ أَنِّي فِي آخِرِ يَوْمٍ مِنْ الدُّنْيَا وَأَوَّلِ يَوْمٍ مِنْ الْآخِرَةِ فَرَكِبَ وَأَنَا مَعَهُ فَأَسْرَعَ السَّيْرَ حَتَّى حَانَتْ الصَّلَاةُ فَقَالَ لَهُ الْمُؤَذِّنُ الصَّلَاةَ يَا أَبَا عَبْدِ الرَّحْمَنِ فَسَارَ حَتَّى إِذَا كَانَ بَيْنَ الصَّلَاتَيْنِ نَزَلَ فَقَالَ لِلْمُؤَذِّنِ أَقِمْ فَإِذَا سَلَّمْتُ مِنْ الظُّهْرِ فَأَقِمْ مَكَانَكَ فَأَقَامَ فَصَلَّى الظُّهْرَ رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ أَقَامَ مَكَانَهُ فَصَلَّى الْعَصْرَ رَكْعَتَيْنِ ثُمَّ رَكِبَ فَأَسْرَعَ السَّيْرَ حَتَّى غَابَتْ الشَّمْسُ فَقَالَ لَهُ الْمُؤَذِّنُ الصَّلَاةَ يَا أَبَا عَبْدِ الرَّحْمَنِ فَقَالَ كَفِعْلِكَ الْأَوَّلِ فَسَارَ حَتَّى إِذَا اشْتَبَكَتْ النُّجُومُ نَزَلَ فَقَالَ أَقِمْ فَإِذَا سَلَّمْتُ فَأَقِمْ فَصَلَّى الْمَغْرِبَ ثَلَاثًا ثُمَّ أَقَامَ مَكَانَهُ فَصَلَّى الْعِشَاءَ الْآخِرَةَ ثُمَّ سَلَّمَ وَاحِدَةً تِلْقَاءَ وَجْهِهِ ثُمَّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَضَرَ أَحَدَكُمْ أَمْرٌ يَخْشَى فَوْتَهُ فَلْيُصَلِّ هَذِهِ الصَّلَاةَ","id":"Telah mengabarkan kepada kami ['Abdah bin Abdurrahim] dia berkata; Telah menceritakan kepada kami [Ibnu Syumail] dia berkata; Telah menceritakan kepada kami [Katsir bin Qarawanda], dia berkata; \"Aku bertanya kepada [Salim bin Abdullah], \"Apakah ayahmu ([Abdullah]) menjama' antara dua shalat dalam perjalanan? ' la menjawab, 'Tidak kecuali di Muzdalifah'. Kemudian aku mendatanginya, dan ia berkata, 'Di sampingnya ada Shafiyyah (istrinya), maka dia (shafiyyah) menulis surat kepada Salim, bahwa ia pada hari terakhir dari hari-harinya di dunia dan permulaan dari hari-harinya di akhirat. Lalu Salim segera menaiki kendaraannya dan aku bersamanya. Dia (Salim) memacu laju kendaraannya, hingga ketika saat shalat Zhuhur tiba berkatalah muadzin kepadanya, \"Shalat wahai Abu Abdurahman!\" namun beliau tetap berlalu hingga ketika sampai diantara dua shalat beliau turun dan berkata kepada muadzinnya, \"Kumandangkan i iqamat, dan jika aku sudah mengucapkan salam (setelah shalat) dari shalat Zhuhur maka kumandangkan lag! iqamat.\" Lalu muadzin mengumandangkan iqamat, lantas ia (Salim) shalat Zhuhur dua rakaat kemudian salam. Kemudian shalat Ashar dua rakaat. Selanjutnya ia naik kendaraan lagi dan memacu lajunya hingga bila matahari telah terbenam, muadzin berkata kepadanya, \"Shalat, wahai Abdurrahman!\" la berkata, \"Kerjakanlah seperti yang kamu lakukan saat Zhuhur dan Ashar.\" Kemudian dia berjalan lagi hingga ketika bintang mulai bertaburan iapun singgah, kemudian berkata kepada muadzin, \"Kumandangkanlah iqamat dan jika aku telah salam (selesai shalat) maka kumandangkanlah iqamat lagi, lalu dia shalat\" Kemudian dia selesai shalat Maghrib tiga rakaat dan dia tetap di tempatnya hingga shalat Isya yang terakhir, kemudian salam sekali dengan wajahnya. Lalu ia berkata, \"Rasulullah Shallallahu'alaihi wasallam bersabda; \"Bila salah seorang dari kalian menghadapi suatu perkara yang kalian khawatir akan kehilangannya, maka shalatlah seperti ini.\""},"593":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا جَدَّ بِهِ السَّيْرُ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Nafi] dari [Ibnu Umar] bahwa Rasulullah Shallallahu'alaihi wasallam bila tergesa-gesa dalam perjalanan beliau menjama' shalat Maghrib dan lsya'."},"594":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَدَّ بِهِ السَّيْرُ أَوْ حَزَبَهُ أَمْرٌ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Abdur Razak] dia berkata; Telah menceritakan kepada kami [Ma'mar] dari [Musa bin Uqbah] dari [Nafi'] dari [Ibnu Umar] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam apabila tergesa-gesa dalam suatu perjalanan - atau ada perkara yang mendesaknya - maka beliau menjama' antara shalat Maghrib dan Isya'.\""},"595":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ قَالَ أَخْبَرَنِي سَالِمٌ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَدَّ بِهِ السَّيْرُ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; Telah memberitakan kepada kami [Sufyan] dia berkata; Aku mendengar [Az Zuhri] dia berkata; Telah mengabarkan kepadaku [Salim] dari [Bapaknya] dia berkata; \"Aku melihat Nabi Shallallahu'alaihi wasallam bila tergesa-gesa dalam perjalanan beliau menjama' antara shalat Maghrib dan Isya'.\""},"596":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ وَالْعَصْرَ جَمِيعًا وَالْمَغْرِبَ وَالْعِشَاءَ جَمِيعًا مِنْ غَيْرِ خَوْفٍ وَلَا سَفَرٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Zubair] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dia berkata; \"Pernah Rasulullah Shallallahu'alaihi wasallam menjama' shalat Zhuhur dan Ashar, serta menjama' shalat Maghrib dan Isya' bukan karena alasan takut (peperangan) dan bukan karena alasan perjalanan.\""},"597":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ وَاسْمُهُ غَزْوَانُ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بِالْمَدِينَةِ يَجْمَعُ بَيْنَ الصَّلَاتَيْنِ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ مِنْ غَيْرِ خَوْفٍ وَلَا مَطَرٍقِيلَ لَهُ لِمَ قَالَ لِئَلَّا يَكُونَ عَلَى أُمَّتِهِ حَرَجٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul 'Aziz bin Abu Rizmah Ghazwan] dia berkata; Telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Rasulullah Shallallahu'alaihi wasallam pernah shalat di Madinah dengan menjama' Zhuhur dan Ashar, serta Maghrib dan Isya' bukan karena rasa takut (peperangan) dan bukan karena hujan.Ibnu Abbas ditanya, \"Kenapa demikian?\" maka dia menjawab, \"Agar tidak memberatkan umatnya.\""},"598":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الشَّعْثَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَصَلَّيْتُ وَرَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِيًا جَمِيعًا وَسَبْعًا جَمِيعًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Khalid] dia berkata; Telah menceritakan kepada kami [Ibnu Juraij] dari [Amr bin Dinar] dari [Abu Asy-Sya'tsa] dari [Ibnu Abbas] dia berkata; \"Aku shalat di belakang Rasulullah Shallallahu'alaihi wasallam delapan rakaat secara jama' dan tujuh rakaat secara jama'.\""},"599":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ هَارُونَ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِقَالَ سَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَتَى عَرَفَةَ فَوَجَدَ الْقُبَّةَ قَدْ ضُرِبَتْ لَهُ بِنَمِرَةَ فَنَزَلَ بِهَا حَتَّى إِذَا زَاغَتْ الشَّمْسُ أَمَرَ بِالْقَصْوَاءِ فَرُحِلَتْ لَهُ حَتَّى إِذَا انْتَهَى إِلَى بَطْنِ الْوَادِي خَطَبَ النَّاسَ ثُمَّ أَذَّنَ بِلَالٌ ثُمَّ أَقَامَ فَصَلَّى الظُّهْرَ ثُمَّ أَقَامَ فَصَلَّى الْعَصْرَ وَلَمْ يُصَلِّ بَيْنَهُمَا شَيْئًا","id":"Telah mengabarkan kepada kami [Ibrahim bin Harun] dia berkata; Telah menceritakan kepada kami [Hatim bin Ismail] dia berkata; Telah menceritakan kepada kami [Ja'far bin Muhammad] dari [Bapaknya] bahwa [Jabir bin Abdullah] berkata; \"Rasulullah Shallallahu'alaihi wasallam berjalan hingga ke Arafah, lalu beliau mendapati kemah telah didirikan untuk dirinya di daerah Namirah, maka beliau singgah sampai matahari terbenam. Beliau mempersiapkan untanya untuk segera berangkat. Sesampainya di Bathn Al Wadi beliau berkhutbah dihadapan manusia, lalu Bilal mengumandangkan adzan, dan shalat Zhuhur. Kemudian iqamat lagi dan mengerjakan shalat Ashar. Beliau tidak mengerjakan shalat apapun diantara keduanya.\""},"600":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ أَنَّ أَبَا أَيُّوبَ الْأَنْصَارِيَّ أَخْبَرَهُأَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ الْمَغْرِبَ وَالْعِشَاءَ بِالْمُزْدَلِفَةِ جَمِيعًا","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Yahya bin Sa'id] dari ['Adi bin Tsabit] dari ['Abdullah bin Yazid] bahwasanya [Abu Ayyub Al-Anshari] mengabarkan kepadanya bahwasanya dia pernah shalat bersama Rasulullah Shallallahu'alaihi wasallam dalam haji Wada', yakni shalat jama' antara Maghrib dan Isya' di Muzdalifah."},"601":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَكُنْتُ مَعَ ابْنِ عُمَرَ حَيْثُ أَفَاضَ مِنْ عَرَفَاتٍ فَلَمَّا أَتَى جَمْعًا جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ فَلَمَّا فَرَغَ قَالَ فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَكَانِ مِثْلَ هَذَا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Husyaim] dari [Isma'il bin Abu Khalid] dia berkata; telah menceritakan kepada kami [Abu Ishaq] dari [Sa'id bin Jubair] dia berkata, \"Aku bersama [Ibnu Umar] bertolak dari Arafah, dan setelah sampai di Jama' (Muzdalifah) beliau menjamak antara shalat Maghrib dan Isya'. Setelah selesai dia berkata; 'Rasulullah Shallallahu'alaihi wasallam pernah melakukan hal seperti ini di tempat ini'.\""},"602":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الْمَغْرِبَ وَالْعِشَاءَ بِالْمُزْدَلِفَةِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Malik] dari [Az-Zuhri] dari [Salim] dari [Ibnu 'Umar] bahwa Nabi Shallallahu'alaihi wasallam shalat Maghrib dan Isya di Muzdalifah."},"603":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ قَالَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ بَيْنَ صَلَاتَيْنِ إِلَّا بِجَمْعٍ وَصَلَّى الصُّبْحَ يَوْمَئِذٍ قَبْلَ وَقْتِهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al-A'masy] dari ['Umarah] dari ['Abdurrahman bin Yazid] dari ['Abdullah] dia berkata; \"Aku tidak melihat Rasulullah Shallallahu'alaihi wasallam menjamak antara dua shalat kecuali di Jama' (Muzdalifah) beliau shalat Subuh sebelum waktunya.\""},"604":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ عُقْبَةَ وَمُحَمَّدُ بْنُ أَبِي حَرْمَلَةَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُسَامَةَ بْنِ زَيْدٍوَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْدَفَهُ مِنْ عَرَفَةَ فَلَمَّا أَتَى الشِّعْبَ نَزَلَ فَبَالَ وَلَمْ يَقُلْ أَهْرَاقَ الْمَاءَ قَالَ فَصَبَبْتُ عَلَيْهِ مِنْ إِدَاوَةٍ فَتَوَضَّأَ وُضُوءًا خَفِيفًا فَقُلْتُ لَهُ الصَّلَاةَ فَقَالَ الصَّلَاةُ أَمَامَكَ فَلَمَّا أَتَى الْمُزْدَلِفَةَ صَلَّى الْمَغْرِبَ ثُمَّ نَزَعُوا رِحَالَهُمْ ثُمَّ صَلَّى الْعِشَاءَ","id":"Telah mengabarkan kepada kami [Al-Husain bin Huraits] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin 'Uqbah] dan [Muhammad bin Abu Harmalah] dari [Kuraib] dari [Ibnu 'Abbas] dari [Usamah bin Zaid] bahwa Nabi Shallallahu'alaihi wasallam pernah memboncengnya dari Arafah, dan setelah sampai di Syi'b (jalan setapak) beliau turun dan buang air kecil. Beliau tidak berkata, \"Tuangkan air.\" Ia berkata, \"Aku menuangkan air kepadanya dari ember, lalu beliau berwudhu dengan ringan. Lantas aku berkata kepada beliau, 'Waktu Shalat telah tiba! ' Beliau Shallallahu'alaihi wasallam lalu berkata, 'Shalat (nanti) di depanmu'. Maka setelah sampai Muzdalifah beliau shalat Maghrib, kemudian mereka menurunkan barang bekalannya lalu beliau shalat Isya.\""},"605":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي الْوَلِيدُ بْنُ الْعَيْزَارِ قَالَ سَمِعْتُ أَبَا عَمْرٍو الشَّيْبَانِيَّ يَقُولُ حَدَّثَنَا صَاحِبُ هَذِهِ الدَّارِ وَأَشَارَ إِلَى دَارِ عَبْدِ اللَّهِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْعَمَلِ أَحَبُّ إِلَى اللَّهِ تَعَالَى قَالَ الصَّلَاةُ عَلَى وَقْتِهَا وَبِرُّ الْوَالِدَيْنِ وَالْجِهَادُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Al-Walid bin Al-'Aizar] dia berkata; aku mendengar [Abu 'Amr Asy-Syaibani] berkata; telah menceritakan kepada kami penghuni rumah ini -dan mengisyaratkan ke arah rumah ['Abdullah] - dia berkata; 'Aku pernah bertanya kepada Rasulullah Shallallahu'alaihi wasallam, \"Apakah amalan yang paling dicintai Allah Azza wa Jalla? Beliau menjawab.\"Shalat pada waktunya, berbakti kepada orang tua, dan jihad di jalan Allah Azza wa Jalla.\""},"606":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ النَّخَعِيُّ سَمِعَهُ مِنْ أَبِي عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْعَمَلِ أَحَبُّ إِلَى اللَّهِ عَزَّ وَجَلَّ قَالَ إِقَامُ الصَّلَاةِ لِوَقْتِهَا","id":"Telah mengabarkan kepada kami ['Abdullah bin Muhammad bin 'Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah An-Nakha'i] yang mendengarnya dari [Abu 'Amr] dari ['Abdullah bin Mas'ud] dia berkata; \"Aku bertanya kepada Rasulullah Shallallahu'alaihi wasallam, 'Apakah amalan yang paling dicintai Allah Azza wa Jalla? Beliau menjawab: \"Mendirikan shalat pada waktunnya.\""},"607":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَكِيمٍ وَعَمْرُو بْنُ يَزِيدَ قَالَا حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ أَنَّهُكَانَ فِي مَسْجِدِ عَمْرِو بْنِ شُرَحْبِيلَ فَأُقِيمَتْ الصَّلَاة فَجُعِلُوا يُنْتَظَرُونَهُ فَقَالَ إِنِّي كُنْتُ أُوتِرُ قَال وَسُئِلَ عَبْدُ اللَّهِ هَلْ بَعْدَ الْأَذَانِ وِتْرٌ قَالَ نَعَمْ وَبَعْدَ الْإِقَامَةِ وَحَدَّثَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَامَ عَنْ الصَّلَاةِ حَتَّى طَلَعَتْ الشَّمْسُ ثُمَّ صَلَّىوَاللَّفْظُ لِيَحْيَى","id":"Telah mengabarkan kepada kami [Yahya bin Hakim] dan ['Amr bin Yazid] mereka berdua berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Ibrahim bin Muhammad bin Al-Muntasyir] dari [bapaknya] bahwa dia sedang berada di masjid [Amru bin Syurahbil], kemudian iqamah dikumandangkan dan mereka menunggunya, dia berkata.\"Aku telah shalat witir.\" Dia berkata, \" [Abdullah] pernah ditanya, 'Apakah ada shalat witir setelah adzan? dia menjawab, \"Ya, juga setelah iqamah'. Lalu ia menceritakan bahwa Rasulullah Shallallahu'alaihi wasallam pernah ketiduran dari shalat hingga matahari terbit, kemudian beliau Shallallahu'alaihi wasallam mengerjakan shalat (witir) '.\""},"608":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَسِيَ صَلَاةً فَلْيُصَلِّهَا إِذَا ذَكَرَهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa lupa shalat, maka hendaklah mengerjakannya apabila dia ingat.\""},"609":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ يَزِيدَ قَالَ حَدَّثَنَا حَجَّاجٌ الْأَحْوَلُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يَرْقُدُ عَنْ الصَّلَاةِ أَوْ يَغْفُلُ عَنْهَا قَالَ كَفَّارَتُهَا أَنْ يُصَلِّيَهَا إِذَا ذَكَرَهَا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Yazid] dia berkata; telah menceritakan kepada kami [Hajjaj Al-Ahwal] dari [Qatadah] dari [Anas] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam pernah ditanya tentang orang yang tidak shalat, karena tertidur atau lalai. Beliau Shallallahu'alaihi wasallam menjawab: \"Kafaratnya (tebusannya) adalah mengerjakannya saat ingat.\""},"610":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَ قَالَذَكَرُوا لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَوْمَهُمْ عَنْ الصَّلَاةِ فَقَالَ إِنَّهُ لَيْسَ فِي النَّوْمِ تَفْرِيطٌ إِنَّمَا التَّفْرِيطُ فِي الْيَقَظَةِ فَإِذَا نَسِيَ أَحَدُكُمْ صَلَاةً أَوْ نَامَ عَنْهَا فَلْيُصَلِّهَا إِذَا ذَكَرَهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari ['Abdullah bin Rabah] dari [Abu Qatadah] dia berkata; \"Para sahabat menceritakan kepada Nabi Shallallahu'alaihi wasallam bahwa mereka tertidur sehingga tidak shalat, maka Rasulullah Shallallahu'alaihi wasallam bersabda, 'Sikap meremehkan (sembrono) itu tidak berlaku dalam keadaan tidur, tetapi sikap meremehkan itu berlaku dalam keadaan terjaga. Jika salah seorang dari kalian lupa shalat atau tertidur, maka hendaklah ia mengerjakannya ketika ia ingat'.\""},"611":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ وَهُوَ ابْنُ الْمُبَارَكِ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِي النَّوْمِ تَفْرِيطٌ إِنَّمَا التَّفْرِيطُ فِيمَنْ لَمْ يُصَلِّ الصَّلَاةَ حَتَّى يَجِيءَ وَقْتُ الصَّلَاةِ الْأُخْرَى حِينَ يَنْتَبِهُ لَهَا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al-Mubarak] dari [Sulaiman bin Al-Mughirah] dari [Tsabit] dari ['Abdullah bin Rabah] dari [Abu Qatadah] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Sikap meremehkan (sembrono) itu tidak berlaku saat keadaan tidur, melainkan sikap sembrono itu berlaku pada orang yang tidak mengerjakan shalat hingga tiba waktu shalat selanjutnya, sedangkan dia dalam keadaan sadar.\""},"612":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا نَامُوا عَنْ الصَّلَاةِ حَتَّى طَلَعَتْ الشَّمْسُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيُصَلِّهَا أَحَدُكُمْ مِنْ الْغَدِ لِوَقْتِهَا","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Tsabit Al-Banani] dari ['Abdullah bin Rabah] dari [Abu Qatadah] bahwa ketika para sahabat tertidur dari shalat hingga matahari terbit, Rasulullah Shallallahu'alaihi wasallam bersabda: \"Hendaklah salah seorang dari kalian melaksanakan shalat keesokan harinya pada waktunya.\" "},"613":{"ar":"أَخْبَرَنَا عَبْدُ الْأَعْلَى بْنُ وَاصِلِ بْنِ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا يَعْلَى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نَسِيتَ الصَّلَاةَ فَصَلِّ إِذَا ذَكَرْتَ فَإِنَّ اللَّهَ تَعَالَى يَقُولُ{ أَقِمْ الصَّلَاةَ لِذِكْرِي }قَالَ عَبْدُ الْأَعْلَى حَدَّثَنَا بِهِ يَعْلَى مُخْتَصَرًا","id":"Telah mengabarkan kepada kami ['Abdul A'la bin Washil bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Ya'la] dia berkata; telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Az-Zuhri] dari [Sa'id] dari [Abu Hurairah] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Apabila kamu lupa mengerjakan shalat maka kerjakanlah bila kamu ingat. Sesungguhnya Allah Ta'ala berfirman. 'Tegakkanlah shalat untuk mengingat-Ku'. (Qs. Thaahaa (20: 14) \" Abdul A'la berkata; Telah menceritakan kepada kami Ya'ala hadis tersebut secara ringkas. "},"614":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْ��َسْوَدِ بْنِ عَمْرٍو قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَنْبَأَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَسِيَ صَلَاةً فَلْيُصَلِّهَا إِذَا ذَكَرَهَا فَإِنَّ اللَّهَ تَعَالَى قَالَ{ أَقِمْ الصَّلَاةَ لِذِكْرِي }","id":"Telah mengabarkan kepada kami ['Amr bin Sawwad bin Al-Aswad bin 'Amr] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah memberitakan kepada kami [Yunus] dari [Ibnu Syihab] dari [Sa'id bin Al-Musayyab] dari [Abu Hurairah] Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa lupa mengerjakan shalat, maka hendaklah mengerjakannya apabila ia ingat. Sesungguhnya Allah Ta 'ala berfirman, 'Tegakkanlah shalat untuk mengingat-Ku'. (Qs. Thaahaa (20: 14).\""},"615":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَسِيَ صَلَاةً فَلْيُصَلِّهَا إِذَا ذَكَرَهَا فَإِنَّ اللَّهَ تَعَالَى يَقُولُ أَقِمْ الصَّلَاةَ لِلذِّكْرَىقُلْتُ لِلزُّهْرِيِّ هَكَذَا قَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Ma'mar] dari [Az-Zuhri] dari [Sa'id bin Al-Musayyab] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda; \"Barangsiapa lupa mengerjakan shalat, hendaklah mengerjakannya apabila ia ingat. Sesungguhnya Allah Ta 'ala berfirman, 'Tegakkanlah shalat sebagai peringatan.\" Zuhri (perawi) pernah ditanya, \"Apakah begini Rasulullah Shallallahu'alaihi wasallam membaca Al Qur'an?\" dia menjawab, \"Ya.\""},"616":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ أَبِيهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَأَسْرَيْنَا لَيْلَةً فَلَمَّا كَانَ فِي وَجْهِ الصُّبْحِ نَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَامَ وَنَامَ النَّاسُ فَلَمْ يَسْتَيْقِظْ إِلَّا بِالشَّمْسِ قَدْ طَلَعَتْ عَلَيْنَا فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤَذِّنَ فَأَذَّنَ ثُمَّ صَلَّى الرَّكْعَتَيْنِ قَبْلَ الْفَجْرِ ثُمَّ أَمَرَهُ فَأَقَامَ فَصَلَّى بِالنَّاسِ ثُمَّ حَدَّثَنَا بِمَا هُوَ كَائِنٌ حَتَّى تَقُومَ السَّاعَةُ","id":"Telah mengabarkan kepada kami [Hunnad bin As-Sari] dari [Abu Al-Ahwash] dari ['Atha bin As-Saib] dari [Buraid bin Abu Maryam] dari [bapaknya] dia berkata; \"Kami bersama Rasulullah Shallallahu'alaihi wasallam dalam suatu perjalanan. Kami berjalan di malam hari. Ketika menjelang Subuh Rasulullah Shallallahu'alaihi wasallam singgah lalu tertidur. Semua sahabat juga tertidur, dan mereka terbangun setelah matahari menyinari kami. Lantas Rasulullah Shallallahu'alaihi wasallam menyuruh muadzin untuk adzan, kemudian shalat dua rakaat sebelum Fajar. Rasulullah Shallallahu'alaihi wasallam menyuruhnya kembali untuk adzan, dan selanjutnya iqamah, lalu beliau Shallallahu'alaihi wasallam shalat bersama para sahabat. Setelah itu beliau menceritakan keadaan yang ada sampai perihal hari Kiamat kepada kami.\""},"617":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ هِشَامٍ الدَّسْتَوَائِيِّ عَنْ أَبِي الزُّبَيْرِ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِي عُبَيْدَةَ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحُبِسْنَا عَنْ صَلَاةِ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ فَاشْتَدَّ ذَلِكَ عَلَيَّ فَقُلْتُ فِي نَفْسِي نَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي سَبِيلِ اللَّهِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالًا فَأَقَامَ فَصَلَّى بِنَا الظُّهْرَ ثُمَّ أَقَامَ فَصَلَّى بِنَا الْعَصْرَ ثُمَّ أَقَامَ فَصَلَّى بِنَا الْمَغْرِبَ ثُمَّ أَقَامَ فَصَلَّى بِنَا الْعِشَاءَ ثُمَّ طَافَ عَلَيْنَا فَقَالَ مَا عَلَى الْأَرْضِ عِصَابَةٌ يَذْكُرُونَ اللَّهَ عَزَّ وَجَلَّ غَيْرُكُمْ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Hisyam Ad-Dastawa'i] dari [Abu Az Zubair] dari [Nafi' bin Jubair bin Muth'im] dari [Abu 'Ubaidah bin 'Abdullah] dari ['Abdullah bin Mas'ud] dia berkata; kami dan Rasulullah Shallallahu'alaihi wasallam terhalang dari melaksanakan shalat Zhuhur, Ashar, Maghrib dan Isya. Dan itu membuatku merasa berat. Maka akupun berkata pada diriku sendiri, kita sedang bersama Rasulullah Shallallahu'alaihi wasallam dalam melaksanakan jihad fi sabilillah. Kemudian tiba-tiba Rasulullah Shallallahu'alaihi wasallam menyuruh Bilal untuk adzan, lalu iiqamat dan kami pun shalat zhuhur bersama beliau. Kemudian iqamat lagi, dan kamipun shalat ashar bersama beliau, kemudian iiqamat lagi, dan kamipun shalat maghrib bersama beliau, lalu iiqamat lagi, dan kamipun shalat isya bersama beliau. Kemudian beliau berkeliling pada kami dan bersabda: \" Di muka bumi ini tidak ada kelompok yang senantiasa mengingat Allah Azza wa Jalla selain kalian.\" "},"618":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى عَنْ يَزِيدَ بْنِ كَيْسَانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَعَرَّسْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ نَسْتَيْقِظْ حَتَّى طَلَعَتْ الشَّمْسُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَل��يْهِ وَسَلَّمَ لِيَأْخُذْ كُلُّ رَجُلٍ بِرَأْسِ رَاحِلَتِهِ فَإِنَّ هَذَا مَنْزِلٌ حَضَرَنَا فِيهِ الشَّيْطَانُ قَالَ فَفَعَلْنَا فَدَعَا بِالْمَاءِ فَتَوَضَّأَ ثُمَّ صَلَّى سَجْدَتَيْنِ ثُمَّ أُقِيمَتْ الصَّلَاةُ فَصَلَّى الْغَدَاةَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya] dari [Yazid bin Kaisan] dia berkata; telah menceritakan kepada kami [Abu Hazim] dari [Abu Hurairah] dia berkata; \"Kami tidur untuk istirahat bersama Rasulullah Shallallahu'alaihi wasallam dan terbangun ketika matahari terbit. Rasulullah Shallallahu'alaihi wasallam lalu bersabda: \"Hendaknya tiap orang berpegangan dengan kepala tunggangannya. Sesungguhnya tempat ini didatangi oleh setan '.\" Abu Hurairah berkata; \"Lalu kami melaksanakannya, dan beliau meminta air kemudian berwudhu. Lalu beliau mengerjakan shalat dua sujud (rakaat) dan iqamah. Kemudian beliau Shallallahu'alaihi wasallam shalat Subuh.\""},"619":{"ar":"أَخْبَرَنَا أَبُو عَاصِمٍ خُشَيْشُ بْنُ أَصْرَمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي سَفَرٍ لَهُ مَنْ يَكْلَؤُنَا اللَّيْلَةَ لَا نَرْقُدَ عَنْ صَلَاةِ الصُّبْحِ قَالَ بِلَالٌ أَنَا فَاسْتَقْبَلَ مَطْلَعَ الشَّمْسِ فَضُرِبَ عَلَى آذَانِهِمْ حَتَّى أَيْقَظَهُمْ حَرُّ الشَّمْسِ فَقَامُوا فَقَالَ تَوَضَّئُوا ثُمَّ أَذَّنَ بِلَالٌ فَصَلَّى رَكْعَتَيْنِ وَصَلَّوْا رَكْعَتَيْ الْفَجْرِ ثُمَّ صَلَّوْا الْفَجْرَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim Khusyaisy bin Ashram] dia berkata; telah menceritakan kepada kami [Yahya bin Hassan] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari ['Amr bin Dinar] dari [Nafi' bin Jubair] dari [bapaknya] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda ketika dalam perjalanan, \"Siapa yang menjaga kita pada malam ini, agar kita tidak tertidur dari shalat Subuh?\" Bilal berkata, \"Aku\". Tak tahunya kemudian waktu sudah dekat matahari terbit, telinga mereka tertutup hingga mereka terbangun karena sengatan terik matahari. Lalu mereka bangun dan berwudhu, kemudian Bilal adzan. Beliau Shallallahu'alaihi wasallam lalu shalat dua rakaat dan para sahabat ikut shalat Fajar dua rakaat. Setelah itu mereka semua shalat Subuh."},"620":{"ar":"أَخْبَرَنَا أَبُو عَاصِمٍ قَالَ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا حَبِيبٌ عَنْ عَمْرِو بْنِ هَرِمٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَدْلَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ عَرَّسَ فَلَمْ يَسْتَيْقِظْ حَتَّى طَلَعَتْ الشَّمْسُ أَوْ بَعْضُهَا فَلَمْ يُصَلِّ حَتَّى ارْتَفَعَتْ الشَّمْسُ فَصَلَّى وَهِيَ صَلَاةُ الْوُسْطَى","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dia berkata; telah menceritakan kepada kami [Habban bin Hilal] telah menceritakan kepada kami [Habib] dari ['Amr bin Harim] dari [Jabir bin Zaid] dari [Ibnu 'Abbas] dia berkata; Pernah Rasulullah Shallallahu'alaihi wasallam berjalan semalam suntuk, kemudian beliau istirahat, dan beliau tidak bangun sampai matahari terbit atau muncul sebagian, beliau juga tidak shalat hingga matahari meninggi baru beliau melaksanakan shalat. Yaitu shalat subuh. "},"621":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ وَإِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَا حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ كَانَ يَقُولُ كَانَ الْمُسْلِمُونَ حِينَ قَدِمُوا الْمَدِينَةَ يَجْتَمِعُونَ فَيَتَحَيَّنُونَ الصَّلَاةَ وَلَيْسَ يُنَادِي بِهَا أَحَدٌ فَتَكَلَّمُوا يَوْمًا فِي ذَلِكَ فَقَالَ بَعْضُهُمْ اتَّخِذُوا نَاقُوسًا مِثْلَ نَاقُوسِ النَّصَارَى وَقَالَ بَعْضَهُمْ بَلْ قَرْنًا مِثْلَ قَرْنِ الْيَهُودِ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ أَوَلَا تَبْعَثُونَ رَجُلًا يُنَادِي بِالصَّلَاةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بِلَالُ قُمْ فَنَادِ بِالصَّلَاةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il] dan [Ibrahim bin Al-Hasan] mereka berdua berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Nafi'] dari ['Abdullah bin 'Umar] dia berkata, \"Ketika kaum muslim datang ke Madinah, mereka berkumpul lalu tiba waktu shalat dan tidak ada orang yang menyeru kepadanya. Ketika mereka berbincang-bincang tentang perkara tersebut, sebagian dari mereka berkata, 'Bunyikan loceng seperti locengnya orang Nasrani'. Sebagian lain berkata, 'Bunyikan terompet seperti terompetnya orang Yahudi '. Kemudian Umar Radliyallahu'anhu berkata, 'Mengapa kalian tidak menyuruh seseorang agar menyeru kepada shalat? ' Lantas Rasulullah Shallallahu'alaihi wasallam bersabda: \"Wahai Bilal! Bangunlah dan serukan untuk shalat'."},"622":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِلَالًا أَنْ يَشْفَعَ الْأَذَانَ وَأَنْ يُوتِرَ الْإِقَامَةَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami ['Abdul Wahhab] dari [Ayyub] dari [Abu Qilabah] dari [Anas] dia berkata; Rasulullah Shallallahu'alaihi wasallam pernah memerintahkan Bilal untuk menggenapkan adzan dan mengganjilkan iqamah.\""},"623":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي أَبُو جَعْفَرٍ عَنْ أَبِي الْمُثَنَّى عَنْ ابْنِ عُمَرَ قَالَكَانَ الْأَذَانُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثْنَى مَثْنَى وَالْإِقَامَةُ مَرَّةً مَرَّةً إِلَّا أَنَّكَ تَقُولُ قَدْ قَامَتْ الصَّلَاةُ قَدْ قَامَتْ الصَّلَاةُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepada kami [Abu Ja'far] dari [Abu Al-Mutsanna] dari [Ibnu 'Umar] dia berkata; \"Dahulu adzan pada zaman Rasulullah Shallallahu'alaihi wasallam dua kali-dua kali, sedangkan iqamah sekali-sekali, kecuali ucapan 'Qadqaamatish-shalah, qad qaamatish-shalah'.\""},"624":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ مُعَاذٍ قَالَ حَدَّثَنِي إِبْرَاهِيمُ وَهُوَ ابْنُ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ قَالَ حَدَّثَنِي أَبِي عَبْدُ الْعَزِيزِ وَجَدِّي عَبْدُ الْمَلِكِ عَنْ أَبِي مَحْذُورَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْعَدَهُ فَأَلْقَى عَلَيْهِ الْأَذَانَ حَرْفًا حَرْفًا قَالَ إِبْرَاهِيمُ هُوَ مِثْلُ أَذَانِنَا هَذَا قُلْتُ لَهُ أَعِدْ عَلَيَّ قَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ مَرَّتَيْنِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ مَرَّتَيْنِ ثُمَّ قَالَ بِصَوْتٍ دُونَ ذَلِكَ الصَّوْتِ يُسْمِعُ مَنْ حَوْلَهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ مَرَّتَيْنِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ مَرَّتَيْنِ حَيَّ عَلَى الصَّلَاةِ مَرَّتَيْنِ حَيَّ عَلَى الْفَلَاحِ مَرَّتَيْنِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah mengabarkan kepada kami [Bisyr bin Mu'adz] dia berkata; telah menceritakan kepada kami [Ibrahim bin 'Abdul 'Aziz bin 'Abdul Malik bin Abu Mahdzurah] dia berkata; bapakku ['Abdul 'Aziz] dan kakekku ['Abdul Malik] telah menceritakan kepadaku, dari [Abu Mahdzurah] bahwa Rasulullah Shallallahu'alaihi wasallam mendudukkannya kemudian menyampaikan Adzan kepadanya kalimat demi kalimat. Ibrahim berkata; \"Ini seperti adzan kita. Kemudian aku berkata; Ulangi kepadaku. kemudian beliau bersabda: Allahu Akbar Allahu Akbar, (Allah Maha Besar, Allah Maha Besar). Asyhadu An Laa llaaha Illallah-dua kali- (Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah Subhaanahu wa Ta'ala). Asyhadu Anna Muhammadar-Rasuulullah-dua kali-, (Aku bersaksi bahwa Muhammad adalah utusan Allah'). kemudian beliau mengucapkan suara yang tidak seperti tadi, yang bisa di dengar oleh orang-orang di sekitarnya, \" Asyhadu An laa Ilaaha Illallah -dua kali-, Asyhadu Anna Muhammadar Rasulullah-dua kali-, Hayya 'Alas-Shalaah-dua kali-, Hayya 'Alal Falaah-dua kali-, Allahu Akbar Allahu Akbar, Laa Ilaaha Illallah."},"625":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ هَمَّامِ بْنِ يَحْيَى عَنْ عَامِرِ بْنِ عَبْدِ الْوَاحِدِ حَدَّثَنَا مَكْحُولٌ عَنْ عَبْدِ اللَّهِ بْنِ مُحَيْرِيزٍ عَنْ أَبِي مَحْذُورَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَذَانُ تِسْعَ عَشْرَةَ كَلِمَةً وَالْإِقَامَةُ سَبْعَ عَشْرَةَ كَلِمَةًثُمَّ عَدَّهَا أَبُو مَحْذُورَةَ تِسْعَ عَشْرَةَ كَلِمَةً وَسَبْعَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Hammam bin Yahya] dari ['Amir bin 'Abdul Wahid] telah menceritakan kepada kami [Makhul] dari ['Abdullah bin Muhairiz] dari [Abu Mahdzurah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: Adzan itu terdiri dari sembilan belas kalimat. Dan Iqamah terdiri dari tujuh belas kalimat. Kemudian Abu Mahdzurah menghitungnya sembilan belas kalimat dan tujuh belas kalimat."},"626":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ عَامِرٍ الْأَحْوَلِ عَنْ مَكْحُولٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَيْرِيزٍ عَنْ أَبِي مَحْذُورَةَ قَالَعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَذَانَ فَقَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ ثُمَّ يَعُودُ فَيَقُولُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Mu'adz bin Hisyam] dia berkata, telah menceritakan kepadaku [bapakku] dari ['Amir 'Al Ahwal] dari [Makhul] dari ['Abdullah bin Muhairiz] dari [Abu Mahdzurah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam mengajarkan adzan kepadaku, beliau bersabda, \"ALLAHU AKBAR ALLAAHU AKBAR, ALLAHU AKBAR ALLAHU AKBAR (Allah Maha Besar, Allah Maha Besar, Allah Maha Besar, Allah Maha Besar). ASYHADU AN LAA ILAAHA ILLALLAH, ASYHADU AN LAA ILAAHA ILLALLAH, (Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah). ASYHADU ANNA MUHAMMADAR RASUULULLAH (Aku bersaksi bahwa Muhammad adalah utusan Allah). Kemudian beliau mengulangi dan berkata, ASYHADU AN LAA ILAAHA ILLALLAAH, ASYHADU AN LAA ILAAHA ILLALLAAH, (Aku bersaksi bahwa tidak ada tuhan yang berhak disembahj kecuali Allah. Aku bersaksi bahwa tidak ada tuhan yang berhak disembahj kecuali Allah). ASYHADU ANNA MUHAMMADAR RASUULULLAH, ASYHADU ANNA MUHAMMADAR RASUULULLAH (Aku juga bersaksi bahwa Muhammad adalah utusan Allah, aku juga bersaksi bahwa Muhammad adalah utusan Allah.) HAYYA 'ALASH SHALAAH, HAYYA 'ALASH SHALAAH (Mari mengerjakan shalat, mari mengerjakan shalat), HAYYA 'ALAL FALAAH, HAYYA 'ALAL FALAAH, (Mari mencapai kebahagiaan, mari mencapai kebahagiaan). ALLAAHU AKBAR ALLAAHU AKBAR (Allah Maha Besar, Allah Maha Besar). LAA ILAAHA ILLALLAAH (Tidak ada tuhan yang berhak disembah kecuali Allah) \"."},"627":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ وَيُوسُفُ بْنُ سَعِيدٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ أَنَّ عَبْدَ اللَّهِ بْنَ مُحَيْرِيزٍ أَخْبَرَهُ وَكَانَ يَتِيمًا فِي حِجْرِ أَبِي مَحْذُورَةَ حَتَّى جَهَّزَهُ إِلَى الشَّامِ قَالَ يَالَ لِأَبِي مَحْذُورَةَإِنِّي خَارِجٌ إِلَى الشَّامِ وَأَخْشَى أَنْ أُسْأَلَ عَنْ تَأْذِينِكَ فَأَخْبَرَنِي أَنَّ أَبَا مَحْذُورَةَ قَالَ لَهُ خَرَجْتُ فِي نَفَرٍ فَكُنَّا بِبَعْضِ طَرِيقِ حُنَيْنٍ مَقْفَلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ حُنَيْنٍ فَلَقِيَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ الطَّرِيقِ فَأَذَّنَ مُؤَذِّنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّلَاةِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْنَا صَوْتَ الْمُؤَذِّنِ وَنَحْنُ عَنْهُ مُتَنَكِّبُونَ فَظَلِلْنَا نَحْكِيهِ وَنَهْزَأُ بِهِ فَسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّوْتَ فَأَرْسَلَ إِلَيْنَا حَتَّى وَقَفْنَا بَيْنَ يَدَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّكُمْ الَّذِي سَمِعْتُ صَوْتَهُ قَدْ ارْتَفَعَ فَأَشَارَ الْقَوْمُ إِلَيَّ وَصَدَقُوا فَأَرْسَلَهُمْ كُلَّهُمْ وَحَبَسَنِي فَقَالَ قُمْ فَأَذِّنْ بِالصَّلَاةِ فَقُمْتُ فَأَلْقَى عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّأْذِينَ هُوَ بِنَفْسِهِ قَالَ قُلْ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ ثُمَّ قَالَ ارْجِعْ فَامْدُدْ صَوْتَكَ ثُمَّ قَالَ قُلْ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ ثُمَّ دَعَانِي حِينَ قَضَيْتُ التَّأْذِينَ فَأَعْطَانِي صُرَّةً فِيهَا شَيْءٌ مِنْ فِضَّةٍ فَقُلْتُ يَا رَسُولَ اللَّهِ مُرْنِي بِالتَّأْذِينِ بِمَكَّةَ فَقَالَ أَمَرْتُكَ بِهِ فَقَدِمْتُ عَلَى عَتَّابِ بْنِ أَسِيدٍ عَامِلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ فَأَذَّنْتُ مَعَهُ بِالصَّلَاةِ عَنْ أَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al-Hasan] dan [Yusuf bin Sa'id] -dan lafazh ini baginya- mereka berdua berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdul Malik bin Abu Mahdzurah] bahwasanya ['Abdullah bin Muhairiz] mengabarkan kepadanya -dia dulu anak yatim yang diasuh oleh Abu Mahdzurah hingga dia menyiapkannya pergi ke Syam- dia berkata, 'Aku pernah berkata kepada Abu Mahdzurah, 'Aku akan pergi ke Syam dan aku khawatir akan ditanya tentang permintaan izin kepadamu'.\" Lalu dia mengabarkan bahwa [Abu Mahdzurah] pernah berkata, 'Aku keluar bersama sebagian orang dan saat itu kami berada di jalan Hunain -jalan pulangnya Rasulullah Shallallahu'alaihi wasallam dari Hunain- kami berjumpa dengan Rasulullah Shallallahu'alaihi wasallam pada sebagian jalan. Lalu muadzin Rasulullah Shallallahu'alaihi wasallam mengumandangkan adzan untuk shalat di sisi beliau Shallallahu'alaihi wasalam. Kami mendengar suara muadzin dan kami berpaling darinya. Kami masih terus bercerita dan mengejeknya. Rasulullah Shallallahu'alaihi wasallam mendengar suara lalu mengirim seseorang kepada kami hingga kami berdiri di hadapan beliau Shallallahu'alaihi wasallam, lalu beliau Shallallahu'alaihi wasallam bersabda: 'Siapakah yang suaranya kudengar sangat keras? ' Orang-orang menunjuk kepadaku, dan mereka memang benar. Kemudian Rasulullah Shallallahu'alaihi wasallam menyuruh semua orang pergi sedangkan beliau menahanku, kemudian beliau Shallallahu'alaihi wasallam bersabda, 'Bangkit dan adzanlah untuk shalat'. Akupun bangun dan Rasulullah Shallallahu'alaihi wasallam sendiri yang menuntunku untuk adzan. Beliau Shallallahu'alaihi wasallam berkata, 'Katakanlah, \"ALLAAHU AKBAR ALLAAHU AKBAR, ALLAHU AKBAR ALLAHU AKBAR (Allah Maha Besar, Allah Maha Besar, Allah Maha Besar, Allah Maha Besar). ASYHADU AN LAA ILAAHA ILLALLAAH, ASYHADU AN LAA ILAAHA ILLALLAAH, (Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah) ASYHADU ANNA MUHAMMADAR RASUULULLAH, ASYHADU ANNA MUHAMMADAR RASUULULLAAH (Aku juga bersaksi bahwa Muhammad adalah utusan Allah, aku juga bersaksi bahwa Muhammad adalah utusan Allah). Kemudian Rasulullah Shallallahu'alaihi wasallam bersabda, \"Ulangi dan panjangkan suaramu\". Kemudian beliau Shallallahu'alaihi wasallam bersabda, 'Katakanlah, \"ASYHADU AN LAA ILAAHA ILLALLAH, ASYHADU AN LAA ILAAHA ILLALLAAH, (Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah). ASYHADU ANNA MUHAMMADAR RASUULULLAH, ASYHADU ANNA MUHAMMADUR RASUULULLAAH (Aku juga bersaksi bahwa Muhammad adalah utusan Allah, aku juga bersaksi bahwa Muhammad adalah utusan Allah). HAYYA 'ALASH SHALAAH, HAYYA 'ALASH SHALAAH (Mari mengerjakan shalat, mari mengerjakan shalat), HAYYA 'ALAL FALAAH, HAYYA 'ALAL FALAAH, (Mari mencapai kebahagiaan, mari mencapai kebahagiaan). ALLAHU AKBAR ALLAAHU AKBAR (Allah Maha Besar, Allah Maha Besar). LAA ILAAHA ILLALLAAH (Tidak ada tuhan yang berhak disembah kecuali Allah). Setelah adzan beliau Shallallahu'alaihi wasallam memanggilku dan memberikan sebuah kantong berisi perak, maka aku berkata, 'Wahai Rasulullah, perintahkan aku untuk adzan di Makkah. Beliau menjawab, 'Aku perintahkan kamu untuk itu'. Kemudian aku datang ke Attab bin Usaid -pegawai Rasulullah Shallallahu'alaihi wasallam di Makkah- lalu aku mengumandangkan adzan untuk shalat berjama'ah sesuai perintah Rasulullah Shallallahu'alaihi wasallam.\""},"628":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ عَنْ عُثْمَانَ بْنِ السَّائِبِ قَالَ أَخْبَرَنِي أَبِي وَأُمُّ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ عَنْ أَبِي مَحْذُورَةَ قَالَلَمَّا خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ حُنَيْنٍ خَرَجْتُ عَاشِرَ عَشْرَةٍ مِنْ أَهْلِ مَكَّةَ نَطْلُبُهُمْ فَسَمِعْنَاهُمْ يُؤَذِّنُونَ بِالصَّلَاةِ فَقُمْنَا نُؤَذِّنُ نَسْتَهْزِئُ بِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ سَمِعْتُ فِي هَؤُلَاءِ تَأْذِينَ إِنْسَانٍ حَسَنِ الصَّوْتِ فَأَرْسَلَ إِلَيْنَا فَأَذَّنَّا رَجُلٌ رَجُلٌ وَكُنْتُ آخِرَهُمْ فَقَالَ حِينَ أَذَّنْتُ تَعَالَ فَأَجْلَسَنِي بَيْنَ يَدَيْهِ فَمَسَحَ عَلَى نَاصِيَتِي وَبَرَّكَ عَلَيَّ ثَلَاثَ مَرَّاتٍ ثُمَّ قَالَ اذْهَبْ فَأَذِّنْ عِنْدَ الْبَيْتِ الْحَرَامِ قُلْتُ كَيْفَ يَا رَسُولَ اللَّهِ فَعَلَّمَنِي كَمَا تُؤَذِّنُونَ الْآنَ بِهَا اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ فِي الْأُولَى مِنْ الصُّبْحِ قَالَ وَعَلَّمَنِي الْإِقَامَةَ مَرَّتَيْنِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ حَيَّ عَلَى الْفَلَاحِ قَدْ قَامَتْ الصَّلَاةُ قَدْ قَامَتْ الصَّلَاةُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُقَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عُثْمَانُ هَذَا الْخَبَرَ كُلَّهُ عَنْ أَبِيهِ وَعَنْ أُمِّ عَبْدِ الْمَلِكِ بْنِ أَبِي مَحْذُورَةَ أَنَّهُمَا سَمِعَا ذَلِكَ مِنْ أَبِي مَحْذُورَةَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al-Hasan] dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dari ['Utsman bin As-Saib] dia berkata; [bapakku] dan [Ummu 'Abdul Malik bin Abu Mahdzurah] telah mengabarkan kepadaku dari [Abu Mahdzurah] dia berkata; \"Tatkala Rasulullah Shallallahu'alaihi wasallam keluar dari Hunain, aku orang yang kesepuluh dari sepuluh orang Quraisy yang pergi mencari mereka (Rasulullah Shallallahu'alaihi wasallam dan para sahabat). Kami mendengar mereka mengumandangkan adzan untuk shalat, maka kami mulai ikut adzan sebagai ejekan kepada mereka. Oleh karena itu Rasulullah Shallallahu'alaihi wasallam bersabda: 'Aku mendengar seseorang yang merdu suaranya di antara mereka mengumandangkan adzan'. Beliau Shallallahu'alaihi wasallam mengutus seseorang kepada kami, lalu kamipun mengumandangkan adzan satu persatu dan aku orang yang terakhir. Ketika mendengarku mengumandangkan adzan beliau Shallallahu'alaihi wasallam berkata, 'Kemari'. Beliau mempersilakanku duduk di depannya dan mengusap ujung rambutku, serta mendoakan keberkahan untukku -sampai tiga kali- kemudian berkata, 'Pergilah dan kumandangkan adzan di Masjidil Haram\". Aku berkata, 'Bagaimana caranya wahai Rasulullah Shallallahu'alaihiwasallam? ' Lalu beliau mengajariku sebagaimana yang kalian ucapkan saat adzan sekarang: \"ALLAAHU AKBAR ALLAAHU AKBAR, ALLAAHU AKBAR ALLAAHU AKBAR (Allah Maha Besar, Allah Maha Besar, Allah Maha Besar, Allah Maha Besar). ASYHADU AN LAA ILAAHA ILLALLAAH, ASYHADU AN LAA ILAAHA ILLALLAAH, (Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah) ASYHADU ANNA MUHAMMADAR RASUULULLAH, ASYHADU ANNA MUHAMMADAR RASUULULLAH (Aku juga bersaksi bahwa Muhammad adalah utusan Allah, aku juga bersaksi bahwa Muhammad adalah utusan Allah). ASYHADU AN LAA ILAAHA ILLALLAAH, ASYHADU AN LAA ILAAHA ILLALLAAH, (Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah) ASYHADU ANNA MUHAMMADAR RASUULULLAH, ASYHADU ANNA MUHAMMADAR RASUULULLAH (Aku juga bersaksi bahwa Muhammad adalah utusan Allah, aku juga bersaksi bahwa Muhammad adalah utusan Allah). HAYYA 'ALASH SHALAAH, HAYYA 'ALASH SHALAAH (Mari mengerjakan shalat, mari mengerjakan shalat), HAYYA 'ALAL FALAAH, HAYYA 'ALAL FALAAH, (Mari mencapai kebahagiaan, mari mencapai kebahagiaan), ASH SHALAATU KHAIRUMMINANNAUM (Shalat itu lebih baik daripada tidur) -pada adzan pertama saat shalat Subuh-.\" dia berkata; \"Beliau mengajari iqamah dua kali: ALLAAHU AKBAR ALLAAHU AKBAR (Allah Maha Besar, Allah Maha Besar) ASYHADU AN LAA ILAAHA ILLALLAAH, ASYHADU AN LAA ILAAHA ILLALLAAH, (Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah). ASYHADU ANNA MUHAMMADAR RASUULULLAH, ASYHADU ANNA MUHAMMADAR RASUULULLAH (Aku juga bersaksi bahwa Muhammad adalah utusan Allah, aku juga bersaksi bahwa Muhammad adalah utusan Allah). HAYYA 'ALASH SHALAAH, HAYYA 'ALASH SHALAAH (Mari mengerjakan shalat, mari mengerjakan shalat), HAYYA 'ALAL FALAAH, HAYYA 'ALAL FALAAH, (Mari mencapai kebahagiaan, mari mencapai kebahagiaan). QAD QAAMATISH SHALAAH, QAD QAAMATISH SHALAAH (Shalat telah siap ditegakkan, shalat telah siap ditegakkan). ALLAAHU AKBAR ALLAAHU AKBAR (Allah Maha Besar Allah Maha Besar), LAA ILAAHA ILLALLAAH, (Tidak ada tuhan yang berhak disembah kecuali Allah).\""},"629":{"ar":"أَخْبَرَنَا حَاجِبُ بْنُ سُلَيْمَانَ عَنْ وَكِيعٍ عَنْ سُفْيَانَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَابْنُ عَمٍّ لِي وَقَالَ مَرَّةً أُخْرَى أَنَا وَصَاحِبٌ لِي فَقَالَ إِذَا سَافَرْتُمَا فَأَذِّنَا وَأَقِيمَا وَلْيَؤُمَّكُمَا أَكْبَرُكُمَا","id":"Telah mengabarkan kepada kami [Hajib bin Sulaiman] dari [Waki'] dari [Sufyan] dari [Khalid Al-Hadzdza'] dari [Abu Qilabah] dari [Malik bin Al-Huwairits] dia berkata; \"Aku dan anak pamanku mendatangi Nabi Shallallahu'alaihi wasallam. -dalam kesempatan lain dia berkata, \"Aku dan kawanku datang kepada Nabi Shallallahu'alaihi wasallam\"- lalu beliau bersabda: \"Jika kalian berdua bepergian, maka kumandangkanlah adzan dan iqamah, dan hendaklah yang paling besar (tua) menjadi imam'.\" "},"630":{"ar":"أَخْبَرَنِي زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ شَبَبَةٌ مُتَقَارِبُونَ فَأَقَمْنَا عِنْدَهُ عِشْرِينَ لَي��لَةً وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِيمًا رَفِيقًا فَظَنَّ أَنَّا قَدْ اشْتَقْنَا إِلَى أَهْلِنَا فَسَأَلَنَا عَمَّنْ تَرَكْنَاهُ مِنْ أَهْلِنَا فَأَخْبَرْنَاهُ فَقَالَ ارْجِعُوا إِلَى أَهْلِيكُمْ فَأَقِيمُوا عِنْدَهُمْ وَعَلِّمُوهُمْ وَمُرُوهُمْ إِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ وَلْيَؤُمَّكُمْ أَكْبَرُكُمْ","id":"Telah mengabarkan kepadaku [Ziyad bin Ayyub] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Ayyub] dari [Abu Qibalah] dari [Malik bin Al-Huwairits] dia berkata; \"Kami datang kepada Rasulullah Shallallahu'alaihi wasallam dan kami pemuda yang sebaya. Kami tinggal bersama Rasulullah Shallallahu'alaihi wasallam selama dua puluh malam. Rasulullah Shallallahu'alaihi wasallam adalah seorang yang sangat penyayang dan sangat lembut. Beliau mengira kalau kami merindukan keluarga kami, maka beliau bertanya tentang keluarga kami yang ditinggalkan. Kami pun memberitahukannya, lalu beliau Shallallahu'alaihi wasallam bersabda, \"Pulanglah ke keluarga kalian. Tinggallah bersama mereka dan ajari mereka serta perintahkan mereka untuk shalat. Jika telah datang waktu shalat, maka hendaklah salah seorang dari kalian mengumandangkan adzan, dan yang paling tua menjadi imam'.\""},"631":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَمْرِو بْنِ سَلَمَةَفَقَالَ لِي أَبُو قِلَابَةَ هُوَ حَيٌّ أَفَلَا تَلْقَاهُ قَالَ أَيُّوبُ فَلَقِيتُهُ فَسَأَلْتُهُ فَقَالَ لَمَّا كَانَ وَقْعَةُ الْفَتْحِ بَادَرَ كُلُّ قَوْمٍ بِإِسْلَامِهِمْ فَذَهَبَ أَبِي بِإِسْلَامِ أَهْلِ حِوَائِنَا فَلَمَّا قَدِمَ اسْتَقْبَلْنَاهُ فَقَالَ جِئْتُكُمْ وَاللَّهِ مِنْ عِنْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَقًّا فَقَالَ صَلُّوا صَلَاةَ كَذَا فِي حِينِ كَذَا وَصَلَاةَ كَذَا فِي حِينِ كَذَا فَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ وَلْيَؤُمَّكُمْ أَكْثَرُكُمْ قُرْآنًا","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Sulaiman bin Harb] dia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari ['Amr bin Salamah]. Abu Qilabah berkata kepada Ayyub dia -Amr bin Salamah- masih hidup, apakah kamu tidak menemuinya? Ayyub berkata; 'maka aku menemuinya, dan bertanya kepadanya. Lalu dia berkata,; \"Setelah penakluklan (Fathu) Makkah, setiap kabilah bergegas memeluk Islam. [Ayahku] mengajak kaumnya masuk Islam. Ketika dia datang kami menyambutnya, dia berkata, 'Demi Allah, aku datang dari sisi Rasulullah Shallallahu'alaihi wasallam membawa kebenaran kepada kalian, beliau bersabda, \"Shalatlah kalian begini pada waktu tertentu dan shalat tertentu pada waktu tertentu pula. Bila telah tiba waktu shalat, maka hendaklah salah seorang dari kalian adzan, lalu yang paling banyak hapalan Al Qur'annya menjadi imam bagi kalian.\""},"632":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى يُنَادِيَ ابْنُ أُمِّ مَكْتُومٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari ['Abdullah bin Dinar] dari [Ibnu 'Umar] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bilal mengumandangkan adzan pada malam hari, maka makan dan minumlah, hingga Ibnu Ummi Maktum mengumandangkan adzan.\""},"633":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ فَكُلُوا وَاشْرَبُوا حَتَّى تَسْمَعُوا تَأْذِينَ ابْنِ أُمِّ مَكْتُومٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al-Laits] dari [Ibnu Syihab] dari [Salim] dari [Bapaknya] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bilal mengumandangkan adzan pada malam hari, maka makan dan minumlah, hingga kalian mendengar adzan Ibnu Ummi Maktum.\""},"634":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حَفْصٌ عَنْ عُبَيْدِ اللَّهِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَذَّنَ بِلَالٌ فَكُلُوا وَاشْرَبُوا حَتَّى يُؤَذِّنَ ابْنُ أُمِّ مَكْتُومٍقَالَتْ وَلَمْ يَكُنْ بَيْنَهُمَا إِلَّا أَنْ يَنْزِلَ هَذَا وَيَصْعَدَ هَذَا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Hafsh] dari ['Ubaidullah] dari [Al-Qasim] dari ['Aisyah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika Bilal mengumandangkan adzan, maka makan dan minumlah hingga Ibnu Ummi Maktum mengumandangkan adzan.\" Aisyah berkata; \"Diantara keduanya selalu bergantian. Bila satunya turun maka yang lain naik. dan sebaliknya.\""},"635":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ هُشَيْمٍ قَالَ أَنْبَأَنَا مَنْصُورٌ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَمَّتِهِ أُنَيْسَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَذَّنَ ابْنُ أُمِّ مَكْتُومٍ فَكُلُوا وَاشْرَبُوا وَإِذَا أَذَّنَ بِلَالٌ فَلَا تَأْكُلُوا وَلَا تَشْرَبُوا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari [Husyaim] dia berkata; telah memberitakan kepada kami [Manshur] dari [Khubaib bin 'Abdurrahman] dari bibinya [Unaisah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika Ibnu Ummi Maktum mengumandangkan adzan, maka makan dan minumlah. lika Bilal mengumandangkan adzan, maka jangan makan dan minum'.\""},"636":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ أَبِي عُثْمَانَ عَنْ ابْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بِلَالًا يُؤَذِّنُ بِلَيْلٍ لِيُوقِظَ نَائِمَكُمْ وَلِيَرْجِعَ قَائِمَكُمْ وَلَيْسَ أَنْ يَقُولَ هَكَذَا يَعْنِي فِي الصُّبْحِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Bapaknya] dari [Abu 'Utsman] dari [Ibnu Mas'ud] dari Nabi Shallallahu'alaihi wasallam beliau Shallallahu'alaihi wasallam bersabda: \"Bilal adzan pada malam hari untuk membangunkan orang yang tidur dan agar orang yang shalat Qiyamullail kembali (istirahat) dan bukan untuk dikatakan begini -yakni panggilan pada waktu Subuh-.\""},"637":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍأَنَّ سَائِلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ وَقْتِ الصُّبْحِ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالًا فَأَذَّنَ حِينَ طَلَعَ الْفَجْرُ فَلَمَّا كَانَ مِنْ الْغَدِ أَخَّرَ الْفَجْرَ حَتَّى أَسْفَرَ ثُمَّ أَمَرَهُ فَأَقَامَ فَصَلَّى ثُمَّ قَالَ هَذَا وَقْتُ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yazid] dia berkata; telah menceritakan kepada kami [Humaid] dari [Anas], Ada seorang laki-laki yang bertanya kepada Rasulullah Shallallahu'alaihi wasallam tentang waktu Subuh. Maka Rasulullah Shallallahu'alaihi wasallam menyuruh Bilal untuk adzan ketika terbit Fajar. Besoknya beliau Shallallahu'alaihi wasallam mengakhirkan shalat Subuh sampai agak terang, dan menyuruh Bilal untuk adzan lalu iqamah lantas shalat. Kemudian beliau Shallallahu'alaihi wasallam bersabda, \"Begitu waktu shalat Subuh.\""},"638":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ بِلَالٌ فَأَذَّنَ فَجَعَلَ يَقُولُ فِي أَذَانِهِ هَكَذَا يَنْحَرِفُ يَمِينًا وَشِمَالًا","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Aun bin Abu Juhaifah] dari [Bapaknya], dia berkata; \"Aku datang kepada Rasulullah Shallallahu'alaihi wasallam, lalu Bilal keluar dan adzan. Dia (Bilal) memiringkan badannya ke kanan dan ke kiri.\""},"639":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ الْأَنْصَارِيُّ الْمَازِنِيُّ عَنْ أَبِيهِ أَنَّهُ أَخْبَرَهُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ قَالَ لَهُإِنِّي أَرَاكَ تُحِبُّ الْغَنَمَ وَالْبَادِيَةَ فَإِذَا كُنْتَ فِي غَنَمِكَ أَوْ بَادِيَتِكَ فَأَذَّنْتَ بِالصَّلَاةِ فَارْفَعْ صَوْتَكَ فَإِنَّهُ لَا يَسْمَعُ مَدَى صَوْتِ الْمُؤَذِّنِ جِنٌّ وَلَا إِنْسٌ وَلَا شَيْءٌ إِلَّا شَهِدَ لَهُ يَوْمَ الْقِيَامَةِ قَالَ أَبُو سَعِيدٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnul Qasim] dari [Malik] dia berkata; telah menceritakan kepadaku ['Abdurrahman bin 'Abdullah bin 'Abdurrahman bin Abu Sha'sha' ah Al-Anshari Al-Mazini] dari [Bapaknya] bahwasanya dia mengabarkan kepadanya bahwasanya [Abu Sa'id Al-Khudri] berkata kepadanya; \"Aku melihatmu suka kepada kambing dan perkampungan. Jika kamu sedang berada di rombongan kambing atau perkampunganmu, maka kumandangkan adzan untuk shalat dan keraskan suaramu. Sesungguhnya tidaklah jangkauan suara adzan tersebut bisa didengar oleh jin, manusia, dan sesuatu apapun melainkan (mereka) akan menjadi saksi baginya pada hari Kiamat.\"Abu Sa'id Al Khudri berkata; \"Aku mendengarnya dari Rasululullah Shallallahu'alaihi wasallam.\""},"640":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُوسَى بْنِ أَبِي عُثْمَانَ عَنْ أَبِي يَحْيَى عَنْ أَبِي هُرَيْرَةَسَمِعَهُ مِنْ فَمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُؤَذِّنُ يُغْفَرُ لَهُ بِمَدِّ صَوْتِهِ وَيَشْهَدُ لَهُ كُلُّ رَطْبٍ وَيَابِسٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dan [Muhammad bin 'Abdul A'la] mereka berdua berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Musa bin Abu 'Utsman] dari [Abu Yahya] dari [Abu Hurairah] dia mendengar dari lisan Rasulullah Shallallahu'alaihi wasallam bersabda,: \"Muadzin akan diampuni dosanya sejauh suara adzannya dan semua (makhluk) yang basah atau yang kering akan menjadi saksi baginya.\""},"641":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي إِسْحَقَ الْكُوفِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى الصَّفِّ الْمُقَدَّمِ وَالْمُؤَذِّنُ يُغْفَرُ لَهُ بِمَدِّ صَوْتِهِ وَيُصَدِّقُهُ مَنْ سَمِعَهُ مِنْ رَطْبٍ وَيَابِسٍ وَلَهُ مِثْلُ أَجْرِ مَنْ صَلَّى مَعَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al-Mutsanna] dia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; [Bapakku] telah menceritakan kepadaku dari [Qatadah] dari [Abu Ishaq Al-Kufi] dari [Al-Barra' bin 'Azib] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Allah dan para malaikat mendoakan (orang-orang) yang berada di shaf terdepan. Seorang muadzin akan diampuni sepanjang suaranya dan dibenarkan oleh yang mendengarnya dari semua yang basah dan kering, dan dia mendapat pahala seperti pahala orang yang ikut shalat bersamanya.\""},"642":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ أَبِي جَعْفَرٍ عَنْ أَبِي سَلْمَانَ عَنْ أَبِي مَحْذُورَةَ قَالَكُنْتُ أُؤَذِّنُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكُنْتُ أَقُولُ فِي أَذَانِ الْفَجْرِ الْأَوَّلِ حَيَّ عَلَى الْفَلَاحِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ الصَّلَاةُ خَيْرٌ مِنْ النَّوْمِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُأَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى وَعَبْدُ الرَّحْمَنِ قَالَا حَدَّثَنَا سُفْيَانُ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ أَبُو عَبْد الرَّحْمَنِ وَلَيْسَ بِأَبِي جَعْفَرٍ الْفَرَّاءِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Sufyan] dari [Abu Ja'far] dari [Abu Salman] dari [Abu Mahdzurah] dia berkata; \"Aku pernah adzan untuk Rasulullah Shallallahu'alaihi wasallam dan aku mengucapkan (kalimat) pada adzan Fajar pertama: HAYYA 'ALAL FALAAH (mari menggapai kebahagiaan) ASH SHALAATU KHAIRUM MINANNAUM (shalat lebih baik dari pada tidur), ASHSHALATU KHAIRUM MINANNAUM (shalat lebih baik dari pada tidur). ALLAAHU AKBAR (Allah Maha Besar), ALLAAHU AKBAR (Allah Maha Besar), LAA ILAAHA ILLALLAAH (Tidak ada Tuhan yang berhak disembah selain Allah).\" Telah mengkabarkan kepada kami [Amr bin Ali] dia berkata; Telah menceritkan kepada kami [Yahya] dan [Abdurrahman] mereka berkata; Telah menceritakan kepada kami [Sufyan] dengan sanad yang serupa. Abu Abdurrahman berkata; \"Tapi bukan dari Abu Ja'far Al Farra.\""},"643":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْدَانَ بْنِ عِيسَى قَالَ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ بِلَالٍ قَالَآخِرُ الْأَذَانِ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'dan bin 'Isa] dia berkata; telah menceritakan kepada kami [Al-Hasan bin A'yan] dia berkata; telah menceritakan kepada kami [Zuhair] dia berkata; telah menceritakan kepada kami [Al-A'masy] dari [Ibrahim] dari [Al-Aswad] dari [Bilal] dia berkata; \"Lafazh adzan yang terakir adalah: ALLAAHU AKBAR, ALLAAHU AKBAR (Allah Maha Besar. Allah Maha Besar), LAA ILAAHA ILLALLAAH (Tidak ada tuhan (yang berhak disembah kecuali Allah).\""},"644":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَكَانَ آخِرُ أَذَانِ بِلَالٍ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ لَا إِلَهَ إِلَّا اللَّهُأَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Suwaid] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al-Aswad] dia berkata; \"Lafazh adzan yang terakir adalah: ALLAAHU AKBAR, ALLAAHU AKBAR (Allah Maha Besar. Allah Maha Besar), LAA ILAAHA ILLALLAAH (Tidak ada tuhan (yang berhak disembah kecuali Allah).\" Telah mengabarkan kepada kami [Suwaid] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Sufyan] dari [Al-A'masy] dari [Ibrahim] dari [Al-Aswad] yang semisal itu."},"645":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ بْنِ أَبِي إِسْحَقَ عَنْ مُحَارِبِ بْنِ دِثَارٍ قَالَ حَدَّثَنِي الْأَسْوَدُ بْنُ يَزِيدَ عَنْ أَبِي مَحْذُورَةَأَنَّ آخِرَ الْأَذَانِ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah mengabarkan kepada kami [Suwaid] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Yunus bin Abu Ishaq] dari [Muharib bin Ditsar] dia berkata; telah menceritakan kepadaku [Al-Aswad bin Yazid] dari [Abu Mahdzurah], \"Sesungguhnya lafazh adzan yang terakir adalah: LAA ILAAHA ILLALLAAH (Tidak ada Tuhan yang berhak disembah kecuali Allah).\""},"646":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَمْرِو بْنِ أَوْسٍ يَقُولُ أَنْبَأَنَا رَجُلٌ مِنْ ثَقِيفٍأَنَّهُ سَمِعَ مُنَادِيَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي فِي لَيْلَةٍ مَطِيرَةٍ فِي السَّفَرِ يَقُولُ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ صَلُّوا فِي رِحَالِكُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr bin Dinar] dari ['Amr bin Aus] dia berkata; telah memberitakan kepada kami [seorang laki-laki] dari Tsaqif bahwasanya dia mendengar muadzin Rasulullah Shallallahu'alaihi wasallam -pada malam turun hujan dalam suatu perjalanan- berkata, \"HAYYA 'ALASH-SHALAAH (Mari menuju shalat), HAYYA 'ALASH-SHALAAH (Mari menggapai kebahagiaan). SHALLU FII RIHAALIKUM (Shalatlah kalian di tempat-tempat kalian).\""},"647":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَأَذَّنَ بِالصَّلَاةِ فِي لَيْلَةٍ ذَاتِ بَرْدٍ وَرِيحٍ فَقَالَ أَلَا صَلُّوا فِي الرِّحَالِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ الْمُؤَذِّنَ إِذَا كَانَتْ لَيْلَةٌ بَارِدَةٌ ذَاتُ مَطَرٍ يَقُولُ أَلَا صَلُّوا فِي الرِّحَالِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] bahwasanya [Ibnu 'Umar] pernah adzan untuk shalat pada malam yang sangat dingin dan berangin, dia berkata, \"Hendaklah kalian shalat di rumah. Dulu bila malam sangat dingin dan turun hujan, maka Rasulullah Shallallahu'alaihi wasallam menyuruh muadzin untuk mengucapkan, Shallu fii Rihaalikum 'Hendaklah kalian shalat di rumah'.\""},"648":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ هَارُونَ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ قَالَ أَنْبَأَنَا جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَسَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَتَى عَرَفَةَ فَوَجَدَ الْقُبَّةَ قَدْ ضُرِبَتْ لَهُ بِنَمِرَةَ فَنَزَلَ بِهَا حَتَّى إِذَا زَاغَتْ الشَّمْسُ أَمَرَ بِالْقَصْوَاءِ فَرُحِّلَتْ لَهُ حَتَّى إِذَا انْتَهَى إِلَى بَطْنِ الْوَادِي خَطَبَ النَّاسَ ثُمَّ أَذَّنَ بِلَالٌ ثُمَّ أَقَامَ فَصَلَّى الظُّهْرَ ثُمَّ أَقَامَ فَصَلَّى الْعَصْرَ وَلَمْ يُصَلِّ بَيْنَهُمَا شَيْئًا","id":"Telah mengabarkan kepada kami [Ibrahim bin Harun] dia berkata; telah menceritakan kepada kami [Hatim bin Isma'il] dia berkata; telah memberitakan kepada kami [Ja'far bin Muhammad] dari [bapaknya] bahwasanya [Jabir bin 'Abdullah] berkata; \"Rasulullah Shallallahu'alaihi wasallam berjalan hingga ke Arafah, dan beliau mendapati kemah telah didirikan untuknya di Namirah, maka beliau singgah sampai saatnya matahari terbenam. Lantas beliau mempersiapkan untanya untuk segera berangkat. Sesampainya di Bathn Al Wadi beliau berkhutbah di hadapan manusia, lalu Bilal mengumandangkan adzan dan melakukan iqamah. lalu shalat Zhuhur, kemudian melakukan iqamah lagi dan mengerjakan shalat Ashar, dan beliau tidak mengerjakan shalat apapun diantara keduanva.\" "},"649":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ هَارُونَ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَدَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْتَهَى إِلَى الْمُزْدَلِفَةِ فَصَلَّى بِهَا الْمَغْرِبَ وَالْعِشَاءَ بِأَذَانٍ وَإِقَامَتَيْنِ وَلَمْ يُصَلِّ بَيْنَهُمَا شَيْئًا","id":"Telah mengabarkan kepadaku [Ibrahim bin Harun] dia berkata; telah menceritakan kepada kami [Hatim bin Isma'il] dia berkata; telah menceritakan kepada kami [Ja'far bin Muhammad] dari [bapaknya] bahwasanya [Jabir bin 'Abdullah] berkata; \"Rasulullah Shallallahu'alaihi wasallam berangkat hingga ke Muzdalifah, lalu shalat Maghrib dan Isya' dengan satu kali adzan dan dua iqamah tanpa ada shalat apapun di antara keduanya.\" "},"650":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا مَعَهُ بِجَمْعٍ فَأَذَّنَ ثُمَّ أَقَامَ فَصَلَّى بِنَا الْمَغْرِبَ ثُمَّ قَالَ الصَّلَاةَ فَصَلَّى بِنَا الْعِشَاءَ رَكْعَتَيْنِ فَقُلْتُ مَا هَذِهِ الصَّلَاةُ قَالَ هَكَذَا صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَل��َى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْمَكَانِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Syarik] dari [Salamah bin Kuhail] dari [Sa'id bin Jubair] dari [Ibnu 'Umar] dia berkata; \"Kami bersama Nabi Shallallahu'alaihi wasallam di Muzdalifah, kemudian beliau mengumandangkan adzan lalu iqamah dan shalat Maghrib bersama kami, lalu beliau berkata, 'Shalat'. Kemudian beliaupun shalat Isya' dua rakaat bersama kami.\" Aku bertanya kepada Ibnu Umar, \"Shalat apa ini?\" dia menjawab \"Beginilah dahulu kami shalat bersama Rasulullah Shallallahu'alaihi wasallam, di tempat ini."},"651":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ وَسَلَمَةُ بْنُ كُهَيْلٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍأَنَّهُ صَلَّى الْمَغْرِبَ وَالْعِشَاءَ بِجَمْعٍ بِإِقَامَةٍ وَاحِدَةٍ ثُمَّ حَدَّثَ عَنْ ابْنِ عُمَرَ أَنَّهُ صَنَعَ مِثْلَ ذَلِكَ وَحَدَّثَ ابْنُ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al-Mutsanna] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al-Hakam] dan [Salamah bin Kuhail] dari [Sa'id bin Jubair] bahwasanya dia Shalat Maghrib dan Isya di Muzdalifah dengan satu iqamah. Kemudian dia berkata; dari [Ibnu Umar] bahwa dia mengerjakan seperti itu juga. Dan Ibnu Umar berkata; Bahwa Rasulullah Shallallahu'alaihi wasallam juga melakukan seperti itu."},"652":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ أَبِي خَالِدٍ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَأَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَمْعٍ بِإِقَامَةٍ وَاحِدَةٍ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dia berkata; telah menceritakan kepadaku [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu 'Umar] bahwa dia shalat bersama Rasulullah Shallallahu'alaihi wasallam di Muzdalifah dengan satu Iqamah."},"653":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ وَكِيعٍ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ بَيْنَهُمَا بِالْمُزْدَلِفَةِ صَلَّى كُلَّ وَاحِدَةٍ مِنْهُمَا بِإِقَامَةٍ وَلَمْ يَتَطَوَّعْ قَبْلَ وَاحِدَةٍ مِنْهُمَا وَلَا بَعْدُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dari [Waki'] dia berkata; telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Az-Zuhri] dari [Salim] dari [Bapaknya] bahwa Rasulullah Shallallahu'alaihi wasallam menjama' antara dua shalat di Muzdalifah, beliau mengerjakan setiap shalat dengan iqamah tanpa ada shalat sunah baik sebelum maupun sesudahnya."},"654":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ قَالَشَغَلَنَا الْمُشْرِكُونَ يَوْمَ الْخَنْدَقِ عَنْ صَلَاةِ الظُّهْرِ حَتَّى غَرَبَتْ الشَّمْسُ وَذَلِكَ قَبْلَ أَنْ يَنْزِلَ فِي الْقِتَالِ مَا نَزَلَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَكَفَى اللَّهُ الْمُؤْمِنِينَ الْقِتَالَ }فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَالًا فَأَقَامَ لِصَلَاةِ الظُّهْرِ فَصَلَّاهَا كَمَا كَانَ يُصَلِّيهَا لِوَقْتِهَا ثُمَّ أَقَامَ لِلْعَصْرِ فَصَلَّاهَا كَمَا كَانَ يُصَلِّيهَا فِي وَقْتِهَا ثُمَّ أَذَّنَ لِلْمَغْرِبِ فَصَلَّاهَا كَمَا كَانَ يُصَلِّيهَا فِي وَقْتِهَا","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Ibnu Abu Dzi'b] dia berkata; telah menceritakan kepada kami [Sa'id bin Abu Sa'id] dari ['Abdurrahman bin Abu Sa'id] dari [Bapaknya] dia berkata; \"Orang-orang musyrik menyibukkan kami dari shalat Zhuhur saat perang Khandaq hingga matahari terbenam, kejadian ini sebelum turunnya ayat tentang perang, maka Allah Azza wa Jalla menurunkan firman-Nya, 'Dan Allah menghindarkan orang-orang mukmin dari peperangan' (Al Ahzab: 26). Lalu Rasulullah Shallallahu'alaihi wasallam memerintahkan Bilal mengumandangkan iqamah untuk shalat Zhuhur, lantas beliau shalat Zhuhur sebagaimana beliau shalat pada waktunya. Kemudian iqamah untuk shalat Ashar dan beliau mengerjakan shalat Ashar sebagaimana beliau mengerjakan shalat Ashar pada waktunya. Setelah itu adzan Maghrib lalu shalat Maghrib sebagaimana shalat Maghrib pada waktunya.\""},"655":{"ar":"أَخْبَرَنَا هَنَّادٌ عَنْ هُشَيْمٍ عَنْ أَبِي الزُّبَيْرِ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ أَبِي عُبَيْدَةَ قَالَ قَالَ عَبْدُ اللَّهِإِنَّ الْمُشْرِكِينَ شَغَلُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَرْبَعِ صَلَوَاتٍ يَوْمَ الْخَنْدَقِ فَأَمَرَ بِلَالًا فَأَذَّنَ ثُمَّ أَقَامَ فَصَلَّى الظُّهْرَ ثُمَّ أَقَامَ فَصَلَّى الْعَصْرَ ثُمَّ أَقَامَ فَصَلَّى الْمَغْرِبَ ثُمَّ أَقَامَ فَصَلَّى الْعِشَاءَ","id":"Telah mengabarkan kepada kami [Hannad] dari [Husyaim] dari [Abu Az Zubair] dari [Nafi' bin Jubair] dari [Abu \"Ubaidah] dia berkata; ['Abdullah] berkata; \"Orang-orang musyrik telah menyibukkan Nabi Shallallahu'alaihi wasallam dari empat waktu shalat saat perang Khandaq. Beliau menyuruh Bilal adzan dan melakukan iqamah, lantas beliau shalat Zhuhur. Kemudian melaksanakan iqamah lagi dan beliau segera shalat Ashar. Kemudian iqamah lagi, lalu beliau shalat Maghrib, dan terakhir ia melakukan iqamah lagi kemudian shalat Isya'.\""},"656":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ قَالَ حَدَّثَنَا هِشَامٌ أَنَّ أَبَا الزُّبَيْرِ الْمَكِّيَّ حَدَّثَهُمْ عَنْ نَافِعِ بْنِ جُبَيْرٍ أَنَّ أَبَا عُبَيْدَةَ بْنَ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ حَدَّثَهُمْ أَنَّ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ قَالَكُنَّا فِي غَزْوَةٍ فَحَبَسَنَا الْمُشْرِكُونَ عَنْ صَلَاةِ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ فَلَمَّا انْصَرَفَ الْمُشْرِكُونَ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنَادِيًا فَأَقَامَ لِصَلَاةِ الظُّهْرِ فَصَلَّيْنَا وَأَقَامَ لِصَلَاةِ الْعَصْرِ فَصَلَّيْنَا وَأَقَامَ لِصَلَاةِ الْمَغْرِبِ فَصَلَّيْنَا وَأَقَامَ لِصَلَاةِ الْعِشَاءِ فَصَلَّيْنَا ثُمَّ طَافَ عَلَيْنَا فَقَالَ مَا عَلَى الْأَرْضِ عِصَابَةٌ يَذْكُرُونَ اللَّهَ عَزَّ وَجَلَّ غَيْرُكُمْ","id":"Telah mengabarkan kepada kami [Al-Qasim bin Zakaria bin Dinar] dia berkata; telah menceritakan kepada kami [Husain bin 'Ali] dari [Zaidah] dia berkata; telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dia berkata; telah menceritakan kepada kami [Hisyam] bahwasanya [Abu Az Zubair Al Makki] menceritakan kepada mereka dari [Nafi' bin Jubair] bahwasanya [Abu 'Ubaidah bin 'Abdullah bin Mas'ud] menceritakan kepada mereka bahwasanya ['Abdullah bin Mas'ud] berkata; kami dalam suatu peperangan, sehingga orang-orang Musyrik menghalangi kami dari melaksanakan Shalat zhuhur, Ashar, Maghrib, dan Isya. Tatkala orang-orang Musyrik telah pergi, Rasulullah Shallallahu'alaihi wasallam menyuruh Mu'adzin untuk adzan dan melakukan iqamah untuk shalat Zhuhur, lalu kami shalat. Kemudian melaksanakan iqamah lagi untuk shalat Ashar, lalu kami shalat Ashar. Kemudian iqamah lagi untuk shalat Maghrib, lalu kami shalat Maghrib dan terakhir dia melakukan iqamah lagi untuk shalat Isya, dan kamipun shalat Isya'.\" Kemudian Beliau Shallallahu'alaihi wasallam berkeliling diantara kami dan bersabda: Di muka bumi ini tidak ada sekelompok manusia yang mengingat Allah Azza wa Jalla selain kalian."},"657":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّ سُوَيْدَ بْنَ قَيْسٍ حَدَّثَهُ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمًا فَسَلَّمَ وَقَدْ بَقِيَتْ مِنْ الصَّلَاةِ رَكْعَةٌ فَأَدْرَكَهُ رَجُلٌ فَقَالَ نَسِيتَ مِنْ الصَّلَاةِ رَكْعَةً فَدَخَلَ الْمَسْجِدَ وَأَمَرَ بِلَالًا فَأَقَامَ الصَّلَاةَ فَصَلَّى لِلنَّاسِ رَكْعَةًفَأَخْبَرْتُ بِذَلِكَ النَّاسَ فَقَالُوا لِي أَتَعْرِفُ الرَّجُلَ قُلْتُ لَا إِلَّا أَنْ أَرَاهُ فَمَرَّ بِي فَقُلْتُ هَذَا هُوَ قَالُوا هَذَا طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al-Laits] dari [Yazid bin Abu Habib] bahwasanya [Suwaid bin Qais] menceritakan kepadanya dari [Mu'awiyah bin Hudaij] bahwa pada suatu hari Rasulullah Shallallahu'alaihi wasallam mengerjakan shalat lalu salam, dan ada satu rakaat yang ketinggalan. Ada seorang laki-laki yang mengetahuinya, maka dia berkata, \"Wahai Rasulullah Shallallahu'alaihi wasallam, engkau lupa satu rakaat\" Nabi Shallallahu'alaihi wasallam lalu segera masuk masjid dan memerintahkan Bilal untuk iqamah, lalu beliau shalat satu rakaat dengan orang-orang. Kemudian hal ini aku kabarkan kepada orang-orang, maka mereka berkata kepadaku, \"Apakah kamu tahu siapa laki-laki tersebut?\" Aku menjawab, \"Tidak, kecuali jika aku melihatnya.\" Lalu dia lewat di depanku, maka segera kukatakan, \"Betul, Inikah orangnya?.\" Mereka (para sahabat) berkata, \"Ya Ini, Thalhah bin Ubaidillah.\""},"658":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ رُبَيِّعَةَأَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَسَمِعَ صَوْتَ رَجُلٍ يُؤَذِّنُ فَقَالَ مِثْلَ قَوْلِهِ ثُمَّ قَالَ إِنَّ هَذَا لَرَاعِي غَنَمٍ أَوْ عَازِبٌ عَنْ أَهْلِهِ فَنَظَرُوا فَإِذَا هُوَ رَاعِي غَنَمٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah memberitakan kepada kami ['Abdurrahman] dari [Syu'bah] dari [Al-Hakim] dari [Ibnu Abu Laila] dari ['Abdullah bin Rubai'ah], bahwa dia pernah bersama Rasulullah Shallallahu'alaihi wasallam dalam suatu perjalanan, lalu beliau Shallallahu'alaihi wasallam mendengar suara seorang laki-Iaki sedang adzan, maka beliau Shallallahu'alaihi wasallam mengucapkan seperti yang dia kumandangkan, kemudian bersabda, \"Ini Adzannya pengembala kambing atau seorang laki-laki yang jauh dari istrinya.\" Lalu mereka melihatnya, ternyata dia seorang pengembala kambing."},"659":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ أَنَّ أَبَا عُشَّانَةَ الْمَعَافِرِيَّ حَدَّثَهُ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَعْجَبُ رَبُّكَ مِنْ رَاعِي غَنَمٍ فِي رَأْسِ شَظِيَّةِ الْجَبَلِ يُؤَذِّنُ بِالصَّلَاةِ وَيُصَلِّي فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ انْظُرُوا إِلَى عَبْدِي هَذَا يُؤَذِّنُ وَيُقِيمُ الصَّلَاةَ يَخَافُ مِنِّي قَدْ غَفَرْتُ لِعَبْدِي وَأَدْخَلْتُهُ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari ['Amr bin Al-Harits] bahwasanya [Abu 'Usysyanah Al-Ma'afiri] menceritakan kepadanya dari ['Uqbah bin 'Amir] dia berkata; \"Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Rabbrnu kagum kepada seorang pengembala kambing yang berada di puncak gunung, dia mengumandangkan adzan untuk shalal lalu dia shalat, maka Allah Azza wa Jalla berfirman, \"Lihatlah kepada hamba-Ku ini, dia mengumandangkan adzan dan iqamah lalu shalat karena takut kepada-Ku. Aku telah mengampuni hamba-Ku ini dan memasukkannya ke surga.\""},"660":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا يَحْيَى بْنُ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَا هُوَ جَالِسٌ فِي صَفِّ الصَّلَاةِ الْحَدِيثَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Yahya bin 'Ali bin Yahya bin Khallad bin Rifa'ah bin Rafi' Az-Zuraqi] dari [bapaknya] dari [kakeknya] dari [Rifa'ah bin Rafi'] \"Rasulullah Shallallahu'alaihi wasallam bersama kita dan beliau duduk di shaf shalat…\" (Al hadis) "},"661":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ تَمِيمٍ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ شُعْبَةَ قَالَ سَمِعْتُ أَبَا جَعْفَرٍ مُؤَذِّنَ مَسْجِدِ الْعُرْيَانِ عَنْ أَبِي الْمُثَنَّى مُؤَذِّنِ مَسْجِدِ الْجَامِعِ قَالَ سَأَلْتُ ابْنَ عُمَرَعَنْ الْأَذَانِ فَقَالَ كَانَ الْأَذَانُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثْنَى مَثْنَى وَالْإِقَامَةُ مَرَّةً مَرَّةً إِلَّا أَنَّكَ إِذَا قُلْتَ قَدْ قَامَتْ الصَّلَاةُ قَالَهَا مَرَّتَيْنِ فَإِذَا سَمِعْنَا قَدْ قَامَتْ الصَّلَاةُ تَوَضَّأْنَا ثُمَّ خَرَجْنَا إِلَى الصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Abdullah bin Muhammad bin Tamim] dia berkata; telah menceritakan kepada kami [Hajjaj] dari [Syu'bah] dia berkata; aku mendengar [Abu Ja'far] - mu'adzin masjid Al 'Uryan- dari [Abu Al Mutsanna] -mu'adzin masjid jami'- dia berkata; \"Aku pernah bertanya kepada [Ibnu 'Umar] tentang adzan, lalu beliau menjawab, 'Adzan pada zaman Rasulullah Shallallahu'alaihi wasallam adalah dua-dua dan iqamah sekali-sekali, kecuali ketika mengucapkan, \"Qad qaamatish-shalah\".' -diucapkannya dua kali-. Ketika kami mendengar 'Qad qaamatish-shalah\" kami telah berwudhu, kemudian segera shalat.\""},"662":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِصَاحِبٍ لِي إِذَا حَضَرَتْ الصَّلَاةُ فَأَذِّنَا ثُمَّ أَقِيمَا ثُمَّ لِيَؤُمَّكُمَا أَحَدُكُمَا","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dari [Khalid Al-Hadza'i] dari [Abu Qilabah] dari [Malik bin Al-Huwairits] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam bersabda kepadaku dan temanku, \"Jika telah tiba waktu shalat, maka adzanlah lalu lakukanlah iqamah, kemudian hendaklah salah seorang dari kalian menjadi imam.\""},"663":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نُودِيَ لِلصَّلَاةِ أَدْبَرَ الشَّيْطَانُ وَلَهُ ضُرَاطٌ حَتَّى لَا يَسْمَعَ التَّأْذِينَ فَإِذَا قُضِيَ النِّدَاءُ أَقْبَلَ حَتَّى إِذَا ثُوِّبَ بِالصَّلَاةِ أَدْبَرَ حَتَّى إِذَا قُضِيَ التَّثْوِيبُ أَقْبَلَ حَتَّى يَخْطُرَ بَيْنَ الْمَرْءِ وَنَفْسِهِ يَقُولُ اذْكُرْ كَذَا اذْكُرْ كَذَا لِمَا لَمْ يَكُنْ يَذْكُرُ حَتَّى يَظَلَّ الْمَرْءُ إِنْ يَدْرِي كَمْ صَلَّى","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Az-Zinad] dari [Al-A'raj] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: Apabila adzan dikumandangkan, maka setan kabur sambil kentut hingga ia tidak mendengar suara adzan. Jika adzan telah selesai, maka setan datang lagi. Ketika iqamah dikumandangkan, maka setan kabur lagi. Dan saat iqamah selesai, maka setan kembali lagi. Sehingga setan ini masuk ke benak seseorang dan berkata; \"Ingat ini, ingat itu, terhadap hal-hal yang tadinya ia lupakan. Sampai seseorang tidak tahu berapa jumlah raka'at yang telah ia kerjakan.\""},"664":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ يَعْلَمُ النَّاسُ مَا فِي النِّدَاءِ وَالصَّفِّ الْأَوَّلِ ثُمَّ لَمْ يَجِدُوا إِلَّا أَنْ يَسْتَهِمُوا عَلَيْهِ لَاسْتَهَمُوا عَلَيْهِ وَلَوْ يَعْلَمُونَ مَا فِي التَّهْجِيرِ لَاسْتَبَقُوا إِلَيْهِ وَلَوْ عَلِمُوا مَا فِي الْعَتَمَةِ وَالصُّبْحِ لَأَتَوْهُمَا وَلَوْ حَبْوًا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Sumayyi] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda; \"Seandainya manusia mengetahui apa yang ada didalam adzan dan shaf pertama kemudian mereka tidak mendapatkannya kecuali dengan mengundi, maka mereka pasti akan mengundinya. Seandainya manusia mengetahui apa yang ada didalam menyegerakan shalat, maka mereka pasti akan berlomba untuk mendapatkannya. Seandainya manusia mengetahui apa yang ada didalam shalat Isya dan shalat Subuh, maka mereka pasti akan mendatanginya walaupun dengan merangkak.\""},"665":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا سَعِيدٌ الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ عَنْ مُطَرِّفٍ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ اجْعَلْنِي إِمَامَ قَوْمِي فَقَالَ أَنْتَ إِمَامُهُمْ وَاقْتَدِ بِأَضْعَفِهِمْ وَاتَّخِذْ مُؤَذِّنًا لَا يَأْخُذُ عَلَى أَذَانِهِ أَجْرًا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami ['Affan] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dia berkata; telah menceritakan kepada kami [Sa'id bin Al-Jurairi] dari [Abu Al-'Alaa] dari [Mutharrif] dari ['Utsman bin Abul 'Ash] dia berkata; \"Aku pernah memohon, 'Wahai Rasulullah Shallallahu'alaihi wasallam, jadikan aku sebagai imam kaumku? ' Rasulullah Shallallahu'alaihi wasallam menjawab, 'Kamu imam mereka dan perhatikan orang yang paling lemah serta jangan menjadikan muadzin yang mengambil upah dari adzannya '.\""},"666":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا سَمِعْتُمْ النِّدَاءَ فَقُولُوا مِثْلَ مَا يَقُولُ الْمُؤَذِّنُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Az Zuhri] dari ['Atha bin Yazid] dari [Abu Sa'id Al Khudri] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika kalian mendengar adzan, maka ucapkanlah seperti apa yang diucapkan oleh muadzin.\""},"667":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ أَنَّ بُكَيْرَ بْنَ الْأَشَجِّ حَدَّثَهُ أَنَّ عَلِيَّ بْنَ خَالِدٍ الزُّرَقِيَّ حَدَّثَهُ أَنَّ النَّضْرَ بْنَ سُفْيَانَ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ بِلَالٌ يُنَادِي فَلَمَّا سَكَتَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ مِثْلَ هَذَا يَقِينًا دَخَلَ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari ['Amr bin Al-Harits] bahwasanya [Bukair bin Al-Asyajji] menceritakan kepadanya bahwasanya ['Ali bin Khalid Az-Zuraqi] menceritakan kepadanya bahwasanya [An-Nadhr bin Sufyan] menceritakan kepadanya sesungguhnya dia mendengar [Abu Hurairah] berkata; \"Suatu ketika kami bersama Rasulullah Shallallahu'alaihi wasallam, lalu bangkitlah Bilal untuk adzan. Setelah selesai adzan. Rasulullah Shallallahu'alaihi wasallam bersabda. 'Barangsiapa mengucapkan seperti yang dikumandangkan oleh muadzin dengan yakin, maka dia masuk surga'.\""},"668":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مُجَمِّعِ بْنِ يَحْيَى الْأَنْصَارِيِّ قَالَ كُنْتُ جَالِسًا عِنْدَ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍفَأَذَّنَ الْمُؤَذِّنُ فَقَالَ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ فَكَبَّرَ اثْنَتَيْنِ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ فَتَشَهَّدَ اثْنَتَيْنِ فَقَالَ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَتَشَهَّدَ اثْنَتَيْنِ ثُمَّ قَالَ حَدَّثَنِي هَكَذَا مُعَاوِيَةُ بْنُ أَبِي سُفْيَانَ عَنْ قَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ حَدَّثَنَا جَرِيرٌ عَنْ مِسْعَرٍ عَنْ مُجَمِّعٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ قَالَ سَمِعْتُ مُعَاوِيَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُ سَمِعْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَمِعَ الْمُؤَذِّنَ فَقَالَ مِثْلَ مَا قَالَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] telah memberitakan kepada kami ['Abdullah bin Al-Mubarak] dari [Mujammi' bin Yahya Al-Anshari] dia berkata; \"Aku pernah duduk di sisi [Abu Umamah bin Sahl bin Hunaif] lalu seorang muadzin mengumandangkan adzan, ALLAAHU AKBAR, ALLAAHU AKBAR (Allah Maha Besar, Allah Maha Besar'). Dia bertakbir dua kali. Muadzin meneruskan adzannya, ASYHADU AN LAA ILAAHA ILLALLAAH ('Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah'). dia ikut mengucapkan syahadat dua kali. Muadzin melanjutkan, ASYHADU ANNA MUHAMMADAR RASUULULLAAH (Aku bersaksi bahwa Muhammad adalah utusan Allah'). dia ikut mengucapkan syahadat dua kali, kemudian berkata; \"Beginilah [Mu'awiyah bin Abu Sufyan] bercerita kepadaku dari sabda Rasulullah Shallallahu'alaihi wasallam tentang hal ini'.\" Telah mengabarkan kepada kami [Muhammad bin Qudamah] telah menceritakan kepada kami [Jarir] dari [Mis'ar] dari [Mujammi'] dari [Abu Umamah bin Sahl] dia berkata; aku mendengar [Mu'awiyah Radliyallahu'anhu] berkata; berkata; Aku mendengar dari Rasulullah Shallallahu'alaihi wasallam ketika beliau mendengar Mua'adzin, beliau mengucapkan sebagaimana yang dia ucapkan."},"669":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى وَإِبْرَاهِيمُ بْنُ الْحَسَنِ الْمِقْسَمِيُّ قَالَا حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ يَحْيَى أَنَّ عِيسَى بْنَ عُمَرَ أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَلْقَمَةَ بْنِ وَقَّاصٍ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ قَالَإِنِّي عِنْدَ مُعَاوِيَةَ إِذْ أَذَّنَ مُؤَذِّنُهُ فَقَالَ مُعَاوِيَةُ كَمَا قَالَ الْمُؤَذِّنُ حَتَّى إِذَا قَالَ حَيَّ عَلَى الصَّلَاةِ قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ فَلَمَّا قَالَ حَيَّ عَلَى الْفَلَاحِ قَالَ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ وَقَالَ بَعْدَ ذَلِكَ مَا قَالَ الْمُؤَذِّنُ ثُمَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Mujahid bin Musa] dan [Ibrahim bin Al-Hasan Al-Miqsami] mereka berdua berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij], telah mengabarkan kepadaku ['Amr bin Yahya] bahwasanya ['Isa bin 'Umar] mengabarkan kepadanya dari ['Abdullah bin 'Alqamah bin Waqqash] dari ['Alqamah bin Waqqash] dia berkata; \"Aku pemah berada di sisi [Muawiyah] ketika muadzinnya mengumandangkan adzan, dan ternyata Muawiyah mengucapkan sebagaimana yang diucapkan oleh muadzin. Tatkala muadzin mengucapkan `Hayya 'alash-shalaah' (Mari menuju sholat) dia mengucapkan, 'Laa haula walaa quwwata illaa billaah' (Tiada daya dan upaya kecuali dengan pertolongan Allah) dan ketika sampai ke lafazh, 'Hayya 'alai, falaah' (Mari menuju kebahagiaan) dia juga mengucapkan, 'Laa haula walaa quwwata illaa billaah' (Tiada daya dan upaya kecuali dengan pertolongan Allah). Setelah itu beliau mengucapkan seperti ucapan yang dikumandangkan oleh muadzin. Lantas dia berkata, 'Aku mendengar Rasulullah Shallallahu'alaihi wasallam mengucapkan seperti itu'.\""},"670":{"ar":"أَخْبَرَنَا سُوَيْدٌ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ أَنَّ كَعْبَ بْنَ عَلْقَمَةَ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ جُبَيْرٍ مَوْلَى نَافِعِ بْنِ عَمْرٍو الْقُرَشِيِّ يُحَدِّثُ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَمِعْتُمْ الْمُؤَذِّنَ فَقُولُوا مِثْلَ مَا يَقُولُ وَصَلُّوا عَلَيَّ فَإِنَّهُ مَنْ صَلَّى عَلَيَّ صَلَاةً صَلَّى اللَّهُ عَلَيْهِ عَشْرًا ثُمَّ سَلُوا اللَّهَ لِي الْوَسِيلَةَ فَإِنَّهَا مَنْزِلَةٌ فِي الْجَنَّةِ لَا تَنْبَغِي إِلَّا لِعَبْدٍ مِنْ عِبَادِ اللَّهِ أَرْجُو أَنْ أَكُونَ أَنَا هُوَ فَمَنْ سَأَلَ لِي الْوَسِيلَةَ حَلَّتْ لَهُ الشَّفَاعَةُ","id":"Telah mengabarkan kepada kami [Suwaid] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Haiwah bin Syuraih] bahwasanya [Ka'b bin 'Alqamah] mendengar ['Abdurrahman bin Jubair] -bekas budak Nafi' bin 'Amr Al-Qurasyi- menceritakan bahwasanya dia mendengar ['Abdullah bin 'Amr] berkata; \"Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika kalian mendengar suara muadzin, maka ucapkanlah seperti apa yang diucapkan oleh dia, lalu bacalah shalawat atasku. Barangsiapa bershalawat atasku sekali saja, maka Allah akan bershalawat (mendoakan kesejahteraan) kepadanya sepuluh kali. Kemudian mintalah wasilah kepada Allah untukku, karena wasilah adalah suatu kedudukan di surga yang tidak patut (mendapatnya) kecuali seorang hamba dari hamba-hamba Allah. Aku sangat berharap menjadi orang yang patut tersebut, dan barangsiapa memintakan wasilah untukku maka dia berhak mendapat syafaat!.\""},"671":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ اللَّيْثِ عَنْ الْحُكَيْمِ بْنِ عَبْدِ اللَّهِ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ حِينَ يَسْمَعُ الْمُؤَذِّنَ وَأَنَا أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ رَضِيتُ بِاللَّهِ رَبًّا وَبِمُحَمَّدٍ رَسُولًا وَبِالْإِسْلَامِ دِينًا غُفِرَ لَهُ ذَنْبُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Al-Laits] dari [Al-Hakim bin 'Abdullah] dari ['Amir bin Sa'd] dari [Sa'ad bin Abu Waqqash] dari Rasulullah Shallallahu'alaihi wasallam, beliau bersabda: \"Barangsiapa setelah mendengar adzan mengucapkan doa, `Aku bersaksi bahwa tiada Dzat yang berhak diibadahi selain Allah, tanpa sekutu bagi-Nya. Aku juga bersaksi bahwa Muhammad adalah hamba dan utusan-Nya. Aku rela Allah sebagai Tuhan, Muhammad sebagai Rasul, dan Islam sebagai agama' maka dosa-dosanya akan diampuni.\""},"672":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ حِينَ يَسْمَعُ النِّدَاءَ اللَّهُمَّ رَبَّ هَذِهِ الدَّعْوَةِ التَّامَّةِ وَالصَّلَاةِ الْقَائِمَةِ آتِ مُحَمَّدًا الْوَسِيلَةَ وَالْفَضِيلَةَ وَابْعَثْهُ الْمَقَامَ الْمَحْمُودَ الَّذِي وَعَدْتَهُ إِلَّا حَلَّتْ لَهُ شَفَاعَتِي يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami ['Ali bin 'Ayyasy] dia berkata; telah menceritakan kepada kami [Syu'aib] dari [Muhammad bin Al-Munkadir] dari [Jabir] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa ketika mendengar adzan ia mengucapkan doa, `Ya Allah, Rabb Yang Memiliki seruan yang sempurna ini dan shalat yang ditegakkan, berikanlah kepada Muhammad wasilah dan fadhilah (keutamaan). Bangkitkanlah beliau pada kedudukan yang mulia sebagaimana telah Engkau janjikan' maka ia pasti mendapat syafaatku pada hari Kiamat.\""},"673":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ يَحْيَى عَنْ كَهْمَسٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ لِمَنْ شَاءَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dari [Yahya] dari [Kahmas] dia berkata; telah menceritakan kepada kami ['Abdullah bin Buraidah] dari ['Abdullah bin Mughaffal] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Diantara dua adzan ada shalat, diantara dua adzan ada shalat, diantara dua adzan ada Shalat, bagi Yang menghendaki.\" "},"674":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ عَامِرٍ الْأَنْصَارِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ الْمُؤَذِّنُ إِذَا أَذَّنَ قَامَ نَاسٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَبْتَدِرُونَ السَّوَارِيَ يُصَلُّونَ حَتَّى يَخْرُجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُمْ كَذَلِكَ وَيُصَلُّونَ قَبْلَ الْمَغْرِبِ وَلَمْ يَكُنْ بَيْنَ الْأَذَانِ وَالْإِقَامَةِ شَيْءٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Abu 'Amir] telah menceritakan kepada kami [Syu'bah] dari ['Amr bin 'Amir Al-Anshari] dari [Anas bin Malik] dia berkata; \"Bila muadzin telah mengumandangkan adzan, maka para sahabat segera bangkit mendekati tiang-tiang (masjid) dan shalat hingga Rasulullah Shallallahu'alaihi wasallam keluar dan mereka masih dalam keadaan demikian. Mereka shalat sebelum Maghrib, dan sebelumnya tidak ada shalat diantara adzan dan iqamah sesuatupun jua.\""},"675":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ أَبِيهِ قَالَرَأَيْتُ أَبَا هُرَيْرَةَ وَمَرَّ رَجُلٌ فِي الْمَسْجِدِ بَعْدَ النِّدَاءِ حَتَّى قَطَعَهُ فَقَالَ أَبُو هُرَيْرَةَ أَمَّا هَذَا فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dari ['Umar bin Sa'id] dari [Asy'ats bin Abu Asy-Sya'tsa'] dari [Bapaknya] dia berkata; aku melihat Abu Hurairah kemudian seorang laki-laki berjalan di masjid setelah adzan hingga dia keluar dari masjid. Lalu [Abu Hurairah] berkata; \"Orang ini telah melakukan perbuatan maksiat terhadap Abu Qasim (Rasulullah Shallallahu'alaihi wasallam).\""},"676":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ أَبِي عُمَيْسٍ قَالَ أَخْبَرَنَا أَبُو صَخْرَةَ عَنْ أَبِي الشَّعْثَاءِ قَالَخَرَجَ رَجُلٌ مِنْ الْمَسْجِدِ بَعْدَ مَا نُودِيَ بِالصَّلَاةِ فَقَالَ أَبُو هُرَيْرَةَ أَمَّا هَذَا فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Utsman bin Hakim] dia berkata; telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Abu 'Umais] dia berkata; telah mengabarkan kepada kami [Abu Shakhrah] dari [Abu Asy-Sya'tsa'] dia berkata; seorang laki-laki keluar dari masjid setelah diseru untuk shalat maka [Abu Hurairah] berkata; \"Ada orang yang keluar dari masjid setelah dikumandangkan adzan, maka Abu Hurairah berkata, 'Orang tersebut telah melakukan perbuatan maksiat terhadap Abu Qasim (Rusulullah Shallallahu'alaihi wasallam) '.\""},"677":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي ذِئْبٍ وَيُونُسُ وَعَمْرُو بْنُ الْحَارِثِ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُمْ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِيمَا بَيْنَ أَنْ يَفْرُغَ مِنْ صَلَاةِ الْعِشَاءِ إِلَى الْفَجْرِ إِحْدَى عَشْرَةَ رَكْعَةً يُسَلِّمُ بَيْنَ كُلِّ رَكْعَتَيْنِ وَيُوتِرُ بِوَاحِدَةٍ وَيَسْجُدُ سَجْدَةً قَدْرَ مَا يَقْرَأُ أَحَدُكُمْ خَمْسِينَ آيَةً ثُمَّ يَرْفَعُ رَأْسَهُ فَإِذَا سَكَتَ الْمُؤَذِّنُ مِنْ صَلَاةِ الْفَجْرِ وَتَبَيَّنَ لَهُ الْفَجْرُ رَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِ حَتَّى يَأْتِيَهُ الْمُؤَذِّنُ بِالْإِقَامَةِ فَيَخْرُجُ مَعَهُوَبَعْضُهُمْ يَزِيدُ عَلَى بَعْضٍ فِي الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As-Sarh] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Ibnu Abu Dzi'b] dan [Yunus] dan ['Amr bin Al-Harits] bahwasanya [Ibnu Syihab] mengabarkan kepada mereka dari ['Urwah] dari ['Aisyah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam shalat sebelas rakaat diantara setelah lsya' sampai Fajar. Beliau salam pada setiap dua rakaat dan witir satu rakaat. Beliau sujud selama ukuran salah seorang dari kalian membaca lima puluh ayat, kemudian beliau mengangkat kepalanya. Bila muadzin telah diam dari shalat (adzan) Fajar dan Fajar telah jelas, maka beliau shalat dua rakaat yang ringan, kemudian berbaring dengan posisi miring ke kanan hingga muadzin mendatangi beliau untuk iqamah, lalu beliau keluar bersamanya.\" Dan sebagian perawi ada yang saling menambahkan dalam hadis ini dari satu orang ke yang lainnya."},"678":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ أَنَّ كُرَيْبًا مُولِي ابْنِ عَبَّاسٍ أَخْبَرَهُ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ قُلْتُكَيْفَ كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَوَصَفَ أَنَّهُ صَلَّى إِحْدَى عَشْرَةَ رَكْعَةً بِالْوِتْرِ ثُمَّ نَامَ حَتَّى اسْتَثْقَلَ فَرَأَيْتُهُ يَنْفُخُ وَأَتَاهُ بِلَالٌ فَقَالَ الصَّلَاةُ يَا رَسُولَ اللَّهِ فَقَامَ فَصَلَّى رَكْعَتَيْنِ وَصَلَّى بِالنَّاسِ وَلَمْ يَتَوَضَّأْ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al-Hakim] dari [Syu'aib] dari [Al-Laits] dia berkata; telah menceritakan kepada kami [Khalid] dari [Ibnu Abu Hilal] dari [Makhramah bin Sulaiman] bahwasanya [Kuraib] -budak Ibnu Abbas- mengabarkan kepadanya, dia berkata; \"Aku bertanya kepada Ibnu Abbas, 'Bagaimana cara shalat Rasulullah Shallallahu'alaihi wasallam pada malam hari? ' [Ibnu Abbas] mengatakan bahwa beliau Shallallahu'alaihi wasallam shalat sebelas rakaat dengan satu rakaat witir. Kemudian beliau tidur hingga merasa berat dan aku melihatnya mendengkur. Lalu datanglah Bilal dan berkata, 'Dirikan Shalat wahai Rasulullah! ' Kemudian beliau bangun dan shalat dua rakaat, lantas beliau shalat bersama orang-orang tanpa berwudhu (lagi).\""},"679":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مَعْمَرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا تَقُومُوا حَتَّى تَرَوْنِي خَرَجْتُ","id":"Telah mengabarkan kepada kami [Al-Husain bin Huraits] dia berkata; telah menceritakan kepada kami [Al-Fadhl bin Musa] dari [Ma'mar] dari [Yahya bin Abu Katsir] dari ['Abdullah bin Abu Qatadah] dari [Bapaknya], dia berkata; Rasulullah Shallallahu'alaihi wasallam Bersabda: \"Bila telah dikumandangkan iqamah untuk shalat, maka kalian jangan bangkit hingga melihatku datang.\""},"680":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ عَمْرِو بْنِ عَبَسَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَنَى مَسْجِدًا يُذْكَرُ اللَّهُ فِيهِ بَنَى اللَّه�� عَزَّ وَجَلَّ لَهُ بَيْتًا فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman] dia berkata; telah menceritakan kepada kami [Baqiyyah] dari [Bahir] dari [Khalid bin Ma'dan] dari [Katsir bin Murrah] dari ['Amr bin 'Abasah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, \"Barangsiapa membangun masjid yang dipakai untuk berdzikir kepada Allah, maka Allah Azza wa Jalla akan membangun sebuah rumah di surga baginya.\""},"681":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ أَشْرَاطِ السَّاعَةِ أَنْ يَتَبَاهَى النَّاسُ فِي الْمَسَاجِدِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al-Mubarak] dari [Hammad bin Salamah] dari [Ayyub] dari [Abu Qibalah] dari [Anas] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Diantara tanda- tanda hari Kiamat adalah manusia bermegah-megahan dalam membangun masjid. "},"682":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ قَالَكُنْتُ أَقْرَأُ عَلَى أَبِي الْقُرْآنَ فِي السِّكَّةِ فَإِذَا قَرَأْتُ السَّجْدَةَ سَجَدَ فَقُلْتُ يَا أَبَتِ أَتَسْجُدُ فِي الطَّرِيقِ فَقَالَ إِنِّي سَمِعْتُ أَبَا ذَرٍّ يَقُولُ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ مَسْجِدٍ وُضِعَ أَوَّلًا قَالَ الْمَسْجِدُ الْحَرَامُ قُلْتُ ثُمَّ أَيٌّ قَالَ الْمَسْجِدُ الْأَقْصَى قُلْتُ وَكَمْ بَيْنَهُمَا قَالَ أَرْبَعُونَ عَامًا وَالْأَرْضُ لَكَ مَسْجِدٌ فَحَيْثُمَا أَدْرَكْتَ الصَّلَاةَ فَصَلِّ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami ['Ali bin Mushir] dari [Al-A'masy] dari [Ibrahim] dia berkata; \"Aku pernah membaca Al-Qur'an di hadapan [Bapakku] di jalan, dan ketika aku membaca ayat Sajdah dia segera sujud. Aku berkata kepadanya, ' Wahai ayahku, apakah engkau sujud di jalan? ' dia menjawab; Sesungguhnya aku mendengar [Abu Dzarr] berkata; \"Aku pernah bertanya kepada Rasulullah Shallallahu'alaihi wasallam tentang masjid yang pertama kali dibangun, lalu beliau Shallallahu'alaihi wasallam menjawab. 'Masjidil Haram'. Aku katakan lagi, 'Lantas masjid mana lagi`? ' Beliau menjawab, 'Masjidil Aqsha'. Aku berkata lagi, 'Berapa lama jarak antara keduanya? ' Rasulullah menjawab, 'Empat puluh tahun. Bumi bagimu adalah masjid, maka di mana saja kamu mendapatkan shalat maka shalatlah'.\""},"683":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ مَعْبَدِ بْنِ عَبَّاسٍ أَنَّ مَيْمُونَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْمَنْ صَلَّى فِي مَسْجِدِ رَسُولِ اللَّهِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الصَّلَاةُ فِيهِ أَفْضَلُ مِنْ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ إِلَّا مَسْجِدَ الْكَعْبَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al-Laits] dari [Nafi'] dari [Ibrahim bin 'Abdullah bin Ma'bad bin 'Abbas] bahwasanya [Maimunah] -Istri Nabi Shallallahu'alaihi wasallam- berkata, \"Barangsiapa shalat di masjid Rasulullah Shallallahu'alaihi wasallam -sesungguhnya aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda- `Shalat di dalam masjid Rasulullah Shallallahu'alaihi wasallam lebih utama seribu kali shalat di masjid lain, kecuali masjid Ka'bah (Masjidil Haram).\""},"684":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيْتَ هُوَ وَأُسَامَةُ بْنُ زَيْدٍ وَبِلَالٌ وَعُثْمَانُ بْنُ طَلْحَةَ فَأَغْلَقُوا عَلَيْهِمْ فَلَمَّا فَتَحَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنْتُ أَوَّلَ مَنْ وَلَجَ فَلَقِيتُ بِلَالًا فَسَأَلْتُهُ هَلْ صَلَّى فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ صَلَّى بَيْنَ الْعَمُودَيْنِ الْيَمَانِيَيْنِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al-Laits] dari [Ibnu Syihab] dari [Salim] dari [Bapaknya], dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam masuk ke dalam Ka'bah bersama Usamah bin Zaid, Bilal, dan Utsman bin Thalhah, lalu mereka menutup (pintu Ka'bah). Ketika Rasulullah membukanya, maka akulah yang pertama kali masuk dan berjumpa dengan [Bilal]. Lalu aku bertanya kepadanya, \"Apakah Rasulullah Shallallahu'alaihi wasallam shalat di dalamnya'?\" dia berkata, \"Ya, beliau Shallallahu'alaihi wasallam shalat diantara dua tiang Yamani.\""},"685":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو مُسْهِرٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ رَبِيعَةَ بْنِ يَزِيدَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ ابْنِ الدَّيْلَمِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ سُلَيْمَانَ بْنَ دَاوُدَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا بَنَى بَيْتَ الْمَقْدِسِ سَأَلَ اللَّهَ عَزَّ وَجَلَّ خِلَالًا ثَلَاثَةً سَأَلَ اللَّهَ عَزَّ وَجَلَّ حُكْمًا يُصَادِفُ حُكْمَهُ فَأُوتِيَهُ وَسَأَلَ اللَّهَ عَزَّ وَجَلَّ مُلْكًا لَا يَنْبَغِي لِأَحَدٍ مِنْ بَعْدِهِ فَأُوتِيَهُ وَسَأَلَ اللَّهَ عَزَّ وَجَلَّ حِينَ فَرَغَ مِنْ بِنَاءِ الْمَسْجِدِ أَنْ لَا يَأْتِيَهُ أَحَدٌ لَا يَنْهَزُهُ إِلَّا الصَّلَاةُ فِيهِ أَنْ يُخْرِجَهُ مِنْ خَطِيئَتِهِ كَيَوْمِ وَلَدَتْهُ أُمُّهُ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami [Abu Mushar] dia berkata; telah menceritakan kepada kami [Sa'id bin 'Abdul 'Aziz] dari [Rabi'ah bin Yazid] dari [Abu Idris Al-Khaulani] dari [Ibnu Ad-Dailami] dari ['Abdullah bin 'Amr] dari Rasulullah Shallallahu'alaihi wasallam, beliau bersabda \"Sulaiman bin Daud alaihissalam ketika membangun Baitul Maqdis meminta kepada Allah Azza wa Jalla tiga hal: meminta kepada Allah Azza wa Jalla hukum yang sesuai dengan hukumnya, lalu ia pun diberi. Dia meminta kepada Allah Azza wa Jalla suatu kerajaan yang tidak ada yang pantas memilikinya setelahnya, kemudian ia pun diberi. Dia juga meminta kepada Allah Azza wa Jalla ketika selesai dari pembangunan masjid agar orang yang datang ke sini dengan satu motivasi yaitu shalat, agar semua kesalahannya dihapuskan hingga ia laksana bayi yang baru dilahirkan ibunya.\""},"686":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَأَبِي عَبْدِ اللَّهِ الْأَغَرِّ مَوْلَى الْجُهَنِيِّينَ وَكَانَا مِنْ أَصْحَابِ أَبِي هُرَيْرَةَ أَنَّهُمَا سَمِعَا أَبَا هُرَيْرَةَ يَقُولُصِوَاو فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ مِنْ أَلْفِ صَلَاةٍ فِيمَا سِوَاهُ مِنْ الْمَسَاجِدِ إِلَّا الْمَسْجِدَ الْحَرَامَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آخِرُ الْأَنْبِيَاءِ وَمَسْجِدُهُ آخِرُ الْمَسَاجِدِقَالَ أَبُو سَلَمَةَ وَأَبُو عَبْدِ اللَّهِ لَمْ نَشُكَّ أَنَّ أَبَا هُرَيْرَةَ كَانَ يَقُولُ عَنْ حَدِيثِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمُنِعْنَا أَنْ نَسْتَثْبِتَ أَبَا هُرَيْرَةَ فِي ذَلِكَ الْحَدِيثِ حَتَّى إِذَا تُوُفِّيَ أَبُو هُرَيْرَةَ ذَكَرْنَا ذَلِكَ وَتَلَاوَمْنَا أَنْ لَا نَكُونَ كَلَّمْنَا أَبَا هُرَيْرَةَ فِي ذَلِكَ حَتَّى يُسْنِدَهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ سَمِعَهُ مِنْهُ فَبَيْنَا نَحْنُ عَلَى ذَلِكَ جَالَسْنَا عَبْدَ اللَّهِ بْنَ إِبْرَاهِيمَ بْنِ قَارِظٍ فَذَكَرْنَا ذَلِكَ الْحَدِيثَ وَالَّذِي فَرَّطْنَا فِيهِ مِنْ نَصِّ أَبِي هُرَيْرَةَ فَقَالَ لَنَا عَبْدُ اللَّهِ بْنُ إِبْرَاهِيمَ أَشْهَدُ أَنِّي سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنِّي آخِرُ الْأَنْبِيَاءِ وَإِنَّهُ آخِرُ الْمَسَاجِدِ","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid] dia berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Az-Zubaidi] dari [Az-Zuhri] dari [Abu Salamah bin 'Abdurrahman] dan [Abu 'Abdullah Al-Agharr] -budak Al Juhaniyyin dan keduanya termasuk sahabat Abu Hurairah- bahwasanya keduanya mendengar [Abu Hurairah] berkata; \"Shalat di masjid Rasulullah Shallallahu'alaihi wasallam lebih utama daripada shalat seribu kali di masjid lain, kecuali Masjidil Haram. Rasulullah Shallallahu'alaihi wasallam adalah rasul terakhir dan masjidnya adalah masjid yang terakhir.\" Abu Salamah dan Abu Abdullah berkata, \"Kami tidak ragu bahwa Abu Hurairah mengatakan demikian dari hadis Rasulullah Shallallahu'alaihi wasallam, dan kami dilarang untuk mengecek kepada Abu Hurairah dalam hal hadis ini hingga beliau wafat baru kami sebutkan hadis ini. Kami saling mencela agar kami tidak berbicara kepada Abu Hurairah dalam hal itu, sehingga hadis tersebut disandarkan kepada Rasulullah Shallallahu'alaihi wasallam kendati dia memang mendengarnya dari Rasulullah Shallallahu'alaihi wasallam. Ketika dalam keadaan demikian tiba-tiba [Abdullah bin Ibrahim bin Qarizh] duduk bersama kami lalu menyebutkan hadis tersebut dari nash Abu Hurairah yang kami tinggalkan. dia berkata kepada kami, \"Aku bersaksi bahwa aku mendengar [Abu Hurairah] berkata, 'Rasulullah Shallallahu'alaihi wasallam bersabda, \"...Aku adalah nabi yang paling akhir, dan masjid tersebut juga masjid yang paling akhir.\""},"687":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ بَيْتِي وَمِنْبَرِي رَوْضَةٌ مِنْ رِيَاضِ الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari ['Abdullah bin Abu Bakr] dari ['Abbad bin Tamim] dari ['Abdullah bin Zaid] dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, \"Antara rumahku dan mimbarku adalah taman dari taman-taman yang ada di surga.\""},"688":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمِّارٍ الدُّهْنِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ قَوَائِمَ مِنْبَرِي هَذَا رَوَاتِبُ فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ammar Ad-Duhni] dari [Abu Salamah] dari ['Ummu Salamah] bahwa Nabi Shallallahu'alaihi wasallam bersabda, \"Bumi (tanah) mimbarku ini akan berada (akan permanen dengan dipindahkan) di Surga.\""},"689":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ ابْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِ قَالَتَمَارَى رَجُلَانِ فِي الْمَسْجِدِ الَّذِي أُسِّسَ عَلَى التَّقْوَى مِنْ أَوَّلِ يَوْمٍ فَقَالَ رَجُلٌ هُوَ مَسْجِدُ قُبَاءَ وَقَالَ الْآخَرُ هُوَ مَسْجِدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ مَسْجِدِي هَذَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari ['Imran bin Abu Anas] dari [Ibnu Abu Sa'id Al-Khudri] dari [Bapaknya] dia berkata; \"Ada dua orang yang bertengkar tentang masjid yang pertama kali didirikan atas dasar takwa semenjak hari pertamanya dibangun. Salah seorang dari dua orang tersebut berkata, 'Masjid Quba. Yang lain berkata. Masjid Rasulullah Shallallahu'alaihi wasallam'. Lantas Rasulullah Shallallahu'alaihi wasallam bersabda: \"Masjidku ini.\""},"690":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي قُبَاءَ رَاكِبًا وَمَاشِيًا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari ['Abdullah bin Dinar] dari [Ibnu 'Umar] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam pernah datang ke Quba' dengan naik kendaraan dan jalan kaki.\""},"691":{"ar":"أَخْبَرَنَ�� قُتَيْبَةُ قَالَ حَدَّثَنَا مُجَمِّعُ بْنُ يَعْقُوبَ عَنْ مُحَمَّدِ بْنِ سُلَيْمَانَ الْكَرْمَانِيِّ قَالَ سَمِعْتُ أَبَا أُمَامَةَ بْنَ سَهْلِ بْنِ حُنَيْفٍ قَالَ قَالَ أَبِيقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ خَرَجَ حَتَّى يَأْتِيَ هَذَا الْمَسْجِدَ مَسْجِدَ قُبَاءَ فَصَلَّى فِيهِ كَانَ لَهُ عَدْلَ عُمْرَةٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Mujammi' bin Ya'qub] dari [Muhammad bin Sulaiman Al-Karmani] dia berkata; aku mendengar [Abu Umamah bin Sahl bin Hunaif] dia berkata; [Bapakku] berkata; \"Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa keluar hingga masjid ini, yakni masjid Quba ' lalu shalat di dalamnya, maka -pahalanya- sebanding dengan umrah.\""},"692":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ مَسْجِدِ الْحَرَامِ وَمَسْجِدِي هَذَا وَمَسْجِدِ الْأَقْصَى","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dari Rasulullah Shallallahu'alaihi wasallam, beliau Shallallahu'alaihi wasallam bersabda, \"Tidak dianjurkan mempersiapkan perjalanan untuk mengagungkan masjid khusus, kecuali ke tiga masjid, yaitu Masjidil Haram, Masjidku (Nabawi) ini, dan Masjidil Aqsha.\""},"693":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ مُلَازِمٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بَدْرٍ عَنْ قَيْسِ بْنِ طَلْقٍ عَنْ أَبِيهِ طَلْقِ بْنِ عَلِيٍّ قَالَخَرَجْنَا وَفْدًا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعْنَاهُ وَصَلَّيْنَا مَعَهُ وَأَخْبَرْنَاهُ أَنَّ بِأَرْضِنَا بِيعَةً لَنَا فَاسْتَوْهَبْنَاهُ مِنْ فَضْلِ طَهُورِهِ فَدَعَا بِمَاءٍ فَتَوَضَّأَ وَتَمَضْمَضَ ثُمَّ صَبَّهُ فِي إِدَاوَةٍ وَأَمَرَنَا فَقَالَ اخْرُجُوا فَإِذَا أَتَيْتُمْ أَرْضَكُمْ فَاكْسِرُوا بِيعَتَكُمْ وَانْضَحُوا مَكَانَهَا بِهَذَا الْمَاءِ وَاتَّخِذُوهَا مَسْجِدًا قُلْنَا إِنَّ الْبَلَدَ بَعِيدٌ وَالْحَرَّ شَدِيدٌ وَالْمَاءَ يَنْشُفُ فَقَالَ مُدُّوهُ مِنْ الْمَاءِ فَإِنَّهُ لَا يَزِيدُهُ إِلَّا طِيبًا فَخَرَجْنَا حَتَّى قَدِمْنَا بَلَدَنَا فَكَسَرْنَا بِيعَتَنَا ثُمَّ نَضَحْنَا مَكَانَهَا وَاتَّخَذْنَاهَا مَسْجِدًا فَنَادَيْنَا فِيهِ بِالْأَذَانِ قَالَ وَالرَّاهِبُ رَجُلٌ مِنْ طَيِّئٍ فَلَمَّا سَمِعَ الْأَذَانَ قَالَ دَعْوَةُ حَقٍّ ثُمَّ اسْتَقْبَلَ تَلْعَةً مِنْ تِلَاعِنَا فَلَمْ نَرَهُ بَعْدُ","id":"Telah mengabarkan kepada kami [Hunnad bin As-Sariy] dari [Mulazim] dia berkata; telah menceritakan kepadaku ['Abdullah bin Badr] dari [Qais bin Thalaq] dari Bapaknya [Thalaq bin 'Ali] dia berkata; \"Kami datang kepada Rasulullah Shallallahu'alaihi wasallam sebagai utusan, lalu kami berbaiat kepadanya dan shalat bersamanya. Aku kabarkan kepada Rasulullah Shallallahu'alaihi wasallam bahwa di daerah kami ada tempat ibadah (kuil) milik kita, maka aku hendak meminta sisa air bersucinya. Beliaupun meminta air lalu berwudhu dan berkumur, kemudian menuangkan air ke dalam ember dan menyuruh kami untuk mengambilnya. Beliau lalu bersabda, `Keluarlah (pulanglah) kalian. Bila telah sampai ke negeri kalian, maka hancurkan kuil itu dan siramlah Puing-puingnya dengan air ini, lalu jadikanlah sebagai masjid'. Kami berkata, \"Negeri kami jauh dan sangat panas sekali, sedangkan air ini akan mengering'. Rasulullah Shallallahu'alaihi wasallam bersabda. 'Perbanyaklah airnya. Air ini tidak akan menambah apa-apa kecuali kebaikan'. Kamipun keluar hingga ke negeri kami, lalu kami menghancurkan kuil itu dan menyiramkan air tersebut ke puing-puing bangunannya. Kemudian kami jadikan sebagai masjid dan kami mengumandangkan adzan.\" la berkata lagi, \"Pendetanya adalah laki-laki dari Thayyi'. Ketika mendengar adzan, ia berkata, `Ini dakwah yang hak'. Kemudian ia pergi ke tempat yang tinggi yang ada di daerah kami, dan kami tidak pernah melihatnya lagi setelah itu.\""},"694":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ فِي عُرْضِ الْمَدِيِنَةِ فِي حَيٍّ يُقَالُ لَهُمْ بَنُو عَمْرِو بْنِ عَوْفٍ فَأَقَامَ فِيهِمْ أَرْبَعَ عَشْرَةَ لَيْلَةً ثُمَّ أَرْسَلَ إِلَى مَلَإٍ مِنْ بَنِي النَّجَّارِ فَجَاءُوا مُتَقَلِّدِي سُيُوفِهِمْ كَأَنِّي أَنْظُرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَاحِلَتِهِ وَأَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ رَدِيفَهُ وَمَلَأٌ مِنْ بَنِي النَّجَّارِ حَوْلَهُ حَتَّى أَلْقَى بِفِنَاءِ أَبِي أَيُّوبَ وَكَانَ يُصَلِّي حَيْثُ أَدْرَكَتْهُ الصَّلَاةُ فَيُصَلِّي فِي مَرَابِضِ الْغَنَمِ ثُمَّ أَمَرَ بِالْمَسْجِدِ فَأَرْسَلَ إِلَى مَلَإٍ مِنْ بَنِي النَّجَّارِ فَجَاءُوا فَقَالَ يَا بَنِي النَّجَّارِ ثَامِنُونِي بِحَائِطِكُمْ هَذَا قَالُوا وَاللَّهِ لَا نَطْلُبُ ثَمَنَهُ إِلَّا إِلَى اللَّهِ عَزَّ وَجَلَّ قَالَ أَنَسٌ وَكَانَتْ فِيهِ قُبُورُ الْمُشْرِكِينَ وَكَانَتْ فِيهِ خَرِبٌ وَكَانَ فِيهِ نَخْلٌ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقُبُورِ الْمُشْرِكِينَ فَنُبِشَتْ وَبِالنَّخْلِ فَقُطِعَتْ وَبِالْخَرِبِ فَسُوِّيَتْ فَصَفُّوا النَّخْلَ قِبْلَةَ الْمَسْجِدِ وَجَعَلُوا عِضَادَتَيْهِ الْحِجَارَةَ وَجَعَلُوا يَنْقُلُونَ الصَّخْرَ وَهُمْ يَرْتَجِزُونَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهُمْ وَهُمْ يَقُولُونَ اللَّهُمَّ لَا خَيْرَ إِلَّا خَيْرُ الْآخِرَةِفَانْصُرْ الْأَنْصَارَ وَالْمُهَاجِرَةَ","id":"Telah mengabarkan kepada kami ['Imran bin Musa] dia berkata; telah menceritakan kepada kami ['Abdul Warits] dari [Abu At-Tayyah] dari [Anas bin Malik] dia berkata; Anas bin Malik, dia berkata, \"Ketika Rasulullah Shallallahu'alaihi wasallam datang ke Madinah, beliau singgah di tanah lapang di perkampungan yang dinamakan Bani Amru bin Auf. Beliau Shallallahu'alaihi wasallam tinggal selama empat belas hari. Kemudian beliau mengutus orang kepada pembesar Bani Najjar, lalu mereka datang dengan menghunus pedang-pedang mereka. Aku melihat Rasulullah Shallallahu'alaihi wasallam berada di atas unta kendaraannya dan Abu Bakar Radliyallahu'anhu naik di belakangnya, sedangkan pembesar Bani Najjar berada di sekelilingnya hingga beliau sampai ke pekarangan Abu Ayub, dan beliau Shallallahu'alaihi wasallam mengerjakan shalat kapansaja datang waktu shalat. Lantas beliau Shallallahu'alaihi wasallam mengerjakan shalat di tempat pengikatan kambing, dan beliau menyuruh untuk membuat masjid. Kemudian beliau mengirim orang ke pembesar Bani Najjar dan mereka pun datang, maka Rasulullah Shallallahu'alaihi wasallam bersabda kepada mereka, 'Wahai Bani Najjar, tentukan harga pekarangan ini? ' Mereka menjawab, 'Demi Allah, kami tidak menjualnya kecuali kepada Allah Azza wa Jalla'.\" Anas berkata, \"Dulu di tempat itu ada kuburan orang-orang musyrik, reruntuhan bangunan, dan pohon kurma. Rasulullah Shallallahu'alaihi wasallam menyuruh untuk membongkar kuburan orang-orang musyrik dan memotong pangkal pohon kurma, serta meratakan bekas bangunan. Lalu beliau menjadikan pohon kurma sebagai arah kiblat masjid dan sebuah batu besar sebagai dua batu masjid. Mulailah mereka memindahkan batu besar dengan kerja keras sambil mendendangkan lantunan syair -Sedang Rasulullah Shallallahu'alaihi wasallam bersama mereka- yang berbunyi: 'Ya Allah, tiada kebaikan yang lebih baik daripada kebaikan akhirat. Ya Allah, tolonglah orang-orang Anshar dan Muhajirin '.\""},"695":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ وَيُونُسَ قَالَا قَالَ الزُّهْرِيُّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ أَنَّ عَائِشَةَ وَابْنَ عَبَّاسٍ قَالَالَمَّا نُزِلَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَفِقَ يَطْرَحُ خَمِيصَةً لَهُ عَلَى وَجْهِهِ فَإِذَا اغْتَمَّ كَشَفَهَا عَنْ وَجْهِهِ قَالَ وَهُوَ كَذَلِكَ لَعْنَةُ اللَّهِ عَلَى الْيَهُودِ وَالنَّصَارَى اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al-Mubarak] dari [Ma'mar] dan [Yunus] mereka berdua berkata; [Az-Zuhri] berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah] bahwasanya ['Aisyah] dan [Ibnu 'Abbas] berkata; \"Tatkala diturunkan kepada Rasulullah Shallallahu'alaihi wasallam penyakit yang mengakibatkan kematiannya maka beliau menutupkan kain di wajahnya. Ketika beliau tidak bisa keluar maka beliau membuka selimutnya dari wajahnya. Nabi Shallallahu'alaihi wasallam bersabda, 'Allah melaknat orang-orang Yahudi dan Nasrani yang telah menjadikan kuburan nabi-nabi mereka sebagai masjid '.\""},"696":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ قَالَ حَدَّثَنِي أَبِي عَنْ عَائِشَةَأَنَّ أُمَّ حَبِيبَةَ وَأُمَّ سَلَمَةَ ذَكَرَتَا كَنِيسَةً رَأَتَاهَا بِالْحَبَشَةِ فِيهَا تَصَاوِيرُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُولَئِكَ إِذَا كَانَ فِيهِمْ الرَّجُلُ الصَّالِحُ فَمَاتَ بَنَوْا عَلَى قَبْرِهِ مَسْجِدًا وَصَوَّرُوا تِيكِ الصُّوَرَ أُولَئِكَ شِرَارُ الْخَلْقِ عِنْدَ اللَّهِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dia berkata; [bapakku] telah menceritakan kepadaku dari ['Aisyah] bahwa Ummu Habibah dan Ummu Salamah menceritakan tentang gereja yang dilihatnya di Habasyah, di dalamnya banyak terdapat gambar-gambar, lalu Rasulullah Shallallahu'alaihi wasallam bersabda, \"Jika di kalangan mereka ada seorang laki-laki shalih yang mati, mereka membangun masjid di atas kuburannya dan menggambar beberapa gambar. Mereka itulah seburuk-buruk makhluk di sisi Allah pada hari Kiamat.\""},"697":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنَا الْأَسْوَدُ بْنُ الْعَلَاءِ بْنِ جَارِيَةَ الثَّقَفِيُّ عَنْ أَبِي سَلَمَةَ هُوَ ابْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حِينَ يَخْرُجُ الرَّجُلُ مِنْ بَيْتِهِ إِلَى مَسْجِدِهِ فَرِجْلٌ تُكْتَبُ حَسَنَةً وَرِجْلٌ تَمْحُو سَيِّئَةً","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Ibnu Abu Dzi'b] dia berkata; telah menceritakan kepada kami [Al Aswad bin Al-'Alaa' bin Jariyah Ats-Tsaqafi] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] dari Rasulullah Shallallahu'alaihi wasallam, beliau Shallallahu'alaihi wasallam bersabda \"Ketika seseorang keluar dari rumahnya menuju masjid, maka tiap langkah satu kakinya dicatat satu kebaikan dan dari kakinya yang satu lagi sebagai penghapus satu kejelekan.\""},"698":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَأْذَنَتْ امْرَأَةُ أَحَدِكُمْ إِلَى الْمَسْجِدِ فَلَا يَمْنَعْهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Sufyan] dari [Az-Zuhri] dari [Salim] dari [bapaknya], dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, \"Apabila istri salah seorang dari kalian minta izin untuk ke masjid, janganlah ia mencegahnya.\""},"699":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنَا عَطَاءٌ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ قَالَ أَوَّلَ يَوْمٍ الثُّومِ ثُمَّ قَالَ الثُّومِ وَالْبَصَلِ وَالْكُرَّاثِ فَلَا يَقْرَبْنَا فِي مَسَاجِدِنَا فَإِنَّ الْمَلَائِكَةَ تَتَأَذَّى مِمَّا يَتَأَذَّى مِنْهُ الْإِنْسُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] dia berkata; telah menceritakan kepada kami ['Atha] dari [Jabir] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda, \"Barangsiapa makan dari pohon ini -beliau bersabda pada pagi hari--: bawang putih.\" Kemudian beliau bersabda, \"Bawang putih dan bawang merah, serta tumbuhan yang baunya sangat menyengat (seperti bawang), maka jangan mendekat ke masjid kami. Sesungguhnya malaikat merasa terganggu dari hal-hal yang manusia juga merasa terganggu karenanya.\""},"700":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ قَالَإِنَّكُمْ أَيُّهَا النَّاسُ تَأْكُلُونَ مِنْ شَجَرَتَيْنِ مَا أُرَاهُمَا إِلَّا خَبِيثَتَيْنِ هَذَا الْبَصَلُ وَالثُّومُ وَلَقَدْ رَأَيْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَجَدَ رِيحَهُمَا مِنْ الرَّجُلِ أَمَرَ بِهِ فَأُخْرِجَ إِلَى الْبَقِيعِ فَمَنْ أَكَلَهُمَا فَلْيُمِتْهُمَا طَبْخًا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Hisyam] dia berkata; telah menceritakan kepada kami [Qatadah] dari [Salim bin Abu Ja'ad] dari [Ma'dan bin Abu Thalhah] dari [Umar bin Khaththab], dia berkata, \"Wahai manusia, kalian makan dari dua pohon ini, aku tidak berpendapat melainkan keduanya tidak menyedapkan, yang pertama bawang merah dan yang kedua bawang putih. Rasulullah Shallallahu'alaihi wasallam bila mencium bau keduanya dari seseorang maka beliau memerintahkan agar ia diasingkan di Baqi'. Siapa saja yang ingin memakannya maka hilangkan bau itu dengan memasaknya.\""},"701":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْلَى قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَعْتَكِفَ صَلَّى الصُّبْحَ ثُمَّ دَخَلَ فِي الْمَكَانِ الَّذِي يُرِيدُ أَنْ يَعْتَكِفَ فِيهِ فَأَرَادَ أَنْ يَعْتَكِفَ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَ فَأَمَرَ فَضُرِبَ لَهُ خِبَاءٌ وَأَمَرَتْ حَفْصَةُ فَضُرِبَ لَهَا خِبَاءٌ فَلَمَّا رَأَتْ زَيْنَبُ خِبَاءَهَا أَمَرَتْ فَضُرِبَ لَهَا خِبَاءٌ فَلَمَّا رَأَى ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ آلْبِرَّ تُرِدْنَ فَلَمْ يَعْتَكِفْ فِي رَمَضَانَ وَاعْتَكَفَ عَشْرًا مِنْ شَوَّالٍ","id":"Telah mengabarkan kepada kami [Abu Daud] dia berkata; telah menceritakan kepada kami [Ya'la] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Amrah] dari [Aisyah] dia berkata, \"Bila Rasulullah Shallallahu'alaihi wasallam hendak i'tikaf maka Beliau mengerjakan shalat Subuh, lalu masuk ke tempat yang biasa dia gunakan untuk i'tikaf. Ketika beliau hendak i'tikaf pada sepuluh terakhir dibulan Ramadhan, beliau menyuruh seseorang untuk membuatkan tenda baginya, dan Hafshah juga menyuruh demikian. Keduanya dibuatkan tenda. Ketika Zainab melihat tenda Hafshah, dia minta dibuatkan sebuah tenda untuk dirinya, lalu ia pun dibuatkan juga. Tatkala Rasulullah Shallallahu'alaihi wasallam melihat hal tersebut, beliau Shallallahu'alaihi wasallam bersabda, 'Apakah kalian menghendaki kebaikan? ' Lalu Rasulullah Shallallahu'alaihi wasallam tidak jadi i'tikaf dibulan Ramadhan, dan beri'tikaf pada sepuluh hari di bulan Syawal.\""},"702":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأُصِيبَ سَعْدٌ يَوْمَ الْخَنْدَقِ رَمَاهُ رَجُلٌ مِنْ قُرَيْشٍ رَمْيَةً فِي الْأَكْحَلِ فَضَرَبَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْمَةً فِي الْمَسْجِدِ لِيَعُودَهُ مِنْ قَرِيبٍ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abdullah bin Numair] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah Radliyallahu'anha], dia berkata, \"Pada perang Khandaq Sa'ad terkena panah yang dibidikkan oleh orang Quraisy dibagian tengah mata yang berwarna hitam, maka Rasulullah Shallallahu'alaihi wasallam membuat tenda untuk dirinya, agar bisa menjenguknya dari dekat dengan mudah.\""},"703":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ أَنَّهُ سَمِعَ أَبَا قَتَادَةَ يَقُولُبَيْنَا نَحْنُ جُلُوسٌ فِي الْمَسْجِدِ إِذْ خَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْمِلُ أُمَامَةَ بِنْتَ أَبِي الْعَاصِ بْنِ الرَّبِيعِ وَأُمُّهَا زَيْنَبُ بِنْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ صَبِيَّةٌ يَحْمِلُهَا فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ عَلَى عَاتِقِهِ يَضَعُهَا إِذَا رَكَعَ وَيُعِيدُهَا إِذَا قَامَ حَتَّى قَضَى صَلَاتَهُ يَفْعَلُ ذَلِكَ بِهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari [Amr bin Sulaim Az-Zuraqi] bahwasannya dia mendengar [Abu Qatadah] dia berkata; \"Ketika kami sedang duduk-duduk di masjid, tiba-tiba Rasulullah Shallallahu'alaihi wasallam menemui kami dengan membawa Umamah bin Abu Ash bin Ar Rabi' -ibunya adalah Zainab binti Rasulullah Shallallahu'alaihi wasallam, dan dia (Umamah) masih kecil- lalu Rasulullah Shallallahu'alaihi wasallam shalat dan dia (Umamah) masih dalam gendongannya. Rasulullah Shallallahu'alaihi wasallam meletakkannya ketika beliau ruku' dan menggendongnya kembali ketika berdiri, hingga dia selesai shalatnya dengan melakukan hal seperti itu.\""},"704":{"ar":"أَخْبَرَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْلًا قِبَلَ نَجْدٍ فَجَاءَتْ بِرَجُلٍ مِنْ بَنِي حَنِيفَةَ يُقَالُ لَهُ ثُمَامَةُ بْنُ أُثَالٍ سَيِّدُ أَهْلِ الْيَمَامَةِ فَرُبِطَ بِسَارِيَةٍ مِنْ سَوَارِي الْمَسْجِدِ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] bahwasannya dia mendengar [Abu Hurairah] berkata; \"Rasulullah Shallallahu'alaihi wasallam mengirim pasukan berkuda ke arah Najed, lalu pasukan ini datang dengan membawa satu tahanan dari Bani Hanifah -yang bernama Tsumamah bin Utsal, tokoh penduduk Yamamah- lalu tahanan tersebut diikat disalah satu tiang masjid.\" Demikian redaksi ini secara ringkas."},"705":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ فِي حَجَّةِ الْوَدَاعِ عَلَى بَعِيرٍ يَسْتَلِمُ الرُّكْنَ بِمِحْجَنٍ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dari [Ibnu Wahab] dia berkata; Telah mengabarkan kepadakku [Yunus] dari [Ibnu Syihab] dari [Ubaidillah bin Abdullah] dari [lbnu Abbas], bahwa Rasulullah Shallallahu'alaihi wasallam thawaf saat haji Wada' di atas untanya. Beliau mengistilami pojok Ka'bah dengan tongkat."},"706":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ التَّحَلُّقِ يَوْمَ الْجُمُعَةِ قَبْلَ الصَّلَاةِ وَعَنْ الشِّرَاءِ وَالْبَيْعِ فِي الْمَسْجِدِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah mengabarkan kepadaku [Yahya bin Sa'id] dari [Ibnu 'Ajlan] dari [Amr bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Nabi Shallallahu'alaihi wasallam melarang mencukur rambut sebelum shalat Jum'at dan melarang jual-beli dalam masjid."},"707":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ عَجْلَانَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ تَنَاشُدِ الْأَشْعَارِ فِي الْمَسْجِدِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits bin Sa'ad] dari [Ibnu 'Ajlan] dari [Amr bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Nabi Shallallahu'alaihi wasallam melarang melantunkan syair dalam masjid."},"708":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ قَالَمَرَّ عُمَرُ بِحَسَّانَ بْنِ ثَابِتٍ وَهُوَ يُنْشِدُ فِي الْمَسْجِدِ فَلَحَظَ إِلَيْهِ فَقَالَ قَدْ أَنْشَدْتُ وَفِيهِ مَنْ هُوَ خَيْرٌ مِنْكَ ثُمَّ الْتَفَتَ إِلَى أَبِي هُرَيْرَةَ فَقَالَ أَسَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَجِبْ عَنِّي اللَّهُمَّ أَيِّدْهُ بِرُوحِ الْقُدُسِ قَالَ اللَّهُمَّ نَعَمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dia berkata; \"Umar pernah melewati Hasan bin Tsabit yang sedang membaca syair di dalam masjid, maka Umar memperingatkannya. [Hasan] berkata, Aku pernah pernah membaca syair dalam masjid padahal orang yang lebih baik daripada kamu (maksudnya nabi shallallahu 'alaihi wasallam) berada di dalam masjid tersebut. Kemudian dia menoleh kepada [Abu Hurairah] sambil berkata, 'Apakah engkau mendengar Rasulullah Shallallahu'alaihi wasallam memohon Ya Allah, kabulkanlah untukku, kuatkanlah ia dengan Ruhul Qudus (Jibril). Maka Hasan menjawab, 'Ya Allah, benar'."},"709":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ أَبِي عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَجَاءَ رَجُلٌ يَنْشُدُ ضَالَّةً فِي الْمَسْجِدِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَجَدْتَ","id":"Telah mengabarkan kepada kami [Muhammad bin Wahab] dia berkata; telah menceritakan kepada kami [Muhammad bin Salamah] dari [Abu Abdurrahim] dia berkata; telah menceritakan kepadaku [Zaid bin Abu Unaisah] dari [Abu Zubair] dari [Jabir] dia berkata, \"Seorang laki-laki datang dengan mengumumkan barang yang hilang di masjid, lalu Rasulullah Shallallahu'alaihi wasallam bersabda kepadanya, \"Kiranya engkau tidak menemukannya.\""},"710":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ وَمُحَمَّدُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا سُفْيَانُ قَالَ قُلْتُ لِعَمْرٍو أَسَمِعْتَ جَابِرًا يَقُولُمَرَّ رَجُلٌ بِسِهَامٍ فِي الْمَسْجِدِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْ بِنِصَالِهَا قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abdurrahman] dan [Muhammad bin Manshur] keduanya berkata; telah menceritakan kepada kami [Sufyan] dia berkata; \"Aku berkata kepada [Amru].\"Apakah engkau mendengar [Jabir] berkata, \"Ada seorang laki-laki lewat di masjid yang membawa anak panah, lalu Rasulullah Shallallahu'alaihi wasallam menegurnya, \"Tolong pegang kepala panahnya! ' dia menjawab, 'Ya'.\""},"711":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَدَخَلْتُ أَنَا وَعَلْقَمَةُ عَلَى عَبْدِ اللَّهِ بْنِ مَسْعُودٍ فَقَالَ لَنَا أَصَلَّى هَؤُلَاءِ قُلْنَا لَا قَالَ قُومُوا فَصَلُّوا فَذَهَبْنَا لِنَقُومَ خَلْفَهُ فَجَعَلَ أَحَدَنَا عَنْ يَمِينِهِ وَالْآخَرَ عَنْ شِمَالِهِ فَصَلَّى بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍ فَجَعَلَ إِذَا رَكَعَ شَبَّكَ بَيْنَ أَصَابِعِهِ وَجَعَلَهَا بَيْنَ رُكْبَتَيْهِ وَقَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَأَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ إِبْرَاهِ��مَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ عَنْ عَبْدِ اللَّهِ فَذَكَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Isa bin Yunus] dia berkata; telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dia berkata; \"Aku dan [Alqamah] pernah datang kepada [Abdullah bin Mas'ud], lalu dia berkata kepada kami, 'Apakah kalian telah shalat? ' Kami menjawab, 'Belum'. la berkata lagi, 'Berdirilah dan shalatlah'. Lalu kami shalat di belakangnya, dan beliau menjadikan salah seorang dari kami di samping kanannya dan yang lain disamping kirinya. Kemudian ia shalat tanpa adzan dan iqamah. Setelah ia shalat, maka ia menjalin jari jemari tangannya dan meletakkannya di antara dua lututnya. Ia lalu berkata, 'Beginilah dahulu Rasulullah Shallallahu'alaihi wasallam melakukannya.\" Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [An-Nadlar] dia berkata; Telah memberitakan kepada kami [Syu'bah] dari [Sulaiman] dia berkata; \"Saya mendengar [Ibrahim] dari [AlQamah] dan [Al Aswad] dari [Abdullah] dia menyebutkan seperti Hadis diatas."},"712":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَلْقِيًا فِي الْمَسْجِدِ وَاضِعًا إِحْدَى رِجْلَيْهِ عَلَى الْأُخْرَى","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Abad bin Tamim] dari [Pamannya] bahwa dia pernah melihat Rasulullah Shallallahu'alaihi wasallam telentang di masjid dengan meletakkan salah satu kakinya di alas kaki yang lain."},"713":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ يَنَامُ وَهُوَ شَابٌّ عَزْبٌ لَا أَهْلَ لَهُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dia berkata; Telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] bahwa ia pernah tidur di dalam masjid; dia pemuda lajang yang belum mempunyai istri. Pada masa Rasulullah Shallallahu'alaihi wasallam ia tidur di masjid Nabi Shallallahu'alaihi wasallam."},"714":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبُصَاقُ فِي الْمَسْجِدِ خَطِيئَةٌ وَكَفَّارَتُهَا دَفْنُهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas bin Malik], dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Meludah di dalam masjid merupakan suatu kesalahan, dan kafaratnya (tebusannya) adalah menimbunnya.\""},"715":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى بُصَاقًا فِي جِدَارِ الْقِبْلَةِ فَحَكَّهُ ثُمَّ أَقْبَلَ عَلَى النَّاسِ فَقَالَ إِذَا كَانَ أَحَدُكُمْ يُصَلِّي فَلَا يَبْصُقَنَّ قِبَلَ وَجْهِهِ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ قِبَلَ وَجْهِهِ إِذَا صَلَّى","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah Shallallahu'alaihi wasallam melihat ludah di tembok arah kiblat, maka beliau mengeroknya kemudian menghadap manusia dan berkata, \"Apabila salah seorang dari kalian shalat, jangan meludah/berdahak di hadapannya, sesungguhnya Allah Azza wa Jalla berada di arah wajahnya ketika ia shalat.\""},"716":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى نُخَامَةً فِي قِبْلَةِ الْمَسْجِدِ فَحَكَّهَا بِحَصَاةٍ وَنَهَى أَنْ يَبْصُقَ الرَّجُلُ بَيْنَ يَدَيْهِ أَوْ عَنْ يَمِينِهِ وَقَالَ يَبْصُقُ عَنْ يَسَارِهِ أَوْ تَحْتَ قَدَمِهِ الْيُسْرَى","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az-Zuhri] dari [Humaid bin Abdurrahman] dari [Abu Sa'id Al Khurdri] bahwa Nabi Shallallahu'alaihi wasallam melihat dahak di tembok bagian arah kiblat masjid, maka beliau mengeroknya dengan batu kecil dan melarang untuk meludah di depan atau di samping kanannya. Beliau bersabda, \"Hendaklah ia meludah ke arah kiri atau bawah telapak kaki kirinya.\""},"717":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي مَنْصُورٌ عَنْ رِبْعِيٍّ عَنْ طَارِقِ بْنِ عَبْدِ اللَّهِ الْمُحَارِبِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كُنْتَ تُصَلِّي فَلَا تَبْزُقَنَّ بَيْنَ يَدَيْكَ وَلَا عَنْ يَمِينِكَ وَابْصُقْ خَلْفَكَ أَوْ تِلْقَاءَ شِمَالِكَ إِنْ كَانَ فَارِغًا وَإِلَّا فَهَكَذَا وَبَزَقَ تَحْتَ رِجْلِهِ وَدَلَكَهُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; Telah mengabarkan kepadaku [Manshur] dari [Rib'i] dari [Thariq bin Abdullah Al Muharibi] dia berkata; dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, \"Bila kamu sedang shalat, jangan meludah di hadapanmu dan di sebelah kananmu. Meludahlah di belakang atau di samping kiri kamu jika dalam keadaan kosong. Tetapi jika tidak memungkinkan maka beginilah\" -lantas beliau berludah ke bawah telapak kakinya dan menggosoknya."},"718":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي الْعَلَاءِ بْنِ الشِّخِّيرِ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَنَخَّعَ فَدَلَكَهُ بِرِجْلِهِ الْيُسْرَى","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah] dari [Sa'id Al Jurairi] dari [Abul 'Alla bin As-Syakhir] dari [Bapaknya] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam berdahak lalu menggosoknya dengan kaki kirinya.\""},"719":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَائِذُ بْنُ حَبِيبٍ قَالَ حَدَّثَنَا حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُخَامَةً فِي قِبْلَةِ الْمَسْجِدِ فَغَضِبَ حَتَّى احْمَرَّ وَجْهُهُ فَقَامَتْ امْرَأَةٌ مِنْ الْأَنْصَارِ فَحَكَّتْهَا وَجَعَلَتْ مَكَانَهَا خَلُوقًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَحْسَنَ هَذَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami ['Aidz bin Habib] dia berkata; telah menceritakan kepada kami [Humaid At-Thawil] dari [Anas bin Malik] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam melihat dahak di arah kiblat masjid, maka beliau marah hingga memerah wajahnya, kemudian ada seorang perempuan Anshar yang bangkit untuk menggosoknya dan memberi wangi-wangian di bekas tempat ludah tadi. Rasulullah Shallallahu'alaihi wasallam lalu bersabda. 'Alangkah baiknya ini'.\""},"720":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ عُبَيْدِ اللَّهِ الْغَيْلَانِيُّ بَصْرِيٌّ قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ حَدَّثَنَا سُلَيْمَانُ عَنْ رَبِيعَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدٍ قَالَ سَمِعْتُ أَبَا حُمَيْدٍ وَأَبَا أُسَيْدٍ يَقُولَانِقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَقُلْ اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ فَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ","id":"Telah mengabarkan kepada kami [Sulaiman bin Ubaidullah Al Ghailani Bashri] dia berkata; telah menceritakan kepada kami [Abu 'Amir] dia berkata; telah menceritakan kepada kami [Sulaiman] dari [Rabi'ah] dari [Abdul Malik bin Sa'id] dia berkata; saya mendengar [Abu Humaid] dan [Abu Usaid] keduanya berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian masuk ke dalam masjid, maka hendaklah mengucapkan, 'Ya Allah, bukakan bagiku pintu-pintu rahmat-Mu'. Jika keluar dari masjid, maka hendaklah mengucapkan, 'Ya Allah, aku memohon karunia-Mu'.\""},"721":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مَالِكٌ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَرْكَعْ رَكْعَتَيْنِ قَبْلَ أَنْ يَجْلِسَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Malik] dari [Amir bin Abdullah bin Jubair] dari [Amr bin Sulaim] dari [Abu Qatadah], bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian masuk masjid, hendaklah ia melakukan shalat dua rakaat sebelum duduk.\""},"722":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ قَالَ ابْنُ شِهَابٍ وَأَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ كَعْبِ بْنِ مَالِكٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبٍ قَالَسَمِعْتُ كَعْبَ بْنَ مَالِكٍ يُحَدِّثُ حَدِيثَهُ حِينَ تَخَلَّفَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ قَالَ وَصَبَّحَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَادِمًا وَكَانَ إِذَا قَدِمَ مِنْ سَفَرٍ بَدَأَ بِالْمَسْجِدِ فَرَكَعَ فِيهِ رَكْعَتَيْنِ ثُمَّ جَلَسَ لِلنَّاسِ فَلَمَّا فَعَلَ ذَلِكَ جَاءَهُ الْمُخَلَّفُونَ فَطَفِقُوا يَعْتَذِرُونَ إِلَيْهِ وَيَحْلِفُونَ لَهُ وَكَانُوا بِضْعًا وَثَمَانِينَ رَجُلًا فَقَبِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَانِيَتَهُمْ وَبَايَعَهُمْ وَاسْتَغْفَرَ لَهُمْ وَوَكَلَ سَرَائِرَهُمْ إِلَى اللَّهِ عَزَّ وَجَلَّ حَتَّى جِئْتُ فَلَمَّا سَلَّمْتُ تَبَسَّمَ تَبَسُّمَ الْمُغْضَبِ ثُمَّ قَالَ تَعَالَ فَجِئْتُ حَتَّى جَلَسْتُ بَيْنَ يَدَيْهِ فَقَالَ لِي مَا خَلَّفَكَ أَلَمْ تَكُنِ ابْتَعْتَ ظَهْرَكَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي وَاللَّهِ لَوْ جَلَسْتُ عِنْدَ غَيْرِكَ مِنْ أَهْلِ الدُّنْيَا لَرَأَيْتُ أَنِّي سَأَخْرُجُ مِنْ سَخَطِهِ وَلَقَدْ أُعْطِيتُ جَدَلًا وَلَكِنْ وَاللَّهِ لَقَدْ عَلِمْتُ لَئِنْ حَدَّثْتُكَ الْيَوْمَ حَدِيثَ كَذِبٍ لِتَرْضَى بِهِ عَنِّي لَيُوشَكُ أَنَّ اللَّهَ عَزَّ وَجَلَّ يُسْخِطُكَ عَلَيَّ وَلَئِنْ حَدَّثْتُكَ حَدِيثَ صِدْقٍ تَجِدُ عَلَيَّ فِيهِ إِنِّي لَأَرْجُو فِيهِ عَفْوَ اللَّهِ وَاللَّهِ مَا كُنْتُ قَطُّ أَقْوَى وَلَا أَيْسَرَ مِنِّي حِينَ تَخَلَّفْتُ عَنْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا هَذَا فَقَدْ صَدَقَ فَقُمْ حَتَّى يَقْضِيَ اللَّهُ فِيكَ فَقُمْتُ فَمَضَيْتُ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dia berkata; telah menceritakan kepada kami [Ibnu Wahab] dari [Yunus], [Ibnu Syihab] berkata; Telah mengabarkan kepadaku [Abdurrahman bin Ka'ab bin Malik] bahwa [Abdullah bin Ka'ab] berkata; \"Aku mendengar [Ka'ab bin Malik] menceritakan peristiwanya ketika tertinggal dalam perang Tabuk, dia berkata, 'Rasulullah Shallallahu'alaihi wasallam datang dengan wajah berseri-seri dan kebiasaan beliau jika datang dari perjalanan, beliau langsung ke masjid, lalu shalat dua rakaat. Kemudian duduk-duduk bersama para sahabat. Setelah beliau melakukan hal tersebut. datanglah orang-orang yang tertinggal (dari perang Tabuk ini). Mereka menyampaikan alasannya dan bersumpah kepadanya. Jumlah mereka ada sekitar delapan puluh lebih laki-laki. Rasulullah Shallallahu'alaihi wasallam menerima keterus terangan mereka, membai'atnya, memintakan ampun untuk mereka, serta menyerahkan rahasia (yang ada dalam hati mereka) kepada Allah Azza wa Jalla hingga kemudian aku datang. Setelah aku memberikan salam dan beliau tersenyum dengan senyuman orang yang marah, beliau Shallallahu'alaihi wasallam memanggilku, \"Kemarilah.\" Aku lalu mendekat dan duduk di hadapannya, lantas beliau bertanya lagi kepadaku, \"Apa yang menyebabkanmu tertinggal? Bukankah kamu telah membeli hewan tungganganmu?\" Aku menjawab, \"Wahai Rasulullah Shallallahu'alaihi wasallam, demi Allah, aku kalau duduk bersama selain dirimu dari penduduk bumi ini, pasti aku berkeyakinan bahwa aku bisa terbebas dari murkanya karena aku mempunyai kemampuan berdebat. Akan tetapi, demi Allah, aku mengetahui kalau aku pada hari ini menceritakan suatu cerita dusta agar engkau ridha kepadaku, pasti Allah menciptakan suatu hal yang menjadikan engkau marah kepadaku, sebaliknya seandainya aku ceritakan hal sebenarnya secara blak-blakan yang ada padaku, maka hal itu karena aku sangat mengharap ampunan Allah. Demi Allah, saat aku tertinggal dari engkau, belum pernah aku sekuat dan selapang saat itu.\" Lantas Rasulullah Shallallahu'alaihi wasallam bersabda.\"Orang ini berbuat jujur, hanya pergilah hingga Allah memutuskan perkaramu.\" Lalu aku berdiri dan pergi'.\" (Secara ringkas) "},"723":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ بْنِ أَعَيْنَ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ أَبِي هِلَالٍ قَالَ أَخْبَرَنِي مَرْوَانُ بْنُ عُثْمَانَ أَنَّ عُبَيْدَ بْنَ حُنَيْنٍ أَخْبَرَهُ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّى قَالَكُنَّا نَغْدُو إِلَى السُّوقِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَمُرُّ عَلَى الْمَسْجِدِ فَنُصَلِّي فِيهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakim bin A'ain] dia berkata; telah menceritakan kepada kami [Syu'aib] dia berkata; telah menceritakan kepada kami [Al Laits] dia berkata; telah menceritakan kepada kami [Khalid] dari [Ibnu Abu Hilal] dia berkata; Telah mengabarkan kepadaku [Marwan bin Utsman] bahwa [Ubaid bin Hunain] Telah mengabarkan kepadanya dari [Abu Sa'id bin Al Mu'lla] dia berkata; \"Pada masa Rasulullah Shallallahu'alaihi wasallam, kami pergi ke Pasar, kemudian kami melewati masjid dan shalat di dalamnya.\""},"724":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَلَائِكَةَ تُصَلِّي عَلَى أَحَدِكُمْ مَا دَامَ فِي مُصَلَّاهُ الَّذِي صَلَّى فِيهِ مَا لَمْ يُحْدِثْ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Para malaikat bershalawat (mendoakan) kepada salah seorang dari kalian, selama masih di tempat shalatnya, selama belum batal. Para malaikat mendoakan, 'Ya Allah, ampuni dan rahmatilah dia '.\""},"725":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ عَيَّاشِ بْنِ عُقْبَةَ أَنَّ يَحْيَى بْنَ مَيْمُونٍ حَدَّثَهُ قَالَ سَمِعْتُ سَهْلًا السَّاعِدِيِّ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ فِي الْمَسْجِدِ يَنْتَظِرُ الصَّلَاةَ فَهُوَ فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Bakr bin Mudhar] dari ['Ayyasy bin 'Uqbah] bahwasanya [Yahya bin Maimun] telah menceritakan kepadanya, dia berkata; aku mendengar [Sahl Al Sa'idi Radliyallahu'anhu] dia berkata; \"Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: 'Barangsiapa menunggu waktu shalat di masjid, maka dia (pahalanya seperti) orang yang sedang shalat.\""},"726":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ أَشْعَثَ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ فِي أَعْطَانِ الْإِبِلِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dari [Asy'ats] dari [Al Hasan] dari [Abdullah bin Mughaffal] bahwa Rasulullah Shallallahu'alaihi wasallam melarang shalat di tempat peristirahatan unta. "},"727":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْمَعِيلَ بْنِ سُلَيْمَانَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا سَيَّارٌ عَنْ يَزِيدَ الْفَقِيرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُعِلَتْ لِي الْأَرْضُ مَسْجِدًا وَطَهُورًا أَيْنَمَا أَدْرَكَ رَجُلٌ مِنْ أُمَّتِي الصَّلَاةَ صَلَّى","id":"Telah mengabarkan kepada kami [Al Hasan bin Isma'il bin Sulaiman] dia berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah menceritakan kepada kami [Sayyar] dari [Yazid Al Faqir] dari [Jabir bin Abdullah] dia berkata; dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, \"Bumi dijadikan untukku sebagai masjid dan alat untuk bersuci, maka di mana saja umatku mendapatkan waktu shalat maka hendaklah ia shalat.\""},"728":{"ar":"أَخْبَرَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ أُمَّ سُلَيْمٍ سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْتِيَهَا فَيُصَلِّيَ فِي بَيْتِهَا فَتَتَّخِذَهُ مُصَلًّى فَأَتَاهَا فَعَمِدَتْ إِلَى حَصِيرٍ فَنَضَحَتْهُ بِمَاءٍ فَصَلَّى عَلَيْهِ وَصَلَّوْا مَعَهُ","id":"Telah mengabarkan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwasanya Ummu Sulaim pernah meminta Rasulullah Shallallahu'alaihi wasallam untuk datang kepadanya dan shalat di rumahnya, maka dia menyiapkan tempat shalat untuk Rasulullah Shallallahu'alaihi wasallam. Lalu Rasulullah datang kepada Ummu Sulaim, dan Ummu Sulaim segera menuju tikar, lalu menyiramnya dengan air, maka beliau shalat di atasnya dan mereka (keluarga Ummu Sulaim) shalat bersamanya."},"729":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ يَعْنِي الشَّيْبَانِيَّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ مَيْمُونَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي عَلَى الْخُمْرَةِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Sulaiman Asy Syaibani] dari [Abdullah bin Syaddad] dari [Maimunah] bahwa Rasulullah Shallallahu'alaihi wasallam pernah shalat di atas tikar kecil."},"730":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي أَبُو حَازِمِ بْنُ دِينَارٍأَنَّ رِجَالًا أَتَوْا سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ وَقَدْ امْتَرَوْا فِي الْمِنْبَرِ مِمَّ عُودُهُ فَسَأَلُوهُ عَنْ ذَلِكَ فَقَالَ وَاللَّهِ إِنِّي لَأَعْرِفُ مِمَّ هُوَ وَلَقَدْ رَأَيْتُهُ أَوَّلَ يَوْمٍ وُضِعَ وَأَوَّلَ يَوْمٍ جَلَسَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى فُلَانَةَ امْرَأَةٍ قَدْ سَمَّاهَا سَهْلٌ أَنْ مُرِي غُلَامَكِ النَّجَّارَ أَنْ يَعْمَلَ لِي أَعْوَادًا أَجْلِسُ عَلَيْهِنَّ إِذَا كَلَّمْتُ النَّاسَ فَأَمَرَتْهُ فَعَمِلَهَا مِنْ طَرْفَاءِ الْغَابَةِ ثُمَّ جَاءَ بِهَا فَأُرْسِلَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ بِهَا فَوُضِعَتْ هَا هُنَا ثُمَّ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَقِيَ فَصَلَّى عَلَيْهَا وَكَبَّرَ وَهُوَ عَلَيْهَا ثُمَّ رَكَعَ وَهُوَ عَلَيْهَا ثُمَّ نَزَلَ الْقَهْقَرَى فَسَجَدَ فِي أَصْلِ الْمِنْبَرِ ثُمَّ عَادَ فَلَمَّا فَرَغَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّمَا صَنَعْتُ هَذَا لِتَأْتَمُّوا بِي وَلِتَعَلَّمُوا صَلَاتِي","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Ya'qub bin 'Abdurrahman] dia berkata; telah menceritakan kepadaku [Abu Hazim bin Dinar] bahwasanya beberapa orang laki-laki mendatangi Sahl bin Sa'd As-Sa'idi dan mereka berdebat tentang kayu yang digunakan untuk membuat mimbar; Mereka bertanya tentang hal itu. [Sahal bin Sa'ad] berkata, \"Demi Allah, aku mengetahui jenis kayu yang digunakan untuk membuat mimbar itu. Aku pernah melihat pada hari pembuatannya dan pada hari pertama Rasulullah Shallallahu'alaihi wasallam duduk di atasnya. Rasulullah Shallallahu'alaihi wasallam pernah mengutus seseorang kepada Fulanah -perempuan yang namanya disebutkan oleh Sahal- dan dikatakan kepadanya, 'Suruh budakmu si tukang kayu agar membuatkan kayu-kayu untuk tempat dudukku bila sedang berbicara dengan orang banyak'. Lalu perempuan itu menyuruhnya membuatnya dari kayu hutan. Kemudian orang ini membawanya kepada Rasulullah Shallallahu'alaihi wasallam, dan beliau Shallallahu'alaihi wasallam menyuruhnya meletakkannya di sini. Setelah itu aku melihat Rasulullah Shallallahu'alaihi wasallam naik ke atas mimbar tersebut lalu shalat di atasnya. Beliau bertakbir di atas mimbar kemudian ruku', juga masih di atasnya. Lantas beliau turun sambil mundur, kemudian sujud di dasar mimbar, dan kembali lagi. Setelah selesai shalat beliau menghadap kepada manusia dan bersabda, 'Wahai manusia, aku berbuat demikian agar kalian mengikutiku dan mempelajari shalatku '.\""},"731":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ ابْنِ عُمَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى حِمَارٍ وَهُوَ مُتَوَجِّهٌ إِلَى خَيْبَرَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari ['Amr bin Yahya] dari [Sa'id bin Yasar] dari [Ibnu 'Umar] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam shalat di atas keledai saat beliau menuju Khaibar.\""},"732":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عُمَرَ قَالَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى حِمَارٍ وَهُوَ رَاكِبٌ إِلَى خَيْبَرَ وَالْقِبْلَةُ خَلْفَهُقَالَ أَبُو عَبْد الرَّحْمَنِ لَا نَعْلَمُ أَحَدًا تَابَعَ عَمْرَو بْنَ يَحْيَى عَلَى قَوْلِهِ يُصَلِّي عَلَى حِمَارٍ وَحَدِيثُ يَحْيَى بْنِ سَعِيدٍ عَنْ أَنَسٍ الصَّوَابُ مَوْقُوفٌ وَاللَّهُ سُبْحَانَهُ وَتَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Isma'il bin 'Umar] dia berkata; telah menceritakan kepada kami [Dawud bin Qais] dari [Muhammad bin 'Ajlan] dari [Yahya bin Sa'id] dari [Anas bin Malik] bahwa dia pernah melihat Rasulullah Shallallahu'alaihi wasallam shalat di atas keledai saat beliau mengendarainya ke arah Khaibar, sedangkan kiblat di belakangnya. Abu Abdurrahman berkata; kami tidak mengetahui seorangpun yang mengikuti Amr bin Yahya atas ucapannya \"Beliau shalat di atas keledai\" dan mengenai Hadis Yahya bin Sa'id yang benar adalah Hadisnya mauquf. Wallahu Subhanahu wa Ta'ala A'lam."},"733":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ فَصَلَّى نَحْوَ بَيْتِ الْمَقْدِسِ سِتَّةَ عَشَرَ شَهْرًا ثُمَّ وُجِّهَ إِلَى الْكَعْبَةِ فَمَرَّ رَجُلٌ قَدْ كَانَ صَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى قَوْمٍ مِنْ الْأَنْصَارِ فَقَالَ أَشْهَدُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ وُجِّهَ إِلَى الْكَعْبَةِ فَانْحَرَفُوا إِلَى الْكَعْبَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] dari [Zakaria bin Abu Zaidah] dari [Abu Ishaq] dari [Al Barra bin 'Azib] dia berkata; -'Ketika Rasulullah Shallallahu'alaihi wasallam baru datang ke Madinah, beliau Shallallahu'alaihi wasallam shalat menghadap ke arah Baitul Maqdis sekitar enam belas bulan, lalu dialihkan ke kiblat (Ka'bah). Ada seseorang yang (selesai shalat bersama Rasulullah Shallallahu'alaihi wasallam) melewati sekelompok kalangan Anshar, kemudian ia berkata, 'Aku menyaksikan Rasulullah Shallallahu'alaihi wasallam telah dialihkan kiblatnya ke Ka'bah'. Lalu orang-orang segera beralih ke Ka' bah.\""},"734":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ فِي السَّفَرِ حَيْثُمَا تَوَجَّهَتْقَالَ مَالِكٌ قَالَ عَبْدُ اللَّهِ بْنُ دِينَارٍ وَكَانَ ابْنُ عُمَرَ يَفْعَلُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik bin Anas] dari [Abdullah bin Dinar] dari [Ibnu 'Umar] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam shalat di atas kendaraannya dalam suatu perjalanan. Beliau menghadap ke arah kendaraannya mengarah.\" Malik berkata; Abdullah bin Dinar berkata; \"Dahulu Ibnu Umar juga melakukan hal yang sama.\""},"735":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى الرَّاحِلَةِ قِبَلَ أَيِّ وَجْهٍ تَوَجَّهُ بِهِ وَيُوتِرُ عَلَيْهَا غَيْرَ أَنَّهُ لَا يُصَلِّي عَلَيْهَا الْمَكْتُوبَةَ","id":"Telah mengabarkan kepada kami ['Isa bin Hammad] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim] dari [Abdullah] dia berkata; \"'Rasulullah Shallallahu'alaihi wasallam shalat di atas hewan kendaraannya menghadap mana saja hewan tunggangannya mengarah. la juga mengerjakan shalat witir di atas kendaraannya, tetapi beliau tidak mengerjakan shalat wajib di atas kendaraannya.\""},"736":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَبَيْنَمَا النَّاسُ بِقُبَاءَ فِي صَلَاةِ الصُّبْحِ جَاءَهُمْ آتٍ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أُنْزِلَ عَلَيْهِ اللَّيْلَةَ قُرْآنٌ وَقَدْ أُمِرَ أَنْ يَسْتَقْبِلَ الْقِبْلَةَ فَاسْتَقْبِلُوهَا وَكَانَتْ وُجُوهُهُمْ إِلَى الشَّامِ فَاسْتَدَارُوا إِلَى الْكَعْبَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abdullah bin Dinar] dari [Ibnu 'Umar] dia berkata, \"Tatkala orang-orang berada di Quba' saat shalat Subuh, datang seseorang lalu berkata, 'Rasulullah Shallallahu'alaihi wasallam pada malam ini mendapat wahyu, beliau diperintahkan menghadap ke Ka'bah'. Mereka pun segera beralih ke Ka'bah, padahal sebelumnya wajah-wajah mereka menghadap ke Syam (Baitul Maqdis) '.\""},"737":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ قَالَ حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ عَنْ سُتْرَةِ الْمُصَلِّي فَقَالَ مِثْلُ مُؤْخِرَةِ الرَّحْلِ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin Muhammad Abdullah-Duriy] dia berkata; telah menceritakan kepada kami [Abdullah bin Yazid] dia berkata; telah menceritakan kepada kami [Haiwah bin Syuraih] dari [Abul Aswad] dari ['Urwah] dari ['Aisyah Radliyallahu'anha], dia berkata, 'Rasulullah Shallallahu'alaihi wasallam pernah ditanya saat perang Tabuk tentang sutrah (pembatas) bagi orang yang sedang shalat, lalu beliau Shallallahu'alaihi wasallam menjawab, `Seperti kayu yang dijadikan sandaran di belakang pelana'.\""},"738":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَنْبَأَنَا نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ يَرْكُزُ الْحَرْبَةَ ثُمَّ يُصَلِّي إِلَيْهَا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dia berkata; telah memberitakan kepada kami [Nafi'] dari [Ibnu 'Umar] dari Rasulullah Shallallahu'alaihi wasallam, beliau bersabda, \"Beliau dahulu (kalau hendak Shalat) menancapkan tombak pendek, lalu shalat di belakang (menghadap) tombak tersebut.\""},"739":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ وَإِسْحَقُ بْنُ مَنْصُورٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ إِلَى سُتْرَةٍ فَلْيَدْنُ مِنْهَا لَا يَقْطَعَ الشَّيْطَانُ عَلَيْهِ صَلَاتَهُ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dan [Ishaq bin Manshur] mereka berdua berkata; telah menceritakan kepada kami [Sufyan] dari [Shafwan bin Sulaim] dari [Nafi' bin Jubair] dari [Sahl bin Abu Hatsmah] dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika salah seorang dari kalian shalat menghadap ke arah Sutrah (pembatas) maka mendekatlah kepadanya, agar setan tidak memutus shalatnya.\""},"740":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْكَعْبَةَ هُوَ وَأُسَامَةُ بْنُ زَيْدٍ وَبِلَالٌ وَعُثْمَانُ بْنُ طَلْحَةَ الْحَجَبِيُّ فَأَغْلَقَهَا عَلَيْهِ قَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ فَسَأَلْتُ بِلَالًا حِينَ خَرَجَ مَاذَا صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَعَلَ عَمُودًا عَنْ يَسَارِهِ وَعَمُودَيْنِ عَنْ يَمِينِهِ وَثَلَاثَةَ أَعْمِدَةٍ وَرَاءَهُ وَكَانَ الْبَيْتُ يَوْمَئِذٍ عَلَى سِتَّةِ أَعْمِدَةٍ ثُمَّ صَلَّى وَجَعَلَ بَيْنَهُ وَبَيْنَ الْجِدَارِ نَحْوًا مِنْ ثَلَاثَةِ أَذْرُعٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan aku mendengarnya dari [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Abdullah bin 'Umar] bahwa Rasulullah Shallallahu'alaihi wasallam pernah masuk Ka'bah bersama Usamah bin Zaid, Bilal dan Utsman bin Thalhah. lalu mereka menutupnya. Ibnu Umar berkata, \"Lalu aku bertanya kepada [Bilal]. 'Apakah yang diperbuat oleh Rasulullah Shallallahu'alaihi wasallam? ' la menjawab, 'Beliau Shallallahu'alaihi wasallam memposisikan satu tiang di samping kiri, dua tiang di samping kanannya, dan tiga tiang di belakangnya. Ka'bah saat itu mempunyai enam tiang. Kemudian beliau Shallallahu'alaihi wasallam Shalat, dan diantara beliau dengan tembok jaraknya sekitar 3 hasta'.\""},"741":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا يَزِيدُ قَالَ حَدَّثَنَا يُونُسُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ أَحَدُكُمْ قَائِمًا يُصَلِّي فَإِنَّهُ يَسْتُرُهُ إِذَا كَانَ بَيْنَ يَدَيْهِ مِثْلُ آخِرَةِ الرَّحْلِ فَإِنْ لَمْ يَكُنْ بَيْنَ يَدَيْهِ مِثْلُ آخِرَةِ الرَّحْلِ فَإِنَّهُ يَقْطَعُ صَلَاتَهُ الْمَرْأَةُ وَالْحِمَارُ وَالْكَلْبُ الْأَسْوَدُ قُلْتُ مَا بَالُ الْأَسْوَدِ مِنْ الْأَصْفَرِ مِنْ الْأَحْمَرِ فَقَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا سَأَلْتَنِي فَقَالَ الْكَلْبُ الْأَسْوَدُ شَيْطَانٌ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah memberitakan kepada kami [Yazid] dia berkata; telah menceritakan kepada kami [Yunus] dari [Humaid bin Hilal] dari [Abdullah bin Ash-Shamit] dari [Abu Dzarr] dia berkata; Apabila salah seorang diantara kalian shalat, hendaknya dia membuat pembatas di hadapannya seperti kayu yang dijadikan sandaran di belakang pelana. Karena kalau tidak ada pembatasnya, shalatnya akan terputus apabila lewat di hadapannya seorang perempuan, keledai dan anjing hitam. Lalu aku bertanya kepada Abu Dzar, kenapa yang berwarna hitam, bagaimana dengan warna kuning atau merah? Dia menjawab, \"Saya pernah bertanya kepada Rasulullah Shallallahu'alaihi wasallam sebagaimana yang anda tanyakan kepadaku, dan beliau Shallallahu'alaihi wasallam menjawab; Anjing hitam adalah setan.\""},"742":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنِي شُعْبَةُ وَهِشَامٌ عَنْ قَتَادَةَ قَالَقُلْتُ لِجَابِرِ بْنِ زَيْدٍ مَا يَقْطَعُ الصَّلَاةَ قَالَ كَانَ ابْنُ عَبَّاسٍ يَقُولُ الْمَرْأَةُ الْحَائِضُ وَالْكَلْبُقَالَ يَحْيَى رَفَعَهُ شُعْبَةُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepadaku [Syu'bah] dan [Hisyam] dari [Qatadah] dia berkata; aku bertanya kepada [Jabir bin Zaid] apa yang bisa memutus shalat? Dia menjawab, [Ibnu Abbas] pernah berkata; yang bisa memutus shalat adalah perempuan yang haidl, dan anjing. Yahya berkata; Hadis ini telah dimarfukan oleh Syu'bah."},"743":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ قَالَ حَدَّثَنَا الزُّهْرِيُّ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَجِئْتُ أَنَا وَالْفَضْلُ عَلَى أَتَانٍ لَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِالنَّاسِ بِعَرَفَةَ ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا فَمَرَرْنَا عَلَى بَعْضِ الصَّفِّ فَنَزَلْنَا وَتَرَكْنَاهَا تَرْتَعُ فَلَمْ يَقُلْ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dia berkata; telah menceritakan kepada kami [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Ubaidullah] dari [Ibnu 'Abbas] dia berkata; \"Aku dan Fadl datang dengan naik keledai betina milik kami, dan saat itu Rasulullah Shallallahu'alaihi wasallam sedang shalat bersama orang-orang di Arafah -kemudian dia menyebutkan beberapa kalimat yang maknanya adalah- Maka kami melewati sebagian shaf shalat, lalu kami segera turun dan kami biarkan saja keledai itu makan rumput. Rasulullah Shallallahu'alaihi wasallam juga tidak menegur kami sedikitpun.\""},"744":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيٍّ عَنْ عَبَّاسِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ الْفَضْلِ بْنِ الْعَبَّاسِ قَالَزَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبَّاسًا فِي بَادِيَةٍ لَنَا وَلَنَا كُلَيْبَةٌ وَحِمَارَةٌ تَرْعَى فَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ وَهُمَا بَيْنَ يَدَيْهِ فَلَمْ يُزْجَرَا وَلَمْ يُؤَخَّرَا","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Khalid] dia berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Muhammad bin 'Umar bin 'Ali] dari ['Abbas bin 'Ubaidullah bin 'Abbas] dari [Al Fadhl bin 'Abbas] dia berkata; Rasulullah Shallallahu'alaihi wasallam mengunjungi Abbas di kampung kami, dan kami memelihara seekor anjing kecil dan keledai. Lalu Rasulullah Shallallahu'alaihi wasallam shalat Ashar sedangkan dihadapannya anjing dan keledai itu, beliau tidak menghardiknya dan tidak pula menyuruhnya untuk mundur."},"745":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ أَنَّ الْحَكَمَ أَخْبَرَهُ قَالَ سَمِعْتُ يَحْيَى بْنَ الْجَزَّارِ يُحَدِّثُ عَنْ صُهَيْبٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يُحَدِّثُأَنَّهُ مَرَّ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ وَغُلَامٌ مِنْ بَنِي هَاشِمٍ عَلَى حِمَارٍ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَنَزَلُوا وَدَخَلُوا مَعَهُ فَصَلَّوْا وَلَمْ يَنْصَرِفْ فَجَاءَتْ جَارِيَتَانِ تَسْعَيَانِ مِنْ بَنِي عَبْدِ الْمُطَّلِبِ فَأَخَذَتَا بِرُكْبَتَيْهِ فَفَرَعَ بَيْنَهُمَا وَلَمْ يَنْصَرِفْ","id":"Telah mengabarkan kepada kami [Abul Asy'ats] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] bahwasanya [Al Hakim] mengabarkan kepadanya, dia berkata; aku mendengar [Yahya bin Al Jazzar] menceritakan dari [Shuhaib] dia berkata; \"Aku mendengar [Ibnu Abbas] menceritakan bahwa ia pernah lewat di depan Rasulullah Shallallahu'alaihi wasallam bersama anak kecil dari Bani Hasyim dengan mengendarai seekor keledai. dan Rasulullah Shallallahu'alaihi wasallam saat itu sedang mengerjakan shalat. Lalu mereka turun dan masuk bersamanya, kemudian shalat dan beliau belum selesai. Kemudian datanglah dua anak perempuan dari Bani Abdul Muththalib, lantas keduanya berpegangan kedua lututnya, maka beliau Shallallahu'alaihi wasallam menghalangi keduanya dan beliau belum beranjak"},"746":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَإِذَا أَرَدْتُ أَنْ أَقُومَ كَرِهْتُ أَنْ أَقُومَ فَأَمُرَّ بَيْنَ يَدَيْهِ انْسَلَلْتُ انْسِلَالًا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] Radliyallahu'anha, dia berkata, \"Aku di hadapan Rasulullah Shallallahu'alaihi wasallam yang sedang shalat, dan bila aku hendak bangun aku tidak suka untuk bangun, maka aku melewati depannya dan keluar dengan sembunyi-sembunyi.\""},"747":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍأَنَّ زَيْدَ بْنَ خَالِدٍ أَرْسَلَهُ إِلَى أَبِي جُهَيْمٍ يَسْأَلُهُ مَاذَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الْمَارِّ بَيْنَ يَدَيْ الْمُصَلِّي فَقَالَ أَبُو جُهَيْمٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ يَعْلَمُ الْمَارُّ بَيْنَ يَدَيْ الْمُصَلِّي مَاذَا عَلَيْهِ لَكَانَ أَنْ يَقِفَ أَرْبَعِينَ خَيْرًا لَهُ مِنْ أَنْ يَمُرَّ بَيْنَ يَدَيْهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu An Nadhr] dari [Busr bin Sa'id] bahwasanya Zaid bin Khalid mengutusnya kepada Abu Juhaim, ia lalu bertanya, \"Apa yang kamu dengar dari Rasulullah Shallallahu'alaihi wasallam tentang orang yang lewat di depan orang yang sedang shalat?\" [Abu Juhaim] mengatakan bahwa Rasulullah Shallallahu'alaihi wasallam bersabda; \"Andai orang yang lewat di depan orang yang sedang shalat mengetahui akibatnya, maka ia pasti akan berdiri empat puluh lebih baik daripada berlalu di hadapan orang yang sedang shalat."},"748":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ أَحَدُكُمْ يُصَلِّي فَلَا يَدَعْ أَحَدًا أَنْ يَمُرَّ بَيْنَ يَدَيْهِ فَإِنْ أَبَى فَلْيُقَاتِلْهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Zaid bin Aslam] dari ['Abdurrahman bin Abu Sa'id] dari [Abu Sa'id] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika salah seorang dari kalian shalat, jangan biarkan orang lewat di hadapannya. Jika ia tetap bersikukuh (untuk lewat depannya), hendaklah dia perangi.\""},"749":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَبْدِ الْعَزِيزِ بْنِ جُرَيْجٍ عَنْ كَثِيرِ بْنِ كَثِيرٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ بِالْبَيْتِ سَبْعًا ثُمَّ صَلَّى رَكْعَتَيْنِ بِحِذَائِهِ فِي حَاشِيَةِ الْمَقَامِ وَلَيْسَ بَيْنَهُ وَبَيْنَ الطُّوَّافِ أَحَدٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Isa bin Yunus] dia berkata; telah menceritakan kepada kami [Abdul Malik bin Abdul 'Aziz bin Juraij] dari [Katsir bin Katsir] dari [Bapaknya] dari [kakeknya], dia berkata; 'Kami melihat Rasulullah Shallallahu'alaihi wasallam thawaf di Ka'bah tujuh kali, kemudian beliau shalat dua raka'at dengan memakai sepatunya di ujung Maqam Ibarahim, dan tidak ada seorangpun bersamanya ketika beliau thawaf."},"750":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ حَدَّثَنَا أَبِي عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ وَأَنَا رَاقِدَةٌ مُعْتَرِضَةٌ بَيْنَهُ وَبَيْنَ الْقِبْلَةِ عَلَى فِرَاشِهِ فَإِذَا أَرَادَ أَنْ يُوتِرَ أَيْقَظَنِي فَأَوْتَرْتُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Hisyam] dia berkata; [bapakku] telah menceritakan kepada kami dari ['Aisyah] Radliyallahu'anha, dia berkata; \"Dulu Rasululluh Shallallahu'alaihi wasallam shalat pada waktu malam, sedangkan aku sedang tidur terlentang di atas kasurnya di antara beliau Shallallahu'alaihi wasallam dan kiblat, dan jika beliau hendak witir maka heliau Shallallahu'alaihi wasallam membangunkanku hingga aku juga shalat witir.\""},"751":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ ابْنِ جَابِرٍ عَنْ بُسْرِ بْنِ عُبَيْدِ اللَّهِ عَنْ وَاثِلَةَ بْنِ الْأَسْقَعِ عَنْ أَبِي مَرْثَدٍ الْغَنَوِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُصَلُّوا إِلَى الْقُبُورِ وَلَا تَجْلِسُوا عَلَيْهَا","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Al Walid] dari [Ibnu Jabir] dari [Busr bin 'Ubaidulah] dari [Watsilah bin Al Asqa'] dari [Abu Martsad Al Ghanawi] dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Janganlah kalian shalat menghadap kuburan dan janganlah kalian duduk di atasnya.\""},"752":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ قَالَ سَمِعْتُ الْقَاسِمَ يُحَدِّثُ عَنْ عَائِشَةَ قَالَتْكَانَ فِي بَيْتِي ثَوْبٌ فِيهِ تَصَاوِيرُ فَجَعَلْتُهُ إِلَى سَهْوَةٍ فِي الْبَيْتِ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَيْهِ ثُمَّ قَالَ يَا عَائِشَةُ أَخِّرِيهِ عَنِّي فَنَزَعْتُهُ فَجَعَلْتُهُ وَسَائِدَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la Ash-Shan'ani] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Abdurrahman bin Al Qasim] dia berkata; aku mendengar [Al Qasim] menceritakan dari ['Aisyah] Radliyallahu'anha, dia berkata; \"Dahulu di rumahku ada kain yang bergambar, maka aku jadikan sebagai gorden/tirai. Namun ketika Rasulullah Shallallahu'alaihi wasallam shalat menghadap ke arahnya, beliau berkata, 'Wahai Aisyah, palingkan dariku dan lepaslah'. Kemudian aku melepaskan kain itu dan aku jadikan bantal.\""},"753":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَصِيرَةٌ يَبْسُطُهَا بِالنَّهَارِ وَيَحْتَجِرُهَا بِاللَّيْلِ فَيُصَلِّي فِيهَا فَفَطَنَ لَهُ النَّاسُ فَصَلَّوْا بِصَلَاتِهِ وَبَيْنَهُ وَبَيْنَهُمْ الْحَصِيرَةُ فَقَالَ اكْلَفُوا مِنْ الْعَمَلِ مَا تُطِيقُونَ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يَمَلُّ حَتَّى تَمَلُّوا وَإِنَّ أَحَبَّ الْأَعْمَالِ إِلَى اللَّهِ عَزَّ وَجَلَّ أَدْوَمُهُ وَإِنْ قَلَّ ثُمَّ تَرَكَ مُصَلَّاهُ ذَلِكَ فَمَا عَادَ لَهُ حَتَّى قَبَضَهُ اللَّهُ عَزَّ وَجَلَّ وَكَانَ إِذَا عَمِلَ عَمَلًا أَثْبَتَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sa'id Al Maqburi] dari [Abu Salamah] dari ['Aisyah] dia berkata; \"Dahulu Rasulullah Shallallahu'alaihi wasallam mempunyai sebuah tikar yang biasa beliau bentangkan pada siang hari dan beliau jadikan seperti kamar (agar beliau bisa shalat seleluasa panjangnya dan tidak ditiru sahabatnya) pada malam hari, lalu beliau shalat padanya. Kemudian para sahabatnya paham hal ini (shalat beliau yang sedemikian dahsyat panjangnya), maka mereka shalat dan diantara beliau Shallallahu'alaihi wasallam dengan mereka ada tikar. Hingga beliau bersabda, 'Kerjakanlah amalan itu sesuai yang kalian mampu. Sesungguhnya Allah Azza wa Jalla tidak pernah jenuh hingga kalian merasa jenuh. Sesungguhnya perbuatan yang paling disukai Allah Azza wa Jalla adalah yang berkesinambungan, walaupun sedikit'. Kemudian beliau meninggalkan tempat shalat tersebut dan tidak kembali lagi hingga beliau Shallallahu'alaihi wasallam wafat. Adalah Rasulullah Shallallahu'alaihi wasallam jika melakukan suatu perbuatan maka beliau melakukannya secara terus-menerus\"."},"754":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ سَائِلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّلَاةِ فِي الثَّوْبِ الْوَاحِدِ فَقَالَ أَوَلِكُلِّكُمْ ثَوْبَانِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa ada Seseorang yang bertanya kepada Rasulullah Shallallahu'alaihi wasallam tentang shalat dengan satu pakaian, lalu beliau Shallallahu'alaihi wasallam bersabda, \"Apakah tiap-tiap kalian mempunyai dua pakaian?\""},"755":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي ثَوْبٍ وَاحِدٍ فِي بَيْتِ أُمِّ سَلَمَةَ وَاضِعًا طَرَفَيْهِ عَلَى عَاتِقَيْهِ","id":"Telah mengkabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Umar bin Abu Salamah] bahwa ia pernah melihat Rasulullah Shallallahu'alaihi wasallam shalat dengan memakai satu kain di rumah Ummu Salamah, dan kedua ujung kain itu diikat di leher beliau."},"756":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْعَطَّافُ عَنْ مُوسَى بْنِ إِبْرَاهِيمَ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي لَأَكُونُ فِي الصَّيْدِ وَلَيْسَ عَلَيَّ إِلَّا الْقَمِيصُ أَفَأُصَلِّي فِيهِ قَالَ وَزُرَّهُ عَلَيْكَ وَلَوْ بِشَوْكَةٍ","id":"Telah mengkabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al 'Aththaf] dari [Musa bin Ibrahim] dari [Salamah bin Al Akwa'] dia berkata; \"Aku bertanya kepada Rasulullah Shallallahu'alaihi wasallam. 'Wahai Rasulullah Shallallahu'alaihi wasallam, aku pernah berburu, sedangkan saat itu aku hanya mempunyai satu baju, jadi apakah aku boleh shalat dengannya? ' Beliau Shallallahu'alaihi wasallam menjawab, 'Yang penting kancingkan baju itu walau hanya dengan duri '.\""},"757":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَكَانَ رِجَالٌ يُصَلُّونَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَاقِدِينَ أُزْرَهُمْ كَهَيْئَةِ الصِّبْيَانِ فَقِيلَ لِلنِّسَاءِ لَا تَرْفَعْنَ رُءُوسَكُنَّ حَتَّى يَسْتَوِيَ الرِّجَالُ جُلُوسًا","id":"Telah mengkabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; telah menceritakan kepadaku [Abu Hazim] dari [Sahl bin Sa'd] dia berkata; \"Para sahabat shalat bersama Rasulullah Shallallahu'alaihi wasallam dengan mengikatkan kain mereka seperti yang dilakukan oleh anak-anak. Kemudian dikatakan kepada para wanita, 'Janganlah kalian mengangkat kepala kalian hingga semua laki-laki duduk dengan sempurna..\""},"758":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا عَاصِمٌ عَنْ عَمْرِو بْنِ سَلَمَةَ قَالَلَمَّا رَجَعَ قَوْمِي مِنْ عِنْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا إِنَّهُ قَالَ لِيَؤُمَّكُمْ أَكْثَرُكُمْ قِرَاءَةً لِلْقُرْآنِ قَالَ فَدَعَوْنِي فَعَلَّمُونِي الرُّكُوعَ وَالسُّجُودَ فَكُنْتُ أُصَلِّي بِهِمْ وَكَانَتْ عَلَيَّ بُرْدَةٌ مَفْتُوقَةٌ فَكَانُ��ا يَقُولُونَ لِأَبِي أَلَا تُغَطِّي عَنَّا اسْتَ ابْنِكَ","id":"Telah mengkabarkan kepada kami [Syu'aib bin Yusuf] dia berkata; telah menceritakan kepada kami [Yazid bin Harun] dia berkata; telah memberitakan kepada kami ['Ashim] dari ['Amr bin Salamah] dia berkata; \"Tatkala kaumku pulang dari sisi Rasulullah Shallallahu'alaihi wasallam. mereka mengatakan bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, 'yang menjadi imam shalat kalian adalah yang paling banyak hapal Al Qur'an.\" Amru berkata lagi, \"Mereka mengajak kami dan mengajari kami cara ruku' dan sujud. Dulu aku shalat bersama mereka, sedangkan aku hanya memakai selimut yang banyak lubangnya, lantas mereka berkata kepada ayahku, 'Kenapa kamu tidak menutup pantat anakmu sehingga kami tidak melihatnya? "},"759":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِاللَّيْلِ وَأَنَا إِلَى جَنْبِهِ وَأَنَا حَائِضٌ وَعَلَيَّ مِرْطٌ بَعْضُهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengkabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Thalhah bin Yahya] dari ['Ubaidullah bin Abdullah] dari ['Aisyah] dia berkata; \"Dulu Rasulullah Shallallahu'alaihi wasallam shalat pada malam hari dan aku berada di sampingnya, padahal saat itu aku sedang haid dan aku memakai kain tanpa jahitan yang sebagiannya ada pada Rasulullah Shallallahu'alaihi wasallam.\""},"760":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُصَلِّيَنَّ أَحَدُكُمْ فِي الثَّوْبِ الْوَاحِدِ لَيْسَ عَلَى عَاتِقِهِ مِنْهُ شَيْءٌ","id":"Telah mengkabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Abu Az-Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda, \"Janganlah salah seorang dari kalian shalat dengan satu kain, yang kain tersebut di lehernya sama sekali tak ada apa-apanya (tidak ada pengikat, kancing, benik pengikat).\""},"761":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَعِيسَى بْنُ حَمَّادٍ زُغْبَةُ عَنْ اللَّيْثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَأُهْدِيَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُّوجُ حَرِيرٍ فَلَبِسَهُ ثُمَّ صَلَّى فِيهِ ثُمَّ انْصَرَفَ فَنَزَعَهُ نَزْعًا شَدِيدًا كَالْكَارِهِ لَهُ ثُمَّ قَالَ لَا يَنْبَغِي هَذَا لِلْمُتَّقِينَ","id":"Telah mengkabarkan kepada kami [Qutaibah] dan ['Isa bin Hammad Zughbah] dari [Al Laits] dari [Yazid bin Abu Habib] dari [Abul Khair] dari ['Uqbah bin 'Amir] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam diberi hadiah sejenis pakaian luar dari sutra, dan beliau Shallallahu'alaihi wasallam memakainya ketika shalat. Selesai shalat, beliau segera menanggalkannya dengan cepat seperti tidak menyukainya. Kemudian beliau bersabda, 'Pakaian ini bukan untuk orang-orang yang bertakwa'.\""},"762":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَاللَّفْظُ لَهُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي خَمِيصَةٍ لَهَا أَعْلَامٌ ثُمَّ قَالَ شَغَلَتْنِي أَعْلَامُ هَذِهِ اذْهَبُوا بِهَا إِلَى أَبِي جَهْمٍ وَأْتُونِي بِأَنْبِجَانِيِّهِ","id":"Telah mengkabarkan kepada kami [Ishaq bin Ibrahim] dan [Qutaibah bin Sa'id] -dan lafadz ini baginya- dari [Sufyan] dari [Az Zuhri] dari ['Urwah bin Az-Zubair] dari ['Aisyah] dia berkata, \"Nabi Shallallahu'alaihi wasallam pernah shalat dengan memakai pakaian bercorak/berbatik. Kemudian beliau Shallallahu'alaihi wasallam bersabda: \"Aku merasa terganggu dengan corak baju ini. Bawalah baju ini kepada Abu Jahm dan ambilkan untukku baju lain yang tidak bercorak/berbatik.\""},"763":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فِي حُلَّةٍ حَمْرَاءَ فَرَكَزَ عَنَزَةً فَصَلَّى إِلَيْهَا يَمُرُّ مِنْ وَرَائِهَا الْكَلْبُ وَالْمَرْأَةُ وَالْحِمَارُ","id":"Telah mengkabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Aun bin Abu Juhaifah] dari [Bapaknya], bahwa Rasulullah Shallallahu'alaihi wasallam keluar dengan pakaian berwarna merah. lalu beliau menancapkan sebuah tongkat kecil dan beliau shalat ke arah tongkat tersebut, lalu ada anjing, perempuan, dan keledai yang lewat di belakang tongkat tersebut."},"764":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا جَابِرُ بْنُ صُبْحٍ قَالَ سَمِعْتُ خِلَاسَ بْنَ عَمْرٍو يَقُولُ سَمِعْتُ عَائِشَةَ تَقُولُكُنْتُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبُو الْقَاسِمِ فِي الشِّعَارِ الْوَاحِدِ وَأَنَا حَائِضٌ طَامِثٌ فَإِنْ أَصَابَهُ مِنِّي شَيْءٌ غَسَلَ مَا أَصَابَهُ لَمْ يَعْدُهُ إِلَى غَيْرِهِ وَصَلَّى فِيهِ ثُمَّ يَعُودُ مَعِي فَإِنْ أَصَابَهُ مِنِّي شَيْءٌ فَعَلَ مِثْلَ ذَلِكَ لَمْ يَعْدُهُ إِلَى غَيْرِهِ","id":"Telah mengkabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami [Hisyam bin Abdul Malik] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Jabir bin Shubh] dia berkata; aku mendengar [Khilash bin 'Amr] berkata; aku mendengar ['Aisyah] berkata; \"Aku pernah tidur bersama Rasulullah Shallallahu'alaihi wasallam -alias Abu Al Qasim- dalam satu selimut, sedangkan aku sedang haid. Jika beliau terkena sesuatu dariku, maka beliau membasuh tempat yang terkena tadi dan tidak melebihinya, kemudian beliau shalat dengan selimut tadi. Lalu beliau kembali lagi, dan jika beliau terkena sesuatu dariku maka beliau melakukan hal seperti sebelumnya dan tidak melebihinya, lalu shalat dengan selimut tersebut.\""},"765":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامٍ قَالَرَأَيْتُ جَرِيرًا بَالَ ثُمَّ دَعَا بِمَاءٍ فَتَوَضَّأَ وَمَسَحَ عَلَى خُفَّيْهِ ثُمَّ قَامَ فَصَلَّى فَسُئِلَ عَنْ ذَلِكَ فَقَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ مِثْلَ هَذَا","id":"Telah mengkabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari [Hammam] dia berkata; Aku melihat [Jarir] buang air kecil lalu meminta air, kemudian berwudhu dan mengusap sepasang sepatunya (khuff), lalu berdiri dan mengerjakan shalat. Kemudian beliau ditanya (tentang perbuatannya tadi, maka ia menjawab. 'Aku melihat Rasulullah Shallallahu'alaihi wasallam melakukan hal seperti ini.\""},"766":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ يَزِيدَ بْنِ زُرَيْعٍ وَغَسَّانَ بْنِ مُضَرَ قَالَا حَدَّثَنَا أَبُو مَسْلَمَةَ وَاسْمُهُ سَعِيدُ بْنُ يَزِيدَ بَصْرِيٌّ ثِقَةٌ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍأَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي النَّعْلَيْنِ قَالَ نَعَمْ","id":"Telah mengkabarkan kepada kami ['Amr bin 'Ali] dari [Yazid bin Zurai'] dan [Ghassan bin Mudhar] mereka berdua berkata; telah menceritakan kepada kami [Abu Maslamah Sa'id bin Yazid] -seorang penduduk Bashrah yang tsiqah- dia berkata; aku bertanya kepada [Anas bin Malik] 'Apakah Rasulullah Shallallahu'alaihi wasallam pernah shalat dengan mengenakan sandal? ' Beliau menjawab, Ya.\""},"767":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ وَشُعَيْبُ بْنُ يُوسُفَ عَنْ يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبَّادٍ عَنْ عَبْدِ اللَّهِ بْنِ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ الْفَتْحِ فَوَضَعَ نَعْلَيْهِ عَنْ يَسَارِهِ","id":"Telah mengkabarkan kepada kami ['Ubaidullah bin Sa'id] dan [Syu'aib bin Yusuf] dari [Yahya] dari [Ibnu Juraij] dia berkata; telah mengkabarkan kepadaku [Muhammad bin 'Abbad] dari [Abdullah bin Sufyan] dari [Abdullah bin As Saib] bahwa Rasulullah Shallallahu'alaihi wasallam pernah shalat pada hari Fathu (Penaklukan) Makkah dengan meletakkan sandal di sebelah kirinya."},"768":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَهَنَّادُ بْنُ السَّرِيِّ عَنْ حُسَيْنِ بْنِ عَلَيٍّ عَنْ زَائِدَةَ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا قُبِضَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ الْأَنْصَارُ مِنَّا أَمِيرٌ وَمِنْكُمْ أَمِيرٌ فَأَتَاهُمْ عُمَرُ فَقَالَ أَلَسْتُمْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَمَرَ أَبَا بَكْرٍ أَنْ يُصَلِّيَ بِالنَّاسِ فَأَيُّكُمْ تَطِيبُ نَفْسُهُ أَنْ يَتَقَدَّمَ أَبَا بَكْرٍ قَالُوا نَعُوذُ بِاللَّهِ أَنْ نَتَقَدَّمَ أَبَا بَكْرٍ","id":"Telah mengkabarkan kepada kami [Ishaq bin Ibrahim] dan [Hannad bin As-Sari] dari [Husain bin 'Ali] dari [Zaidah] dari ['Ashim] dari [Zirr] dari [Abdullah] dia berkata; \"Tatkala Rasulullah Shallallahu'alaihi wasallam wafat. orang-orang Anshar berkata, 'Dari kami ada pemimpin dan dari kalian (Muhajirin) juga ada pemimpin'. [Umar] segera mendatangi mereka dan berkata, 'Bukankah kalian tahu bahwa Rasulullah Shallallahu'alaihi wasallam menyuruh Abu Bakar menjadi imam dalam shalat mereka? Siapa di antara kalian yang hatinya ingin mendahului Abu Bakar? ' Mereka berkata, 'Kami berlindung kepada Allah dari mendahului Abu Bakar.\""},"769":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي الْعَالِيَةِ الْبَرَّاءِ قَالَأَخَّرَ زِيَادٌ الصَّلَاةَ فَأَتَانِي ابْنُ صَامِتٍ فَأَلْقَيْتُ لَهُ كُرْسِيًّا فَجَلَسَ عَلَيْهِ فَذَكَرْتُ لَهُ صُنْعَ زِيَادٍ فَعَضَّ عَلَى شَفَتَيْهِ وَضَرَبَ عَلَى فَخِذِي وَقَالَ إنِّي سَأَلْتُ أَبَا ذَرٍّ كَمَا سَأَلْتَنِي فَضَرَبَ فَخِذِي كَمَا ضَرَبْتُ فَخْذَكَ وَقَالَ إِنِّي سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا سَأَلْتَنِي فَضَرَبَ فَخِذِي كَمَا ضَرَبْتُ فَخِذَكَ فَقَالَ عَلَيْهِ الصَّلَاة وَالسَّلَامُ صَلِّ الصَّلَاةَ لِوَقْتِهَا فَإِنْ أَدْرَكْتَ مَعَهُمْ فَصَلِّ وَلَا تَقُلْ إِنِّي صَلَّيْتُ فَلَا أُصَلِّي","id":"Telah mengkabarkan kepada kami [Ziyad bin Ayyub] dia berkata; telah mengabarkan kepada kami [Ismail bin 'Ulayyah] dia berkata; telah menceritakan kepada kami [Ayyub] dari [Abu Al Aliyah Al Barra], dia berkata; \"Ziyad mengakhirkan shalat, maka [Ibnu Shamit] mendatangiku. Lalu aku persilakan untuk duduk di kursi. dan dia pun duduk. Kemudian segera kuceritakan perbuatan Ziyad. lalu dia menggigit kedua bibirnya dan memukul pahaku, dan berkata, 'Aku pernah bertanya kepada [Abu Dzar] seperti yang kamu tanyakan kepadaku, dan ia (Abu Dzar) memukul pahaku seperti aku memukul pahamu. Dia (Abu Dzar) berkata, \"Aku pernah bertanya kepada Rasulullah Shallallahu'alaihi wasallam sebagaimana yang kamu tanyakan kepadaku, lantas beliau Shallallahu'alaihi wasallam memukul pahaku seperti aku memukul pahamu! Lantas beliau Shallallahu'alaihi wasallam bersabda, 'Shalatlah pada waktunya. Jika kamu mendapatkan shalat bersama mereka (penguasa/imam yang jahat), maka shalatlah bersama mereka dan jangan kamu berkata.\"Aku sudah shalat maka aku tidak akan shalat (lagi).\""},"770":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّكُمْ سَتُدْرِكُونَ أَقْوَامًا يُصَلُّونَ الصَّلَاةَ لِغَيْرِ وَقْتِهَا فَإِنْ أَدْرَكْتُمُوهُمْ فَصَلُّوا الصَّلَاةَ لِوَقْتِهَا وَصَلُّوا مَعَهُمْ وَاجْعَلُوهَا سُبْحَةً","id":"Telah mengkabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari ['Ashim] dari [Zirr] dari [Abdullah] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda, \"Mungkin kalian akan menjumpai suatu kaum yang mengerjakan shalat tidak pada waktunya. Jika kalian mendapati mereka, maka shalatlah pada waktunya, kemudian ikutlah shalat bersama mereka dan anggaplah itu sebagai shalat sunnah.\""},"771":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ أَنْبَأَنَا فُضَيْلُ بْنُ عِيَاضٍ عَنْ الْأَعْمَشِ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ عَنْ أَوْسِ بْنِ ضَمْعَجٍ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّ الْقَوْمَ أَقْرَؤُهُمْ لِكِتَابِ اللَّهِ فَإِنْ كَانُوا فِي الْقِرَاءَةِ سَوَاءً فَأَقْدَمُهُمْ فِي الْهِجْرَةِ فَإِنْ كَانُوا فِي الْهِجْرَةِ سَوَاءً فَأَعْلَمُهُمْ بِالسُّنَّةِ فَإِنْ كَانُوا فِي السُّنَّةِ سَوَاءً فَأَقْدَمُهُمْ سِنًّا وَلَا تَؤُمَّ الرَّجُلَ فِي سُلْطَانِهِ وَلَا تَقْعُدْ عَلَى تَكْرِمَتِهِ إِلَّا أَنْ يَأْذَنَ لَكَ","id":"Telah mengkabarkan kepada kami [Qutaibah] dia berkata; telah memberitakan kepada kami [Fudhail bin 'Iyadh] dari [Al A'masy] dari [Isma'il bin Raja'] dari [Aus bin Dham'aj] dari [Abu Mas'ud] dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, orang yang menjadi imam untuk suatu kaum adalah yang paling menguasai AI Qur'an. Jika bacaan mereka sama, maka yang jadi imam adalah orang yang lebih dulu hijrah. Jika dalam hijrah mereka sama. maka yang jadi imam adalah orang yang paling mengetahui tlenlang Sunnah. Jika pengetahuan mereka tentang Sunnah sama, maka yang jadi imam adalah orang yang paling tua di antara mereka. Janganlah kamu mengimami seseorang di tempat yang menjadi wewenangnya dan janganlah duduk di atas tempat kemuliaannya kecuali seizinnya.'\""},"772":{"ar":"أَخْبَرَنَا حَاجِبُ بْنُ سُلَيْمَانَ الْمَنْبِجِيُّ عَنْ وَكِيعٍ عَنْ سُفْيَانَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَابْنُ عَمٍّ لِي وَقَالَ مَرَّةً أَنَا وَصَاحِبٌ لِي فَقَالَ إِذَا سَافَرْتُمَا فَأَذِّنَا وَأَقِيمَا وَلْيَؤُمَّكُمَا أَكْبَرُكُمَا","id":"Telah mengkabarkan kepada kami [Hajib bin Sulaiman Al Manbiji] dari [Waki'] dari [Sufyan] dari [Khalid Al Hadza'] dari [Abu Qibalah] dari [Malik bin Al Huwairits] dia berkata; \"Aku pernah datang kepada Rasulullah Shallallahu'alaihi wasallam bersama anak pamanku -pada kesempatan lain ia berkata, \"bersama temanku\"- lantas Nabi Shallallahu'alaihi wasallam bersabda, 'Jika kalian berdua melakukan perjalanan, maka adzan dan iqamahlah, dan hendaknya yang paling tua menjadi imam bagi yang lain'"},"773":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ يَحْيَى عَنْ هِشَامٍ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانُوا ثَلَاثَةً فَلْيَؤُمَّهُمْ أَحَدُهُمْ وَأَحَقُّهُمْ بِالْإِمَامَةِ أَقْرَؤُهُمْ","id":"Telah mengkabarkan kepada kami ['Ubaidullah bin Sa'id] dari [Yahya] dari [Hisyam] dia berkata; telah menceritakan kepada kami [Qatadah] dari [Abu Nadhrah] dari [Abu Sa'id] dari Nabi Shallallahu'alaihi wasallam, beliau bersabda, \"Bila mereka bertiga, maka salah satunya menjadi imam, dan yang lebih berhak adalah yang paling bagus bacaannya.\""},"774":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدٍ التَّيْمِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ عَنْ أَوْسِ بْنِ ضَمْعَجٍ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُؤَمُّ الرَّجُلُ فِي سُلْطَانِهِ وَلَا يُجْلَسُ عَلَى تَكْرِمَتِهِ إِلَّا بِإِذْنِهِ","id":"Telah mengkabarkan kepada kami [Ibrahim bin Muhammad At Taimi] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Isma'il bin Raja'] dari [Aus bin Dham'aj] dari [Abu Mas'ud] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda, \"Janganlah seseorang menjadi imam di tempat yang menjadi wewenangnya dan janganlah duduk diatas tempat kemuliaannya, kecuali seizinnya.\""},"775":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلَغَهُ أَنَّ بَنِي عَمْرِو بْنِ عَوْفٍ كَانَ بَيْنَهُمْ شَيْءٌ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُصْلِحَ بَيْنَهُمْ فِي أُنَاسٍ مَعَهُ فَحُبِسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَانَتْ الْأُولَى فَجَاءَ بِلَالٌ إِلَى أَبِي بَكْرٍ فَقَالَ يَا أَبَا بَكْرٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ حُبِسَ وَقَدْ حَانَتْ الصَّلَاةُ فَهَلْ لَكَ أَنْ تَؤُمَّ النَّاسَ قَالَ نَعَمْ إِنْ شِئْتَ فَأَقَامَ بِلَالٌ وَتَقَدَّمَ أَبُو بَكْرٍ فَكَبَّرَ بِالنَّاسِ وَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْشِي فِي الصُّفُوفِ حَتَّى قَامَ فِي الصَّفِّ وَأَخَذَ النَّاسُ فِي التَّصْفِيقِ وَكَانَ أَبُو بَكْرٍ لَا يَلْتَفِتُ فِي صَلَاتِهِ فَلَمَّا أَكْثَرَ النَّاسُ الْتَفَتَ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَشَارَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُهُ أَنْ يُصَلِّيَ فَرَفَعَ أَبُو بَكْرٍ يَدَيْهِ فَحَمِدَ اللَّهَ عَزَّ وَجَلَّ وَرَجَعَ الْقَهْقَرَى وَرَاءَهُ حَتَّى قَامَ فِي الصَّفِّ فَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ فَلَمَّا فَرَغَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ يَا أَيُّهَا النَّاسُ مَا لَكُمْ حِينَ نَابَكُمْ شَيْءٌ فِي الصَّلَاةِ أَخَذْتُمْ فِي التَّصْفِيقِ إِنَّمَا التَّصْفِيقُ لِلنِّسَاءِ مَنْ نَابَهُ شَيْءٌ فِي صَلَاتِهِ فَلْيَقُلْ سُبْحَانَ اللَّهِ فَإِنَّهُ لَا يَسْمَعُهُ أَحَدٌ حِينَ يَقُولُ سُبْحَانَ اللَّهِ إِلَّا الْتَفَتَ إِلَيْهِ يَا أَبَا بَكْرٍ مَا مَنَعَكَ أَنْ تُصَلِّيَ لِلنَّاسِ حِينَ أَشَرْتُ إِلَيْكَ قَالَ أَبُو بَكْرٍ مَا كَانَ يَنْبَغِي لِابْنِ أَبِي قُحَافَةَ أَنْ يُصَلِّيَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengkabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Ya'qub bin 'Abdurrahman] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwa telah sampai kabar kepada Rasulullah Shallallahu'alaihi wasallam bahwa Bani Amru bin Auf mempunyai suatu masalah. Rasulullah Shallallahu'alaihi wasallam dan beberapa orang lalu datang mendamaikan mereka. Rasulullah Shallallahu'alaihi wasallam tertahan (oleh urusan mereka) sampai tibalah waktu shalat pertama (Zhuhur). Kemudian Bilal datang kepada Abu Bakar dan berkata, \"Wahai Abu Bakar, Rasulullah Shallallahu'alaihi wasallam tertahan sedangkan waktu shalat sudah tiba. Apakah engkau sudi menjadi imam bagi orang-orang?\" la menjawab, \"Ya, jika kamu mau.\" Lalu Bilal menyerukan iqamah dan Abu Bakar maju lantas bertakbir bersama kaum muslim. Kemudian datang Rasulullah Shallallahu'alaihi wasallam di celah-celah barisan shalat hingga beliau Shallallahu'alaihi wasallam berdiri di barisan shalat. Orang-orang lalu mulai menepukkan tangannya, tetapi Abu Bakar tidak menoleh dalam shalatnya. Setelah orang-orang banyak yang menepukkan tangannya (sebagai isyarat), Abu Bakar menoleh dan mendapati Rasulullah Shallallahu'alaihi wasallam, maka Rasulullah Shallallahu'alaihi wasallam mengisyaratkan kepadanya untuk terus melanjutkan shalatnya, namun Abu Bakar mengangkat kedua tangannya dan memuji Allah Azza wa Jalla lantas mundur ke belakang hingga berdiri pada barisan makmum. Rasulullah Shallallahu'alaihi wasallam lalu maju untuk menjadi imam. Setelah selesai beliau Shallallahu'alaihi wasallam menghadap kepada orang-orang dan bersabda, \"Wahai manusia sekalian, Kenapa kalian ketika shalat bertepuk tangan? Tepuk langan hanya untuk perempuan. Barangsiapa mendapati sesuatu yang kurang beres pada shalalnya, maka ucapkan. 'Subhanallah (Maha Suci Allah), karena tidak seorangpun yang mendengar ketika ada yang mengucapkan subhanallah (Maha Suci Allah) kecuali pasli menolehnya. Wahai Abu Bakar, apakah yang menghalangimu untuk shalat menjadi imam bagi orang-orang saat kuisyaratkan demikian?\" Abu Bakar berkata, \"Tidaklah panlas bagi Ibnu Quhafah untuk shalat -menjadi imam- di depan Rasulullah Shallallahu'alaihi wasallam.\""},"776":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَآخِرُ صَلَاةٍ صَلَّاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ الْقَوْمِ صَلَّى فِي ثَوْبٍ وَاحِدٍ مُتَوَشِّحًا خَلْفَ أَبِي بَكْرٍ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Humaid] dari [Anas] dia berkata; \"Shalat terakhir Rasulullah Shallallahu'alaihi wasallam yang dikerjakan bersama para sahabat adalah shalat yang beliau kerjakan dengan mengenakan baju yang kasar di belakang Abu Bakar.\""},"777":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا بَكْرُ بْنُ عِيسَى صَاحِبُ الْبُصْرَى قَالَ سَمِعْتُ شُعْبَةَ يَذْكُرُ عَنْ نُعَيْمِ بْنِ أَبِي هِنْدٍ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ أَبَا بَكْرٍ صَلَّى لِلنَّاسِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّفِّ","id":"Telah mengkabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Bakr bin 'Isa] -sahabat Al Bashri- dia berkata; aku mendengar [Syu'bah] menyebutkan dari [Nu'aim bin Abu Hind] dari [Abu Wa'il] dari [Masruq] dari ['Aisyah] Radliyallahu'anha, bahwa Abu Bakar pernah shalat mengimami orang-orang dan Rasulullah Shallallahu'alaihi wasallam berada di barisan shalat."},"778":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ أَبَانَ بْنِ يَزِيدَ قَالَ حَدَّثَنَا بُدَيْلُ بْنُ مَيْسَرَةَ قَالَ حَدَّثَنَا أَبُو عَطِيَّةَ مَوْلًى لَنَا عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا زَارَ أَحَدُكُمْ قَوْمًا فَلَا يُصَلِّيَنَّ بِهِمْ","id":"Telah mengkabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah] dari [Aban bin Yazid] dia berkata; telah menceritakan kepada kami [Badil bin Maisarah] dia berkata; telah menceritakan kepada kami [Abu 'Athiyyah] -budak kami- dari [Malik bin Al Huwairits] dia berkata; \"Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda, 'Jika salah seorang dari kalian berkunjung ke suatu kaum, maka janganlah menjadi imam bagi mereka.\""},"779":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ ح قَالَ وَحَدَّثَنَا الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ مَحْمُودِ بْنِ الرَّبِيعِأَنَّ عِتْبَانَ بْنَ مَالِكٍ كَانَ يَؤُمُّ قَوْمَهُ وَهُوَ أَعْمَى وَأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا تَكُونُ الظُّلْمَةُ وَالْمَطَرُ وَالسَّيْلُ وَأَنَا رَجُلٌ ضَرِيرُ الْبَصَرِ فَصَلِّ يَا رَسُولَ اللَّهِ فِي بَيْتِي مَكَانًا أَتَّخِذُهُ مُصَلًّى فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ لَكَ فَأَشَارَ إِلَى مَكَانٍ مِنْ الْبَيْتِ فَصَلَّى فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengkabarkan kepada kami [Harun bin Abdullah] dia berkata; telah menceritakan kepada kami [Ma'an] dia berkata; telah menceritakan kepada kami [Malik] dia berkata; dan telah menceritakan kepada kami [Al Harits bin Miskin] dalam bentuk bacaan kepadanya dan saya mendengar lafazhnya dari dia dari [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Mahmud bin Ar-Rabi'] bahwasanya ['Itban bin Malik] pernah menjadi imam bagi kaumnya, padahal dia buta. Dia berkata kepada Rasulullah Shallallahu'alaihi wasallam, \"Saat ini gelap, turun hujan, serta banjir, sementara aku orang buta, maka shalatlah di rumahku yang telah kujadikan masjid wahai Rasulullah Shallallahu'alaihi wasallam.\" Rasulullah Shallallahu'alaihi wasallam lalu berkata, \"Di mana yang kamu inginkan agar aku shalat bersamamu?\" la menunjukkan tempat yang ada di rumahnya, lalu Rasulullah Shallallahu'alaihi wasallam shalat di sana."},"780":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ الْمَسْرُوقِيُّ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ سُفْيَانَ عَنْ أَيُّوبَ قَالَ حَدَّثَنِي عَمْرُو بْنُ سَلَمَةَ الْجَرْمِيُّ قَالَكَانَ يَمُرُّ عَلَيْنَا الرُّكْبَانُ فَنَتَعَلَّمُ مِنْهُمْ الْقُرْآنَ فَأَتَى أَبِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِيَؤُمَّكُمْ أَكْثَرُكُمْ قُرْآنًا فَجَاءَ أَبِي فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِيَؤُمَّكُمْ أَكْثَرُكُمْ قُرْآنًا فَنَظَرُوا فَكُنْتُ أَكْثَرَهُمْ قُرْآنًا فَكُنْتُ أَؤُمُّهُمْ وَأَنَا ابْنُ ثَمَانِ سِنِينَ","id":"Telah mengkabarkan kepada kami [Musa bin 'Abdurrahman Al Masruqi], telah menceritakan kepada kami [Husain bin 'Ali] dari [Zaidah] dari [Sufyan] dari [Ayyub] dia berkata; telah menceritakan kepada kami ['Amr bin Salamah Al Jarmi] dia berkata; \"Suatu rombongan melewati kami, dan kami belajar Al Qur'an kepada mereka. Lalu ayahku datang kepada Nabi Shallallahu'alaihi wasallam, dan beliau Shallallahu'alaihi wasallam bersabda, 'Orang yang menjadi imam bagi kalian adalah yang paling banyak hapal Al Qur 'an'. Maka [ayahku] datang dan mengatakan bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, 'Orang yang menjadi imam bagi kalian adalah yang paling banyak hapal Al Qur'an'. Lantas mereka saling memandang siapakah yang paling banyak hapal Al Qur'an, dan ternyata aku orang yang paling banyak hapal Al Qur'an, maka aku menjadi imam bagi mereka, padahal umurku saat itu delapan tahun.\""},"781":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ هِشَامِ بْنِ أَبِي عَبْدِ اللَّهِ وَحَجَّاجُ بْنُ أَبِي عُثْمَانَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا نُودِيَ لِلصَّلَاةِ فَلَا تَقُومُوا حَتَّى تَرَوْنِي","id":"Telah mengkabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Husyaim] dari [Hisyam bin Abu Abdullah] dan [Hajjaj bin Abu 'Utsman] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [bapaknya], dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda, \"Jika shalat telah diserukan, maka janganlah kalian berdiri hingga melihatku.\""},"782":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَنَسٍ قَالَأُقِيمَتْ الصَّلَاةُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَجِيٌّ لِرَجُلٍ فَمَا قَامَ إِلَى الصَّلَاةِ حَتَّى نَامَ الْقَوْمُ","id":"Telah mengkabarkan kepada kami [Ziyad bin Ayyub] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Abdul 'Aziz] dari [Anas] dia berkata; \"Tatkala iqamah dikumandangkan, Rasulullah Shallallahu'alaihi wasallam berbicara dengan seseorang yang membutuhkannya, maka beliau menunda shalat hingga orang-orang tertidur.\""},"783":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ وَالْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأُقِيمَتْ الصَّلَاةُ فَصَفَّ النَّاسُ صُفُوفَهُمْ وَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا قَامَ فِي مُصَلَّاهُ ذَكَرَ أَنَّهُ لَمْ يَغْتَسِلْ فَقَالَ لِلنَّاسِ مَكَانَكُمْ ثُمَّ رَجَعَ إِلَى بَيْتِهِ فَخَرَجَ عَلَيْنَا يَنْطِفَ رَأْسُهُ فَاغْتَسَلَ وَنَحْنُ صُفُوفٌ","id":"Telah mengkabarkan kepada kami ['Amr bin 'Utsman bin Sa'id bin Katsir] dia berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Az-Zubaidi] dari [Az-Zuhri] dan [Al Walid] dari [Al Auza'i] dari [Az-Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; \"Setelah iqamah dikumandangkan, orang-orang segera merapikan barisan mereka, kemudian Rasulullah Shallallahu'alaihi wasallam keluar hingga tatkala beliau sampai di tempat shalatnya beliau ingat bahwa dirinya belum mandi. Lantas beliau Shallallahu'alaihi wasallam bersabda kepada jamaah, 'Tolong tetaplah kalian di tempat\". Rasulullah Shallallahu'alaihi wasallam segera kembali ke rumahnya dan keluar lagi kepada kami dalam keadaan rambut yang masih basah, saat beliau mandi kami tetap dalam barisan.\""},"784":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدَةَ عَنْ حَمَّادِ بْنِ زَيْدٍ ثُمَّ ذَكَرَ كَلِمَةً مَعْنَاهَا قَالَ حَدَّثَنَا أَبُو حَازِمٍ قَالَ سَهْلُ بْنُ سَعْدٍكَانَ قِتَالٌ بَيْنَ بَنِي عَمْرِو بْنِ عَوْفٍ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى الظُّهْرَ ثُمَّ أَتَاهُمْ لِيُصْلِحَ بَيْنَهُمْ ثُمَّ قَالَ لِبِلَالٍ يَا بِلَالُ إِذَا حَضَرَ الْعَصْرُ وَلَمْ آتِ فَمُرْ أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَلَمَّا حَضَرَتْ أَذَّنَ بِلَالٌ ثُمَّ أَقَامَ فَقَالَ لِأَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ تَقَدَّمْ فَتَقَدَّمَ أَبُو بَكْرٍ فَدَخَلَ فِي الصَّلَاةِ ثُمَّ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَشُقُّ النَّاسَ حَتَّى قَامَ خَلْفَ أَبِي بَكْرٍ وَصَفَّحَ الْقَوْمُ وَكَانَ أَبُو بَكْرٍ إِذَا دَخَلَ فِي الصَّلَاةِ لَمْ يَلْتَفِتْ فَلَمَّا رَأَى أَبُو بَكْرٍ التَّصْفِيحَ لَا يُمْسَكُ عَنْهُ الْتَفَتَ فَأَوْمَأَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ فَحَمِدَ اللَّهَ عَزَّ وَجَلَّ عَلَى قَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ امْضِهْ ثُمَّ مَشَى أَبُو بَكْرٍ الْقَهْقَرَى عَلَى عَقِبَيْهِ فَتَأَخَّرَ فَلَمَّا رَأَى ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقَدَّمَ فَصَلَّى بِالنَّاسِ فَلَمَّا قَضَى صَلَاتَهُ قَالَ يَا أَبَا بَكْرٍ مَا مَنَعَكَ إِذْ أَوْمَأْتُ إِلَيْكَ أَنْ لَا تَكُونَ مَضَيْتَ فَقَالَ لَمْ يَكُنْ لِابْنِ أَبِي قُحَافَةَ أَنْ يَؤُمَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لِلنَّاسِ إِذَا نَابَكُمْ شَيْءٌ فَلْيُسَبِّحْ الرِّجَالُ وَلْيُصَفِّحْ النِّسَاءُ","id":"Telah mengkabarkan kepada kami [Ahmad bin 'Abdah] dari [Hammad bin Zaid] kemudian dia menyebutkan kalimat yang maknanya, dia berkata; telah menceritakan kepada kami [Abu Hazim] dia berkata; berkata [Sahl bin Sa'd] Bahwa Bani Amru bin Auf mempunyai suatu masalah, lalu hal ini sampai kepada Rasulullah Shallallahu'alaihi wasallam, maka beliau Shallallahu'alaihi wasallam shalat Zhuhur kemudian mendatangi mereka untuk mendamaikan mereka. Rasulullah Shallallahu'alaihi wasallam bersabda kepada Bilal, \"Wahai Bilal, jika tiba waktu shalat Ashar sedangkan aku belum datang, maka suruh Abu Bakar (menjadi imam) shalat bersama kaum muslim.\"Tatkala datang waktu Ashar, maka Bilal segera adzan dan dilanjutkan dengan iqamah. Lantas Bilal berkata kepada Abu Bakar Rabi'ah, \"Majulah (jadi imam).\" maka Abu Bakar maju menjadi imam shalat. Saat itu Rasulullah Shallallahu'alaihi wasallam datang, beliau Shallallahu'alaihi wasallam segera masuk lewat celah-celah barisan shalat hingga beliau berdiri di belakang Abu Bakar. Orang-orang mulai menepukkan tangannya, dan Abu Bakar bila telah memulai shalat biasanya ia tidak menoleh dalam shalatnya. Setelah Abu Bakar melihat banyaknya orang-orang yang bertepuk tangan, maka Abu Bakar tidak mampu menahan untuk tidak menoleh, sehingga ia mendapati Rasulullah Shallallahu'alaihi wasallam, dan beliau Shallallahu'alaihi wasallam memberikan isyarat dengan tangannya kepada Abu Bakar, namun Abu Bakar memuji Allah Azza wa Jalla atas perintah beliau Shallallahu'alaihi wasallam kepada dirinya, \"Lanjutkan saja.\" Lalu Abu Bakar kembali ke belakang dengan mundur, dan Rasulullah Shallallahu'alaihi wasallam segera maju untuk menjadi imam dan shalat bersama kaum muslim. Setelah selesai, beliau Shallallahu'alaihi wasallam menghadap ke jemaah dan bersabda, \"Wahai Abu Bakar, apakah yang menghalangimu untuk shalat menjadi imam bagi para jemaah saat kuisyaratkan demikian.\" Abu Bakar berkata, \"Tidaklah pantas bagi Ibnu Quhafah untuk shalat menjadi imam bagi Rasulullah Shallallahu'alaihi wasallam.\" Beliau Shallallahu'alaihi wasallam lalu bersabda kepada kaum muslim, \"Jika kalian mengalami sesuatu -dalam shalat- maka hendaknya bagi orang laki-laki untuk bertasbih dan bagi orang perempuan untuk bertepuk tangan.\""},"785":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ ابْنِ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَقَطَ مِنْ فَرَسٍ عَلَى شِقِّهِ الْأَيْمَنِ فَدَخَلُوا عَلَيْهِ يَعُودُونَهُ فَحَضَرَتْ الصَّلَاةُ فَلَمَّا قَضَى الصَّلَاةَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا سَجَدَ فَاسْجُدُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا لَكَ الْحَمْدُ","id":"Telah mengkabarkan kepada kami [Hannad bin As-Sari] dari [Ibnu 'Uyainah] dari [Az-Zuhri] dari [Anas] bahwa Rasulullah Shallallahu'alaihi wasallam pernah jatuh dari kudanya dan badan bagian kanan beliau terluka, maka para sahabat segera membesuknya, lalu tibalah waktu shalat. Setelah selesai shalat, beliau Shallallahu'alaihi wasallam bersabda, \"Sesungguhnya seorang imam itu dijadikan untuk diikuti. Bila dia ruku' maka rukulah kalian, bila ia mengangkat kepalanya maka hendaklah kalian mengangkat kepala, jika ia sujud maka sujudlah kalian, dan jika ia mengucapkan 'Sami 'alluhu liman hamidah (Allah Maha Mendengar terhadap semua yang memuji-Nya) ' maka ucapkan, 'Rabbana lakal hamdu (Ya Allah, hanya kepada Engkau kami memuji).\""},"786":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ جَعْفَرِ بْنِ حَيَّانَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى فِي أَصْحَابِهِ تَأَخُّرًا فَقَالَ تَقَدَّمُوا فَأْتَمُّوا بِي وَلْيَأْتَمَّ بِكُمْ مَنْ بَعْدَكُمْ وَلَا يَزَالُ قَوْمٌ يَتَأَخَّرُونَ حَتَّى يُؤَخِّرَهُمْ اللَّهُ عَزَّ وَجَلَّأَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ نَحْوَهُ","id":"Telah mengkabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Ja'far bin Hayyan] dari [Abu Nadhrah] dari [Abu Sa'id Al Khudri] bahwa Rasulullah Shallallahu'alaihi wasallam pernah melihat sahabatnya terlambat, maka dia bersabda, \"Majulah kalian dan shalatlah di belakangku. Sedangkan orang yang terlambat maka bermakmumlah kepada orang yang di belakang kalian. Sesungguhnya suatu kaum senantiasa terlambat hingga Allah Azza wa Jalla mengakhirkan mereka.\" Sedang telah mengabarkan kepada kami [Suwaid bin Nashr] mengatakan, telah mengabarkan kepada kami [Abdullah] dari [Aljurairi] dari [Abi Nadhrah] semisalnya."},"787":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنِي أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ يُحَدِّثُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أَبَا بَكْرٍ أَنْ يُصَلِّيَ بِالنَّاسِ قَالَتْ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ يَدَيْ أَبِي بَكْرٍ فَصَلَّى قَاعِدًا وَأَبُو بَكْرٍ يُصَلِّي بِالنَّاسِ وَالنَّاسُ خَلْفَ أَبِي بَكْرٍ","id":"Telah mengkabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepadaku [Abu Dawud] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Musa bin Abu 'Aisyah] dia berkata; aku mendengar ['Ubaidullah bin Abdullah] menceritakan dari ['Aisyah] Radliyallahu'anha, bahwa Rasulullah Shallallahu'alaihi wasallam menyuruh Abu Bakar shalat mengimami orang-orang (sahabat). Aisyah lalu berkata; \"Nabi Shallallahu'alaihi wasallam pernah shalat sambil duduk di depan Abu Bakar, sedangkan Abu Bakar shalat bersama orang-orang, dan mereka shalat di belakang Abu Bakar.\""},"788":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ يَحْيَى قَالَ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ حُمَيْدٍ الرُّوَاسِيُّ عَنْ أَبِيهِ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ وَأَبُو بَكْرٍ خَلْفَهُ فَإِذَا كَبَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبَّرَ أَبُو بَكْرٍ يُسْمِعُنَا","id":"Telah mengkabarkan kepada kami ['Ubaidullah bin Fadhalah bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya bin Yahya] dia berkata; telah menceritakan kepada kami [Humaid bin 'Abdurrahman bin Humaid Ar-Ruwasi] dari [bapaknya] dari [Abu Az Zubair] dari [Jabir] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam shalat Zhuhur bersama kami dan Abu Bakar berada di belakang beliau. Bila Rasulullah Shallallahu'alaihi wasallam bertakbir, maka Abu Bakar ikut bertakbir untuk memperdengarkan (takbir Rasulullah Shallallahu'alaihi wasallam) kepada kami.\""},"789":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْكُوفِيُّ عَنْ مُحَمَّدِ بْنِ فُضَيْلٍ عَنْ هَارُونَ بْنِ عَنْتَرَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ الْأَسْوَدِ وَعَلْقَمَةَ قَالَادَخَلْنَا عَلَى عَبْدِ اللَّهِ نِصْفَ النَّهَارِ فَقَالَ إِنَّهُ سَيَكُونُ أُمَرَاءُ يَشْتَغِلُونَ عَنْ وَقْتِ الصَّلَاةِ فَصَلُّوا لِوَقْتِهَا ثُمَّ قَامَ فَصَلَّى بَيْنِي وَبَيْنَهُ فَقَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَ","id":"Telah mengkabarkan kepada kami [Muhammad bin 'Ubaid Al Kufi] dari [Muhammad bin Fudhail] dari [Harun bin 'Antarah] dari ['Abdurrahman bin Al Aswad] dari [Al Aswad] dan ['Alqamah] mereka berdua berkata; Pernah kami menemui [Abdullah] pada pertengahan siang, lalu ia berkata; 'Akan ada penguasa yang lalai waktu shalat, maka shalatlah kalian pada waktunya'. Kemudian ia berdiri dan mengerjakan shalat di antara aku dan temanku, lalu berkata, 'Beginilah aku melihat Rasulullah Shallallahu'alaihiwasallam melakukannya.\""},"790":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنَا أَفْلَحُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا بُرَيْدَةُ بْنُ سُفْيَانَ بْنِ فَرْوَةَ الْأَسْلَمِيُّ عَنْ غُلَامٍ لِجَدِّهِ يُقَالُ لَهُ مَسْعُودٌ فَقَالَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ فَقَالَ لِي أَبُو بَكْرٍ يَا مَسْعُودُ ائْتِ أَبَا تَمِيمٍ يَعْنِي مَوْلَاهُ فَقُلْ لَهُ يَحْمِلْنَا عَلَى بَعِيرٍ وَيَبْعَثْ إِلَيْنَا بِزَادٍ وَدَلِيلٍ يَدُلُّنَا فَجِئْتُ إِلَى مَوْلَايَ فَأَخْبَرْتُهُ فَبَعَثَ مَعِي بِبَعِيرٍ وَوَطْبٍ مِنْ لَبَنٍ فَجَعَلْتُ آخُذُ بِهِمْ فِي إِخْفَاءِ الطَّرِيقِ وَحَضَرَتْ الصَّلَاةُ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَقَامَ أَبُو بَكْرٍ عَنْ يَمِينِهِ وَقَدْ عَرَفْتُ الْإِسْلَامَ وَأَنَا مَعَهُمَا فَجِئْتُ فَقُمْتُ خَلْفَهُمَا فَدَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَدْرِ أَبِي بَكْرٍ فَقُمْنَا خَلْفَهُقَالَ أَبُو عَبْد الرَّحْمَنِ بُرَيْدَةُ هَذَا لَيْسَ بِالْقَوِيِّ فِي الْحَدِيثِ","id":"Telah mengabarkan kepada kami ['Abdah bin Abdullah] dia berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] dia berkata; telah menceritakan kepada kami [Aflah bin Sa'id] dia berkata; telah menceritakan kepada kami [Buraidah bin Sufyan bin Farwah Al Aslami] dari seorang cucu kakeknya yang bernama [Mas'ud] dia berkata; Rasulullah Shalallahu 'Alaihi Wa sallam dan Abu Bakr melewatiku. Lalu Abu Bakar berkata kepadaku; Wahai Mas'ud, panggil Abu Tamim (yaitu budaknya) dan katakan kepadanya agar ia bersedia membawa kami dengan Untanya dan membawakan bekal perjalanan untuk kami sekaligus menjadi petunjuk jalan. Maka aku pun menemui budakku dan mengabarkan kepadanya. Kemudian aku kembali dengan membawa unta dan sekantong susu. Lalu Aku membawa keduanya melalui jalan yang belum mereka kenal, tiba-tiba datang waktu shalat, maka Rasulullah Shalallahu 'Alaihi Wa sallam berdiri untuk shalat dan Abu Bakr berdiri di sebelah kanannya. Waktu itu aku sudah masuk Islam, akupun berdiri dibelakang mereka berdua, kemudian Rasulullah Shalallahu 'Alaihi Wa sallam mendorong dada Abu Bakar kebelakang hingga kami berdua shalat dibelakangnya. Abu Abdurrahman berkata; 'Buraidah orangnya lemah dalam meriwayatkan Hadis.'"},"791":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ جَدَّتَهُ مُلَيْكَةَ دَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ قَدْ صَنَعَتْهُ لَهُ فَأَكَلَ مِنْهُ ثُمَّ قَالَ قُومُوا فَلِأُصَلِّيَ لَكُمْ قَالَ أَنَسٌ فَقُمْتُ إِلَى حَصِيرٍ لَنَا قَدْ اسْوَدَّ مِنْ طُولِ مَا لُبِسَ فَنَضَحْتُهُ بِمَاءٍ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَفْتُ أَنَا وَالْيَتِيمُ وَرَاءَهُ وَالْعَجُوزُ مِنْ وَرَائِنَا فَصَلَّى لَنَا رَكْعَتَيْنِ ثُمَّ انْصَرَفَ","id":"Telah mengkabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] bahwasanya neneknya Mulaikah pernah mengundang Rasulullah Shallallahu'alaihi wasallam untuk jamuan makan yang telah ia buat khusus untuk Rasulullah Shallallahu'alaihi wasallam, dan Rasulullah Shallallahu'alaihi wasallam menyantap jamuan tersebut. Kemudian beliau Shallallahu'alaihi wasallam bersabda, \"Berdirilah kalian, aku akan shalat bersama kalian.\" Anas berkata; \"Lalu aku berdiri di tikar kami yang sudah berubah warnanya jadi hitam karena lama tidak dipakai, maka aku menyiramnya dengan air. Rasulullah Shallallahu'alaihi wasallam segera berdiri dan aku berbaris dengan seorang anak yatim di belakangnya serta seorang perempuan tua (Mulaikah) di belakang kami. Beliau shalat dua rakaat kemudian pergi.\""},"792":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَدَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا هُوَ إِلَّا أَنَا وَأُمِّي وَالْيَتِيمُ وَأُمُّ حِرَامٍ خَالَتِي فَقَالَ قُومُوا فَلِأُصَلِّيَ بِكُمْ قَالَ فِي غَيْرِ وَقْتِ صَلَاةٍ قَالَ فَصَلِّي بِنَا","id":"Telah mengkabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam datang ke tempat kami dan beliau hanya bersama aku, ibuku, seorang anak yatim, serta Ummu Hiram (bibiku). Rasulullah Shallallahu'alaihi wasallam kemudian bersabda, 'Berdirilah kalian, aku akan shalat bersama kalian.\" Anas berkata, \"(Hal ini) diluar waktu shalat.\" la juga menambahkan, \"Rasulullah Shallallahu'alaihi wasallam lalu shalat bersama kami.\" "},"793":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُخْتَارٍ يُحَدِّثُ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ أَنَسٍأَنَّهُ كَانَ هُوَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمُّهُ وَخَالَتُهُ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ أَنَسًا عَنْ يَمِينِهِ وَأُمَّهُ وَخَالَتَهُ خَلْفَهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abdullah bin Mukhtar] menceritakan dari [Musa bin Anas] dari [Anas] bahwa suatu saat ia bersama Rasulullah Shallallahu'alaihi wasallam, ibunya, dan bibinya. Rasulullah Shallallahu'alaihi wasallam lalu melakukan shalat, beliau menyuruh Anas (berdiri) di sebelah kanannya dan ibu serta bibinya di belakangnya."},"794":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي زِيَادٌ أَنَّ قَزَعَةَ مَوْلًى لِعَبْدِ قَيْسٍ أَخْبَرَهُ أَنَّهُ سَمِعَ عِكْرِمَةَ مَوْلَى ابْنِ عَبَّاسٍ قَالَ قَالَ ابْنُ عَبَّاسٍصَلَّيْتُ إِلَى جَنْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَائِشَةُ خَلْفَنَا تُصَلِّي مَعَنَا وَأَنَا إِلَى جَنْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُصَلِّي مَعَهُ","id":"Telah mengkabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij] berkata; telah mengkabarkan kepadaku [Ziyad] bahwasanya [Qaza'ah] -budak 'Abdu Qais- mengkabarkan kepadanya bahwasanya dia mendengar ['Ikrimah] -budak Ibnu 'Abbas- berkata; [Ibnu 'Abbas] berkata; \"Aku pernah shalat di samping Rasulullah Shallallahu'alaihi wasallam dan Aisyah juga ikut shalat bersama kami di belakang, adapun aku di samping Rasulullah Shallallahu'alaihi wasallam shalat bersama beliau Shallallahu'alaihi wasallam."},"795":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ الْمُخْتَارِ عَنْ مُوسَى بْنِ أَنَسٍ عَنْ أَنَسٍ قَالَصَلَّى بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِامْرَأَةٍ مِنْ أَهْلِي فَأَقَامَنِي عَنْ يَمِينِهِ وَالْمَرْأَةُ خَلْفَنَا","id":"Telah mengkabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Al Mukhtar] dari [Musa bin Anas] dari [Anas] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam shalat bersamaku dan seorang perempuan dari keluargaku. Beliau meletakkan kami di sebelah kanannya dan perempuan di belakang kami."},"796":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ فَقُمْتُ عَنْ شِمَالِهِ فَقَالَ بِي هَكَذَا فَأَخَذَ بِرَأْسِي فَأَقَامَنِي عَنْ يَمِينِهِ","id":"Telah mengkabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Ayyub] dari [Abdullah bin Sa'id bin Jubair] dari [bapaknya] dari [Ibnu 'Abbas] dia berkata; \"Aku pernah menginap di tempat bibiku (Maimunah). Ketika Rasulullah Shallallahu'alaihi wasallam bangun untuk shalat malam, aku berdiri di sebelah kirinya. Beliau Shallallahu'alaihi wasallam lalu berkata kepadaku, 'Begini*. lalu beliau Shallallahu'alaihi wasallam memegang kepalaku dan menyuruhku berdiri di sebelah kanannya.\""},"797":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ مَنَاكِبَنَا فِي الصَّلَاةِ وَيَقُولُ لَا تَخْتَلِفُوا فَتَخْتَلِفَ قُلُوبُكُمْ لِيَلِيَنِّي مِنْكُمْ أُولُو الْأَحْلَامِ وَالنُّهَى ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْقَالَ أَبُو مَسْعُودٍ فَأَنْتُمْ الْيَوْمَ أَشَدُّ اخْتِلَافًا قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو مَعْمَرٍ اسْمُهُ عَبْدُ اللَّهِ بْنُ سَخْبَرَةَ","id":"Telah mengkabarkan kepada kami [Hannad bin As-Sari] dari [Abu Mu'awiyah] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Abu Ma'mar] dari [Abu Mas'ud] dia berkata; \"Dahulu Rasulullah Shallallahu'alaihi wasallam mengusap bahu-bahu kami sebelum shalat sambil bersabda, janganlah kalian berselisih, karena (Jika kalian berselisih) maka hati kalian akan berselisih. Hendaklah yang berdiri di belakangku adalah orang-orang yang bijak dan berilmu, kemudian setelah mereka adalah orang yang kapasitasnya kurang dari mereka, dan begitu selanjutnya.\" Abu Mas'ud berkata; \"Sesungguhnya kalian pada hari ini sangat sering berselisih. Abu Abdurrahaman berkata; nama Abu Ma'mar adalah Abdullah bin Sakhbarah."},"798":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيِّ بْنِ مُقَدَّمٍ قَالَ حَدَّثَنَا يُوسُفُ بْنُ يَعْقُوبَ قَالَ أَخْبَرَنِي التَّيْمِيُّ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بنِ عُبَادٍ قَالَبَيْنَا أَنَا فِي الْمَسْجِدِ فِي الصَّفِّ الْمُقَدَّمِ فَجَبَذَنِي رَجُلٌ مِنْ خَلْفِي جَبْذَةً فَنَحَّانِي وَقَامَ مَقَامِي فَوَاللَّهِ مَا عَقَلْتُ صَلَاتِي فَلَمَّا انْصَرَفَ فَإِذَا هُوَ أُبَيُّ بْنُ كَعْبٍ فَقَالَ يَا فَتَى لَا يَسُؤْكَ اللَّهُ إِنَّ هَذَا عَهْدٌ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْنَا أَنْ نَلِيَهُثُمَّ اسْتَقْبَلَ الْقِبْلَةَ فَقَالَ هَلَكَ أَهْلُ الْعُقَدِ وَرَبِّ الْكَعْبَةِ ثَلَاثًا ثُمَّ قَالَ وَاللَّهِ مَا عَلَيْهِمْ آسَى وَلَكِنْ آسَى عَلَى مَنْ أَضَلُّوا قُلْتُ يَا أَبَا يَعْقُوبَ مَا يَعْنِي بِأَهْلِ الْعُقَدِ قَالَ الْأُمَرَاءُ","id":"Telah mengkabarkan kepada kami [Muhammad bin 'Umar bin 'Ali bin Muqaddam] dia berkata; telah menceritakan kepada kami [Yusuf bin Ya'qub] dia berkata; telah mengkabarkan kepadaku [At-Taimi] dari [Abu Mijlaz] dari [Qais bin 'Ubad] dia berkata; \"Tatkala aku shalat di masjid pada shaf terdepan, tiba-tiba seorang laki-Iaki menarikku dari belakang dan menyingkirkanku, lalu ia berdiri di tempatku tadi berdiri. Demi Allah, aku tidak faham dengan shalatku ini. Setelah selesai shalat, ternyata dia adalah [Ubay bin Ka'ab]. Kemudian ia berkata, 'Hai pemuda, semoga Allah tidak menjelekkanmu. Ini adalah ajaran (wasiat) Rasulullah Shallallahu'alaihi wasallam kepada kita, agar kami berdiri di belakangnya'. Lalu ia menghadap ke kiblat dan berkata, 'Demi Allah, celakalah Ahlul 'Aqdi' -ia ucapkan tiga kali- Kemudian ia berkata, 'Demi Allah, aku tidak sedih kepada mereka, tetapi aku sedih kepada orang yang menyesatkan'. Aku berkata, 'Wahai Abu Ya'qub, siapa yang di maksud dengan Ahlul 'Aqdi? ' Ia menjawab, 'Para penguasa'.\""},"799":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُأُقِيمَتْ الصَّلَاةُ فَقُمْنَا فَعُدِّلَتْ الصُّفُوفُ قَبْلَ أَنْ يَخْرُجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا قَامَ فِي مُصَلَّاهُ قَبْلَ أَنْ يُكَبِّرَ فَانْصَرَفَ فَقَالَ لَنَا مَكَانَكُمْ فَلَمْ نَزَلْ قِيَامًا نَنْتَظِرُهُ حَتَّى خَرَجَ إِلَيْنَا قَدْ اغْتَسَلَ يَنْطُفُ رَأْسُهُ مَاءً فَكَبَّرَ وَصَلَّى","id":"Telah mengkabarkan kepadaku [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Abu Salamah bin 'Abdurrahman] bahwasanya ia mendengar [Abu Hurairah] berkata; \"Setelah iqamah dikumandangkan kami segera bangkit dan barisan telah lurus sebelum Rasulullah Shallallahu'alaihi wasallam keluar kepada kami. Lalu datanglah Rasulullah Shallallahu'alaihi wasallam kepada kami dan beliau berdiri di tempatnya untuk shalat. Sebelum takbir beliau pergi sambil berkata, 'Tetaplah di tempat kalian'. Kami menunggunya sambil berdiri hingga Rasulullah Shallallahu'alaihi wasallam datang, (ternyata) beliau baru mandi dan kepalanya masih meneteskan air. Setelah itu beliau bertakbir dan mengerjakan shalat.\""},"800":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ أَنْبَأَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَوِّمُ الصُّفُوفَ كَمَا تُقَوَّمُ الْقِدَاحُ فَأَبْصَرَ رَجُلًا خَارِجًا صَدْرُهُ مِنْ الصَّفِّ فَلَقَدْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَتُقِيمُنَّ صُفُوفَكُمْ أَوْ لَيُخَالِفَنَّ اللَّهُ بَيْنَ وُجُوهِكُمْ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah memberitakan kepada kami [Abu Al Ahwash] dari [Simak] dari [An Nu'man bin Basyir] dia berkata; \"Dahulu Rasulullah Shallallahu'alaihi wasallam meluruskan barisan seperti meluruskan anak panah. Jika Rasulullah Shallallahu'alaihi wasallam melihat dada seseorang keluar dari barisan, maka aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda, 'Luruskan barisan kalian, atau Allah akan menyelisihkan wajah-wajah kalian.\""},"801":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ مَنْصُ��رٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْسَجَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُ الصُّفُوفَ مِنْ نَاحِيَةٍ إِلَى نَاحِيَةٍ يَمْسَحُ مَنَاكِبَنَا وَصُدُورَنَا وَيَقُولُ لَا تَخْتَلِفُوا فَتَخْتَلِفَ قُلُوبُكُمْ وَكَانَ يَقُولُ إِنَّ اللَّهَ وَمَلَائِكَتَهُ يُصَلُّونَ عَلَى الصُّفُوفِ الْمُتَقَدِّمَةِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Manshur] dari [Thalhah bin Musharrif] dari [Abdurrahman bin 'Ausajah] dari [Al Barra' bin 'Azib] dia berkata; \"Dahulu Rasulullah Shallallahu'alaihi wasallam memeriksa barisan shalat dari satu sisi ke sisi lain dan mengusap pundak serta dada kami, lalu bersabda, \"Janganlah kalian berbeda (bengkok, tidak lurus) sehingga hati kalian akan berselisih'. Beliau Shallallahu'alaihi wasallam juga bersabda, \"Allah dan para malaikat bershalawat (mendoakan) kepada orang yang berada dibarisan terdepan.\""},"802":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ الْعَسْكَرِيُّ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْسَحُ عَوَاتِقَنَا وَيَقُولُ اسْتَوُوا وَلَا تَخْتَلِفُوا فَتَخْتَلِفَ قُلُوبُكُمْ وَلْيَلِيَنِّي مِنْكُمْ أُولُو الْأَحْلَامِ وَالنُّهَى ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid Al 'Askari] dia berkata; telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari [Sulaiman] dari ['Umarah bin 'Umair] dari [Abu Ma'mar] dari [Abu Mas'ud] dia berkata; \"Dulu Rasulullah Shallallahu'alaihi wasallam mengusap bahu kami sambil berkata, \"Luruskan dan jangan berbeda (bengkok), jika kalian berbeda maka hati akan berselisih. Orang yang berdiri setelahku adalah orang yang bijak dan berilmu, kemudian setelah mereka adalah orang yang kapasitasnya kurang, dan begitu selanjutnya.\""},"803":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنِ نَافِعٍ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ اسْتَوُوا اسْتَوُوا اسْتَوُوا فَوَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَرَاكُمْ مِنْ خَلْفِي كَمَا أَرَاكُمْ مِنْ بَيْنِ يَدَيَّ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Nafi'] dia berkata; telah menceritakan kepada kami [Bahz bin Asad] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] bahwa Nabi Shallallahu'alaihi wasallam bersabda: \"Luruskan, luruskan, luruskan. Demi Dzat yang jiwaku ada di tangan-Nya, aku melihat kalian dari belakang sebagaimana aku melihat kalian dari depan.\""},"804":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ أَنْبَأَنَا إِسْمَعِيلُ عَنْ حُمَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَقْبَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَجْهِهِ حِينَ قَامَ إِلَى الصَّلَاةِ قَبْلَ أَنْ يُكَبِّرَ فَقَالَ أَقِيمُوا صُفُوفَكُمْ وَتَرَاصُّوا فَإِنِّي أَرَاكُمْ مِنْ وَرَاءِ ظَهْرِي","id":"Telah mengabarkan kepada kami ['Ali bin Hujr]; telah memberitakan kepada kami [Isma'il] dari [Humaid] dari [Anas] Radliyallahu'anhu, dia berkata; \"Rasulullah Shallallahu'alaihi wasallam menghadap kepada kami dengan wajahnya ketika iqamah telah dikumandangkan sebelum beliau Shallallahu'alaihi wasallam bertakbir, lalu bersabda: \"Luruskan barisan kalian dan rapatkanlah. Aku melihat kalian dari balik punggungku.\""},"805":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ قَالَ حَدَّثَنَا أَبُو هِشَامٍ قَالَ حَدَّثَنَا أَبَانُ قَالَ حَدَّثَنَا قَتَادَةُ قَالَ حَدَّثَنَا أَنَسٌأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَاصُّوا صُفُوفَكُمْ وَقَارِبُوا بَيْنَهَا وَحَاذُوا بِالْأَعْنَاقِ فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ إِنِّي لَأَرَى الشَّيَاطِينَ تَدْخُلُ مِنْ خَلَلِ الصَّفِّ كَأَنَّهَا الْحَذَفُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak Al Mukharrimi] dia berkata; telah menceritakan kepada kami [Abu Hisyam] dia berkata; telah menceritakan kepada kami [Aban] dia berkata; telah menceritakan kepada kami [Qatadah] dia berkata; telah menceritakan kepada kami [Anas] dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"luruskan barisan kalian, saling mendekatlah di antara barisan, dan sejajarkan antara bahu dengan bahu. Demi Dzat yang jiwa Muhammad ada di tangan-Nya, aku melihat setan masuk dari celah-celah barisan laksana kambing kecil.\""},"806":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْفُضَيْلُ بْنُ عِيَاضٍ عَنْ الْأَعْمَشِ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا تَصُفُّونَ كَمَا تَصُفُّ الْمَلَائِكَةُ عِنْدَ رَبِّهِمْ قَالُوا وَكَيْفَ تَصُفُّ الْمَلَائِكَةُ عِنْدَ رَبِّهِمْ قَالَ يُتِمُّونَ الصَّفَّ الْأَوَّلَ ثُمَّ يَتَرَاصُّونَ فِي الصَّفِّ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Fudhail bin 'Iyadh] dari [Al A'masy] dari [Al Musayyab bin Rafi'] dari [Tamim bin Tharafah] dari [Jabir bin Samu Radliyallahu'anha] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam keluar kepada kami sambil bersabda: \"Tidakkah kalian berbaris seperti barisan para malaikat di sisi Rabb mereka? ' Para sahabat bertanya, 'Bagaimanakah cara malaikat berbaris di sisi Rabb mereka? ' Beliau Shallallahu'alaihi wasallam menjawab, 'Mereka menyempurnakan barisan pertama dahulu, kemudian merapatkan barisan tersebut.\""},"807":{"ar":"أَخْبَرَنِي يَحْيَى بْنُ عُثْمَانَ الْحِمْصِيُّ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ الْعِرْبَاضِ بْنِ سَارِيَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي عَلَى الصَّفِّ الْأَوَّلِ ثَلَاثًا وَعَلَى الثَّانِي وَاحِدَةً","id":"Telah mengabarkan kepadaku [Yahya bin 'Utsman Al Himshi] dia berkata; telah menceritakan kepada kami [Baqiyyah] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] dari [Al 'Irbadh bin Sariyah] dari Rasulullah Shallallahu'alihiwasallam bahwa beliau mendoa'akan (Rahmat dan ampunan) barisan pertama tiga kali, lalu mendo'akan barisan kedua satu kali.\""},"808":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ خَالِدٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتِمُّوا الصَّفَّ الْأَوَّلَ ثُمَّ الَّذِي يَلِيهِ وَإِنْ كَانَ نَقْصٌ فَلْيَكُنْ فِي الصَّفِّ الْمُؤَخَّرِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dari [Khalid] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Sempurnakan barisan pertama kemudian barisan selanjutnya, dan jika kekurangan tempat, hendaknya barisan terakhir.\""},"809":{"ar":"أَخْبَرَنَا عِيسَى بْنُ إِبْرَاهِيمَ بْنِ مَثْرُودٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ وَصَلَ صَفًّا وَصَلَهُ اللَّهُ وَمَنْ قَطَعَ صَفًّا قَطَعَهُ اللَّهُ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami ['Isa bin Ibrahim bin Matsrud] dia berkata; telah menceritakan kepada kami [Abdullah bin Wahb] dari [Mu'awiyah bin Shalih] dari [Abu Az Zahiriyyah] dari [Katsir bin Murrah] dari [Abdullah bin 'Umar] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa menyambung barisan Allah menyambung-nya, dan barang siapa memutus barisan Allah Azza wa Jalla memutusnya.\""},"810":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ صُفُوفِ الرِّجَالِ أَوَّلُهَا وَشَرُّهَا آخِرُهَا وَخَيْرُ صُفُوفِ النِّسَاءِ آخِرُهَا وَشَرُّهَا أَوَّلُهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Jarir] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Sebaik-baik barisan laki-laki adalah barisan pertama, dan yang paling jelek adalah barisan paling belakang. Sedangkan barisan perempuan yang baik adalah barisan paling belakang, dan barisan yang paling jelek adalah barisan yang paling depan.\""},"811":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ يَحْيَى بْنِ هَانِئٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ مَحْمُودٍ قَالَكُنَّا مَعَ أَنَسٍ فَصَلَّيْنَا مَعَ أَمِيرٍ مِنْ الْأُمَرَاءِ فَدَفَعُونَا حَتَّى قُمْنَا وَصَلَّيْنَا بَيْنَ السَّارِيَتَيْنِ فَجَعَلَ أَنَسٌ يَتَأَخَّرُ وَقَالَ قَدْ كُنَّا نَتَّقِي هَذَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dari [Sufyan] dari [Yahya bin Hani'] dari [Abdul Hamid bin Mahmud] dia berkata; \"Aku dan Anas pernah shalat bersama salah seorang penguasa, dan karena mereka mendorong kami hingga kami berdiri dan shalat di antara dua tiang, maka [Anas] tergeser ke belakang. Lantas ia berkata, 'Kami menghindari tiang ini pada masa Rasulullah Shallallahu'alaihi wasallam.\""},"812":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مِسْعَرٍ عَنْ ثَابِتِ بْنِ عُبَيْدٍ عَنْ ابْنِ الْبَرَاءِ عَنْ الْبَرَاءِ قَالَكُنَّا إِذَا صَلَّيْنَا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْبَبْتُ أَنْ أَكُونَ عَنْ يَمِينِهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah] dari [Mis'ar] dari [Tsabit bin 'Ubaid] dari [Ibnul Barra'] dari [Al Barra'] dia berkata; \"Kami dahulu bila shalat di belakang Rasulullah Shallallahu'alihiwasallam aku suka berada di sebelah kanannya.\""},"813":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا صَلَّى أَحَدُكُمْ بِالنَّاسِ فَلْيُخَفِّفْ فَإِنَّ فِيهِمْ السَّقِيمَ وَالضَّعِيفَ وَالْكَبِيرَ فَإِذَا صَلَّى أَحَدُكُمْ لِنَفْسِهِ فَلْيُطَوِّلْ مَا شَاءَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi Shallallahu'alihiwasallam beliau bersabda: \"Bila seorang dari kalian melakukan shalat bersama orang-orang (menjadi imam), maka ringankanlah. karena di kalangan mereka ada yang sakit, yang lemah, dan yang sudah tua. Tetapi jika salah seorang dari kalian shalat sendirian, maka ia boleh memperpanjang sekehendaknya. "},"814":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَخَفَّ النَّاسِ صَلَاةً فِي تَمَامٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] bahwa Nabi Shallallahu'alaihi wasallam adalah orang yang paling ringan shalatnya namun sempurna."},"815":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنِّي لَأَقُومُ فِي الصَّلَاةِ فَأَسْمَعُ بُكَاءَ الصَّبِيِّ فَأُوجِزُ فِي صَلَاتِي كَرَاهِيَةَ أَنْ أَشُقَّ عَلَى أُمِّهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami [Abdullah] dari [Al Auza'i] dia berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [bapaknya] dari Nabi Shallallahu'alihiwasallam beliau Shallallahu'alaihi wasallam bersabda: \"Aku sedang berdiri saat shalat, lalu kudengar tangis anak kecil, maka aku pendekkan shalatku. karena aku tidak suka memberatkan (menyusahkan) ibunya.\""},"816":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ ابْنِ أَبِي ذِئْبٍ قَالَ أَخْبَرَنِي الْحَارِثُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِالتَّخْفِيفِ وَيَؤُمُّنَا بِالصَّافَّاتِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dari [Ibnu Abu Dzi'b] dia berkata; telah mengabarkan kepadaku [Al Harits bin 'Abdurrahman] dari [Salim bin Abdullah] dari [Abdullah bin 'Umar] dia berkata; \"Dahulu Rasulullah Shallallahu'alaihi wasallam memerintahkan untuk meringankan shalat. Beliau juga mengimami kami dengan membaca surat Ash-Shaffat.\""},"817":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ أَبِي سُلَيْمَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ أَبِي قَتَادَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّ النَّاسَ وَهُوَ حَامِلٌ أُمَامَةَ بِنْتَ أَبِي الْعَاصِ عَلَى عَاتِقِهِ فَإِذَا رَكَعَ وَضَعَهَا وَإِذَا رَفَعَ مِنْ سُجُودِهِ أَعَادَهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Utsman bin Abu Sulaiman] dari ['Amir bin Abdullah bin Az Zubair] dari ['Amr bin Sulaim Az Zuraqi] dari [Abu Qatadah] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam mengimami orang-orang sedangkan beliau membawa Umamah binti Abu Ash di atas pundaknya. Rasulullah Shallallahu'alaihi wasallam meletakkannya ketika ruku dan menggendongnya ketika bangun dari sujud.\""},"818":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ مُحَمَّدٌ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا يَخْشَى الَّذِي يَرْفَعُ رَأْسَهُ قَبْلَ الْإِمَامِ أَنْ يُحَوِّلَ اللَّهُ رَأْسَهُ رَأْسَ حِمَارٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Muhammad bin Ziyad] dari [Abu Hurairah] dia berkata; \"Nabi Muhammad Shallallahu'alaihi wasallam bersabda: \"Apakah orang yang mengangkat kepalanya -saat shalat- sebelum imam tidak takut kalau Allah merubah kepalanya dengan kepala keledai?.\""},"819":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ يَخْطُبُ قَالَ حَدَّثَنَا الْبَرَاءُ وَكَانَ غَيْرَ كَذُوبٍأَنَّهُمْ كَانُوا إِذَا صَلَّوْا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَامُوا قِيَامًا حَتَّى يَرَوْهُ سَاجِدًا ثُمَّ سَجَدُوا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Abu Ishaq] dia berkata; aku mendengar [Abdullah bin Yazid] berkhutbah, dia berkata; telah menceritakan kepada kami [Al Barra'] -dia bukan pendusta-: Bila mereka (para sahabat) mengerjakan shalat bersama Rasulullah Shallallahu'alihiwasallam dan Rasulullah Shallallahu'alaihi wasallam mengangkat kepalanya dari ruku', maka mereka tetap berdiri hingga mereka melihat Rasulullah Shallallahu'alaihi wasallam dalam keadaan sujud, kemudian setelah itu mereka sujud."},"820":{"ar":"أَخْبَرَنَا مُؤَمَّلُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ قَالَصَلَّى بِنَا أَبُو مُوسَى فَلَمَّا كَانَ فِي الْقَعْدَةِ دَخَلَ رَجُلٌ مِنْ الْقَوْمِ فَقَالَ أُقِرَّتْ الصَّلَاةُ بِالْبِرِّ وَالزَّكَاةِ فَلَمَّا سَلَّمَ أَبُو مُوسَى أَقْبَلَ عَلَى الْقَوْمِ فَقَالَ أَيُّكُمْ الْقَائِلُ هَذِهِ الْكَلِمَةَ فَأَرَمَّ الْقَوْمُ قَالَ يَا حِطَّانُ لَعَلَّكَ قُلْتَهَا قَالَ لَا وَقَدْ خَشِيتُ أَنْ تَبْكَعَنِي بِهَا فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعَلِّمُنَا صَلَاتَنَا وَسُنَّتَنَا فَقَالَ إِنَّمَا الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا قَالَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقُولُوا آمِينَ يُجِبْكُمْ اللَّهُ وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا لَكَ الْحَمْدُ يَسْمَعْ اللَّهُ لَكُمْ وَإِذَا سَجَدَ فَاسْجُدُوا وَإِذَا رَفَعَ فَارْفَعُوا فَإِنَّ الْإِمَامَ يَسْجُدُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ","id":"Telah mengabarkan kepada kami [Muammal bin Hisyam] dia berkata; telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Sa'id] dari [Qatadah] dari [Yunus bin Jubair] dari [Hiththan bin Abdullah] dia berkata; \"Kami shalat bersama Abu Musa, setelah ia duduk seorang laki-laki dari kaumnya datang dan berkata, 'Shalat telah ditetapkan dengan kebaikan dan zakat'. Sesudah Abu Musa salam, ia menghadap kepada kaumnya sambil berkata, Tadi siapa yang mengatakan hal tersebut? ' Kaumnya terdiam semua, lantas ia bertanya, 'Hai Hiththan, mungkin kamu tadi yang mengucapkannya? ' la menjawab, 'Tidak. Aku khawatir kalau engkau akan mencelaku dengan hal ini'. Kemudian [Abu Musa] berkata, 'Rasulullah Shallallahu'alaihi wasallam mengajarkan shalat dan Sunnah-sunnah kepada kami, beliau Shallallahu'alaihi wasallam bersabda, \"Imam itu untuk diikuti. Bila ia bertakbir maka bertakbirlah dan bila imam mengucapkan, 'Ghairil maghdhubi 'alaihim walaadh-dhaalliin (Bukan orang-orang yang dimurkai bukan pula orang-orang yang sesat) ' maka ucapkan, 'Aamiin'. Semoga Allah mengabulkan kalian. Jika imam rukuk maka rukuklah dan jika mengangkat (kepala dari ruku') dengan mengucapkan 'Sami'allaahu liman hamidah (Allah mendengar orang yang memujinya) ' maka ucapkan, 'Rabbanaa lakal hamdu (Wahai Rabb kami, untuk-Mu segala pujian) ' Semoga Allah mendengar kalian. Bila, imam sujud maka ikutlah sujud dan jika ia mengangkat (kepala dari sujud) maka angkatlah. Imam sujud sebelum kalian dan mengangkat (kepala dari sujud) sebelum kalian.\" Lantas Rasulullah Shallallahu'alaihi wasallam bersabda -demikianlah tata cara yang harus dilakukan antara imam dengan makmum-, \" Masing-masing gerakan itu, kalian ikuti sesudahnya\""},"821":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ عَنْ مُحَارِبِ بْنِ دِثَارٍ وَأَبِي صَالِحٍ عَنْ جَابِرٍ قَالَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ وَقَدْ أُقِيمَتْ الصَّلَاةُ فَدَخَلَ الْمَسْجِدَ فَصَلَّى خَلْفَ مُعَاذٍ فَطَوَّلَ بِهِمْ فَانْصَرَفَ الرَّجُلُ فَصَلَّى فِي نَاحِيَةِ الْمَسْجِدِ ثُمَّ انْطَلَقَ فَلَمَّا قَضَى مُعَاذٌ الصَّلَاةَ قِيلَ لَهُ إِنَّ فُلَانًا فَعَلَ كَذَا وَكَذَا فَقَالَ مُعَاذٌ لَئِنْ أَصْبَحْتُ لَأَذْكُرَنَّ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى مُعَاذٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِ فَقَالَ مَا حَمَلَكَ عَلَى الَّذِي صَنَعْتَ فَقَالَ يَا رَسُولَ اللَّهِ عَمِلْتُ عَلَى نَاضِحِي مِنْ النَّهَارِ فَجِئْتُ وَقَدْ أُقِيمَتْ الصَّلَاةُ فَدَخَلْتُ الْمَسْجِدَ فَدَخَلْتُ مَعَهُ فِي الصَّلَاةِ فَقَرَأَ سُورَةَ كَذَا وَكَذَا فَطَوَّلَ فَانْصَرَفْتُ فَصَلَّيْتُ فِي نَاحِيَةِ الْمَسْجِدِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَتَّانٌ يَا مُعَاذُ أَفَتَّانٌ يَا مُعَاذُ أَفَتَّانٌ يَا مُعَاذُ","id":"Telah mengabarkan kepada kami [Washil bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Ibnu Fudhail] dari [Al A'masy] dari [Muharib bin Ditsar] dan [Abu Shalih] dari [Jabir] dia berkata; \"Seorang laki-laki Anshar datang, dan iqamah shalat sudah dikumandangkan. Lalu ia masuk ke masjid dan shalat di belakang Mua'dz. la memperlama shalatnya bersama jamaah, maka laki-laki tadi keluar dari jamaah dan shalat di pojok masjid kemudian pergi. Setelah Mua'dz selesai shalat, ia diberitahu, 'Si Fulan berbuat begini dan begitu'. Lalu Mua'dz berkata, 'Besok pagi akan aku ceritakan hal ini kepada Rasulullah Shallallahu'alihiwasallam. Maka Mua'dz segera datang kepada Rasulullah Shallallahu'alaihi wasallam dan menceritakan hal tersebut. Rasulullah Shallallahu'alaihi wasallam kemudian mengutus seseorang kepadanya (untuk memanggilnya), lalu beliau Shallallahu'alaihi wasallam bertanya kepadanya, ' 'Apakah yang mendorongmu berbuat demikian? ' la menjawab. 'Wahai Rasulullah Shallallahu'alihiwasallam aku pekerja keras di siang hari dan aku datang sedangkan iqamah shalat sudah dikumandangkan. Lalu aku segera masuk masjid dan shalat bersamanya, dan ia membaca surat ini dan surat itu. la memperlama shalatnya, maka aku keluar dan mengerjakan shalat di pojok masjid'. Kemudian Rasulullah Shallallahu'alaihi wasallam bersabda, 'Wahai Mua'dz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? Wahai Mua 'dz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? Wahai Mua 'dz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? "},"822":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكِبَ فَرَسًا فَصُرِعَ عَنْهُ فَجُحِشَ شِقُّهُ الْأَيْمَنُ فَصَلَّى صَلَاةً مِنْ الصَّلَوَاتِ وَهُوَ قَاعِدٌ فَصَلَّيْنَا وَرَاءَهُ قُعُودًا فَلَمَّا انْصَرَفَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا صَلَّى قَائِمًا فَصَلُّوا قِيَامًا وَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا لَكَ الْحَمْدُ وَإِذَا صَلَّى جَالِسًا فَصَلُّوا جُلُوسًا أَجْمَعُونَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Anas bin Malik] bahwa Rasulullah Shallallahu'alaihi wasallam pernah naik kuda dan beliau terjatuh dari kudanya, maka bagian kanan badannya terluka. Kemudian beliau shalat sambil duduk. dan kami juga shalat di belakangnya sambil duduk. Setelah selesai shalat, Beliau Shallallahu'alaihi wasallam bersabda, \"Tidaklah seorang imam itu dijadikan melainkan untuk diikuti. Jika dia shalat dengan berdiri maka shalatlah kalian dengan berdiri, dan jika ia rukuk, maka rukuklah kalian, dan jika ia mengucapkan 'Sami'allahuliman hamidah (Allah Maha Mendengar siapa yang memujinya) maka ucapkan, 'Rabbana lakal hamdu (Ya Allah, untuk-Mu segala pujian) dan bila ia shalat dengan duduk maka shalatlah kalian dengan duduk.\""},"823":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْلَمَّا ثَقُلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ بِلَالٌ يُؤْذِنُهُ بِالصَّلَاةِ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبَا بَكْرٍ رَجُلٌ أَسِيفٌ وَإِنَّهُ مَتَى يَقُومُ فِي مَقَامِكَ لَا يُسْمِعُ النَّاسَ فَلَوْ أَمَرْتَ عُمَرَ فَقَالَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ فَقُلْتُ لِحَفْصَةَ قُولِي لَهُ فَقَالَتْ لَهُ فَقَالَ إِنَّكُنَّ لَأَنْتُنَّ صَوَاحِبَاتُ يُوسُفَ مُرُوا أَبَا بَكْرٍ فَلْيُصَلِّ بِالنَّاسِ قَالَتْ فَأَمَرُوا أَبَا بَكْرٍ فَلَمَّا دَخَلَ فِي الصَّلَاةِ وَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نَفْسِهِ خِفَّةً قَالَتْ فَقَامَ يُهَادَى بَيْنَ رَجُلَيْنِ وَرِجْلَاهُ تَخُطَّانِ فِي الْأَرْضِ فَلَمَّا دَخَلَ الْمَسْجِدَ سَمِعَ أَبُو بَكْرٍ حِسَّهُ فَذَهَبَ لِيَتَأَخَّرَ فَأَوْمَأَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ قُمْ كَمَا أَنْتَ قَالَتْ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى قَامَ عَنْ يَسَارِ أَبِي بَكْرٍ جَالِسًا فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِالنَّاسِ جَالِسًا وَأَبُو بَكْرٍ قَائِمًا يَقْتَدِي أَبُو بَكْرٍ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ يَقْتَدُونَ بِصَلَاةِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] Radliyallahu'anha dia berkata; \"Tatkala Rasulullah Shallallahu'alaihi wasallam merasa berat (sakitnya), Bilal datang kepada beliau untuk memberitahukan tentang (datangnya waktu) shalat, maka beliau Shallallahu'alaihi wasallam bersabda 'Perintahkan Abu Bakar untuk shalat mengimami orang-orang'. Aku berkata, 'Wahai Rasulullah Shallallahu'alihiwasallam Abu Bakar orang yang berhati lembut, jadi jika ia menggantikan posisi engkau maka orang-orang tidak bisa mendengar suaranya. Bagaimana jika engkau menyuruh Umar?\" Beliau Shallallahu'alaihi wasallam tetap berkata, 'Perintahkan Abu Bakar untuk shalat mengimami orang-orang'. Lalu aku berkata kepada Hafshah, 'Katakan kepada beliau Shallallahu'alaihi wasallam (agar beliau menyuruh Umar) '. Kemudian Hafshah berkata kepada Rasulullah Shallallahu'alaihi wasallam tentang hal itu, dan beliau Shallallahu'alaihi wasallam bersabda, Kalian (para wanita seperti) saudara Yusuf, maka perintahkan Abu Bakar untuk Shalat bersama kaum muslim.\" Aisyah berkata; \"Lalu orang-orang menyuruh Abu Bakar. Setelah Abu Bakar memulai shalat, Rasulullah Shallallahu'alaihi wasallam merasakan badannya ringan.\" Aisyah meneruskan ceritanya, \"Lantas Rasulullah Shallallahu'alaihi wasallam bangkit dengan dipapah oleh dua orang laki-laki, sedangkan kedua kakinya menggores di tanah. Sesampainya di dalam masjid, Abu Bakar masih mendengar nafasnya yang terengah-engah, maka ia berusaha untuk mundur, tetapi Rasulullah Shallallahu'alaihi wasallam mengisyaratkan kepadanya agar tetap di tempatnya. Rasulullah lalu duduk di sebelah Abu Bakar. Beliau shalat mengimami kaum muslimin dengan duduk dan Abu Bakar shalat berdiri dengan mengikuti Rasulullah Shallallahu'alihiwasallam sedangkan kaum muslimin mengikuti shalat Abu Bakar Radliyallahu'anhu\""},"824":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا زَائِدَةُ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَ دَخَلْتُ عَلَى عَائِشَةَ فَقُلْتُأَلَا تُحَدِّثِينِي عَنْ مَرَضِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لَمَّا ثَقُلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَصَلَّى النَّاسُ فَقُلْنَا لَا وَهُمْ يَنْتَظِرُونَكَ يَا رَسُولَ اللَّهِ فَقَالَ ضَعُوا لِي مَاءً فِي الْمِخْضَبِ فَفَعَلْنَا فَاغْتَسَلَ ثُمَّ ذَهَبَ لِيَنُوءَ فَأُغْمِيَ عَلَيْهِ ثُمَّ أَفَاقَ فَقَالَ أَصَلَّى النَّاسُ قُلْنَا لَا هُمْ يَنْتَظِرُونَكَ يَا رَسُولَ اللَّهِ فَقَالَ ضَعُوا لِي مَاءً فِي الْمِخْضَبِ فَفَعَلْنَا فَاغْتَسَلَ ثُمَّ ذَهَبَ لِيَنُوءَ ثُمَّ أُغْمِيَ عَلَيْهِ ثُمَّ قَالَ فِي الثَّالِثَةِ مِثْلَ قَوْلِهِ قَالَتْ وَالنَّاسُ عُكُوفٌ فِي الْمَسْجِدِ يَنْتَظِرُونَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِصَلَاةِ الْعِشَاءِ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَبِي بَكْرٍ أَنْ صَلِّ بِالنَّاسِ فَجَاءَهُ الرَّسُولُ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكَ أَنْ تُصَلِّيَ بِالنَّاسِ وَكَانَ أَبُو بَكْرٍ رَجُلًا رَقِيقًا فَقَالَ يَا عُمَرُ صَلِّ بِالنَّاسِ فَقَالَ أَنْتَ أَحَقُّ بِذَلِكَ فَصَلَّى بِهِمْ أَبُو بَكْرٍ تِلْكَ الْأَيَّامَ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ مِنْ نَفْسِهِ خِفَّةً فَجَاءَ يُهَادَى بَيْنَ رَجُلَيْنِ أَحَدُهُمَا الْعَبَّاسُ لِصَلَاةِ الظُّهْرِ فَلَمَّا رَآهُ أَبُو بَكْرٍ ذَهَبَ لِيَتَأَخَّرَ فَأَوْمَأَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا يَتَأَخَّرَ وَأَمَرَهُمَا فَأَجْلَسَاهُ إِلَى جَنْبِهِ فَجَعَلَ أَبُو بَكْرٍ يُصَلِّي قَائِمًا وَالنَّاسُ يُصَلُّونَ بِصَلَاةِ أَبِي بَكْرٍ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَاعِدًافَدَخَلْتُ عَلَى ابْنِ عَبَّاسٍ فَقُلْتُ أَلَا أَعْرِضُ عَلَيْكَ مَا حَدَّثَتْنِي عَائِشَةُ عَنْ مَرَضِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ فَحَدَّثْتُهُ فَمَا أَنْكَرَ مِنْهُ شَيْئًا غَيْرَ أَنَّهُ قَالَ أَسَمَّتْ لَكَ الرَّجُلَ الَّذِي كَانَ مَعَ الْعَبَّاسِ قُلْتُ لَا قَالَ هُوَ عَلِيٌّ كَرَّمَ اللَّهُ وَجْهَهُ","id":"Telah mengabarkan kepada kami [Al 'Abbas bin Abdul 'Azhim Al 'Anbari] dia berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dia berkata; telah menceritakan kepada kami [Zaidah] dari [Musa bin Abu 'Aisyah] dari ['Ubaidullah bin Abdullah] dia berkata; aku masuk menemui 'Aisyah, maka aku berkata; Sudilah kiranya engkau memberitahukanku sakitnya Rasulullah Shallallahu'alihiwasallam. [Aisyah] menjawab. 'Ketika Rasulullah Shallallahu'alaihi wasallam sakit berat, beliau Shallallahu'alaihi wasallam bersabda.\"Apakah orang-orang telah shalat?\" Kami menjawab, \"Belum wahai Rasulullah Shallallahu'alihiwasallam, mereka menunggu engkau.\" Beliau bersabda, \"Letakkan air untukku di dalam bak\": Aisyah berkata, 'Lantas kami mengerjakannya. Lalu beliau mandi, kemudian bangkit dengan susah payah. Tiba-tiba beliau Shallallahu'alaihi wasallam pingsan 'dan tersadar kembali, lalu beliau Shallallahu'alaihi wasallam bersabda: \"Apakah orang-orang sudah shalat?\" Kami menjawab, \"Belum wahai Rasulullah Shallallahu'alihiwasallam mereka menunggu engkau.\" Beliau bersabda; \"Letakkan air untukku di dalam bak\": Aisyah berkata, 'Lantas kami mengerjakannya. Beliau lalu mandi dan bangkit dengan susah payah. Tiba-tiba beliau Shallallahu'alaihi wasallam pingsan dan tersadar kembali lalu bersabda.\"Apakah orang-orang sudah shalat?\" Kami menjawab, \"Belum wahai Rasulullah Shallallahu'alihiwasallam mereka menunggu engkau.\" Kemudian beliau berkata yang ketiga kalinya seperti perkataan tadi. Orang-orang tinggal di masjid untuk menunggu Nabi Shallallahu'alaihi wasallam untuk shalat Isya Kemudian Rasulullah Shallallahu'alaihi wasallam mengutus seseorang kepada Abu Bakar agar menyuruh dia untuk shalat mengimami orang-orang. Ketika utusan Rasulullah Shallallahu'alaihi wasallam datang kepada Abu Bakar, ia berkata, \"Rasulullah Shallallahu'alaihi wasallam memerintahkanmu untuk shalat bersama (mengimami) kaum orang-orang.\" Abu Bakar adalah orang yang sangat lembut hatinya (mudah menangis), maka ia berkata kepada Umar, \"Wahai Umar, shalatlah bersama (mengimami) orang-orang.\" Umar menjawab, \"Kamu lebih berhak untuk itu.\" Kemudian Abu Bakar shalat bersama (megimami) kaum muslim pada hari-hari itu. Kemudian Rasulullah Shallallahu'alaihi wasallam merasa enak badan, maka beliau Shallallahu'alaihi wasallam datang dengan dipapah oleh dua orang laki-laki -salah satunya adalah Abbas- untuk shalat Zhuhur. Tatkala Abu Bakar melihat beliau, ia segera mundur, tetapi Rasulullah Shallallahu'alaihi wasallam mengisyaratkan kepadanya agar tidak mundur. Rasulullah Shallallahu'alaihi wasallam memerintahkan dua orang yang memapahnya untuk mendudukkannya di samping Abu Bakar. Kemudian Abu Bakar shalat sambil berdiri dan oreng-orang shalat dengan mengikuti shalatnya Abu Bakar, sedangkan Rasulullah Shallallahu'alaihi wasallam shalat dengan duduk.' Kemudian aku masuk ke tempat Ibnu Abbas dan aku katakan kepadanya, 'Maukah aku ceritakan kepadamu apa yang diceritakan oleh Aisyah kepadaku tentang sakit Rasulullah Shallallahu'alaihi wasallam? ' [Ibnu Abbas] menjawab, 'Ya'. Maka aku memaparkan cerita Aisyah tadi, dan ia tidak mengingkari sedikitpun. la bertanya kepadaku, 'Apakah ia menyebutkan nama laki-laki yang bersama Abbas? ' Aku menjawab, Tidak'. Ibnu Abbas berkata, 'Dia adalah Ali bin Abu Thalib'.\""},"825":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُكَانَ مُعَاذٌ يُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ يَرْجِعُ إِلَى قَوْمِهِ يَؤُمُّهُمْ فَأَخَّرَ ذَاتَ لَيْلَةٍ الصَّلَاةَ وَصَلَّى مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ رَجَعَ إِلَى قَوْمِهِ يَؤُمُّهُمْ فَقَرَأَ سُورَةَ الْبَقَرَةِ فَلَمَّا سَمِعَ رَجُلٌ مِنْ الْقَوْمِ تَأَخَّرَ فَصَلَّى ثُمَّ خَرَجَ فَقَالُوا نَافَقْتَ يَا فُلَانُ فَقَالَ وَاللَّهِ مَا نَافَقْتُ وَلَآتِيَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُخْبِرُهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ مُعَاذًا يُصَلِّي مَعَكَ ثُمَّ يَأْتِينَا فَيَؤُمُّنَا وَإِنَّكَ أَخَّرْتَ الصَّلَاةَ الْبَارِحَةَ فَصَلَّى مَعَكَ ثُمَّ رَجَعَ فَأَمَّنَا فَاسْتَفْتَحَ بِسُورَةِ الْبَقَرَةِ فَلَمَّا سَمِعْتُ ذَلِكَ تَأَخَّرْتُ فَصَلَّيْتُ وَإِنَّمَا نَحْنُ أَصْحَابُ نَوَاضِحَ نَعْمَلُ بِأَيْدِينَا فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مُعَاذُ أَفَتَّانٌ أَنْتَ اقْرَأْ بِسُورَةِ كَذَا وَسُورَةِ كَذَا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr] dia berkata; aku mendengar [Jabir bin Abdullah] dia berkata; \"Mua'dz shalat bersama Nabi Shallallahu'alihiwasallam, kemudian ia kembali kepada kaumnya dan mengimami shalat mereka di malam hari dan ia (Mua'dz) memanjangkan shalatnya. Kemudian Muadz shalat bersama Rasulullah, lalu ia kembali kepada kaumnya dan mengimami shalat mereka, dan ia membaca surat Al Baqarah. Ketika salah seorang kaumnya mendengar Muadz lama dalam shalat, ia keluar dari shalat dan shalat sendiri, maka kaumnya berkata kepadanya, 'Kamu munafik wahai fulan'. Orang itu menjawab, 'Demi Allah, aku tidak munafik. Aku akan mendatangi dan menceritakan hal ini pada Nabi Shallallahu'alihiwasallam. Lalu orang itu mendatangi Nabi Shallallahu'alaihi wasallam dan berkata, 'Wahai Rasulullah, Muadz shalat bersama Anda. kemudian ia kembali dan mengimami shalat kami. Anda melamakan shalat kemarin malam, lalu Muadz shalat dengan Anda, kemudian dia kembali dan mengimami kami, dan ia memulai shalat dengan membaca surat Albaqarah. Ketika aku mendengarnya membaca surat Albaqarah. maka aku mundur dan shalat sendiri, karena kami pekerja keras yang bekerja dengan tangan kami. Rasulullah Shallallahu'alaihi wasallam lalu bersabda, 'Wahai Muadz, apakah kamu ingin menimbulkan fitnah? Bacalah surat ini dan surat ini (maksudnya surat yang pendek) '.\""},"826":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ أَشْعَثَ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى صَلَاةَ الْخَوْفِ فَصَلَّى بِالَّذِينَ خَلْفَهُ رَكْعَتَيْنِ وَبِالَّذِينَ جَاءُوا رَكْعَتَيْنِ فَكَانَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعًا وَلِهَؤُلَاءِ رَكْعَتَيْنِ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dari [Asy'ats] dari [Al Hasan] dari [Abu Bakar] dari Rasulullah Shallallahu'alihiwasallam bahwa ia pernah shalat Khauf (shalat saat perang). Beliau shalat dengan -jamaah- yang di belakangnya dua rakaat dan shalat dengan -jamaah- yang datang kemudian dua rakaat. Nabi Shallallahu'alaihi wasallam shalat empat rakaat sedangkan para jamaahnya shalat dua rakaat. "},"827":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْجَمَاعَةِ تَفْضُلُ عَلَى صَلَاةِ الْفَذِّ بِسَبْعٍ وَعِشْرِينَ دَرَجَةً","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibnu 'Umar] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, \"Shalat berjamaah lebih utama daripada shalat sendirian, dengan kelebihan dua puluh tujuh derajat.\""},"828":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْجَمَاعَةِ أَفْضَلُ مِنْ صَلَاةِ أَحَدِكُمْ وَحْدَهُ خَمْسًا وَعِشْرِينَ جُزْءًا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, \"Shalat berjamaah lebih utama daripada shalat salah seorang dari kalian sendirian dengan kelebihan dua puluh lima bagian.\""},"829":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَمَّارٍ قَالَ حَدَّثَنِي الْقَاسِمُ بْنُ مُحَمَّدٍ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْجَمَاعَةِ تَزِيدُ عَلَى صَلَاةِ الْفَذِّ خَمْسًا وَعِشْرِينَ دَرَجَةً","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Abdurrahman bin 'Ammar] dia berkata; telah menceritakan kepadaku [Al Qasim bin Muhammad] dari ['Aisyah] dari Nabi Shallallahu'alihiwasallam beliau bersabda: \"Shalat berjamaah (pahalanya) melebihi atas shalat sendirian sebanyak dua puluh lima derajat.\""},"830":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانُوا ثَلَاثَةً فَلْيَؤُمَّهُمْ أَحَدُهُمْ وَأَحَقُّهُمْ بِالْإِمَامَةِ أَقْرَؤُهُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Abu Nadhrah] dari [Abu Sa'id] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bila mereka bertiga, maka salah seorang dari mereka menjadi imam bagi yang lain, dan yang paling berhak menjadi imam adalah yang paling banyak hapalannya.\""},"831":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي زِيَادٌ أَنَّ قَزَعَةَ مَوْلًى لِعَبْدِ الْقَيْسِ أَخْبَرَهُ أَنَّهُ سَمِعَ عِكْرِمَةَ قَالَ قَالَ ابْنُ عَبَّاسٍصَلَّيْتُ إِلَى جَنْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَائِشَةُ خَلْفَنَا تُصَلِّي مَعَنَا وَأَنَا إِلَى جَنْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُصَلِّي مَعَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ib Radliyallahu'anha im] dia berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Ziyad] bahwasanya [Qaza'ah] -seorang budak Abdul Qais- mengabarkan kepadanya bahwasanya ia mendengar ['Ikrimah] berkata; [Ibnu 'Abbas] berkata; \"Aku pernah shalat di samping Rasulullah Shallallahu'alihiwasallam. Aisyah juga shalat bersama kami di belakang, sedangkan aku di samping Rasulullah Shallallahu'alaihi wasallam."},"832":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَنِي بِيَدِهِ الْيُسْرَى فَأَقَامَنِي عَنْ يَمِينِهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami [Abdullah] dari [Abdul Malik bin Abu Sulaiman] dari ['Atha] dari [Ibnu 'Abbas] dia berkata; \"Aku shalat bersama Rasulullah Shallallahu'alihiwasallam dan aku berdiri di sebelah kiri beliau. Tetapi beliau memegangku dengan tangan kirinya dan memposisikan diriku di sebelah kanannya.\""},"833":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ شُعْبَةَ عَنْ أَبِي إِسْحَقَ أَنَّهُ أَخْبَرَهُمْ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَصِيرٍ عَنْ أَبِيهِ قَالَ شُعْبَةُ وَقَالَ أَبُو إِسْحَقَ وَقَدْ سَمِعْتُهُ مِنْهُ وَمِنْ أَبِيهِ قَالَ سَمِعْتُ أُبَيَّ بْنَ كَعْبٍ يَقُولُصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا صَلَاةَ الصُّبْحِ فَقَالَ أَشَهِدَ فُلَانٌ الصَّلَاةَ قَالُوا لَا قَالَ فَفُلَانٌ قَالُوا لَا قَالَ إِنَّ هَاتَيْنِ الصَّلَاتَيْنِ مِنْ أَثْقَلِ الصَّلَاةِ عَلَى الْمُنَافِقِينَ وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا وَالصَّفُّ الْأَوَّلُ عَلَى مِثْلِ صَفِّ الْمَلَائِكَةِ وَلَوْ تَعْلَمُونَ فَضِيلَتَهُ لَابْتَدَرْتُمُوهُ وَصَلَاةُ الرَّجُلِ مَعَ الرَّجُلِ أَزْكَى مِنْ صَلَاتِهِ وَحْدَهُ وَصَلَاةُ الرَّجُلِ مَعَ الرَّجُلَيْنِ أَزْكَى مِنْ صَلَاتِهِ مَعَ الرَّجُلِ وَمَا كَانُوا أَكْثَرَ فَهُوَ أَحَبُّ إِلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dari [Syu'bah] dari [Abu Ishaq] bahwasanya ia mengabarkan kepada mereka, dari [Abdullah bin Abu Bashir] dari [bapaknya], [Syu'bah] berkata; dan berkata [Abu Ishaq] dan aku telah mendengarnya darinya dari [Bapaknya], dia berkata; aku mendengar [Ubay bin Ka'b] berkata; \"Suatu hari Rasulullah Shallallahu'alaihi wasallam mengerjakan shalat Subuh, lantas beliau bersabda, Apakah kamu melihat Fulan ikut shalat berjamaah? ' Para sahabat menjawab, 'Tidak'. Rasulullah Shallallahu'alaihi wasallam bertanya lagi, ' Apakah si Fulan (orang lain lagi) ikut shalat berjamaah? ' Sahabat menjawab, Tidak, Beliau Shallallahu'alaihi wasallam lalu bersabda: 'Dua shalat ini sangat berat bagi orang munafiq. Andaikan mereka mengetahui (pahala) nya, mereka pasti mendatanginya, walau dengan merangkak. Barisan pertama laksana barisan para malaikat, seandainya mereka mengetahui keutamaannya mereka pasti bersegera menuju barisan pertama. Shalatnya seseorang bersama orang lain lebih utama baginya daripada shalat sendirian, dan shalat seseorang bersama dua orang lebih utama daripada shalat bersama satu orang. Kalau mereka bertambah banyak. Allah Azza wa Jalla lebih mencintainya'.\""},"834":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودٍ عَنْ عِتْبَانَ بْنِ مَالِكٍأَنَّهُ قَالَ يَا رَسُولَ اللَّهِ إِنَّ السُّيُولَ لَتَحُولُ بَيْنِي وَبَيْنَ مَسْجِدِ قَوْمِي فَأُحِبُّ أَنْ تَأْتِيَنِي فَتُصَلِّيَ فِي مَكَانٍ مِنْ بَيْتِي أَتَّخِذُهُ مَسْجِدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَنَفْعَلُ فَلَمَّا دَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيْنَ تُرِيدُ فَأَشَرْتُ إِلَى نَاحِيَةٍ مِنْ الْبَيْتِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَفَفْنَا خَلْفَهُ فَصَلَّى بِنَا رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Nashr bin 'Ali] dia berkata; telah memberitakan kepada kami [Abdul A'la] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Mahmud] dari ['Itban bin Malik] bahwasanya dia berkata; \"Wahai Rasulullah Shallallahu'alihiwasallam banjir, menghalangi kami dengan masjid kaumku. Maka aku senang jika engkau shalat di suatu tempat di rumahku yang aku jadikan masjid.\" Rasulullah Shallallahu'alaihi wasallam menjawab, \"Akan aku lakukan.\" Setelah Rasulullah Shallallahu'alaihi wasallam masuk ke rumahnya, beliau bertanya, \"Di sebelah mana kamu ingin aku shalat?\" Lalu dia ditunjukkan ke arah pojok rumah. Kemudian Rasulullah Shallallahu'alaihi wasallam berdiri dan mereka berbaris di belakang beliau, lalu beliau Shallallahu'alaihi wasallam shalat bersama kami dua rakaat."},"835":{"ar":"أَنْبَأَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَأَقْبَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَجْهِهِ حِينَ قَامَ إِلَى الصَّلَاةِ قَبْلَ أَنْ يُكَبِّرَ فَقَالَ أَقِيمُوا صُفُوفَكُمْ وَتَرَاصُّوا فَإِنِّي أَرَاكُمْ مِنْ وَرَاءِ ظَهْرِي","id":"Telah memberitakan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dari [Humaid] dari [Anas] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam menghadap kepada kami dengan wajahnya ketika berdiri sebelum beliau Shallallahu'alaihi wasallam bertakbir, lalu beliau bersabda: \"Luruskan barisan kalian dan rapatkanlah. Karena aku melihat kalian dari balik punggungku.\""},"836":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ قَالَ حَدَّثَنَا أَبُو زُبَيْدٍ وَاسْمُهُ عَبْثَرُ بْنُ الْقَاسِمِ عَنْ حُصَيْنٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ قَالَ بَعْضُ الْقَوْمِ لَوْ عَرَّسْتَ بِنَا يَا رَسُولَ اللَّهِ قَالَ إِنِّي أَخَافُ أَنْ تَنَامُوا عَنْ الصَّلَاةِ قَالَ بِلَالٌ أَنَا أَحْفَظُكُمْ فَاضْطَجَعُوا فَنَامُوا وَأَسْنَدَ بِلَالٌ ظَهْرَهُ إِلَى رَاحِلَتِهِ فَاسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ طَلَعَ حَاجِبُ الشَّمْسِ فَقَالَ يَا بِلَالُ أَيْنَ مَا قُلْتَ قَالَ مَا أُلْقِيَتْ عَلَيَّ نَوْمَةٌ مِثْلُهَا قَطُّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَبَضَ أَرْوَاحَكُمْ حِينَ شَاءَ فَرَدَّهَا حِينَ شَاءَ قُمْ يَا بِلَالُ فَآذِنْ النَّاسَ بِالصَّلَاةِ فَقَامَ بِلَالٌ فَأَذَّنَ فَتَوَضَّئُوا يَعْنِي حِينَ ارْتَفَعَتْ الشَّمْسُ ثُمَّ قَامَ فَصَلَّى بِهِمْ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dia berkata; telah menceritakan kepada kami [Abu Zubaid 'Abtsar bin Al Qasim] dari [Hushain] dari [Abdullah bin Abu Qatadah] dari [Bapaknya], dia berkata; \"Kami bersama Rasulullah Shallallahu'alaihi wasallam lalu ada sebagian orang yang berkata, 'Wahai Rasulullah Shallallahu'alihiwasallam seandainya engkau shalat bersama kami pada akhir malam (pasti itu lebih baik) '. Kemudian beliau bersabda, 'Aku khawatir kalian tertidur sehingga tidak shalat'. Bilal berkata, 'Aku akan menjaga kalian\". Lalu mereka berbaring dan terlelap dalam tidurnya. Sedang Bilal menyandarkan punggungnya ke untanya. Rasulullah Shallallahu'alaihi wasallam terbangun ketika matahari sudah terbit, maka beliau bersabda, 'Wahai Bilal. mana yang kamu katakan? ' la menjawab,; Aku belum pernah tertidur selelap ini'. Rasulullah Shallallahu'alaihi wasallam bersabda, \"Allah Azza wa Jalla menggenggam nyawa kalian ketika menghendaki dan mengembalikannya lagi ketika Dia menghendakinya. Hai Bilal, adzanlah untuk shalat'. Lalu Bilal bangkit (dan mengumandangkan adzan, lantas orang-orang segera berwudhu - yakni saat matahari sudah mulai tinggi- kemudian beliau Shallallahu'alaihi wasallam shalat bersama mereka.\""},"837":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ زَائِدَةَ بْنِ قُدَامَةَ قَالَ حَدَّثَنَا السَّائِبُ بْنُ حُبَيْشٍ الْكَلَاعِيُّ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمُرِيِّ قَالَقَالَ لِي أَبُو الدَّرْدَاءِ أَيْنَ مَسْكَنُكَ قُلْتُ فِي قَرْيَةٍ دُوَيْنَ حِمْصَ فَقَالَ أَبُو الدَّرْدَاءِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ ثَلَاثَةٍ فِي قَرْيَةٍ وَلَا بَدْوٍ لَا تُقَامُ فِيهِمْ الصَّلَاةُ إِلَّا قَدْ اسْتَحْوَذَ عَلَيْهِمْ الشَّيْطَانُ فَعَلَيْكُمْ بِالْجَمَاعَةِ فَإِنَّمَا يَأْكُلُ الذِّئْبُ الْقَاصِيَةَقَالَ السَّائِبُ يَعْنِي بِالْجَمَاعَةِ الْجَمَاعَةَ فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Zaidah bin Qudamah] dia berkata; telah menceritakan kepada kami [As-Saib bin Hubaisy Al Kala'i] dari [Ma'dan bin Abu Thalhah Al Ya'muri] dia berkata; [Abu Ad Darda] bertanya kepadaku 'Di mana rumahmu? ' Aku menjawab, 'Di Desa Duwain Himsha\". Lalu ia berkata, 'Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda, \"Tiga orang yang tinggal di suatu desa atau pegunungan tanpa menegakkan shalat berjamaah, pasti setan menguasai mereka. Hendaklah kalian melaksanakan shalat jamaah, karena serigala memangsa kambing yang sendirian.\" As Saib (perawi) berkata, \"Yang dimaksud dengan jamaah di sini adalah jamaah shalat.\""},"838":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ هَمَمْتُ أَنْ آمُرَ بِحَطَبٍ فَيُحْطَبَ ثُمَّ آمُرَ بِالصَّلَاةِ فَيُؤَذَّنَ لَهَا ثُمَّ آمُرَ رَجُلًا فَيَؤُمَّ النَّاسَ ثُمَّ أُخَالِفَ إِلَى رِجَالٍ فَأُحَرِّقَ عَلَيْهِمْ بُيُوتَهُمْ وَالَّذِي نَفْسِي بِيَدهِ لَوْ يَعْلَمُ أَحَدُهُمْ أَنَّهُ يَجِدُ عَظْمًا سَمِينًا أَوْ مِرْمَاتَيْنِ حَسَنَتَيْنِ لَشَهِدَ الْعِشَاءَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda, \"Demi Dzat yang jiwaku berada di tangan-Nya, aku ingin sekali memerintahkan untuk mengumpulkan kayu bakar, lalu aku perintahkan untuk shalat dengan dikumandangkan adzan, lantas aku juga menyuruh seseorang untuk menjadi imam shalat orang-orang. Sedangkan aku akan mendatangi orang-orang (yang tidak ikut berjamaah) dan membakar rumah mereka. Demi Dzat yang jiwaku ada di tangan-Nya, kalau saja salah seorang dari mereka mengetahui bahwa dia akan mendapatkan daging gemuk atau dua potong daging bagian punggung yang bagus, ia pasti mendatangi shalat Isya berjamaah.\""},"839":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ الْمَسْعُودِيِّ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ أَنَّهُ كَانَ يَقُولُمَنْ سَرَّهُ أَنْ يَلْقَى اللَّهَ عَزَّ وَجَلَّ غَدًا مُسْلِمًا فَلْيُحَافِظْ عَلَى هَؤُلَاءِ الصَّلَوَاتِ الْخَمْسِ حَيْثُ يُنَادَى بِهِنَّ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ شَرَعَ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُنَنَ الْهُدَى وَإِنَّهُنَّ مِنْ سُنَنِ الْهُدَى وَإِنِّي لَا أَحْسَبُ مِنْكُمْ أَحَدًا إِلَّا لَهُ مَسْجِدٌ يُصَلِّي فِيهِ فِي بَيْتِهِ فَلَوْ صَلَّيْتُمْ فِي بُيُوتِكُمْ وَتَرَكْتُمْ مَسَاجِدَكُمْ لَتَرَكْتُمْ سُنَّةَ نَبِيِّكُمْ وَلَوْ تَرَكْتُمْ سُنَّةَ نَبِيِّكُمْ لَضَلَلْتُمْ وَمَا مِنْ عَبْدٍ مُسْلِمٍ يَتَوَضَّأُ فَيُحْسِنُ الْوُضُوءَ ثُمَّ يَمْشِي إِلَى صَلَاةٍ إِلَّا كَتَبَ اللَّهُ عَزَّ وَجَلَّ لَهُ بِكُلِّ خُطْوَةٍ يَخْطُوهَا حَسَنَةً أَوْ يَرْفَعُ لَهُ بِهَا دَرَجَةً أَوْ يُكَفِّرُ عَنْهُ بِهَا خَطِيئَةً وَلَقَدْ رَأَيْتُنَا نُقَارِبُ بَيْنَ الْخُطَا وَلَقَدْ رَأَيْتُنَا وَمَا يَتَخَلَّفُ عَنْهَا إِلَّا مُنَافِقٌ مَعْلُومٌ نِفَاقُهُ وَلَقَدْ رَأَيْتُ الرَّجُلَ يُهَادَى بَيْنَ الرَّجُلَيْنِ حَتَّى يُقَامَ فِي الصَّفِّ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Al Mas'udi] dari ['Ali bin Al Aqmar] dari [Abul Ahwash] dari [Abdullah] bahwasanya ia pernah berkata; \"Barangsiapa ingin berjumpa dengan Allah Azza wa Jalla dalam keadaan muslim, jagalah shalat lima waktu tatkala diseru untuk mengerjakannya. Allah Azza wa Jalla telah mensyariatkan jalan-jalan petunjuk kepada Nabi Shallallahu'alaihi wasallam. Dan shalat lima waktu termasuk jalan petunjuk itu. Aku tidak menaksir salah seorang dari kalian kecuali pasti memiliki masjid dalam rumahnya yang digunakan untuk shalat. Ingat, andaikan engkau shalat di rumah kalian dan meninggalkan masjid kalian, berarti kalian meninggalkan sunnah Nabi kalian. Seandainya kalian meninggalkan Sunnah nabi kalian, kalian pasti tersesat. Tidak ada orang muslim yang berwudhu' dan memperbaiki wudhunya kemudian pergi ke masjid, kecuali Allah Azza wa Jalla menuliskan satu kebaikan bagi setiap langkahnya atau mengangkatnya satu derajat, atau menghapus satu kesalahan darinya dengan langkah tersebut. Aku menyaksikan diri kami merapatkan langkahnya dan Aku bersaksi bahwa tidak ada yang ketinggalan dari shalat berjamaah kecuali orang munafik yang sudah populer kemunafikannya. Aku juga menyaksikan seorang laki-laki yang dipapah oleh dua orang hingga ia berdiri di shaf (barisan) shalat.\""},"840":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ الْأَصَمِّ عَنْ عَمِّهِ يَزِيدَ بْنِ الْأَصَمِّ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ أَعْمَى إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ لَيْسَ لِي قَائِدٌ يَقُودُنِي إِلَى الصَّلَاةِ فَسَأَلَهُ أَنْ يُرَخِّصَ لَهُ أَنْ يُصَلِّيَ فِي بَيْتِهِ فَأَذِنَ لَهُ فَلَمَّا وَلَّى دَعَاهُ قَالَ لَهُ أَتَسْمَعُ النِّدَاءَ بِالصَّلَاةِ قَالَ نَعَمْ قَالَ فَأَجِبْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah] dia berkata; telah menceritakan kepada kami ['Ubaidullah bin Abdullah bin Al Asham] dari pamannya [Yazid bin Al Asham] dari [Abu Hurairah] dia berkata; \"Seorang laki-laki buta datang kepada Rasulullah Shallallahu'alaihi wasallam lalu berkata, 'Aku tidak mempunyai penuntun untuk menuntunku ke masjid'. Kemudian ia meminta keringanan untuk shalat di rumahnya, dan beliau Shallallahu'alaihi wasallam mengizinkannya. Namun setelah dia pergi Rasulullah Shallallahu'alaihi wasallam segera memanggilnya dan bertanya, \"Apakah engkau mendengar panggilan shalat? ' la menjawab, 'Kalau adzan sih mendengar'. Rasulullah Shallallahu'alaihi wasallam lalu bersabda; 'Kamu wajib mendatanginya (shalat berjamaah).\""},"841":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا سُفْيَانُ ح و أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ حَدَّثَنَا قَاسِمُ بْنُ يَزَيْدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ ابْنِ أُمِّ مَكْتُومٍ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنَّ الْمَدِينَةَ كَثِيرَةُ الْهَوَامِّ وَالسِّبَاعِ قَالَ هَلْ تَسْمَعُ حَيَّ عَلَى الصَّلَاةِ حَيَّ عَلَى الْفَلَاحِ قَالَ نَعَمْ قَالَ فَحَيَّ هَلًا وَلَمْ يُرَخِّصْ لَهُ","id":"Telah mengabarkan kepada kami [Harun bin Zaid bin Abu Az Zarqa] dia berkata; [Bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Sufyan] dan telah mengabarkan kepadaku [Abdullah bin Muhammad bin Ishaq] dia berkata; telah menceritakan kepada kami [Qasim bin Yazid] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin 'Abis] dari [Abdurrahman bin Abu Laila] dari [Ibnu Ummi Maktum] bahwasanya dia berkata; \"Wahai Rasulullah Shallallahu'alihiwasallam di Madinah banyak hewan melata dan hewan buas.\" Rasulullah Shallallahu'alaihi wasallam menjawab, \"Apakah kamu mendengar seruan, 'Hayya 'alash-shalah, hayya 'alal falah? '\" la menjawab, \"Ya.\" Kemudian Rasulullah Shallallahu'alaihi wasallam bersabda, \"Maka marilah menyambutnya.\" Beliau Shallallahu'alaihi wasallam tidak memberi keringanan kepadanya."},"842":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِأَنْ عَبْدَ اللَّهِ بْنَ أَرْقَمَ كَانَ يَؤُمُّ أَصْحَابَهُ فَحَضَرَتْ الصَّلَاةُ يَوْمًا فَذَهَبَ لِحَاجَتِهِ ثُمَّ رَجَعَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا وَجَدَ أَحَدُكُمْ الْغَائِطَ فَلْيَبْدَأْ بِهِ قَبْلَ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya], bahwasanya [Abdullah bin Arqam] pernah menjadi Imam shalat bagi para sahabatnya, suatu hari ketika tiba waktu shalat, dia pergi untuk buang air besar, lalu kembali untuk mengimami. Dia berkata; \"Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \" Apabila kalian hendak buang air besar, ketika -tiba waktu shalat-, maka hendaklah ia mendahulukannya sebelum melaksanakan shalat."},"843":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَضَرَ الْعَشَاءُ وَأُقِيمَتْ الصَّلَاةُ فَابْدَءُوا بِالْعَشَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Anas] dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika makan malam telah disediakan, sedangkan iqamah shalat telah dilakukan, maka santaplah terlebih dahulu.\""},"844":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحُنَيْنٍ فَأَصَابَنَا مَطَرٌ فَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ صَلُّوا فِي رِحَالِكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abul Malih] dari [bapaknya], dia berkata; \"Kami pernah bersama Rasulullah Shallallahu'alaihi wasallam pada perang Hunain, lalu kami diguyur hujan, maka Muadzin Rasulullah Shallallahu'alaihi wasallam menyeru, SHALLUU FII RIHAALIKUM 'Shalatlah kalian di tempat (kendaraan) masing-masing kalian.\""},"845":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ ابْنِ طَحْلَاءَ عَنْ مُحْصِنِ بْنِ عَلِيٍّ الْفِهْرِيِّ عَنْ عَوْفِ بْنِ الْحَارِثِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ خَرَجَ عَامِدًا إِلَى الْمَسْجِدِ فَوَجَدَ النَّاسَ قَدْ صَلَّوْا كَتَبَ اللَّهُ لَهُ مِثْلَ أَجْرِ مَنْ حَضَرَهَا وَلَا يَنْقُصُ ذَلِكَ مِنْ أُجُورِهِمْ شَيْئًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Abdul 'Aziz bin Muhammad] dari [Ibnu Thalha'] dari [Muhshin bin 'Ali Al Fihri] dari ['Auf bin Al Harits] dari [Abu Hurairah] dari Rasulullah Shallallahu'alaihi wasallam beliau bersabda: \"Barang siapa berwudhu dan memperbaiki wudhunya kemudian keluar dengan sengaja menuju masjid, lalu mendapati orang-orang sudah mengerjakan shalat, Allah menuliskan pahala baginya seperti pahala orang yang menghadirinya, dan hal itu tidak mengurangi pahala mereka sedikitpun.\""},"846":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ الْحُكَيْمَ بْنَ عَبْدِ اللَّهِ الْقُرَشِيَّ حَدَّثَهُ أَنَّ نَافِعَ بْنَ جُبَيْرٍ وَعَبْدَ اللَّهِ بْنَ أَبِي سَلَمَةَ حَدَّثَاهُ أَنَّ مُعَاذَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُمَا عَنْ حُمْرَانَ مَوْلَى عُثْمَانَ بْنِ عَفَّانَ عَنْ عُثْمَانَ بْنِ عَفَّانَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَوَضَّأَ لِلصَّلَاةِ فَأَسْبَغَ الْوُضُوءَ ثُمَّ مَشَى إِلَى الصَّلَاةِ الْمَكْتُوبَةِ فَصَلَّاهَا مَعَ النَّاسِ أَوْ مَعَ الْجَمَاعَةِ أَوْ فِي الْمَسْجِدِ غَفَرَ اللَّهُ لَهُ ذُنُوبَهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud] dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku ['Amr bin Al Harits] bahwasanya [Al Hukaim bin Abdullah Al Quraisyi] menceritakan kepadanya bahwasanya [Nafi' bin Jubair] dan [Abdullah bin Abu Salamah] menceritakan kepadanya bahwasanya [Mu'adz bin 'Abdurrahman] menceritakan kepadanya dari [Humran] -budak 'Utsman bin 'Affan- dari ['Utsman bin 'Affan] dia berkata, \"Aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barangsiapa berwudhu untuk shalat dan menyempurnakan wudhunya, kemudian ia berangkat untuk shalat wajib dan ia mengerjakannya bersama orang-orang atau bersama jamaah, atau shalat di masjid, Allah mengampuni dosa-dosanya.\""},"847":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ رَجُلٍ مِنْ بَنِي الدِّيلِ يُقَالُ لَهُ بُسْرُ بْنُ مِحْجَنٍ عَنْ مِحْجَنٍأَنَّهُ كَانَ فِي مَجْلِسٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَذَّنَ بِالصَّلَاةِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ رَجَعَ وَمِحْجَنٌ فِي مَجْلِسِهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَنَعَكَ أَنْ تُصَلِّيَ أَلَسْتَ بِرَجُلٍ مُسْلِمٍ قَالَ بَلَى وَلَكِنِّي كُنْتُ قَدْ صَلَّيْتُ فِي أَهْلِي فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جِئْتَ فَصَلِّ مَعَ النَّاسِ وَإِنْ كُنْتَ قَدْ صَلَّيْتَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Zaid bin Aslam] dari seorang lelaki dari Bani Ad Dil yang dipanggil [Busr bin Mihjan] dari [Mihjan] bahwasanya ia pernah berada dalam suatu majelis bersama Rasulullah Shallallahu'alihiwasallam lalu dikumandangkan adzan untuk shalat, maka Rasulullah Shallallahu'alaihi wasallam segera bangkit kemudian kembali, sedangkan Mihjan masih di majelisnya. Rasulullah Shallallahu'alaihi wasallam lalu berkata kepadanya: \"Apakah yang menghalangimu untuk shalat? Bukankah kamu seorang muslim?\" la menjawab, \"Tentu, tetapi aku sudah shalat bersama keluargaku.\" Kemudian Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bila kamu datang (ke masjid) maka shalatlah bersama orang-orang, walaupun kamu telah menunaikannya.\" "},"848":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا يَعْلَى بْنُ عَطَاءٍ قَالَ حَدَّثَنَا جَابِرُ بْنُ يَزِيدَ بْنِ الْأَسْوَدِ الْعَامِرِيُّ عَنْ أَبِيهِ قَالَشَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْفَجْرِ فِي مَسْجِدِ الْخَيْفِ فَلَمَّا قَضَى صَلَاتَهُ إِذَا هُوَ بِرَجُلَيْنِ فِي آخِرِ الْقَوْمِ لَمْ يُصَلِّيَا مَعَهُ قَالَ عَلَيَّ بِهِمَا فَأُتِيَ بِهِمَا تَرْعَدُ فَرَائِصُهُمَا فَقَالَ مَا مَنَعَكُمَا أَنْ تُصَلِّيَا مَعَنَا قَالَا يَا رَسُولَ اللَّهِ إِنَّا قَدْ صَلَّيْنَا فِي رِحَالِنَا قَالَ فَلَا تَفْعَلَا إِذَا صَلَّيْتُمَا فِي رِحَالِكُمَا ثُمَّ أَتَيْتُمَا مَسْجِدَ جَمَاعَةٍ فَصَلِّيَا مَعَهُمْ فَإِنَّهَا لَكُمَا نَافِلَةٌ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] dia berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah menceritakan kepada kami [Ya'la bin 'Atha] dia berkata; telah menceritakan kepada kami [Jabir bin Yazid bin Al Aswad Al 'Amiri] dari [bapaknya], dia berkata; \"Aku ikut shalat Subuh berjamaah di masjid Al Khaif bersama Rasulullah Shallallahu'alihiwasallam dan setelah selesai shalat tiba-tiba ada dua orang di barisan paling belakang tidak ikut shalat bersama beliau Shallallahu'alihiwasallam. Rasulullah Shallallahu'alaihi wasallam lalu bersabda: \"Bawa dua orang tersebut kepadaku\". Kedua orang tersebut kemudian segera dibawa kepada beliau dalam keadaan gemetar sendi-sendinya, lantas beliau bersabda: \"Apakah yang menghalangi kalian berdua untuk shalat bersama kami? ' Keduanya menjawab, 'Wahai Rasulullah Shallallahu'alihiwasallam kami telah shalat di rumah kami'. Rasulullah Shallallahu'alaihi wasallam berkata: \"Jangan kamu lakukan hal itu (meninggalkan shalat berjamaah). Jika kalian berdua telah shalat di rumah kalian, kemudian kalian datang ke masjid yang sedang shalat berjamaah, maka shalatlah bersama mereka, karena bagi kalian hal itu adalah Sunnah.\" "},"849":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى وَمُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ صُدْرَانَ وَاللَّفْظُ لَهُ عَنْ خَالِدِ بْنِ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ بُدَيْلٍ قَالَ سَمِعْتُ أَبَا الْعَالِيَةَ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَضَرَبَ فَخِذِي كَيْفَ أَنْتَ إِذَا بَقِيتَ فِي قَوْمٍ يُؤَخِّرُونَ الصَّلَاةَ عَنْ وَقْتِهَا قَالَ مَا تَأْمُرُ قَالَ صَلِّ الصَّلَاةَ لِوَقْتِهَا ثُمَّ اذْهَبْ لِحَاجَتِكَ فَإِنْ أُقِيمَتْ الصَّلَاةُ وَأَنْتَ فِي الْمَسْجِدِ فَصَلِّ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dan [Muhammad bin Ibrahim bin Shudran] -dan lafadz ini baginya- dari [Khalid bin Al Harits] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Budail] dia berkata; aku mendengar [Abul 'Aliyah] menceritakan dari [Abdullah bin Ash Shamit] dari [Abu Dzarr] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam pernah bersabda kepadaku - sambil menepuk pahaku -: \"Bagaimana jika engkau tinggal pada suatu kaum yang terbiasa mengakhirkan shalat dari waktunya? ' la berkata, 'Apa yang engkau perintahkan? ' Beliau Shallallahu'alaihi wasallam bersabda, 'Shalatlah pada waktunya kemudian pergilah untuk mengurusi urusanmu. Jika ditegakkan shalat dan kamu di dalam masjid, maka ikut shalatlah '."},"850":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدٍ التَّيْمِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ سُلَيْمَانَ مَوْلَى مَيْمُونَةَ قَالَرَأَيْتُ ابْنَ عُمَرَ جَالِسًا عَلَى الْبَلَاطِ وَالنَّاسُ يُصَلُّونَ قُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ مَا لَكَ لَا تُصَلِّي قَالَ إِنِّي قَدْ صَلَّيْتُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُعَادُ الصَّلَاةُ فِي يَوْمٍ مَرَّتَيْنِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Muhammad At Taimi] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Husain Al Mu'allim] dari ['Amr bin Syu'aib] dari [Sulaiman] -budak Maimunah- dia berkata; \"Aku melihat [Ibnu 'Umar] duduk di lantai, padahal orang-orang sedang mengerjakan shalat. Aku lalu bertanya kepadanya, 'Wahai Abu Abdur Rahman, kenapa kamu tidak shalat? ' la menjawab, 'Aku sudah shalat dan aku pernah mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jangan mengulangi shalat dua kali dalam satu hari.\""},"851":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الزُّهْرِيُّ قَالَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَيْتُمْ الصَّلَاةَ فَلَا تَأْتُوهَا وَأَنْتُمْ تَسْعَوْنَ وَأْتُوهَا تَمْشُونَ وَعَلَيْكُمْ السَّكِينَةُ فَمَا أَدْرَكْتُمْ فَصَلُّوا وَمَا فَاتَكُمْ فَاقْضُوا","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin 'Abdurrahman Az Zuhri] dia berkata; telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika kalian mendatangi shalat, jangan dengan lari tergesa-gesa. Datangilah dengan berjalan dan tenang. Apa yang kalian dapati, shalatlah, dan yang ketinggalan maka sempurnakanlah.\""},"852":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ مَنْبُوذٍ عَنْ الْفَضْلِ بْنِ عُبَيْدِ اللَّهِ عَنْ أَبِي رَافِعٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى الْعَصْرَ ذَهَبَ إِلَى بَنِي عَبْدِ الْأَشْهَلِ فَيَتَحَدَّثُ عِنْدَهُمْ حَتَّى يَنْحَدِرَ لِلْمَغْرِبِ قَالَ أَبُو رَافِعٍ فَبَيْنَمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْرِعُ إِلَى الْمَغْرِبِ مَرَرْنَا بِالْبَقِيعِ فَقَالَ أُفٍّ لَكَ أُفٍّ لَكَ قَالَ فَكَبُرَ ذَلِكَ فِي ذَرْعِي فَاسْتَأْخَرْتُ وَظَنَنْتُ أَنَّهُ يُرِيدُنِي فَقَالَ مَا لَكَ امْشِ فَقُلْتُ أَحْدَثْتَ حَدَثًا قَالَ مَا ذَاكَ قُلْتُ أَفَّفْتَ بِي قَالَ لَا وَلَكِنْ هَذَا فُلَانٌ بَعَثْتُهُ سَاعِيًا عَلَى بَنِي فُلَانٍ فَغَلَّ نَمِرَةً فَدُرِّعَ الْآنَ مِثْلُهَا مِنْ نَارٍأَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي مَنْبُوذٌ رَجُلٌ مِنْ آلِ أَبِي رَافِعٍ عَنْ الْفَضْلِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ أَبِي رَافِعٍ نَحْوَهُ","id":"Telah mengabarkan kepada kami ['Amr bin Sawwad bin Al Aswad bin 'Amr] dia berkata; Telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah memberitakan kepada kami [Ibnu Juraij] dari [Manbudz] dari [Al Fadhl bin 'Ubaidullah] dari [Abu Rafi'] dia berkata; \"Dahulu jika Rasulullah Shallallahu'alaihi wasallam telah shalat Ashar maka beliau pergi ke Bani Abdul Asyhal, lalu bercakap-cakap hingga hampir Maghrib.\" Abu Rafi' berkata; \"Tatkala Nabi Shallallahu'alaihi wasallam terburu-buru mendatangi shalat Maghrib, kami melewati kuburan Baqi', maka Rasulullah Shallallahu'alaihi wasallam bersabda: Celaka kamu, celaka kamu (Beliau maksudkan untuk penghuni kubur). Ucapan nabi shallallahu 'alaihi wasallam itu menjadikanku khawatir, maka aku menghentikan jalanku, karena aku mengira beliau tujukan ucapannya kepadaku. Lantas beliau bersabda: 'Ada apa dengan kamu? Berjalanlah'. Aku berkata, 'Anda baru saja berbicara sesuatu'. Beliau berkata, 'Apa itu? Aku menjawab, 'Anda mengatakan kepadaku celaka kamu celaka kamu'. Beliau menimpalinya, 'Tidak, Ucapan itu bukan kumaksudkan untukmu, tetapi aku pernah mengutus penghuni kuburan ini kepada Bani Fulan untuk menarik zakat, namun ia berkhianat dengan mencuri kain wool, maka ia sekarang sedang dipakaikan pakaian sejenisnya dari api neraka.\" Telah mengabarkan kepada kami [Harun bin Abdullah] ia berkata, telah menceritakan kepada kami [Mu'awiyah bin 'Amru] ia berkata, telah menceritakan kepada kami [Abu Ishaq] dari [Ibnu Juraij] ia berkata, telah mengabarkan kepadaku [Manbudz] -ia dari keluarga Abu Rafi'- dari [Al Fadhl bin 'Ubaidillah bin Abu Rafi'] dari [Abu Rafi'] dengan hadits yang senada."},"853":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عُثْمَانُ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَأَبُو عَبْدِ اللَّهِ الْأَغَرُّ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا مَثَلُ الْمُهَجِّرِ إِلَى الصَّلَاةِ كَمَثَلِ الَّذِي يُهْدِي الْبَدَنَةَ ثُمَّ الَّذِي عَلَى إِثْرِهِ كَالَّذِي يُهْدِي الْبَقَرَةَ ثُمَّ الَّذِي عَلَى إِثْرِهِ كَالَّذِي يُهْدِي الْكَبْشَ ثُمَّ الَّذِي عَلَى إِثْرِهِ كَالَّذِي يُهْدِي الدَّجَاجَةَ ثُمَّ الَّذِي عَلَى إِثْرِهِ كَالَّذِي يُهْدِي الْبَيْضَةَ","id":"Telah mengabarkan kepada kami [Ahmad bin Muhammad bin Al Mughirah] dia berkata; telah menceritakan kepada kami ['Utsman] dari [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Abu Salamah bin 'Abdurrahman] dan [Abu Abdullah Al Agharr] bahwasanya [Abu Hurairah] menceritakan kepada keduanya bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Perumpamaan orang yang bersegera ke masjid seperti orang yang berkurban seekor unta, kemudian yang datang selanjutnya seperti orang yang berkurban sapi, orang lain yang datang setelahnya seperti orang yang berkurban kambing, dan yang datang selanjutnya seperti orang yang berkurban ayam, kemudian yang datang setelahnya seperti orang yang berkurban telur.\""},"854":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ زَكَرِيَّا قَالَ حَدَّثَنِي عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ عَطَاءَ بْنَ يَسَارٍ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا صَلَاةَ إِلَّا الْمَكْتُوبَةُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Zakaria] dia berkata; telah menceritakan kepadaku ['Amr bin Dinar] dia berkata; Aku mendengar ['Atha bin Yasar] menceritakan dari [Abu Hurairah] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Bila iqamah telah dikumandangkan, tidak ada shalat kecuali shalat wajib."},"855":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدٌ عَنْ شُعْبَةَ عَنْ وَرْقَاءَ بْنِ عُمَرَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا صَلَاةَ إِلَّا الْمَكْتُوبَةُ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakim] dan [Muhammad bin Basysyar] mereka berkata, telah menceritakan kepada kami [Muhammad] dari [Syu'bah] dari [Warqa' bin 'Umar] dari ['Amr bin Dinar] dari ['Atha bin Yasar] dari [Abu Hurairah] dari Nabi Shallallahu'alihiwasallam beliau Shallallahu'alaihi wasallam bersabda: \"Bila iqamah telah dikumandangkan, tidak ada shalat kecuali shalat wajib.\""},"856":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ ابْنِ بُحَيْنَةَ قَالَأُقِيمَتْ صَلَاةُ الصُّبْحِ فَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُصَلِّي وَالْمُؤَذِّنُ يُقِيمُ فَقَالَ أَتُصَلِّي الصُّبْحَ أَرْبَعًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Sa'ad bin Ibrahim] dari [Hafsh bin 'Ashim] dari [Ibnu Buhainah] dia berkata; \"Ketika shalat Subuh dan iqamah sudah dikumandangkan, Rasulullah Shallallahu'alaihi wasallam melihat seorang laki-laki sedang shalat, padahal muadzin sedang iqamah, maka beliau Shallallahu'alaihi wasallam menegurnya; 'Apakah kamu shalat subuh empat rakaat? '"},"857":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا عَاصِمٌ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَجَاءَ رَجُلٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الصُّبْحِ فَرَكَعَ الرَّكْعَتَيْنِ ثُمَّ دَخَلَ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ قَالَ يَا فُلَانُ أَيُّهُمَا صَلَاتُكَ الَّتِي صَلَّيْتَ مَعَنَا أَوْ الَّتِي صَلَّيْتَ لِنَفْسِكَ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dia berkata; telah menceritakan kepada kami [Hammad] dia berkata; telah menceritakan kepada kami ['Ashim] dari [Abdullah bin Sarjis] dia berkata; \"Seorang laki-laki datang, dan Rasulullah Shallallahu'alaihi wasallam saat itu sedang shalat Subuh. Lalu orang tersebut shalat dua rakaat. kemudian mengikuti shalat beliau. Setelah Rasulullah Shallallahu'alaihi wasallam selesai shalat, beliau Shallallahu'alaihi wasallam bersabda: 'Wahai Fulan, yang manakah shalat subuhmu? Shalat bersama kami (shalat Subuh berjamaah) atau shalat untuk dirimu sendiri (shalat sunnah)? '"},"858":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي إِسْحَقُ بْنُ عَبْدِ اللَّهِ قَالَ سَمِعْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِنَا فَصَلَّيْتُ أَنَا وَيَتِيمٌ لَنَا خَلْفَهُ وَصَلَّتْ أُمُّ سُلَيْمٍ خَلْفَنَا","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin 'Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepadaku [Ishaq bin Abdullah] dia berkata; Aku mendengar [Anas] Radliyallahu'anhu berkata; \"Rasulullah Shallallahu'alaihi wasallam datang ke rumah kami, lalu aku shalat bersama anak yatim di belakang beliau. Sementara Ummu Sulaim shalat di belakang kami.\""},"859":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا نُوحٌ يَعْنِي ابْنَ قَيْسٍ عَنْ ابْنِ مَالِكٍ وَهُوَ عَمْرٌو عَنْ أَبِي الْجَوْزَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ امْرَأَةٌ تُصَلِّي خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَسْنَاءُ مِنْ أَحْسَنِ النَّاسِ قَالَ فَكَانَ بَعْضُ الْقَوْمِ يَتَقَدَّمُ فِي الصَّفِّ الْأَوَّلِ لِئَلَّا يَرَاهَا وَيَسْتَأْخِرُ بَعْضُهُمْ حَتَّى يَكُونَ فِي الصَّفِّ الْمُؤَخَّرِ فَإِذَا رَكَعَ نَظَرَ مِنْ تَحْتِ إِبْطِهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَقَدْ عَلِمْنَا الْمُسْتَقْدِمِينَ مِنْكُمْ وَلَقَدْ عَلِمْنَا الْمُسْتَأْخِرِينَ }","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Nuh bin Qais] dari ['Amr bin Malik] dari [Abu Al Jauza'] dari [Ibnu 'Abbas] dia berkata; \"Ada seorang perempuan cantik menawan shalat di belakang Rasulullah Shallallahu'alaihi wasallam.\" Ibnu Abbas berkata lagi, \"Sebagian orang ada yang maju ke barisan terdepan agar tidak melihatnya, namun sebagian lagi justru ada yang berdiri di barisan terakhir, agar ketika ruku' ia bisa melihatnya dari balik ketiaknya. Kemudian Allah Azza wa Jalla menurunkan ayat, 'Dan sesungguhnya Kami telah mengetahui orang-orang yang meminta di barisan depan dan sesungguhnya Kami mengetahui pula orang-orang yang meminta di barisan belakang (Qs. Al Hijr (15): 24) '.\""},"860":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ يَزِيدَ بْنِ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ زِيَادٍ الْأَعْلَمِ قَالَ حَدَّثَنَا الْحَسَنُ أَنَّ أَبَا بَكْرَةَ حَدَّثَهُأَنَّهُ دَخَلَ الْمَسْجِدَ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَاكِعٌ فَرَكَعَ دُونَ الصَّفِّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَادَكَ اللَّهُ حِرْصًا وَلَا تَعُدْ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Ziyad Al A'lam] dia berkata; telah menceritakan kepada kami [Al Hasan] bahwasanya [Abu Bakar] menceritakan kepadanya, bahwa ia pernah masuk ke dalam masjid sedangkan Nabi Shallallahu'alaihi wasallam sedang ruku', maka ia ikut ruku' sebelum sampai ke barisan shalat. Lalu Rasulullah Shallallahu'alaihi wasallam bersabda: \"Semoga Allah menambah semangatmu, namun jangan kamu ulangi lagi.\""},"861":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنِي أَبُو أُسَامَةَ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ كَثِيرٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا ثُمَّ انْصَرَفَ فَقَالَ يَا فُلَانُ أَلَا تُحَسِّنُ صَلَاتَكَ أَلَا يَنْظُرُ الْمُصَلِّي كَيْفَ يُصَلِّي لِنَفْسِهِ إِنِّي أُبْصِرُ مِنْ وَرَائِي كَمَا أُبْصِرُ بَيْنَ يَدَيَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepadaku [Abu Usamah] dia berkata; telah menceritakan kepadaku [Al Walid bin Katsir] dari [Sa'id bin Abu Sa'id] dari [bapaknya] dari [Abu Hurairah] dia berkata; \"Suatu hari Rasulullah Shallallahu'alaihi wasallam mengerjakan shalat, dan setelah selesai beliau Shallallahu'alaihi wasallam bersabda: 'Wahai Fulan, kenapa engkau tidak membaguskan shalatmu? Kenapa orang yang shalat itu tidak mau intropeksi bagaimana ia mengerjakan shalat untuk dirinya? Sesungguhnya aku mampu melihat dari belakangku seperti aku melihat melalui depanku.'"},"862":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي قَبْلَ الظُّهْرِ رَكْعَتَيْنِ وَبَعْدَهَا رَكْعَتَيْنِ وَكَانَ يُصَلِّي بَعْدَ الْمَغْرِبِ رَكْعَتَيْنِ فِي بَيْتِهِ وَبَعْدَ الْعِشَاءِ رَكْعَتَيْنِ وَكَانَ لَا يُصَلِّي بَعْدَ الْجُمْعَةِ حَتَّى يَنْصَرِفَ فَيُصَلِّيَ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Nafi'] dari [Ibnu 'Umar] bahwa Rasulullah Shallallahu'alaihi wasallam shalat dua rakaat sebelum Zhuhur, dan dua rakaat setelahnya. Beliau Shallallahu'alaihi wasallam juga shalat dua rakaat setelah Maghrib di rumahnya dan shalat dua rakaat setelah Isya. Beliau Shallallahu'alaihi wasallam tidak shalat setelah shalat Jum'at hingga pulang, kemudian beliau Shallallahu'alaihi wasallam mengerjakan shalat dua rakaat."},"863":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ قَالَسَأَلْنَا عَلِيًّا عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّكُمْ يُطِيقُ ذَلِكَ قُلْنَا إِنْ لَمْ نُطِقْهُ سَمِعْنَا قَالَ كَانَ إِذَا كَانَتْ الشَّمْسُ مِنْ هَا هُنَا كَهَيْئَتِهَا مِنْ هَا هُنَا عِنْدَ الْعَصْرِ صَلَّى رَكْعَتَيْنِ فَإِذَا كَانَتْ مِنْ هَا هُنَا كَهَيْئَتِهَا مِنْ هَا هُنَا عِنْدَ الظُّهْرِ صَلَّى أَرْبَعًا وَيُصَلِّي قَبْلَ الظُّهْرِ أَرْبَعًا وَبَعْدَهَا ثِنْتَيْنِ وَيُصَلِّي قَبْلَ الْعَصْرِ أَرْبَعًا يَفْصِلُ بَيْنَ كُلِّ رَكْعَتَيْنِ بِتَسْلِيمٍ عَلَى الْمَلَائِكَةِ الْمُقَرَّبِينَ وَالنَّبِيِّينَ وَمَنْ تَبِعَهُمْ مِنْ الْمُؤْمِنِينَ وَالْمُسْلِمِينَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari ['Ashim bin Dhamrah] dia berkata; \"Kami bertanya kepada Ali tentang shalatnya Rasulullah Shallallahu'alaihi wasallam lalu [Ali] berkata; 'Siapakah di antara kalian yang mampu mengerjakannya? ' Kami menjawab; 'Jika kami tidak mampu, maka kami telah mendengarnya'. ia pun berkata; 'Bila matahari ada di sini seperti keadaannya saat di sini - yakni saat waktu Ashar- maka beliau Shallallahu'alaihi wasallam mengerjakan shalat dua rakaat. Bila matahari ada di sini seperti keadaannya saat di sini -yakni saat waktu Zhuhur- maka beliau Shallallahu'alaihi wasallam shalat empat rakaat, dan shalat dua rakaat setelahnya. Beliau juga shalat empat rakaat sebelum Ashar dengan memisahkan tiap dua rakaat dengan salam. Salam tersebut ditujukan untuk para malaikat yang dekat (dengan Allah), para nabi, serta orang-orang yang mengikuti mereka dari kaum Mukminin dan Muslimin.\" "},"864":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا حُصَيْنُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي إِسْحَقَ عَنْ عَاصِمِ بْنِ ضَمْرَةَ قَالَسَأَلْتُ عَلِيَّ بْنَ أَبِي طَالِبٍ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النَّهَارِ قَبْلَ الْمَكْتُوبَةِ قَالَ مَنْ يُطِيقُ ذَلِكَ ثُمَّ أَخْبَرَنَا قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي حِينَ تَزِيغُ الشَّمْسُ رَكْعَتَيْنِ وَقَبْلَ نِصْفِ النَّهَارِ أَرْبَعَ رَكَعَاتٍ يَجْعَلُ التَّسْلِيمَ فِي آخِرِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Abdurrahman] dia berkata; telah menceritakan kepada kami [Hushain bin 'Abdurrahman] dari [Abu Ishaq] dari ['Ashim bin Dhamrah] dia berkata; \"Aku bertanya kepada [Ali bin Abu Thalib] tentang shalat Nabi Shallallahu'alaihi wasallam pada siang hari sebelum mengerjakan shalat wajib dan ia menjawab, 'Siapa yang mampu mengerjakannya? ' Kemudian ia berkata, 'Rasulullah Shallallahu'alaihi wasallam mengerjakan shalat dua rakaat ketika matahari telah naik dan shalat empat rakaat sebelum matahari sampai ke pertengahan siang, dan beliau mengucapkan salam diakhir shalat.\""},"865":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَالِمٌ ح و أَخْبَرَنِي أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا عُثْمَانُ هُوَ ابْنُ سَعِيدٍ عَنْ شُعَيْبٍ عَنْ مُحَمَّدٍ وَهُوَ الزُّهْرِيُّ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ التَّكْبِيرَ فِي الصَّلَاةِ رَفَعَ يَدَيْهِ حِينَ يُكَبِّرُ حَتَّى يَجْعَلَهُمَا حَذْوَ مَنْكِبَيْهِ وَإِذَا كَبَّرَ لِلرُّكُوعِ فَعَلَ مِثْلَ ذَلِكَ ثُمَّ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَعَلَ مِثْلَ ذَلِكَ وَقَالَ رَبَّنَا وَلَكَ الْحَمْدُ وَلَا يَفْعَلُ ذَلِكَ حِينَ يَسْجُدُ وَلَا حِينَ يَرْفَعُ رَأْسَهُ مِنْ السُّجُودِ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami ['Ali bin 'Ayyasy] dia berkata; telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku [Salim] -dan lewat jalur periwayatan lain- dan telah mengabarkan kepadaku [Ahmad bin Muhammad bin Al Mughirah] dia berkata; telah menceritakan kepada kami ['Utsman bin Sa'id] dari [Syu'aib] dari [Muhammad Az Zuhri] dia berkata; telah mengabarkan kepadaku [Salim bin Abdullah bin 'Umar] dari [Ibnu 'Umar] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam jika memulai takbir dalam shalat maka beliau mengangkat kedua tangannya sampai lurus dengan pundaknya. Beliau juga melakukan hal tersebut saat takbir untuk ruku' dan saat mengangkat kepala dari ruku\" sambil mengucapkan 'Sami'allahu liman hamidah (Allah Maha Mendengar siapa yang memuji-Nya) ', lalu mengucapkan 'Rabbana iakal hamdu (Wahai Tuhan kami, untuk-Mu segala pujian) '. Beliau Shallallahu'alaihi wasallam tidak melakukannya saat sujud dan tidak pula saat mengangkat kepalanya dari sujud.\""},"866":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمٌ عَنْ ابْنِ عُمَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ رَفَعَ يَدَيْهِ حَتَّى تَكُونَا حَذْوَ مَنْكِبَيْهِ ثُمَّ يُكَبِّرُ قَالَ وَكَانَ يَفْعَلُ ذَلِكَ حِينَ يُكَبِّرُ لِلرُّكُوعِ وَيَفْعَلُ ذَلِكَ حِينَ يَرْفَعُ رَأْسَهُ مِنْ الرُّكُوعِ وَيَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ وَلَا يَفْعَلُ ذَلِكَ فِي السُّجُودِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Yunus] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Salim] dari [Ibnu 'Umar] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam jika berdiri untuk shalat maka beliau mengangkat kedua tangannya sampai lurus dengan pundaknya, lalu bertakbir.\" Ibnu Umar lalu berkata; 'Beliau Shallallahu'alaihi wasallam juga melakukan hal tersebut saat takbir untuk ruku' dan saat mengangkat kepala dari ruku', sambil mengucapkan 'Sami'allahu liman Hamidah (Allah Maha Mendengar siapa yang memuji-Nya) ', dan beliau Shallallahu'alaihi wasallam tidak melakukannya saat sujud.\""},"867":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا افْتَتَحَ الصَّلَاةَ رَفَعَ يَدَيْهِ حَذْوَ مَنْكِبَيْهِ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ رَفَعَهُمَا كَذَلِكَ وَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ وَكَانَ لَا يَفْعَلُ ذَلِكَ فِي السُّجُودِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Salim] dari [Abdullah bin 'Umar] dia berkata; bahwa Rasulullah Shallallahu'alaihi wasallam jika mengawali shalatnya maka beliau mengangkat kedua tangannya sampai lurus dengan pundaknya. Beliau Shallallahu'alaihi wasallam juga melakukan hal tersebut saat hendak ruku' dan saat mengangkat kepala dari ruku' sambil mengucapkan \"Sami 'allahu liman hamidah, Rabbana lakal hamdu (Allah Maha Mendengar siapa yang memuji-Nya, wahai Tuhan kami, Segala puji hanya untuk-Mu).\" Beliau Shallallahu'alaihi wasallam tidak melakukannya saat sujud."},"868":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا افْتَتَحَ الصَّلَاةَ كَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى حَاذَتَا أُذُنَيْهِ ثُمَّ يَقْرَأُ بِفَاتِحَةِ الْكِتَابِ فَلَمَّا فَرَغَ مِنْهَا قَالَ آمِينَ يَرْفَعُ بِهَا صَوْتَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Abdul Jabbar bin Wa'il] dari [Bapaknya] dia berkata; \"Aku pernah shalat di belakang Rasulullah Shallallahu'alihiwasallam dan beliau mengawali shalatnya dengan mengangkat kedua tangannya sampai sejajar dengan kedua telinganya, lalu bertakbir. Kemudian beliau Shallallahu'alaihi wasallam membaca surat Al Fatihah, dan setelah selesai membacanya beliau Shallallahu'alaihi wasallam mengucapkan 'Aamiin dengan mengeraskan suaranya."},"869":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ نَصْرَ بْنَ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى رَفَعَ يَدَيْهِ حِينَ يُكَبِّرُ حِيَالَ أُذُنَيْهِ وَإِذَا أَرَادَ أَنْ يَرْكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; Aku mendengar [Nashr bin 'Ashim] dari [Malik bin Al Huwairits] -salah satu sahabat Nabi Shallallahu'alaihi wasallam- bahwa tatkala takbir Rasulullah Shallallahu'alaihi wasallam mengangkat kedua tangannya hingga sejajar dengan kedua telinganya. Beliau juga melakukan hal tersebut ketika hendak ruku' serta saat mengangkat kepala dari ruku'."},"870":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ دَخَلَ فِي الصَّلَاةِ رَفَعَ يَدَيْهِ وَحِينَ رَكَعَ وَحِينَ رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ حَتَّى حَاذَتَا فُرُوعَ أُذُنَيْهِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Ibnu Abu 'Arubah] dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Al Huwairits] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam tatkala memulai shalat, beliau mengangkat kedua tangannya sejajar dengan bagian atas kedua telinganya, juga ketika hendak ruku' serta saat mengangkat kepala dari ruku'.\""},"871":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا فِطْرُ بْنُ خَلِيفَةَ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ رَفَعَ يَدَيْهِ حَتَّى تَكَادَ إِبْهَامَاهُ تُحَاذِي شَحْمَةَ أُذُنَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Muhammad bin Bisyr] dia berkata; telah menceritakan kepada kami [Fithr bin Khalifah] dari [Abdul Jabbar bin Wa'il] dari [bapaknya] bahwa dia melihat Nabi Shallallahu'alaihi wasallam apabila beliau hendak memulai shalat, beliau mengangkat kedua tangannya hingga kedua ibu jarinya hampir sejajar dengan kedua daun telinganya."},"872":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ سَمْعَانَ قَالَجَاءَ أَبُو هُرَيْرَةَ إِلَى مَسْجِدِ بَنِي زُرَيْقٍ فَقَالَ ثَلَاثٌ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْمَلُ بِهِنَّ تَرَكَهُنَّ النَّاسُ كَانَ يَرْفَعُ يَدَيْهِ فِي الصَّلَاةِ مَدًّا وَيَسْكُتُ هُنَيْهَةً وَيُكَبِّرُ إِذَا سَجَدَ وَإِذَا رَفَعَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Ibnu Abu Dzi'b] dia berkata; telah menceritakan kepada kami [Sa'id bin Sam'an] dia berkata; [Abu Hurairah] datang ke Masjid Bani Zuraiq, kemudian ia berkata, 'Ada tiga hal yang dulu selalu dilakukan oleh Rasulullah Shallallahu'alaihi wasallam tetapi banyak ditinggalkan oleh manusia, yaitu beliau mengangkat kedua tangan saat memulai shalat dan terlihat jelas, diam beberapa saat saat mengawali shalat, dan bertakbir bila hendak sujud dan ketika hendak mengangkat kepala dari sujud'.\""},"873":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ قَالَ حَدَّثَنِي سَعِيدُ بْنُ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْمَسْجِدَ فَدَخَلَ رَجُلٌ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ فَصَلَّى كَمَا صَلَّى ثُمَّ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ عَلَيْهِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ السَّلَامُ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَعَلَ ذَلِكَ ثَلَاثَ مَرَّاتٍ فَقَالَ الرَّجُلُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أُحْسِنُ غَيْرَ هَذَا فَعَلِّمْنِي قَالَ إِذَا قُمْتَ إِلَى الصَّلَاةِ فَكَبِّرْ ثُمَّ اقْرَأْ مَا تَيَسَّرَ مَعَكَ مِنْ الْقُرْآنِ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَعْتَدِلَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ جَالِسًا ثُمَّ افْعَلْ ذَلِكَ فِي صَلَاتِكَ كُلِّهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; ['Ubaidullah bin 'Umar] dia berkata; telah menceritakan kepadaku [Sa'id bin Abu Sa'id] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasululluh Shallallahu'alaihi wasallam masuk ke dalam masjid, lalu ada seorang laki-laki yang ikut masuk kemudian shalat. Setelah itu ia datang kepada Rasulullah Shallallahu'alaihi wasallam dengan mengucapkan salam kepada Rasulullah Shallallahu'alihiwasallam dan beliau Shallallahu'alaihi wasallam membalas salamnya sambil berkata, 'Kembalilah dan ulangi shalatmu karena kamu belum mengerjakan shalat! ' la lalu kembali lagi dan mengulangi shalatnya seperti shalat pertamanya. Kemudian ia datang lagi kepada Rasulullah Shallallahu'alaihi wasallam dengan mengucapkan salam kepada beliau Shallallahu'alihiwasallam dan Rasulullah Shallallahu'alaihi wasallam berkata, \"Wa'alaikas-salam. Kembali dan ulangi lagi shalatmu karena kamu belum mengerjakan shalat! ' Lalu orang tersebut shalat seperti itu sampai tiga kali. Setelah itu orang tersebut berkata, \"Demi Dzat yang mengutus engkau dengan membawa kebenaran, aku tidak bisa shalat lebih baik lagi dari yang seperti ini, maka ajarilah aku!\" Rasulullah Shallallahu'alaihi wasallam lalu bersabda: 'Jika kamu telah berdiri untuk shalat, maka bertakbirlah, kemudian bacalah A! Qur'an yang mudah bagimu. Kemudian ruku'lah hingga kamu tenang (thuma 'ninah) dalam rukumu dan bangkitlah dari ruku' hingga kamu berdiri tegak. Lalu sujudlah kamu hingga kamu tenang (thuma 'ninah) dalam sujudmu, dan bangkitlah dari sujud hingga kamu tenang (Thuma'ninah) dalam keadaan duduk. Kerjakanlah semua hal tersebut pada setiap shalatmu.\""},"874":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ أَبِي عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنِي زَيْدٌ هُوَ ابْنُ أَبِي أُنَيْسَةَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَامَ رَجُلٌ خَلْفَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اللَّهُ أَكْبَرُ كَبِيرًا وَالْحَمْدُ لِلَّهِ كَثِيرًا وَسُبْحَانَ اللَّهِ بُكْرَةً وَأَصِيلًا فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَاحِبُ الْكَلِمَةِ فَقَالَ رَجُلٌ أَنَا يَا نَبِيَّ اللَّهِ فَقَالَ لَقَدْ ابْتَدَرَهَا اثْنَا عَشَرَ مَلَكًا","id":"Telah mengabarkan kepadaku [Muhammad bin Wahb] dia berkata; telah menceritakan kepada kami [Muhammad bin Salamah] dari [Abu 'Abdurrahim] dia berkata; telah menceritakan kepadaku [Zaid bin Abu Unaisah] dari ['Amr bin Murrah] dari ['Aun bin Abdullah] dari [Abdullah bin 'Umar] dia berkata; \"Ada seorang laki-laki berdiri di belakang Nabi Shallallahu'alaihi wasallam yang mengucapkan, 'Allaahu akbar kabiiraa wal hamdu lillaahi katsiraa, wa subhaanallaahi bukralan-wa'ashiilaa (Allah Maha Besar, segala puji bagi-Nya, Allah Maha Suci pada pagi dan sore hari) ' maka Nabi Shallallahu'alaihi wasallam bersabda: 'Siapa yang mengucapkan kalimat ini? ' Laki-laki tersebut berkata; 'Aku wahai Nabi Allah! ' Rasulullah Shallallahu'alaihi wasallam lalu bersabda: \"Kalimat tersebut diperebutkan oleh dua belas malaikat (untuk diangkat ke tempat diterimanya amalan).'"},"875":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ شُجَاعٍ الْمَرُّوذِيُّ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ حَجَّاجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ قَالَبَيْنَمَا نَحْنُ نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ اللَّهُ أَكْبَ��ُ كَبِيرًا وَالْحَمْدُ لِلَّهِ كَثِيرًا وَسُبْحَانَ اللَّهِ بُكْرَةً وَأَصِيلًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ الْقَائِلُ كَلِمَةَ كَذَا وَكَذَا فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَنَا يَا رَسُولَ اللَّهِ قَالَ عَجِبْتُ لَهَا وَذَكَرَ كَلِمَةً مَعْنَاهَا فُتِحَتْ لَهَا أَبْوَابُ السَّمَاءِقَالَ ابْنُ عُمَرَ مَا تَرَكْتُهُ مُنْذُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Syuja' Al Marrudzi] dia berkata; telah menceritakan kepada kami [Isma'il] dari [Hajjaj] dari [Abu Az Zubair] dari ['Aun bin Abdullah] dari [Ibnu 'Umar] dia berkata; \"Tatkala kami bersama Rasulullah Shallallahu'alihiwasallam tiba-tiba ada seorang laki-laki yang mengucapkan, 'Allahu akbar kabiraa wal hamdu lillahi katsiraa wa subhanallahi bukrataw-wa ashilaa (Allah Maha Besar segala puji bagi-Nya, Allah Maha Suci pada pagi dan sore hari) ' maka Rasulullah Shallallahu'alaihi wasallam berkata: 'Siapa yang mengucapkan kalimat tersebul? ' Seorang laki-laki dari suatu kaum lalu berkata, 'Aku wahai Rasulullah Shallallahu'alaihi wasallam!\" Rasulullah Shallallahu'alaihi wasallam kemudian bersabda: 'Aku kagum dengan kalimat tersebut.' Setelah itu beliau Shallallahu'alaihi wasallam bersabda yang maknanya, 'Pintu-pintu langit dibuka dengan kalimat tersebut.' Ibnu Umar berkata; 'Aku tidak pernah meninggalkannya sejak aku mendengar sabda Rasulullah Shallallahu'alaihi wasallam tersebut.'"},"876":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مُوسَى بْنِ عُمَيْرٍ الْعَنْبَرِيِّ وَقَيْسِ بْنِ سُلَيْمٍ الْعَنْبَرِيِّ قَالَا حَدَّثَنَا عَلْقَمَةُ بْنُ وَائِلٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ قَائِمًا فِي الصَّلَاةِ قَبَضَ بِيَمِينِهِ عَلَى شِمَالِهِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah] dari [Musa bin 'Umair Al 'Anbari] dan [Qais bin Sulaim Al 'Anbari] mereka berdua berkata; Telah menceritakan kepada kami ['Alqomah bin Wa'il] dari [bapaknya], dia berkata; \"Aku melihat Rasulullah Shalallahu 'Alaihi Wa Sallam apabila berdiri untuk shalat beliau memegang tangan kirinya dengan tangan kanannya.\""},"877":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ الْحَجَّاجِ بْنِ أَبِي زَيْنَبَ قَالَ سَمِعْتُ أَبَا عُثْمَانَ يُحَدِّثُ عَنْ ابْنِ مَسْعُودٍ قَالَرَآنِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ وَضَعْتُ شِمَالِي عَلَى يَمِينِي فِي الصَّلَاةِ فَأَخَذَ بِيَمِينِي فَوَضَعَهَا عَلَى شِمَالِي","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; Telah menceritakan kepada kami [Husyaim] dari [Al Hajjaj bin Abu Zainab] dia berkata; Aku mendengar [Abu 'Utsman] menceritakan dari [Ibnu Mas'ud] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam melihatku meletakkan tangan kiri di atas tangan kanan saat shalat, lain beliau Shallallahu'alaihi wasallam mengambil tangan kananku dan meletakkannya di atas tangan kiriku.\""},"878":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ زَائِدَةَ قَالَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ قَالَ حَدَّثَنِي أَبِي أَنَّ وَائِلَ بْنَ حُجْرٍ أَخْبَرَهُقَالَ قُلْتُ لَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يُصَلِّي فَنَظَرْتُ إِلَيْهِ فَقَامَ فَكَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى حَاذَتَا بِأُذُنَيْهِ ثُمَّ وَضَعَ يَدَهُ الْيُمْنَى عَلَى كَفِّهِ الْيُسْرَى وَالرُّسْغِ وَالسَّاعِدِ فَلَمَّا أَرَادَ أَنْ يَرْكَعَ رَفَعَ يَدَيْهِ مِثْلَهَا قَالَ وَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ ثُمَّ لَمَّا رَفَعَ رَأْسَهُ رَفَعَ يَدَيْهِ مِثْلَهَا ثُمَّ سَجَدَ فَجَعَلَ كَفَّيْهِ بِحِذَاءِ أُذُنَيْهِ ثُمَّ قَعَدَ وَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَوَضَعَ كَفَّهُ الْيُسْرَى عَلَى فَخِذِهِ وَرُكْبَتِهِ الْيُسْرَى وَجَعَلَ حَدَّ مِرْفَقِهِ الْأَيْمَنِ عَلَى فَخِذِهِ الْيُمْنَى ثُمَّ قَبَضَ اثْنَتَيْنِ مِنْ أَصَابِعِهِ وَحَلَّقَ حَلْقَةً ثُمَّ رَفَعَ إِصْبَعَهُ فَرَأَيْتُهُ يُحَرِّكُهَا يَدْعُو بِهَا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Zaidah] dia berkata; telah menceritakan kepada kami ['Ashim bin Kulaib] dia berkata; [bapakku] telah menceritakan kepadaku bahwasanya [Wa'il bin Hujr] mengabarkan kepadanya, dia berkata; \"Aku melihat cara shalat Rasulullah Shallallahu'alihiwasallam. Aku melihat beliau Shallallahu'alaihi wasallam berdiri untuk shalat, kemudian takbir dengan mengangkat kedua tangannya sejajar dengan kedua telinganya. Lantas beliau Shallallahu'alaihi wasallam meletakkan tangan kanannya di atas telapak kirinya, juga di atas pergelangan tangannya, dan meletakkannya di atas lengannya. Ketika hendak ruku' beliau Shallallahu'alaihi wasallam mengangkat kedua tangannya sama seperti tadi (sejajar dengan kedua telinganya). Beliau Shallallahu'alaihi wasallam meletakkan kedua tangannya di kedua lututnya, kemudian mengangkat kepalanya sambil mengangkat kedua tangannya, sejajar dengan kedua telinganya, kemudian sujud. Beliau Shallallahu'alaihi wasallam meletakkan kedua tangannya sejajar dengan kedua telinganya, kemudian duduk di atas kaki kiri. Beliau juga meletakkan telapak tangan kiri diantara paha dan lutut kiri. Lalu beliau Shallallahu'alaihi wasallam meletakkan ujung lengan kanan di atas paha kanan. Kemudian ia menggenggam dua jarinya serta membentuk lingkaran, lantas mengangkat jarinya. Aku melihat beliau Shallallahu'alaihi wasallam menggerak-gerakkannya dan berdoa dengannya.\""},"879":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ هِشَامٍ ح و أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ وَاللَّفْظُ لَهُ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُصَلِّيَ الرَّجُلُ مُخْتَصِرًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Hisyam] -lewat jalur periwayatan lain- dan telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] -dan lafazh ini miliknya- dari [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam melarang seseorang shalat dengan bertolak pinggang. "},"880":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُفْيَانَ بْنِ حَبِيبٍ عَنْ سَعِيدِ بْنِ زِيَادٍ عَنْ زِيَادِ بْنِ صُبَيْحٍ قَالَصَلَّيْتُ إِلَى جَنْبِ ابْنِ عُمَرَ فَوَضَعْتُ يَدِي عَلَى خَصْرِي فَقَالَ لِي هَكَذَا ضَرْبَةً بِيَدِهِ فَلَمَّا صَلَّيْتُ قُلْتُ لِرَجُلٍ مَنْ هَذَا قَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ قُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ مَا رَابَكَ مِنِّي قَالَ إِنَّ هَذَا الصَّلْبُ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا عَنْهُ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Sufyan bin Habib] dari [Sa'id bin Ziyad] dari [Ziyad bin Shubaih] dia berkata; \"Aku shalat di samping [Ibnu Umar], dan aku meletakkan tanganku di atas pinggangku, maka ia berkata kepadaku, 'Begini yang benar' sambil memukulku dengan tangannya. Setelah selesai shalat aku bertanya kepada seseorang, \"Siapa ini? ' la menjawab, \"la adalah Abdullah bin Umar'. Lalu aku berkata, 'Wahai Abu Abdurrahman, apa yang membuatmu tidak suka denganku? ' la menjawab, 'Ini adalah penyilangan (salib), dan Rasulullah Shallallahu'alaihi wasallam melarang kami dari hal tersebut."},"881":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ بْنِ سَعِيدٍ الثَّوْرِيِّ عَنْ مَيْسَرَةَ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ أَبِي عُبَيْدَةَأَنَّ عَبْدَ اللَّهِ رَأَى رَجُلًا يُصَلِّي قَدْ صَفَّ بَيْنَ قَدَمَيْهِ فَقَالَ خَالَفَ السُّنَّةَ وَلَوْ رَاوَحَ بَيْنَهُمَا كَانَ أَفْضَلَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan bin Sa'id Ats-Tsauri] dari [Maisarah] dari [Al Minhal bin 'Amr] dari [Abu 'Ubaidah] bahwasanya [Abdullah] melihat seorang lelaki sedang shalat dengan merapatkan kedua telapak kakinya. Lalu ia berkata; 'Dia telah menyelisihi sunnah, seandainya dia memisahkan keduanya, itu lebih utama.'"},"882":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي مَيْسَرَةُ بْنُ حَبِيبٍ قَالَ سَمِعْتُ الْمِنْهَالَ بْنَ عَمْرٍو يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِأَنَّهُ رَأَى رَجُلًا يُصَلِّي قَدْ صَفَّ بَيْنَ قَدَمَيْهِ فَقَالَ أَخْطَأَ السُّنَّةَ وَلَوْ رَاوَحَ بَيْنَهُمَا كَانَ أَعْجَبَ إِلَيَّ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dia berkata; telah mengabarkan kepadaku [Maisarah bin Habib] dia berkata; Aku mendengar [Al Minhal bin 'Amr] menceritakan dari [Abu 'Ubaidah] dari [Abdullah] bahwasanya ia melihat seorang lelaki sedang shalat dengan merapatkan kedua telapak kakinya. Lalu ia berkata; 'Dia telah menyelisihi sunnah, seandainya dia memisahkan keduanya, itu lebih aku sukai.'"},"883":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتْ لَهُ سَكْتَةٌ إِذَا افْتَتَحَ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah bin 'Amr bin Jarir] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam diam beberapa saat ketika mengawali shalat."},"884":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ سَكَتَ هُنَيْهَةً فَقُلْتُ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ مَا تَقُولُ فِي سُكُوتِكَ بَيْنَ التَّكْبِيرِ وَالْقِرَاءَةِ قَالَ أَقُولُ اللَّهُمَّ بَاعِدْ بَيْنِي وَبَيْنَ خَطَايَايَ كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ نَقِّنِي مِنْ خَطَايَايَ كَمَا يُنَقَّى الثَّوْبُ الْأَبْيَضُ مِنْ الدَّنَسِ اللَّهُمَّ اغْسِلْنِي مِنْ خَطَايَايَ بِالْمَاءِ وَالثَّلْجِ وَالْبَرَدِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; Telah memberitakan kepada kami [Jarir] dari ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah bin 'Amr bin Jarir] dari [Abu Hurairah] dia berkata; \"Apabila Rasulullah Shallallahu'alaihi wasallam mengawali shalat maka beliau diam beberapa saat. Aku lalu berkata, 'Wahai Rasulullah Shallallahu'alihiwasallam, ayah dan ibuku jadi jaminan! Apakah yang engkau baca ketika engkau diam diantara takbiratul ihram dan bacaan Al Fatihah? ' Beliau Shallallahu'alaihi wasallam menjawab, 'Aku mengucapkan: -doa yang artinya- (Ya Allah, jauhkan aku dari kesalahan-kesalahanku, sebagaimana Engkau menjauhkan barat dengan timur. Ya Allah, sucikan aku dari segala dosa dan kesalahan, sebagaimana Engkau mensucikan baju dari segala kotoran. Ya Allah, sucikan aku dari kesalahan-kesalahanku dengan salju dan embun '.\""},"885":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ قَالَ حَدَّثَنَا شُرَيْحُ بْنُ يَزِيدَ الْحَضْرَمِيُّ قَالَ أَخْبَرَنِي شُعَيْبُ بْنُ أَبِي حَمْزَةَ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَفْتَحَ الصَّلَاةَ كَبَّرَ ثُمَّ قَالَ إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ لَا شَرِيكَ لَهُ وَبِذَلِكَ أُمِرْتُ وَأَنَا مِنْ الْمُسْلِمِينَ اللَّهُمَّ اهْدِنِي لِأَحْسَنِ الْأَعْمَالِ وَأَحْسَنِ الْأَخْلَاقِ لَا يَهْدِي لِأَحْسَنِهَا إِلَّا أَنْتَ وَقِنِي سَيِّئَ الْأَعْمَالِ وَسَيِّئَ الْأَخْلَاقِ لَا يَقِي سَيِّئَهَا إِلَّا أَنْتَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman bin Sa'id] dia berkata; telah menceritakan kepada kami [Syuraih bin Yazid Al Hadhrami] dia berkata; telah mengabarkan kepadaku [Syu'aib bin Abu Hamzah] dia berkata; telah mengabarkan kepadaku [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] dia berkata; \"Bila Rasulullah Shallallahu'alaihi wasallam memulai shalat maka beliau bertakbir, kemudian mengucapkan -doa yang artinya- Sesungguhnya shalatku, ibadahku, hidupku, dan matiku hanya bagi Allah, Rabb semesta alam, yang tiada sekutu bagi-Nya. Demikianlah aku diperintahkan, dan aku termasuk kaum muslimin. Ya Allah, tunjukkan saya kepada perbuatan yang terbaik dan kepada akhlak yang terbaik, karena tidak ada yang bisa menunjukkan kepada yang terbaik kecuali Engkau. Jagalah aku dari perbuatan jelek dan akhlak yang jelek, karena tidak ada yang bisa menjagaku dari kejelekan kecuali Engkau '.\""},"886":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ قَالَ حَدَّثَنِي عَمِّي الْمَاجِشُونُ بْنُ أَبِي سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اسْتَفْتَحَ الصَّلَاةَ كَبَّرَ ثُمَّ قَالَ وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّمَوَاتِ وَالْأَرْضَ حَنِيفًا وَمَا أَنَا مِنْ الْمُشْرِكِينَ إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ لَا شَرِيكَ لَهُ وَبِذَلِكَ أُمِرْتُ وَأَنَا مِنْ الْمُسْلِمِينَ اللَّهُمَّ أَنْتَ الْمَلِكُ لَا إِلَهَ إِلَّا أَنْتَ أَنَا عَبْدُكَ ظَلَمْتُ نَفْسِي وَاعْتَرَفْتُ بِذَنْبِي فَاغْفِرْ لِي ذُنُوبِي جَمِيعًا لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ وَاهْدِنِي لِأَحْسَنِ الْأَخْلَاقِ لَا يَهْدِي لِأَحْسَنِهَا إِلَّا أَنْتَ وَاصْرِفْ عَنِّي سَيِّئَهَا لَا يَصْرِفُ عَنِّي سَيِّئَهَا إِلَّا أَنْتَ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ كُلُّهُ فِي يَدَيْكَ وَالشَّرُّ لَيْسَ إِلَيْكَ أَنَا بِكَ وَإِلَيْكَ تَبَارَكْتَ وَتَعَالَيْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dia berkata; telah menceritakan kepada kami [Abdul 'Aziz bin Abu Salamah] dia berkata; pamanku [Al Majisyun bin Abu Salamah] telah menceritakan kepadaku, dari [Abdurrahman Al A'raj] dari ['Ubaidullah bin Abu Rafi'] dari ['Ali] bahwa Rasulullah Shallallahu'alaihi wasallam apabila memulai shalat beliau bertakbir kemudian mengucapkan -doa yang artinya- \"Aku hadapkan wajahku (tujuanku) kepada Dzat yang telah menciptakan lagit dan bumi dan bumi dengan lurus, dan aku bukan termasuk orang-orang musyrik. Sesungguhnya shalatku, ibadahku (Kurbanku), hidupku, dan matiku hanya bagi Allah, Rabb semesta alam. yang tiada sekutu bagi-Nya. Demikianlah aku diperintahkan dan aku termasuk kaum muslimin. Ya Allah, Engkau adalah penguasa yang tiada Dzat yang berhak diibadahi selain Engkau, dan aku adalah hamba-Mu. Aku telah menzhalimi diriku sendiri dan aku mengakui dosaku, maka ampunilah semua dosaku, karena tidak ada yang bisa mengampuni dosa selain Engkau. Tunjukkanlah aku kepada akhlak yang terbaik, karena tidak ada yang dapat menunjukkan kepada akhlak yang baik kecuali Engkau. Palingkanlah aku dari perbuatan jelek, karena tidak ada yang bisa memalingkannya dari kejelekan kecuali Engkau. Aku siap untuk menjalankan perintah-Mu dan taat kepada-Mu. Semua kebaikan ada di tangan-Mu dan kejelekan tidak kembali kepada-Mu. Aku bergantung dan berlindung kepada-Mu. Engkau Maha Suci dan Maha Tinggi, maka aku meminta ampun dan bertaubat kepada-Mu '.\""},"887":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ عُثْمَانَ الْحِمْصِيُّ قَالَ حَدَّثَنَا ابْنُ حِمْيَرٍ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ وَذَكَرَ آخَرَ قَبْلَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ الْأَعْرَجِ عَنْ مُحَمَّدِ بْنِ مَسْلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَامَ يُصَلِّي تَطَوُّعًا قَالَ اللَّهُ أَكْبَرُ وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّمَوَاتِ وَالْأَرْضَ حَنِيفًا مُسْلِمًا وَمَا أَنَا مِنْ الْمُشْرِكِينَ إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ لَا شَرِيكَ لَهُ وَبِذَلِكَ أُمِرْتُ وَأَنَا أَوَّلُ الْمُسْلِمِينَ اللَّهُمَّ أَنْتَ الْمَلِكُ لَا إِلَهَ إِلَّا أَنْتَ سُبْحَانَكَ وَبِحَمْدِكَ ثُمَّ يَقْرَأُ","id":"Telah mengabarkan kepada kami [Yahya bin 'Usman Al Himshi] dia berkata; telah menceritakan kepada kami [Ibnu Hamir] dia berkata; telah menceritakan kepada kami [Syu'aib bin Abu Hamzah] dari [Muhammad bin Al Munkadir] dan menyebutkan sebelumnya dari [Abdurrahman bin Hurmuz Al A'raj] dari [Muhammad bin Maslamah] bahwa jika Rasulullah Shallallahu'alaihi wasallam bangkit untuk mengerjakan shalat sunnah maka beliau membaca -doa yang artinya- \"Allah Maha Besar aku hadapkan wajahku (tujuanku) kepada Dzat yang telah menciptakan langit dan bumi dengan lurus dan pasrah. Aku tidak termasuk orang-orang musyrik. Sesungguhnya shalatku, ibadahku (Kurbanku). hidupkun dan matiku hanya bagi Allah, Rabb semesta alam, yang tiada sekutu bagi-Nya. Demikianlah aku diperintahkan, dan aku termasuk kaum muslim. Ya Allah, Engkau adalah penguasa yang tiada Dzat yang berhak disembah selain Engkau. Engkau Maha Suci dan dengan memuji-Mu.\" Kemudian beliau Shallallahu'alaihi wasallam membaca surat (al-Fatihah)."},"888":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ فَضَالَةَ بْنِ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ عَلِيِّ بْنِ عَلِيٍّ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا افْتَتَحَ الصَّلَاةَ قَالَ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ تَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرُكَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Fadhalah bin Ibrahim] dia berkata; telah memberitakan kepada kami [Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ja'far bin Sulaiman] dari ['Ali bin 'Ali] dari [Abul Mutawakkil] dari [Abu Sa'id] bahwa Nabi Shallallahu'alaihi wasallam bila mengawali shalatnya maka beliau mengucapkan (doa), \"Maha Suci Allah dan kami memuji Engkau. Maha Suci nama-Mu dan Maha Tinggi keluhuran-Mu. Tidak ada Dzat yang berhak disembah selain Engkau.\""},"889":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنِي جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ عَلِيِّ بْنِ عَلِيٍّ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ قَالَ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ وَتَبَارَكَ اسْمُكَ وَتَعَالَى جَدُّكَ وَلَا إِلَهَ غَيْرُكَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] dia berkata; telah menceritakan kepadaku [Ja'far bin Sulaiman] dari ['Ali bin 'Ali] dari [Abul Mutawakkil] dari [Abu Sa'id] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam apabila mengawali shalatnya membaca do'a, 'Maha Suci Allah dan kami memuji Engkau. Maha Suci nama-Mu dan Maha Tinggi keluhuran-Mu. Tidak ada Dzat yang berhak disembah selain Engkau.\""},"890":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ وَقَتَادَةَ وَحُمَيْدٍ عَنْ أَنَسٍ أَنَّهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِنَا إِذْ جَاءَ رَجُلٌ فَدَخَلَ الْمَسْجِدَ وَقَدْ حَفَزَهُ النَّفَسُ فَقَالَ اللَّهُ أَكْبَرُ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ قَالَ أَيُّكُمْ الَّذِي تَكَلَّمَ بِكَلِمَاتٍ فَأَرَمَّ الْقَوْمُ قَالَ إِنَّهُ لَمْ يَقُلْ بَأْسًا قَالَ أَنَا يَا رَسُولَ اللَّهِ جِئْتُ وَقَدْ حَفَزَنِي النَّفَسُ فَقُلْتُهَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ رَأَيْتُ اثْنَيْ عَشَرَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَرْفَعُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Hajjaj] dia berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] dan [Qatadah] dan [Humaid] dari [Anas] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam shalat bersama kami, tiba-tiba ada seorang lelaki yang masuk ke dalam masjid, dan nafasnya masih tersengal-sengal, kemudian ia mengucapkan, 'Allahu akbar, alhamdulillah hamdan katsiran thayyiban mubarakan fiih (Allah Maha Besar, segala puji bagi Allah dengan pujian yang banyak serta pujian yang diberkahi) ', Setelah Rasulullah Shallallahu'alaihi wasallam selesai shalat beliau Shallallahu'alaihi wasallam berkata: \"Siapa di anlara kalian yang mengucapkan kalimat tersebut? ' Orang-orang terdiam, lantas Rasulullah Shallallahu'alaihi wasallam berkata lagi 'Orang yang mengucapkan kalimat tadi tidak mengucapkan hal yang salah'. Lelaki tersebut lalu berkata. 'Aku wahai Rasulullah Shallallallahu'alaihi wasallam! Aku datang dalam keadaan nafasku yang tersengal - sengal. lalu aku mengucapkannya'. Kemudian beliau Shallallahu'alaihi wasallam bersabda: 'Aku melihat dua belas malaikat berebut untuk mengangkat kalimat tersebut '.\""},"891":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا يَسْتَفْتِحُونَ الْقِرَاءَةَ بِ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] dia berkata; dia berkata: \"Nabi Shallallahu'alihiwasallam, Abu Bakar, dan Umar Radliyallahu'anhum memulai bacaannya dengan membaca, 'Alhamdulillah Rabbil 'Alamin.\""},"892":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الزُّهْرِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ أَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَافْتَتَحُوا بِ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin 'Abdurrahman Az Zuhri] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ayyub] dari [Qatadah] dari [Anas] dia berkata; \"Aku pernah shalat bersama Rasulullah Shallallahu'alihiwasallam Abu Bakar, serta Umar Radliyallahu'anhum, dan mereka mengawalinya dengan membaca, 'Alhamdulillah Rabbil 'Alamin.'"},"893":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْمُخْتَارِ بْنِ فُلْفُلٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَبَيْنَمَا ذَاتَ يَوْمٍ بَيْنَ أَظْهُرِنَا يُرِيدُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أَغْفَى إِغْفَاءَةً ثُمَّ رَفَعَ رَأْسَهُ مُتَبَسِّمًا فَقُلْنَا لَهُ مَا أَضْحَكَكَ يَا رَسُولَ اللَّهِ قَالَ نَزَلَتْ عَلَيَّ آنِفًا سُورَةٌ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ{ إِنَّا أَعْطَيْنَاكَ الْكَوْثَرَ فَصَلِّ لِرَبِّكَ وَانْحَرْ إِنَّ شَانِئَكَ هُوَ الْأَبْتَرُ }ثُمَّ قَالَ هَلْ تَدْرُونَ مَا الْكَوْثَرُ قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّهُ نَهْرٌ وَعَدَنِيهِ رَبِّي فِي الْجَنَّةِ آنِيَتُهُ أَكْثَرُ مِنْ عَدَدِ الْكَوَاكِبِ تَرِدُهُ عَلَيَّ أُمَّتِي فَيُخْتَلَجُ الْعَبْدُ مِنْهُمْ فَأَقُولُ يَا رَبِّ إِنَّهُ مِنْ أُمَّتِي فَيَقُولُ لِي إِنَّكَ لَا تَدْرِي مَا أَحْدَثَ بَعْدَكَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami ['Ali bin Mushar] dari [Al Mukhtar bin Fulful] dari [Anas bin Malik] dia berkata; \"Suatu hari Rasulullah Shallallahu'alaihi wasallam berada diantara kami, dan tiba-tiba beliau Shallallahu'alaihi wasallam tertidur sebentar. Kemudian beliau mengangkat kepalanya sambil tersenyum, maka kami bertanya kepadanya, 'Wahai Rasulullah Shallallahu'alihiwasallam apakah yang membuat engkau tersenyum? ' Beliau Shallallahu'alaihi wasallam menjawab, 'Tadi baru saja turun surat (Al Kautsar) Bismillahirrahmaanirrahiim, Sesungguhnya Kami telah memberikan kepadamu nikmat yang banyak. Maka dirikanlah shalat karena Tuhanmu dan berkurbanlah. Sesungguhnya orang-orang yang membenci kamu dialah yang terpuruk (QS. Al Kautsar (108): 1 -3). Kemudian beliau Shallallahu'alaihi wasallam bersabda: 'Apakah kalian tahu apa Al Kautsar itu? ' Kami menjawab, 'Allah dan Rasul-Nya yang lebih mengetahui'. Lalu Rasulullah Shallallahu'alaihi wasallam bersabda: 'Al Kautsar adalah sebuah telaga yang telah dijanjikan Rabb ku untukku di surga; bejananya (tempat airnya) sebanyak jumlah bintang-bintang di langit. Umatku banyak yang datang kepadaku, namun salah seorang umatku ini ditariknya, maka aku berkata.\"Ya Rabbi, dia umatku.\" Lalu Allah berfirman, \"Engkau tidak tahu apa yang terjadi setelah engkau wafat.\""},"894":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا خَالِدٌ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ نُعَيْمٍ الْمُجْمِرِ قَالَصَلَّيْتُ وَرَاءَ أَبِي هُرَيْرَةَ فَقَرَأَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ ثُمَّ قَرَأَ بِأُمِّ الْقُرْآنِ حَتَّى إِذَا بَلَغَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقَالَ آمِينَ فَقَالَ النَّاسُ آمِينَ وَيَقُولُ كُلَّمَا سَجَدَ اللَّهُ أَكْبَرُ وَإِذَا قَامَ مِنْ الْجُلُوسِ فِي الِاثْنَتَيْنِ قَالَ اللَّهُ أَكْبَرُ وَإِذَا سَلَّمَ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَشْبَهُكُمْ صَلَاةً بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakim] dari [Syu'aib] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Khalid] dari [Sa'id bin Abu Hilal] dari [Nu'aim Al Mujmir] dia berkata; Aku pernah shalat di belakang [Abu Hurairah] kemudian dia membaca \"Bismillaahirrohmaanirrohiim, lalu membaca surat Al Fatihah hingga tatkala telah sampai pada 'Ghairil Maghdlubi 'Alaihim Waladlaallin, (bukan orang-orang yang Engkau murkai dan bukan pula orang-orang yang tersesat) dia mengucapkan 'Aamiin.' Orang-orangpun lalu mengucapkan Aamiin pula. Abu Hurairah juga mengucapkan 'Allahu Akbar' setiap hendak sujud, dan bangun dari duduk tahiyyat pertama. Setelah selesai salam, dia berkata; Demi jiwaku yang berada di tangan-Nya, Aku adalah orang yang paling menyerupai Rasulullah Shallallahu'alaihi wasallam dalam shalat."},"895":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ الْحَسَنِ بْنِ شَقِيقٍ قَالَ سَمِعْتُ أَبِي يَقُولُ أَنْبَأَنَا أَبُو حَمْزَةَ عَنْ مَنْصُورِ بْنِ زَاذَانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُسْمِعْنَا قِرَاءَةَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِوَصَلَّى بِنَا أَبُو بَكْرٍ وَعُمَرُ فَلَمْ نَسْمَعْهَا مِنْهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ali bin Al Hasan bin Syaqiq] dia berkata; aku mendengar [bapakku] berkata; telah memberitakan kepada kami [Abu Hamzah] dari [Manshur bin Zadzan] dari [Anas bin Malik] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam shalat bersama kami dan kami tidak mendengar (bacaan) bismillahirrahmaanirrahiim darinya. Kami juga shalat bersama Abu Bakar serta Umar. dan keduanya juga tidak membaca bismillahirrahmaanirrahim.\""},"896":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ أَبُو سَعِيدٍ الْأَشَجُّ قَالَ حَدَّثَنِي عُقْبَةُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا شُعْبَةُ وَابْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ رَضِيَ اللَّهُ عَنْهُمْ فَلَمْ أَسْمَعْ أَحَدًا مِنْهُمْ يَجْهَرُ بِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id Abu Sa'id Al Asyaj] dia berkata; telah menceritakan kepadaku ['Uqbah bin Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dan [Ibnu Abu 'Arubah] dari [Qatadah] dari [Anas] dia berkata; \"Aku shalat di belakang Rasulullah Shallallahu'alihiwasallam Abu Bakar, Umar, serta Utsman Radliyallahu'anhum, dan aku tidak mendengar salah seorang dari mereka mengeraskan bacaan Bismillahirrahmaanirrahiim."},"897":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ غِيَاثٍ قَالَ أَخْبَرَنِي أَبُو نَعَامَةَ الْحَنَفِيُّ قَالَ حَدَّثَنَا ابْنُ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَكَانَ عَبْدُ اللَّهِ بْنُ مُغَفَّلٍ إِذَا سَمِعَ أَحَدَنَا يَقْرَأُ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ يَقُولُ صَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَلْفَ أَبِي بَكْرٍ وَخَلْفَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَمَا سَمِعْتُ أَحَدًا مِنْهُمْ قَرَأَ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami ['Utsman bin Ghiyats] dia berkata; telah mengabarkan kepadaku [Abu Na'amah Al Hanafi] dia berkata; telah menceritakan kepada kami [Ibnu Abdullah bin Mughaffal] dia berkata; adalah [Abdullah bin Mughaffal] jika dia mendengar salah seorang diantara kami membaca bismillahirrahmaanirrahiim, maka dia berkata; \"Aku shalat di belakang Rasulullah Shallallahu'alihiwasallam Abu Bakar, dan Umar Radliyallahu'anhum, dan aku tidak mendengar salah seorang dari mereka membaca Bismillahirrahmaanirrahiim."},"898":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ أَبَا السَّائِبِ مَوْلَى هِشَامِ بْنِ زُهْرَةَ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى صَلَاةً لَمْ يَقْرَأْ فِيهَا بِأُمِّ الْقُرْآنِ فَهِيَ خِدَاجٌ هِيَ خِدَاجٌ هِيَ خِدَاجٌ غَيْرُ تَمَامٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Al 'Ala bin 'Abdurrahman] bahwasanya dia mendengar [Abu As Saib] -maula Hisyam bin Zuhrah- berkata; aku mendengar [Abu Hurairah] berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Barang siapa mengerjakan shalat tanpa membaca Ummul Qur'an (surat Fatihah) maka ia tidak sempurna, ia tidak sempurna, ia tidak sempurna.\""},"899":{"ar":"فَقُلْتُ يَا أَبَا هُرَيْرَةَإِنِّي أَحْيَانًا أَكُونُ وَرَاءَ الْإِمَامِ فَغَمَزَ ذِرَاعِي وَقَالَ اقْرَأْ بِهَا يَا فَارِسِيُّ فِي نَفْسِكَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَقُولُ اللَّهُ عَزَّ وَجَلَّ قَسَمْتُ الصَّلَاةَ بَيْنِي وَبَيْنَ عَبْدِي نِصْفَيْنِ فَنِصْفُهَا لِي وَنِصْفُهَا لِعَبْدِي وَلِعَبْدِي مَا سَأَلَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَءُوا يَقُولُ الْعَبْدُ{ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ }يَقُولُ اللَّهُ عَزَّ وَجَلَّ حَمِدَنِي عَبْدِي يَقُولُ الْعَبْدُ{ الرَّحْمَنِ الرَّحِيمِ }يَقُولُ اللَّهُ عَزَّ وَجَلَّ أَثْنَى عَلَيَّ عَبْدِي يَقُولُ الْعَبْدُ{ مَالِكِ يَوْمِ الدِّينِ }يَقُولُ اللَّهُ عَزَّ وَجَلَّ مَجَّدَنِي عَبْدِي يَقُولُ الْعَبْدُ{ إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ }فَهَذِهِ الْآيَةُ بَيْنِي وَبَيْنَ عَبْدِي وَلِعَبْدِي مَا سَأَلَ يَقُولُ الْعَبْدُ{ اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَهَؤُلَاءِ لِعَبْدِي وَلِعَبْدِي مَا سَأَلَ","id":"(Masih dari hadits sebelumnya). Lalu aku bertanya, \"Wahai [Abu Hurairah]! Aku kadang shalat di belakang imam?\" lalu menarik tanganku sambil berkata, \"Wahai Farisi, bacalah dalam hatimu (dengan lirih), karena aku mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: 'Allah Azza wa Jalla berfirman: \"Aku membagi shalat antara Aku dan hamba-Ku menjadi dua bagian, sebagian untuk-Ku dan sebagian lagi untuk hamha-Ku, untuk hamba-Ku apa yang dia minta.\" Rasulullah Shallallahu'alaihi wasallam bersabda: 'Bacalah -apabila- seorang hamba mengucapkan \"Alhumdulillaah rabbil 'aalamiin (Segala puji bagi Allah, Rabb semesta alam \" maka Allah berfirman, \"Hamba-Ku telah memuji-Ku.\" Apabila hamba tersebut mengucapkan, \"Arrahmaanirrahiim (Maha Pengasih lagi Maha Penyayang) \" maka Allah Azza wa Jalla berfirman, \"Hamba-Ku telah menyanjung-Ku.\"Apabila hamba tadi mengucapkan.\"Maaliki yaumiddiin (Dia penguasa hari Pembalasan) \" maka Allah Azza wa Jalla berfirman, \"Hamba-Ku telah meluhurkan-Ku.\"Apabila hamba itu meneruskan bacaannya, \"lyyaaka na'budu wa iyyaaka nasta'iin (Hanya kepada Engkau kami beribadah dan hanya kepada Engkau kami meminta pertolongan) \" maka ayat tersebut adalah antara Allah dan hamba-Nya. Bagi hamba-Nya apa yang dia minta.\"Apabila hamba tadi melanjutkan bacaannya, \"Ihdinash-shiraathal mustaqiim, shiraathal-ladzina an'amta 'alaihim ghairil maghdhuubi 'alaihim waladh-dhaalliin (Tunjukilah kami jalan yang lurus, yakni jalannya orang-orang yang Engkau beri petunjuk, bukan jalannya orang-orang yang dimurkai dan bukan jalannya orang-orang yang sesat) \" maka itu semua untuk hamba-Ku dan bagi hamba-Ku apa yang ia minta'.\""},"900":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِفَاتِحَةِ الْكِتَابِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dari [Az Zuhri] dari [Mahmud bin Ar Rabi'] dari ['Ubadah bin Ash Shamit] dari Nabi Shallallahu'alaihi wasallam, beliau Shallallallahu'alaihi wasallam bersabda: \"Tidak sah shalat seseorang yang tidak membaca Al Fatihah.\""},"901":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ لِمَنْ لَمْ يَقْرَأْ بِفَاتِحَةِ الْكِتَابِ فَصَاعِدًا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ma'mar] dari [Az Zuhri] dari [Mahmud bin Ar Rabi'] dari ['Ubadah bin Ash Shamit] dia berkata; bahwa Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Tidak sah shalat seseorang yang tidak membaca Al Fatihah dan seterusnya\""},"902":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَمَّارِ بْنِ رُزَيْقٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ جِبْرِيلُ عَلَيْهِ السَّلَام إِذْ سَمِعَ نَقِيضًا فَوْقَهُ فَرَفَعَ جِبْرِيلُ عَلَيْهِ السَّلَام بَصَرَهُ إِلَى السَّمَاءِ فَقَالَ هَذَا بَابٌ قَدْ فُتِحَ مِنْ السَّمَاءِ مَا فُتِحَ قَطُّ قَالَ فَنَزَلَ مِنْهُ مَلَكٌ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبْشِرْ بِنُورَيْنِ أُوتِيتَهُمَا لَمْ يُؤْتَهُمَا نَبِيٌّ قَبْلَكَ فَاتِحَةِ الْكِتَابِ وَخَوَاتِيمِ سُورَةِ الْبَقَرَةِ لَمْ تَقْرَأْ حَرْفًا مِنْهُمَا إِلَّا أُعْطِيتَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak Al Mukharrimi] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari ['Ammar bin Ruzaiq] dari [Abdullah bin 'Isa] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; \"Tatkala Rasulullah Shallallallahu'alaihi wasallam bersama malaikat Jibril, tiba-tiba beliau mendengar suara dari atasnya, maka Jibril mengangkat pandangannya ke langit, kemudian berkata, 'Pintu ini telah dibuka dari langit, yang sebelumnya belum pernah dibuka'.\" Ibnu Abbasn berkata; \"Lalu turun malaikat dan datang kepada Nabi Shallallahu'alaihi wasallam, lantas berkata. 'Berbahagialah dengan dua cahaya yang diberikan kepadamu, dan dua cahaya tersebut belum pernah diberikan kepada seorang nabi shallallahu 'alaihi wasallam pun sebelummu, yakni: Fatihah Al Kitab dan akhir surat Al Baqarah. Kamu tidak membaca satu hurufpun dari keduanya kecuali kamu pasti akan diberi'.\""},"903":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ حَفْصَ بْنَ عَاصِمٍ يُحَدِّثُ عَنْ أَبِي سَعِيدِ بْنِ الْمُعَلَّىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يُصَلِّي فَدَعَاهُ قَالَ فَصَلَّيْتُ ثُمَّ أَتَيْتُهُ فَقَالَ مَا مَنَعَكَ أَنْ تُجِيبَنِي قَالَ كُنْتُ أُصَلِّي قَالَ أَلَمْ يَقُلْ اللَّهُ عَزَّ وَجَلَّ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اسْتَجِيبُوا لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ لِمَا يُحْيِيكُمْ }أَلَا أُعَلِّمُكَ أَعْظَمَ سُورَةٍ قَبْلَ أَنْ أَخْرُجَ مِنْ الْمَسْجِدِ قَالَ فَذَهَبَ لِيَخْرُجَ قُلْتُ يَا رَسُولَ اللَّهِ قَوْلَكَ قَالَ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ هِيَ السَّبْعُ الْمَثَانِي الَّذِي أُوتِيتُ وَالْقُرْآنُ الْعَظِيمُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin 'Abdurrahman] dia berkata; aku mendengar [Hafsh bin 'Ashim] menceritakan dari [Abu Sa'id bin Al Mu'alla] bahwasanya bahwa Nabi Shallallallahu'alaihi wasallam pernah melewatinya ketika dia sedang shalat, lalu beliau Shallallallahu'alaihi wasallam memanggilnya. Abu Said berkata, \"Aku tadi sedang shalat.\" Lantas aku mendatangi beliau Shallallahu'alaihi wasallam. Beliau Shallallallahu'alaihi wasallam bertanya, \"Apakah yang menghalangimu untuk menjawabku?\" Aku menjawab, \"Aku tadi sedang shalat.\" Beliau Shallallallahu'alaihi wasallam bersabda: \"Bukankah Allah Azza wa Julla berfirman: 'Wahai orang-orang yang beriman penuhilah seruan Allah dan Rasul jika menyeru kamu kepada suatu yang memberi kehidupan kepada kamu (Qs. Al Anfaal (8): 24) '. Maukah kalian aku ajarkan tentang surat yang paling agung sebelum aku keluar dari masjid?\" Lalu Abu Sa'id berkata; \"Lalu Rasulullah Shallallallahu'alaihi wasallam pergi keluar masjid, dan aku berkata, 'Wahai Rasulullah Shallallahu'alaihiwasallam, mana sabdamu? ' Beliau Shallallallahu'alaihi wasallam bersabda: 'Alhamdulillah rabbil 'aalamiin (Segala puji bagi Allah. Rabb semesta alam) adalah sab 'ul matsani yang diberikan kepadaku, juga Al Qur 'an Al 'Azhim'.'"},"904":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِي التَّوْرَاةِ وَلَا فِي الْإِنْجِيلِ مِثْلَ أُمِّ الْقُرْآنِ وَهِيَ السَّبْعُ الْمَثَانِي وَهِيَ مَقْسُومَةٌ بَيْنِي وَبَيْنَ عَبْدِي وَلِعَبْدِي مَا سَأَلَ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] dia berkata; telah menceritakan kepada kami [Al Fadhl bin Musa] dari ['Abdul Humaid bin Ja'far] dari [Al 'Alaa bin 'Abdurrahman] dari [bapaknya] dari [Abu Hurairah] dari [Ubay bin Ka'b] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Tidaklah Allah Azza wa Jalla menurunkan dalam Taurat dan Injil seperti Ummul Qur'an. yaitu Sab 'ul Matsani, yang terbagi antara Allah dengan hamba-Nya, bagi hamba-Nya apa yang ia minta '.\""},"905":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَأُوتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعًا مِنْ الْمَثَانِي السَّبْعَ الطُّوَلَ","id":"Telah mengabarkan kepadaku [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Muslim] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; \"Nabi Shallallallahu'alaihi wasallam diberi tujuh (ayat) yang dibaca berulang-ulang, tujuh (surat) yang panjang.\""},"906":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ سَبْعًا مِنْ الْمَثَانِي }قَالَ السَّبْعُ الطُّوَلُ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] mengenai firman Allah Azza wa Jalla 'Sab'u minal Matsani', dia berkata; yaitu tujuh (surah) yang panjang."},"907":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَقَرَأَ رَجُلٌ خَلْفَهُ سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى فَلَمَّا صَلَّى قَالَ مَنْ قَرَأَ سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى قَالَ رَجُلٌ أَنَا قَالَ قَدْ عَلِمْتُ أَنَّ بَعْضَكُمْ قَدْ خَالَجَنِيهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Zurarah] dari ['Imran bin Hushain] dia berkata; \"Nabi Shallallallahu'alaihi wasallam shalat Zhuhur, dan di belakangnya ada seorang laki-laki yang membaca; 'Sabbihisma rabbikal a'laa'. Setelah selesai shalat Nabi Shallallallahu'alaihi wasallam bertanya: 'Siapa tadi yang membaca. 'Sabbihisma rabbikal a'laa? ' Seorang laki-laki berkata, 'Aku'. Nabi Shallallallahu'alaihi wasallam bersabda, 'Aku sudah tahu bahwa sebagian kalian telah menyelisihiku dengan bacaannya'.\""},"908":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةَ الظُّهْرِ أَوْ الْعَصْرِ وَرَجُلٌ يَقْرَأُ خَلْفَهُ فَلَمَّا انْصَرَفَ قَالَ أَيُّكُمْ قَرَأَ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَنَا وَلَمْ أُرِدْ بِهَا إِلَّا الْخَيْرَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ عَرَفْتُ أَنَّ بَعْضَكُمْ قَدْ خَالَجَنِيهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Zurarah bin Aufa] dari ['Imran bin Hushain] bahwa ketika Nabi Shallallallahu'alaihi wasallam shalat Zhuhur atau Ashar pernah ada seorang laki-laki di belakangnya yang membaca bacaan surat, dan setelah selesai shalat Nabi Shallallallahu'alaihi wasallam bertanya, \"Siapa tadi yang membaca, 'Sabbihisma rabhikal a'laa? '\" Seorang laki-laki menjawab, \"Aku. Aku melakukannya karena menginginkan kebaikan!\" Nabi Shallallallahu'alaihi wasallam bersabda: \"Aku sudah tahu bahwa sebagian kalian telah menyelisihiku dengan bacaannya.\""},"909":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ أُكَيْمَةَ اللَّيْثِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ مِنْ صَلَاةٍ جَهَرَ فِيهَا بِالْقِرَاءَةِ فَقَالَ هَلْ قَرَأَ مَعِي أَحَدٌ مِنْكُمْ آنِفًا قَالَ رَجُلٌ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ إِنِّي أَقُولُ مَا لِي أُنَازَعُ الْقُرْآنَ قَالَ فَانْتَهَى النَّاسُ عَنْ الْقِرَاءَةِ فِيمَا جَهَرَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقِرَاءَةِ مِنْ الصَّلَاةِ حِينَ سَمِعُوا ذَلِكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Ibnu Ukaimah Al Laitsi] dari [Abu Hurairah] bahwa Rasulullah Shallallallahu'alaihi wasallam setelah shalat yang bacaannya diperdengarkan, beliau bersabda: \"Apakah tadi ada salah seorang dari kalian yang ikut membaca ayat Al Qur'an bersamaku?\" Seorang laki-laki menjawab.\"Ya, wahai Rasulullah Shallallahu'alaihi wasallam!\" Rasulullah Shallallallahu'alaihi wasallam lalu bersabda: \"Aku mengatakan bahwa kalian jangan menyelisihiku dalam bacaan Al Qur'an?!\" Abu Hurairah berkata; \"Setelah mendengar sabda Nabi tersebut orang-orang tidak membaca Al Qur'an lagi pada shalat yang Rasulullah Shallallallahu'alaihi wasallam mengeraskan bacaannya.\" "},"910":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ عَنْ صَدَقَةَ عَنْ زَيْدِ بْنِ وَاقِدٍ عَنْ حَرَامِ بْنِ حَكِيمٍ عَنْ نَافِعِ بْنِ مَحْمُودِ بْنِ رَبِيعَةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْضَ الصَّلَوَاتِ الَّتِي يُجْهَرُ فِيهَا بِالْقِرَاءَةِ فَقَالَ لَا يَقْرَأَنَّ أَحَدٌ مِنْكُمْ إِذَا جَهَرْتُ بِالْقِرَاءَةِ إِلَّا بِأُمِّ الْقُرْآنِ","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar] dari [Shadaqah] dari [Zaid bin Waqid] dari [Haram bin Hakim] dari [Nafi' bin Mahmud bin Rabi'ah] dari ['Ubadah bin Ash Shamit] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam shalat bersama kami di sebagian shalat yang dibaca jahr (terdengar suaranya), lalu beliau bersabda: \"Janganlah sekali-kali kalian membaca surat, ketika aku memperdengarkan bacaanku dalam shalat, kecuali surat Al Fatihah.\" "},"911":{"ar":"أَخْبَرَنَا الْجَارُودُ بْنُ مُعَاذٍ التِّرْمِذِيُّ قَالَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا قَرَأَ فَأَنْصِتُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ","id":"Telah mengabarkan kepada kami [Al Jarud bin Mu'adz At-Tirmidzi] dia berkata; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Muhammad bin 'Ajlan] dari [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; bahwa Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Yang dijadikan imam adalah untuk diikuti. Maka bila ia bertakbir maka bertakbirlah kalian dan jika ia sedang membaca (Al Qur'an) maka diamlah. Bila dia mengucapkan, 'Sami 'alluhu liman hamidah (Allah Maha Mendengar terhadap semua yang memuji-Nya) ' maka ucapkan, 'Allahumma rabbana lakal hamdu (Ya Allah Tuhan kami, segala puji untuk-Mu) '.\""},"912":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَعْدٍ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا قَرَأَ فَأَنْصِتُواقَالَ أَبُو عَبْد الرَّحْمَنِ كَانَ الْمُخَرِّمِيُّ يَقُولُ هُوَ ثِقَةٌ يَعْنِي مُحَمَّدَ بْنَ سَعْدٍ الْأَنْصَارِيَّ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Muhammad bin Sa'd Al Anshari] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Ajlan] dari [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah] berkata; Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Imam dijadikan untuk diikuti, apabila ia bertakbir maka bertakbirlah kalian dan jika ia sedang membaca (Al Qur'an) maka diamlah.\" Abu Abdurrahman berkata; Al Makhrami berkata; Muhammad bin Sa'ad Al Anshari orangnya tsiqah (terpercaya)."},"913":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ قَالَ حَدَّثَنِي أَبُو الزَّاهِرِيَّةِ قَالَ حَدَّثَنِي كَثِيرُ بْنُ مُرَّةَ الْحَضْرَمِيُّ عَنْ أَبِي الدَّرْدَاءِ سَمِعَهُ يَقُولُسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفِي كُلِّ صَلَاةٍ قِرَاءَةٌ قَالَ نَعَمْ قَالَ رَجُلٌ مِنْ الْأَنْصَارِ وَجَبَتْ هَذِهِ فَالْتَفَتَ إِلَيَّ وَكُنْتُ أَقْرَبَ الْقَوْمِ مِنْهُ فَقَالَ مَا أَرَى الْإِمَامَ إِذَا أَمَّ الْقَوْمَ إِلَّا قَدْ كَفَاهُمْقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَأٌ إِنَّمَا هُوَ قَوْلُ أَبِي الدَّرْدَاءِ وَلَمْ يُقْرَأْ هَذَا مَعَ الْكِتَابِ","id":"Telah mengabarkan kepadaku [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] dia berkata; telah menceritakan kepada kami [Mu'awiyah bin Shalih] dia berkata; telah menceritakan kepada kami [Abu Az Zahiriyyah] dia berkata; telah menceritakan kepada kami [Katsir bin Murrah Al Hadhrami] dari [Abu Ad Darda'] dia mendengarnya berkata; \"Rasulullah Shallallallahu'alaihi wasallam pernah ditanya, 'Apakah setiap shalat ada bacaannya? ' Beliau Shallallallahu'alaihi wasallam menjawab, 'Ya. Seorang laki-laki Anshar lalu berkata, 'Apakah itu wajib? ' Rasulullah Shallallallahu'alaihi wasallam menoleh kepadaku - aku orang yang paling dekat dengannya - dan bersabda: 'Aku berpendapat bahwa bila imam mengimami shalat pada suatu kaum maka imam tersebut telah mencukupi mereka (makmum) '.\" Abu Abdurrahman berkata; 'Yang mengatakan ini adalah ucapan Rasulullah Shallallallahu'alaihi wasallam adalah salah, sebab itu sekedar ucapan Abu Darda dan dia (yang mengatakan) tidak membaca bukunya.'"},"914":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ عِيسَى وَمَحْمُودُ بْنُ غَيْلَانَ عَنْ الْفَضْلِ بْنِ مُوسَى قَالَ حَدَّثَنَا مِسْعَرٌ عَنْ إِبْرَاهِيمَ السَّكْسَكِيِّ عَنْ ابْنِ أَبِي أَوْفَى قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي لَا أَسْتَطِيعُ أَنْ آخُذَ شَيْئًا مِنْ الْقُرْآنِ فَعَلِّمْنِي شَيْئًا يُجْزِئُنِي مِنْ الْقُرْآنِ فَقَالَ قُلْ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ","id":"Telah mengabarkan kepada kami [Yusuf bin 'Isa] dan [Mahmud bin Ghailan] dari [Al Fadhl bin Musa] dia berkata; telah menceritakan kepada kami [Mis'ar] dari [Ibrahim As-Saksaki] dari [Ibnu Abu Aufa] dia berkata; \"Ada seorang laki-laki datang kepada Nabi Shallallahu'alaihi wasallam, lantas dia berkata, 'Aku tidak mampu membaca apa pun dari Al Qur'an, maka ajarilah aku beberapa ayat Al Qur'an yang mencukupiku! ' Lantas beliau Shallallallahu'alaihi wasallam bersabda: 'Ucapkanlah, \"Subhanallah, walhamdulillah, Walaa Ilaaha Illallallah, Waallahu Akbar, Walaa Haula Wala Quwwata Ilia billahi (Maha Suci Allah, segala puji bagi Allah, tiada Dzat yang berhak disembah selain Allah, Allah Maha Besar dan tiada daya dan kekuatan kecuali dengan pertolongan Allah).\""},"915":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ الزُّبَيْدِيِّ قَالَ أَخْبَرَنِي الزُّهْرِيُّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَّنَ الْقَارِئُ فَأَمِّنُوا فَإِنَّ الْمَلَائِكَةَ تُؤَمِّنُ فَمَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غَفَرَ اللَّهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman] dia berkata; telah menceritakan kepada kami [Baqiyyah] dari [Az Zubaidi] dia berkata; telah mengabarkan kepadaku [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Jika pembaca (imam) membaca, 'Aamiin ' maka ucapkanlah 'Aamiin ' karena para malaikat juga ikut mengucapkan, 'Aamiin'. Barang siapa bacaan aamiin-nya bersamaan dengan bacaan aamiin para malaikat, Allah mengampuni dosanya yang lewat.\""},"916":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَمَّنَ الْقَارِئُ فَأَمِّنُوا فَإِنَّ الْمَلَائِكَةَ تُؤَمِّنُ فَمَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Rasulullah Shallallahu'alaihi wasallam, beliau bersabda: \"Jika pembaca (imam) membaca aamiin, maka ucapkanlah aamiin, karena para malaikat juga ikut mengucapkan aamiin. Barangsiapa bacaan aamiin-nya bersamaan dengan bacaan aamiin para malaikat, dosanya yang lalu diampuni.\""},"917":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنِي مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَالَ الْإِمَامُ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقُولُوا آمِينَ فَإِنَّ الْمَلَائِكَةَ تَقُولُ آمِينَ وَإِنَّ الْإِمَامَ يَقُولُ آمِينَ فَمَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepadaku [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dia berkata; Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Bila imam mengucapkan, 'Ghairil maghdhuubi 'alaihim walaadh-dhalliin (Bukan orang-orang yang dimurkai dan bukan orang-orang yang sesat) ' ucapkanlah, 'Aamiin', karena para malaikat juga mengucapkan, 'Aamiin ', juga imam mengucapkan, 'Aamiin'. Maka barangsiapa ucapan aamiin-nya bersamaan dengan bacaan aamiin para malaikat, dosa yang lalu diampuni.\""},"918":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ أَنَّهُمَا أَخْبَرَاهُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَمَّنَ الْإِمَامُ فَأَمِّنُوا فَإِنَّهُ مَنْ وَافَقَ تَأْمِينُهُ تَأْمِينَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Sa'id] dan [Abu Salamah] bahwasanya keduanya mengabarkan kepadanya, dari [Abu Hurairah] bahwa Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Jika imam mengucapkan aamiin, ucapkanlah aamiin. Barangsiapa ucapan aamiin-nya bersamaan dengan bacaan aamiin para malaikat, dosanya yang lalu diampuni.\""},"919":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }فَقُولُوا آمِينَ فَإِنَّهُ مَنْ وَافَقَ قَوْلُهُ قَوْلَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Sumayyi] dari [Abu Shalih] dari [Abu Hurairah] Radliyallahu'anhu bahwa Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Bila imam mengucapkan, 'Ghairil maghdhuubi 'alaihim walaadh-dhalliin (Bukan orang-orang yang dimurkai dan bukan orang-orang yang sesat) ' maka ucapkanlah, 'Aamiin', Barangsiapa ucapan aamiin-nya bersamaan dengan aamiin para malaikat, dosanya yang lalu diampuni.\""},"920":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ أَحَدُكُمْ آمِينَ وَقَالَتْ الْمَلَائِكَةُ فِي السَّمَاءِ آمِينَ فَوَافَقَتْ إِحْدَاهُمَا الْأُخْرَى غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Jika salah seorang dari kalian mengucapkan aamiin dan para malaikat di langit juga mengucapkan aamiin, lalu bacaan aamiin-nya bersamaan antara satu dengan lainnya (antara manusia dan malaikat), dosanya yang lalu diampuni.\""},"921":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا رِفَاعَةُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ عَمِّ أَبِيهِ مُعَاذِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ أَبِيهِ قَالَصَلَّيْتُ خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَطَسْتُ فَقُلْتُ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ مُبَارَكًا عَلَيْهِ كَمَا يُحِبُّ رَبُّنَا وَيَرْضَى فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ فَقَالَ مَنْ الْمُتَكَلِّمُ فِي الصَّلَاةِ فَلَمْ يُكَلِّمْهُ أَحَدٌ ثُمَّ قَالَهَا الثَّانِيَةَ مَنْ الْمُتَكَلِّمُ فِي الصَّلَاةِ فَقَالَ رِفَاعَةُ بْنُ رَافِعِ ابْنِ عَفْرَاءَ أَنَا يَا رَسُولَ اللَّهِ قَالَ كَيْفَ قُلْتَ قَالَ قُلْتُ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ مُبَارَكًا عَلَيْهِ كَمَا يُحِبُّ رَبُّنَا وَيَرْضَى فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ ابْتَدَرَهَا بِضْعَةٌ وَثَلَاثُونَ مَلَكًا أَيُّهُمْ يَصْعَدُ بِهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Rifa'ah bin Yahya bin Abdullah bin Rifa'ah bin Rafi'] dari paman bapaknya [Mu'adz bin Rifa'ah bin Rafi'] dari [Bapaknya] dia berkata; \"Aku shalat di belakang Rasulullah Shallallahu'alaihi wasallam. Lalu aku bersin dan mengucapkan, 'Alhamdulillah hamdan katsiran thayyiban mubarakan fiih mubarakan 'alaih kamaa yuhibbu rabbuna wayardhaa (Allah Maha Besar, segala puji bagi Allah dengan pujian yang banyak serta baik dan diberkahi, keberkahan yang sebagaimana dicintai dan diridhai oleh Rabb kami) '. Setelah Rasulullah Shallallallahu'alaihi wasallam selesai dari shalatnya, beliau bertanya: 'Siapa yang berbicara saat shalat? ' Maka tidak ada seorangpun yang berbicara. Lalu beliau Shallallallahu'alaihi wasallam mengulangi untuk kedua kalinya, 'Siapa yang berbicara saat shalat? ' Rifa'ah bin Raff bin Afra' berkata; 'Aku wahai Rasulullah Shallallahu'alaihi wasallam'. Kemudian Rasulullah Shallallallahu'alaihi wasallam bertanya: 'Apa yang kamu ucapkan (dalam shalat)?\" la menjawab; 'Aku mengucapkan, 'Alhamdulillah hamdan katsiran thayyibun mubaarakan fiih mubaarakan 'alaih kamaa yuhibbu rabbuna wayardhaa (Allah Maha Besar, segala puji bagi Allah dengan pujian yang banyak serta baik dan diberkahi, keberkahan yang sebagaimana dicintai dan diridhai oleh Rabb kami).' Rasulullah Shallallallahu'alaihi wasallam lalu bersabda: 'Demi Dzat yang jiwaku ada di tangan-Nya, sungguh, lebih dari tiga puluh malaikat berebut untuk membawa naik (bacaan itu) '.\""},"922":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِيهِ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا كَبَّرَ رَفَعَ يَدَيْهِ أَسْفَلَ مِنْ أُذُنَيْهِ فَلَمَّا قَرَأَ{ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ }قَالَ آمِينَ فَسَمِعْتُهُ وَأَنَا خَلْفَهُ قَالَ فَسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَقُولُ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا سَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ صَلَاتِهِ قَالَ مَنْ صَاحِبُ الْكَلِمَةِ فِي الصَّلَاةِ فَقَالَ الرَّجُلُ أَنَا يَا رَسُولَ اللَّهِ وَمَا أَرَدْتُ بِهَا بَأْسًا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ ابْتَدَرَهَا اثْنَا عَشَرَ مَلَكًا فَمَا نَهْنَهَهَا شَيْءٌ دُونَ الْعَرْشِ","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad] dia berkata; Telah menceritakan kepada kami [Makhlad] dia berkata; Telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Bapaknya] dari [Abdul Jabar bin Wa'il] dari [Bapaknya] dia berkata; \"Aku pernah shalat di belakang Rasulullah Shallallahu'alaihi wasallam, dan tatkala bertakbir beliau mengangkat kedua tangannya di bawah telinganya. Setelah membaca, 'Ghairil maghdhuubi 'alaihim waladldlaalliin (Bukan orang-orang yang dimurkai dan bukan orang-orang yang sesat) ' ia berkata, 'Aamiin '. Aku mendengarnya karena aku berada di belakangnya.\" la (Wa'il) mengatakan bahwa Rasulullah Shallallallahu'alaihi wasallam mendengar seseorang mengucapkan alhamdulillaahi hamdan katsiiran thayyiban mubaarakan fiih (Allah Maha Besar. segala puji bagi Allah dengan pujian yang banyak serta mulia, dan diberkahi). Setelah Nabi Shallallallahu'alaihi wasallam mengucapkan salam dari shalatnya, beliau bersabda: \"Siapa yang mengucapkan suatu kalimat dalam shalat?\" Seorang laki-laki berkata, \"Aku, wahai Rasulullah Shallallahu'alaihi wasallam. Aku tidak menginginkan kejelekan dengan hal itu.\" Lalu Nabi Shallallallahu'alaihi wasallam bersabda: \"Kalimat tersebut diperebutkan oleh dua belas malaikat (untuk diangkat ke tempat diterima amalan), dan tidak ada yang menghalanginya kecuali 'Arsy.\""},"923":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْسَأَلَ الْحَارِثُ بْنُ هِشَامٍ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يَأْتِيكَ الْوَحْيُ قَالَ فِي مِثْلِ صَلْصَلَةِ الْجَرَسِ فَيَفْصِمُ عَنِّي وَقَدْ وَعَيْتُ عَنْهُ وَهُوَ أَشَدُّهُ عَلَيَّ وَأَحْيَانًا يَأْتِينِي فِي مِثْلِ صُورَةِ الْفَتَى فَيَنْبِذُهُ إِلَيَّ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] dia berkata; \"Harits bin Hisyam bertanya kepada Rasulullah Shallallahu'alaihi wasallam; Bagaimanakah wahyu datang kepada engkau? ' Rasulullah Shallallallahu'alaihi wasallam bersabda: 'Seperti dentang suara lonceng, lalu wahyu terputus dariku dan aku telah hafal (wahyu tersebut), dan kondisi seperti itu yang paling berat kurasakan. Kadang datang kepadaku dalam bentuk seorang pemuda, lalu ia memberikan wahyu kepadaku'.\""},"924":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ الْحَارِثَ بْنَ هِشَامٍ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يَأْتِيكَ الْوَحْيُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْيَانًا يَأْتِينِي فِي مِثْلِ صَلْصَلَةِ الْجَرَسِ وَهُوَ أَشَدُّهُ عَلَيَّ فَيَفْصِمُ عَنِّي وَقَدْ وَعَيْتُ مَا قَالَ وَأَحْيَانًا يَتَمَثَّلُ لِي الْمَلَكُ رَجُلًا فَيُكَلِّمُنِي فَأَعِي مَا يَقُولُ قَالَتْ عَائِشَةُ وَلَقَدْ رَأَيْتُهُ يَنْزِلُ عَلَيْهِ فِي الْيَوْمِ الشَّدِيدِ الْبَرْدِ فَيَفْصِمُ عَنْهُ وَإِنَّ جَبِينَهُ لَيَتَفَصَّدُ عَرَقًا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya, lafazhnya dari dia, dari [Ibnul Qasim] dia berkata; Telah menceritakan kepada ku [Malik] dari [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] dia berkata; \"Harits bin Hisyam bertanya kepada Rasulullah Shallallahu'alaihi wasallam, 'Bagaimanakah wahyu datang kepada engkau? ' Rasulullah Shallallallahu'alaihi wasallam bersabda: 'Kadang datang kepadaku seperti dentang suara lonceng, dan cara tersebut sangat berat kurasakan. Lalu wahyu tersebut terputus dan aku telah hafal (wahyu tersebut). Kadang malaikat datang kepadaku dalam bentuk seorang laki-laki; lalu berbicara denganku, dan aku hapal apa yang ia katakan (wahyu). Aisyah berkata.\"Aku pernah melihatnya ketika wahyu turun kepadanya pada hari yang sangat dingin sekali, dan saat wahyu terputus dari beliau dahi beliau mengalirkan keringat.\""},"925":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مُوسَى بْنِ أَبِي عَائِشَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ إِنَّ عَلَيْنَا جَمْعَهُ وَقُرْآنَهُ }قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَالِجُ مِنْ التَّنْزِيلِ شِدَّةً وَكَانَ يُحَرِّكُ شَفَتَيْهِ قَالَ اللَّهُ عَزَّ وَجَلَّ{ لَا تُحَرِّكْ بِهِ لِسَانَكَ لِتَعْجَلَ بِهِ إِنَّ عَلَيْنَا جَمْعَهُ وَقُرْآنَهُ }قَالَ جَمْعَهُ فِي صَدْرِكَ ثُمَّ تَقْرَؤُهُ{ فَإِذَا قَرَأْنَاهُ فَاتَّبِعْ قُرْآنَهُ }قَالَ فَاسْتَمِعْ لَهُ وَأَنْصِتْ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَاهُ جِبْرِيلُ اسْتَمَعَ فَإِذَا انْطَلَقَ قَرَأَهُ كَمَا أَقْرَأَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; Telah menceritakan kepada kami [Abu 'Awanah] dari [Musa bin Abu Aisyah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] tentang Firman Allah Azza wa Jalla; \"Janganlah kamu gerakkan lidahmu untuk (membaca) Al Qur'an karena hendak cepat-cepat (menguasai) nya Sesungguhnya atas tanggungan Kamilah mengumpulkannya (di dadamu) dan (membuatmu pandai) membacanya.\" (Qs. Al Qiyamah (75): 16-17) la mengatakan bahwa Rasulullah Shallallallahu'alaihi wasallam seringkali berusaha menguasai beban saat wahyu turun, dan beliau menggerakkan kedua bibirnya, lalu Allah Azza wa Jalla berfirman, \"Janganlah kamu gerakkan lidahmu untuk (membaca) Al Qur'an karena hendak cepat-cepat (menguasai) nya. Atas tanggungan Kamilah mengumpulkannya (di dadamu) dan (membuatmu pandai) membacanya\" (Qs. Al Qiyamah (75): 16-17). Ia berkata, \"Allah mengumpulkan Al Qur'an di dalam dadamu. Kemudian ia membaca.\"Apabila Kami telah selesai membacakannya maka ikutilah bacaannya itu.\" (Qs. Al Qiyamah (75): 18). Ia berkata, \"Maka dengarkan dan diamlah, -karena- Nabi Shallallallahu'alaihi wasallam bila didatangi Jibril maka beliau mendengarkannya, dan bila ia pergi maka Nabi Shallallallahu'alaihi wasallam sudah bisa membacanya sebagaimana yang dibacakan (diajarkan) Jibril.\""},"926":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ ابْنِ مَخْرَمَةَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ فَقَرَأَ فِيهَا حُرُوفًا لَمْ يَكُنْ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَنِيهَا قُلْتُ مَنْ أَقْرَأَكَ هَذِهِ السُّورَةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ كَذَبْتَ مَا هَكَذَا أَقْرَأَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذْتُ بِيَدِهِ أَقُودُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّكَ أَقْرَأْتَنِي سُورَةَ الْفُرْقَانِ وَإِنِّي سَمِعْتُ هَذَا يَقْرَأُ فِيهَا حُرُوفًا لَمْ تَكُنْ أَقْرَأْتَنِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ يَا هِشَامُ فَقَرَأَ كَمَا كَانَ يَقْرَأُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ اقْرَأْ يَا عُمَرُ فَقَرَأْتُ فَقَالَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ","id":"Telah mengabarkan kepada kami [Nashr bin Ali] dia berkata; Telah memberitakan kepada kami [Abdul A'la] dia berkata; Telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari [Ibnu Makhramah] bahwa [Umar bin Khatthab] Radliyallahu'anhu berkata; \"Aku mendengar Hisyam bin Hakim bin Hizam membaca surat Al Furqaan, ia membaca huruf-huruf yang tidak pernah dibaca oleh Nabi Shallallahu'alaihi wasallam. Aku berkata kepadanya; 'Siapakah yang membacakan surat ini kepadamu? ' la menjawab, 'Rasulullah Shallallahu'alaihi wasallam'. Aku berkata, 'Kamu dusta, Rasulullah Shallallallahu'alaihi wasallam tidak membacakan kepadamu seperti itu! ' Lalu aku pegang tangannya dan aku bawa dia kepada Rasulullah Shallallahu'alaihi wasallam, lalu aku berkata, 'Wahai Rasulullah Shallallahu'alaihi wasallam, sesungguhnya engkau membacakan surat Al Furqaan kepadaku, sedangkan aku tadi mendengar orang ini membaca huruf-huruf yang tidak pernah engkau bacakan kepadaku! Rasulullah Shallallallahu'alaihi wasallam lalu bersabda: 'Bacalah wahai Hisyam'. lapun membacanya seperti bacaannya (yang didengar oleh Umar), maka Rasulullah Shallallallahu'alaihi wasallam bersabda: 'Begitulah Al Qur'an diturunkan. Kemudian beliau berkata kepada Umar, 'Wahai Umar, bacalah'. Lalu akupun membacanya, kemudian Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Begitulah Al Qur'an diturunkan. Lalu beliau Shallallallahu'alaihi wasallam bersabda: 'Sesungguhnya Al Qur'an diturunkan dengan tujuh huruf (dialek) '.\""},"927":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ قَالَ سَمِعْتُ عُمَرَ ابْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَؤُهَا عَلَيْهِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَنِيهَا فَكِدْتُ أَنْ أَعْجَلَ عَلَيْهِ ثُمَّ أَمْهَلْتُهُ حَتَّى انْصَرَفَ ثُمَّ لَبَّبْتُهُ بِرِدَائِهِ فَجِئْتُ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَأْتَنِيهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ فَقَرَأَ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ يَقْرَأُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِيَ اقْرَأْ فَقَرَأْتُ فَقَالَ هَكَذَا أُنْزِلَتْ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarnya, lafazh ini dari dia, dari [Ibnu Al Qasim] dia berkata; Telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Urwah bin Zubair] dari [Abdurrahman bin Abdul Qari] dia berkata; Saya mendengar [Umar bin Khatthab] berkata; \"Aku mendengar Hisyam bin Hakim membaca surat Al Furqaan tidak sama dengan bacaanku yang diajarkan oleh Rasulullah Shallallallahu'alaihi wasallam kepadaku, hingga nyaris aku mencelanya. Namun aku membiarkannya hingga ia selesai membacanya, kemudian aku pegang kain serbannya. Lalu aku mengajaknya menghadap Rasulullah Shallallahu'alaihi wasallam, dan aku berkata kepada Rasulullah, 'Wahai Rasulullah, tadi aku mendengar orang ini membaca surat Al Furqaan tidak seperti yang engkau bacakan kepadaku'. Rasulullah Shallallallahu'alaihi wasallam bersabda kepada orang itu, 'Bacalah -surah itu-'. Hisyam lalu membaca seperti yang aku dengar saat ia membacanya. Lalu Rasulullah Shallallallahu'alaihi wasallam bersabda: 'Demikianlah surat itu diturunkan'. Kemudian beliau juga menyuruhku; maka akupun membacanya. Beliau lalu bersabda: 'Demikianlah surat itu diturunkan. Al Qur'an diturunkan dengan tujuh huruf (dialek), maka bacalah yang mudah bagimu'. "},"928":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ وَعَبْدَ الرَّحْمَنِ بْنَ عَبْدٍ الْقَارِيَّ أَخْبَرَاهُ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَمَعْتُ لِقِرَاءَتِهِ فَإِذَا هُوَ يَقْرَؤُهَا عَلَى حُرُوفٍ كَثِيرَةٍ لَمْ يُقْرِئْنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَتَصَبَّرْتُ حَتَّى سَلَّمَ فَلَمَّا سَلَّمَ لَبَّبْتُهُ بِرِدَائِهِ فَقُلْتُ مَنْ أَقْرَأَكَ هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ تَقْرَؤُهَا فَقَالَ أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ كَذَبْتَ فَوَاللَّهِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ أَقْرَأَنِي هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ تَقْرَؤُهَا فَانْطَلَقْتُ بِهِ أَقُودُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى حُرُوفٍ لَمْ تُقْرِئْنِيهَا وَأَنْتَ أَقْرَأْتَنِي سُورَةَ الْفُرْقَانِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْهُ يَا عُمَرُ اقْرَأْ يَا هِشَامُ فَقَرَأَ عَلَيْهِ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ يَقْرَؤُهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ يَا عُمَرُ فَقَرَأْتُ الْقِرَاءَةَ الَّتِي أَقْرَأَنِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] dia berkata; Telah menceritakan kepada kami [Ibnu Wahab] dia berkata; Telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku [Urwah bin Zubair] bahwa [Miswar bin Makhramah] dan [Abdurrahman bin Abdul Qari] keduanya telah mengabarkan kepadanya, bahwa keduanya telah mendengar [Umar bin Khatthab] berkata; \"Aku mendengar Hisyam bin Hakim membaca surat Al Furqaan pada masa hidup Rasulullah Shallallahu'alaihi wasallam, lalu aku perhatikan bacaannya. Maka aku dapati ia membacanya dengan dialek yang banyak (yang berbeda) dan bacaannya tidak sama dengan bacaan yang diajarkan oleh Rasulullah Shallallallahu'alaihi wasallam kepadaku. Aku hampir mencelanya ketika masih dalam shalat, namun aku bersabar hingga ia selesai shalat. Ketika selesai shalat, kain serbannya kupegang lalu kukatakan kepadanya; 'Siapakah yang membacakan kepadamu surat ini seperti yang kamu baca? ' la menjawab, 'Rasulullah Shallallallahu'alaihi wasallam membacakannya kepadaku'. Aku berkata, 'Kamu dusta. Demi Allah, Rasulullah Shallallallahu'alaihi wasallam telah membacakan surat ini, dan bacaannya tidak seperti yang kamu baca'. Kemudian aku mengajak dan menuntunnya menghadap Rasulullah Shallallahu'alaihi wasallam. Aku berkata kepada Rasulullah; 'Wahai Rasulullah, tadi aku mendengar orang ini membaca surat Al Furqaan dengan dialek yang tidak seperti engkau bacakan kepadaku! ' Rasulullah Shallallallahu'alaihi wasallam kemudian bersabda: 'Lepaskanlah dia wahai Umar. Bacalah wahai Hisyam! ' Hisyam lalu membacanya seperti yang kudengar sebelumnya. Lantas beliau bersabda: 'Begitulah Al Qur'an diturunkan.' Kemudian Rasulullah Shallallallahu'alaihi wasallam berkata: 'Wahai Umar, bacalah'. Lalu aku membacanya seperti yang Rasulullah Shallallallahu'alaihi wasallam bacakan kepadaku. Beliau Shallallallahu'alaihi wasallam lantas bersabda: 'Demikianlah surat itu diturunkan.' Al Qur'an diturunkan dengan tujuh huruf (dialek), maka bacalah yang mudah bagimu'.\""},"929":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَ أَضَاةِ بَنِي غِفَارٍ فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى حَرْفٍ قَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ وَإِنَّ أُمَّتِي لَا تُطِيقُ ذَلِكَ ثُمَّ أَتَاهُ الثَّانِيَةَ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى حَرْفَيْنِ قَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ وَإِنَّ أُمَّتِي لَا تُطِيقُ ذَلِكَ ثُمَّ جَاءَهُ الثَّالِثَةَ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى ثَلَاثَةِ أَحْرُفٍ فَقَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ وَإِنَّ أُمَّتِي لَا تُطِيقُ ذَلِكَ ثُمَّ جَاءَهُ الرَّابِعَةَ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَأْمُرُكَ أَنْ تُقْرِئَ أُمَّتَكَ الْقُرْآنَ عَلَى سَبْعَةِ أَحْرُفٍ فَأَيُّمَا حَرْفٍ قَرَءُوا عَلَيْهِ فَقَدْ أَصَابُواقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الْحَدِيثُ خُولِفَ فِيهِ الْحَكَمُ خَالَفَهُ مَنْصُورُ بْنُ الْمُعْتَمِرِ رَوَاهُ عَنْ مُجَاهِدٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ مُرْسَلًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah menceritakan kepada kami [Muhammad bin Ja'far Ghundar] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Mujahid] dari [Ibnu Abu Laila] dari [Ubay bin Ka'ab] bahwa Rasulullah Shallallallahu'alaihi wasallam berada di kolam milik Bani Ghifar, lalu Jibril Alaihissalam datang kepadanya dan berkata; \"Allah Azza wa Jalla menyuruhmu membacakan Al Qur'an kepada umatmu dengan satu huruf (dialek).\" Lalu Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Aku memohon kepada Allah untuk memberi keselamatan dan ampunan-Nya, sesungguhnya umatku tidak akan mampu melakukan hal itu!\" Kemudian malaikat Jibril datang lagi untuk kedua kalinya dan berkata: \"Allah Azza wa Jalla menyuruhmu membacakan Al Qur'an kepada umatmu dengan dua dialek.\" Lalu Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Aku memohon Allah untuk memberi keselamatan dan ampunan-Nya, sesungguhnya umatku tidak akan mampu melakukan hal itu!\" Kemudian malaikat Jibril datang lagi untuk ketiga kalinya dan berkata; \"Allah Azza wa Jalla menyuruhmu membacakan Al Qur'an kepada umatmu dengan tiga dialek.\" Lalu Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Aku memohon Allah untuk memberi keselamatan dan ampunan-Nya, sesungguhnya umatku tidak akan mampu melakukan hal itu\" Kemudian malaikat Jibril datang lagi untuk keempat kalinya dan berkata, \"Allah Azza wa Jalla menyuruhmu membacakan Al Qur'an kepada umatmu dengan tujuh dialek. Jadi jika mereka membaca Al Qur'an dengan dialek mana saja dari tujuh huruf (dialek) yang ada, ia benar.\" Abu Abdurrahman berkata; ' hadis ini di selisihi oleh Al Hakam dan Manshur bin Al Mu'tamir dia telah meriwayatkan dari Mujahid dari Ubaid bin Amir secara mursal."},"930":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو جَعْفَرِ بْنُ نُفَيْلٍ قَالَ قَرَأْتُ عَلَى مَعْقِلِ بْنِ عُبَيْدِ اللَّهِ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَأَقْرَأَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُورَةً فَبَيْنَا أَنَا فِي الْمَسْجِدِ جَالِسٌ إِذْ سَمِعْتُ رَجُلًا يَقْرَؤُهَا يُخَالِفُ قِرَاءَتِي فَقُلْتُ لَهُ مَنْ عَلَّمَكَ هَذِهِ السُّورَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَا تُفَارِقْنِي حَتَّى نَأْتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ هَذَا خَالَفَ قِرَاءَتِي فِي السُّورَةِ الَّتِي عَلَّمْتَنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ يَا أُبَيُّ فَقَرَأْتُهَا فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسَنْتَ ثُمَّ قَالَ لِلرَّجُلِ اقْرَأْ فَقَرَأَ فَخَالَفَ قِرَاءَتِي فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسَنْتَ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أُبَيُّ إِنَّهُ أُنْزِلَ الْقُرْآنُ عَلَى سَبْعَةِ أَحْرُفٍ كُلُّهُنَّ شَافٍ كَافٍقَالَ أَبُو عَبْد الرَّحْمَنِ مَعْقِلُ بْنُ عُبَيْدِ اللَّهِ لَيْسَ بِذَلِكَ الْقَوِيِّ","id":"Telah mengabarkan kepadaku [Amr bin Manshur] dia berkata; Telah menceritakan kepada kami [Abu Ja'far bin Nufail] dia berkata; Saya telah membacakan kepada [Ma'qil bin Ubaidullah] dari [Ikrimah bin Khalid] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ubay bin Ka'ab] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam pernah membacakan suatu surat kepadaku, dan tatkala aku sedang duduk di masjid tiba-tiba aku mendengar seorang lelaki membaca dengan bacaan yang berbeda dengan bacaanku, maka aku bertanya kepadanya, Siapa yang mengajari bacaan surat ini? ' ia menjawab, 'Rasulullah Shallallahu'alaihi wasallam\". Aku lalu berkata: 'Jangan pergi dariku hingga kita datang kepada Rasulullah Shallallahu'alaihi wasallam\". Lalu aku mendatangi Rasulullah dan berkata, 'Wahai Rasulullah Shallallahu'alaihi wasallam, orang ini membaca sebuah surat dengan bacaan yang berbeda dengan bacaan yang engkau ajarkan kepadaku'. Kemudian beliau Shallallallahu'alaihi wasallam bersabda: 'Wahai Ubay, bacalah'. Lalu akupun membacanya. Rasulullah Shallallallahu'alaihi wasallam bersabda kepadaku, 'Bacaanmu baik. Kemudian beliau Shallallallahu'alaihi wasallam bersabda kepada laki-laki tersebut, 'Bacalah'. lapun membacanya dan beliau Shallallallahu'alaihi wasallam bersabda kepada laki-laki tersebut, 'Bacaanmu baik. Lalu beliau bersabda; 'Wahai Ubay, Al Qur'an diturunkan dengan tujuh huruf (dialek), dan semuanya benar dan mencukupi'.\" Abu Abdurrahman berkata; Ma'qil bin Ubaidullah orangnya lemah."},"931":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ صَاحِبِ الْقُرْآنِ كَمَثَلِ الْإِبِلِ الْمُعَقَّلَةِ إِذَا عَاهَدَ عَلَيْهَا أَمْسَكَهَا وَإِنْ أَطْلَقَهَا ذَهَبَتْ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibnu Umar] Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Perumpamaan pembawa (orang yang membaca) Al Qur'an laksana unta yang diikat; bila ia menjaganya maka ia dapat menahan (hapalan) nya dan bila ia melepaskannya maka (hapalannya) akan hilang.\""},"932":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بِئْسَمَا لِأَحَدِهِمْ أَنْ يَقُولَ نَسِيتُ آيَةَ كَيْتَ وَكَيْتَ بَلْ هُوَ نُسِّيَ اسْتَذْكِرُوا الْقُرْآنَ فَإِنَّهُ أَسْرَعُ تَفَصِّيًا مِنْ صُدُورِ الرِّجَالِ مِنْ النَّعَمِ مِنْ عُقُلِهِ","id":"Telah mengabarkan kepada kami [Imran bin Musa] dia berkata; Telah menceritakan kepada kami [Yazid bin Zura'i] dia berkata; Telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Wa'il] dari [Abdullah] dari Nabi Shallallahu'alaihi wasallam, beliau bersabda: \"Alangkah buruknya seorang dari mereka yang berkata, 'Aku lupa ayat ini dan itu '. Bahkan melupakannya. Jagalah Al Qur'an dan sesungguhnya Al Qur'an lebih cepat lepasnya (lupa) dari dada manusia dibandingkan, dengan unta yang lepas dari ikatannya.\""},"933":{"ar":"أَخْبَرَنِي عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ قَالَ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا الْآيَةَ الَّتِي فِي الْبَقَرَةِ{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }إِلَى آخِرِ الْآيَةِ وَفِي الْأُخْرَى{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","id":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] dia berkata; Telah menceritakan kepada kami [Utsman bin Hakim] dia berkata; Telah mengabarkan kepadaku [Sa'id bin Yasar] bahwa [Ibnu Abbas] Telah mengabarkan kepadanya, Rasulullah Shallallallahu'alaihi wasallam membaca (ayat) pada dua rakaat shalat Subuh. Pada rakaat pertama beliau membaca ayat dalam surat Al Baqarah, \"Katakanlah (Hai orang-orang mukmin), 'Kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" (Qs. Al Baqarah (2): 136) sampai akhir ayat tersebut, sedangkan pada rakaat kedua beliau membaca, \"Kami telah beriman dan saksikanlah (wahai rasul) bahwa sesungguhnya kami adalah orang-orang yang patut (kepada seruanmu) (Qs. Al Maa'idah (5): 111).\""},"934":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ دُحَيْمٌ قَالَ حَدَّثَنَا مَرْوَانُ قَالَ حَدَّثَنَا يَزِيدُ بْنُ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ فِي رَكْعَتَيْ الْفَجْرِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah mengabarkan kepada kami [Abdurrahman bin Ibrahim Duhaim] dia berkata; Telah menceritakan kepada kami [Marwan] dia berkata; Telah menceritakan kepada kami [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] bahwa Rasulullah Shallallallahu'alaihi wasallam saat membaca qul yaa ayyuhal kaafiruun (Katakanlah wahai Muhammad, wahai orang-orang kafir) -maksudnya surat alkafirun--dan qul huwallaahu ahad (Katakanlah wahai Muhammad bahwa Allah itu satu) -maksudnya surat ikhlas--pada dua rakaat (sunah) fajar."},"935":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْإِنْ كُنْتُ لَأَرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي رَكْعَتَيْ الْفَجْرِ فَيُخَفِّفُهُمَا حَتَّى أَقُولَ أَقَرَأَ فِيهِمَا بِأُمِّ الْكِتَابِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Jarir] dari [Yahya bin Sa'id] dari [Muhammad bin Abdurrahman] dari ['Amrah] dari [Aisyah] dia berkata; \"Aku pernah melihat Rasulullah Shallallallahu'alaihi wasallam shalat (sunah) Fajar dua rakaat dengan ringan (cepat), sehingga aku bertanya-tanya, 'Apakah beliau Shallallallahu'alaihi wasallam (hanya) membaca Fatihah pada dua rakaat tersebut?.\" "},"936":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ شَبِيبٍ أَبِي رَوْحٍ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى صَلَاةَ الصُّبْحِ فَقَرَأَ الرُّومَ فَالْتَبَسَ عَلَيْهِ فَلَمَّا صَلَّى قَالَ مَا بَالُ أَقْوَامٍ يُصَلُّونَ مَعَنَا لَا يُحْسِنُونَ الطُّهُورَ فَإِنَّمَا يَلْبِسُ عَلَيْنَا الْقُرْآنَ أُولَئِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah menceritakan kepada kami [Abdurrahman] dia berkata; Telah memberitakan kepada kami [Sufyan] dari [Abdul Malik bin Umair] dari [Syabib Abu Rauh] dari [salah seorang sahabat] Rasulullah Shallallahu'alaihi wasallam, dari Nabi Shallallahu'alaihi wasallam, bahwa beliau Shallallallahu'alaihi wasallam pernah shalat Subuh dengan membaca surat Ar Ruum, lalu bacaan beliau bercampur dengan lainnya. Setelah selesai shalat beliau bersabda: \"Bagaimana keadaan orang-orang yang shalat tanpa bersuci dengan baik? Bacaan AI Qur'an kita menjadi kacau karena mereka.\""},"937":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ سَيَّارٍ يَعْنِي ابْنَ سَلَامَةَ عَنْ أَبِي بَرْزَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الْغَدَاةِ بِالسِّتِّينَ إِلَى الْمِائَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ismail bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Yazid] dia berkata; Telah memberitakan kepada kami [Sulaiman At-Taimi] dari [Sayyar Yaitu Ibnu Salamah] dari [Abu Barzah] bahwa; Rasulullah Shallallallahu'alaihi wasallam pernah membaca enam puluh sampai seratus ayat pada shalat Subuh."},"938":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا ابْنُ أَبِي الرِّجَالِ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْمَا أَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ إِلَّا مِنْ وَرَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بِهَا فِي الصُّبْحِ","id":"Telah mengabarkan kepada kami ['Imran bin Yazid] dia berkata; Telah menceritakan kepada kami [Ibnu Abu Rizal] dari [Yahya bin Sa'id] dari ['Amrah] dari [Ummu Hisyam binti Haritsah bin An Nu'man] dia berkata; \"Aku tidaklah menghafal surat Qaaf wal Qur'anil Majiid, kecuali dari belakang Rasulullah Shallallallahu'alaihi wasallam yang pernah beliau baca dalam shalat shubuh.\""},"939":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى وَاللَّفْظُ لَهُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ عَمِّي يَقُولُصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّبْحَ فَقَرَأَ فِي إِحْدَى الرَّكْعَتَيْنِ وَالنَّخْلَ بَاسِقَاتٍ لَهَا طَلْعٌ نَضِيدٌ قَالَ شُعْبَةُ فَلَقِيتُهُ فِي السُّوقِ فِي الزِّحَامِ فَقَالَ ق","id":"Telah mengabarkan kepada kami [Ismail bin Ma'sud] dan [Muhamad bin Abdul A'la] lafadz ini darinya dia berkata; telah menceritakan kepada kami [Khalid] dan [Syu'bah] dari [Ziyad bin Ilaqah] dia berkata; \"Aku mendengar [pamanku] berkata; \"Aku shalat Subuh bersama Rasulullah Shallallahu'alaihi wasallam, dan beliau Shallallallahu'alaihi wasallam dalam salah satu rakaatnya membaca ayat, Wannakhla Saabiqaatin Lahaa Thal'un Nadhiij ('Dan pohon Kurma yang tinggi-tinggi yang mempunyai mayang yang bersusun). (Qs.Qaaf (50): 10).\" Syu'bah (salah seorang perawi hadits ini) berkata, \"Lalu aku berjumpa dengannya di pasar yang ramai, beliau berkata, 'yang kubaca tadi surat Qaaf.\""},"940":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ أَبَانَ الْبَلْخِيُّ قَالَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ مِسْعَرٍ وَالْمَسْعُودِيِّ عَنْ الْوَلِيدِ بْنِ سُرَيْعٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْفَجْرِ إِذَا الشَّمْسُ كُوِّرَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Aban Al Balkhi] dia berkata; telah menceritakan kepada kami [Waki' bin Al Jarrah] dari [Mis'ar] dan [Al Mas'udi] dari [Al Walid bin Surai'i] dari [Amr bin Huraits] dia berkata; \"Aku mendengar Rasulullah Shallallallahu'alaihi wasallam membaca Idzasy-syamsu kuwwirat (Qs. At-Takwir atau surat ke 81) saat shalat Subuh.\""},"941":{"ar":"أَخْبَرَنَا مُوسَى بْنُ حِزَامٍ التِّرْمِذِيُّ وَهَارُونُ بْنُ عَبْدِ اللَّهِ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ قَالَ أَخْبَرَنِي سُفْيَانُ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمُعَوِّذَتَيْنِ قَالَ عُقْبَةُ فَأَمَّنَا بِهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الْفَجْرِ","id":"Telah mengabarkan kepada kami [Musa bin Hizam At-Tarmidzi] dan [Harun bin Abdullah] lafazhnya ini miliknya, dia berkata; telah menceritakan kepada kami [Abu Usamah] dia berkata; telah menceritakan kepadaku [Syufyan] dari [Mu'awiyyah bin Shalih] dari [Abdurrahman bin Jubair bin Nufair] dari [Bapaknya] dari [Uqbah bin Amir] bahwa dia pernah bertanya kepada Nabi Shallallallahu'alaihi wasallam tentang mu 'awwidzatain. Uqbah berkata; \"Lalu Rasulullah Shallallallahu'alaihi wasallam mengimami kami saat shalat Subuh dengan membaca Mu'awwidzatain.\""},"942":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي عِمْرَانَ أَسْلَمَ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَاتَّبَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ رَاكِبٌ فَوَضَعْتُ يَدِي عَلَى قَدَمِهِ فَقُلْتُ أَقْرِئْنِي يَا رَسُولَ اللَّهِ سُورَةَ هُودٍ وَسُورَةَ يُوسُفَ فَقَالَ لَنْ تَقْرَأَ شَيْئًا أَبْلَغَ عِنْدَ اللَّهِ مِنْ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَقُلْ أَعُوذُ بِرَبِّ النَّاسِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Imran Aslam] dari [Uqbah bin Amir] dia berkata; \"Aku pernah mengikuti Rasulullah Shallallahu'alaihi wasallam, dan ketika itu beliau sedang naik kendaraan. Kuletakkan tanganku di telapak kaki beliau, dan aku berkata, 'Wahai Rasulullah Shallallahu'alaihi wasallam, bacakan untukku surat Huud dan Yusuf. Beliau Shallallallahu'alaihi wasallam bersabda: 'Kamu tidak akan pernah membaca apapun yang lebih memadai daripada surat qul a 'udzu birabbil falaq dan qul a'udzu birabbin-naas di sisi Allah'.\""},"943":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ بَيَانٍ عَنْ قَيْسٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آيَاتٌ أُنْزِلَتْ عَلَيَّ اللَّيْلَةَ لَمْ يُرَ مِثْلُهُنَّ قَطُّ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَقُلْ أَعُوذُ بِرَبِّ النَّاسِ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Bayan] dari [Qaits] dari [Uqbah bin Amir] dia berkata; Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Tadi malam telah diturunkan kepadaku beberapa ayat yang tidak kulihat bandingannya, yaitu qul a'udzu birabbil falaq dan qul a'udzu birabbin-naas (Al Falaq dan An-Naas).\""},"944":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ ح وَأَنْبَأَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ وَاللَّفْظُ لَهُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الصُّبْحِ يَوْمَ الْجُمُعَةِ الم تَنْزِيلُ وَهَلْ أَتَى","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; Telah mengabarkan kepada kami [Yahya bin Said] dia berkata; Telah mengabarkan kepada kami [Sufyan]. Dan dari jalur periwayatan yang lain telah mengabarkan kepada kami [Amr bin Ali] dia berkata; Telah mengabarkan kepada kami [Abdurrahman] dia berkata; Telah mengabarkan kepada kami [Sufyan] dan lafazhnya dari dia dari [Sa'ad bin Ibrahim] dari [Abdurrahman Al Araj] dari [Abu Hurairah] bahwa Rasulullah Shallallallahu'alaihi wasallam pernah membaca, \"Aliiflaam miim tanziil...\" (Qs. As-Sajdah) dan \"Hal ataa....\" (Qs. Al Insaan) ketika shalat Subuh pada hari Jum'at."},"945":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ ح و أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا شَرِيكٌ وَاللَّفْظُ لَهُ عَنْ الْمُخَوَّلِ بْنِ رَاشِدٍ عَنْ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الصُّبْحِ يَوْمَ الْجُمُعَةِ تَنْزِيلُ السَّجْدَةَ وَهَلْ أَتَى عَلَى الْإِنْسَانِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] -dari jalur periwayatan lain- dan telah memberitakan kepada kami [Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Syarik] dan lafazhnya dari dia dari [Al Mukhawwal bin Rasyid] dari [Muslim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] sesungguhnya Nabi Shallallallahu'alaihi wasallam pernah membaca, \"Tanziil...\" (Qs. As-Sajdah) dan Hal ataa 'alal insaan.\" (Qs. Al Insaan)."},"946":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ الْمِقْسَمِيُّ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ عُمَرَ بْنِ ذَرٍّ عَنْ أَبِيهِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي ص وَقَالَ سَجَدَهَا دَاوُدُ تَوْبَةً وَنَسْجُدُهَا شُكْرًا","id":"Telah mengabarkan kepada kami [Ibrahim bin Hasan Al Miqsami] dia berkata; telah menceritakan kepada kami [Hajaj bin Muhammad] dari [Umar bin Dzar] dari [Bapaknya] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Nabi Shallallallahu'alaihi wasallam pernah sujud ketika membaca surat Shaad, lalu beliau bersabda: \"Nabi Daud bersujud dalam surat Shaad untuk taubat, sedangkan kita sujud untuk bersyukur.\""},"947":{"ar":"أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ عَبْدِ الْحَمِيدِ بْنِ مَيْمُونِ بْنِ مِهْرَانَ قَالَ حَدَّثَنَا ابْنُ حَنْبَلٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنْ ابْنِ طَاوُسٍ عَنْ عِكْرِمَةَ بْنِ خَالِدٍ عَنْ جَعْفَرِ بْنِ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ عَنْ أَبِيهِ قَالَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَكَّةَ سُورَةَ النَّجْمِ فَسَجَدَ وَسَجَدَ مَنْ عِنْدَهُ فَرَفَعْتُ رَأْسِي وَأَبَيْتُ أَنْ أَسْجُدَ وَلَمْ يَكُنْ يَوْمَئِذٍ أَسْلَمَ الْمُطَّلِبُ","id":"Telah mengabarkan kepada kami [Abdul Malik Abdul Hamid bin Maimun bin Mihran] dia berkata; telah menceritakan kepada kami [Ibnu Hambali] dia berkata; Telah mengabarkan kepada kami [Ibrahim bin Khalid] dia berkata; telah menceritakan kepada kami [Rabah] dari [Ma'mar] dari [Ibnu Thawus] dari [Ikrimah bin Khalid] dari [Ja'far bin Al Muthallib bin Abu Wada'ah] dari [Bapaknya] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam pernah membaca surat An-Najm di Makkah, dan beliau Shallallallahu'alaihi wasallam sujud dengan diikuti oleh orang di sekitarnya. Namun aku mengangkat kepalaku dan enggan untuk sujud waktu itu Al Muthallib belum masuk Islam."},"948":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ النَّجْمَ فَسَجَدَ فِيهَا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah] bahwa Rasulullah Shallallallahu'alaihi wasallam pernah membaca surat An Najm, lantas beliau sujud."},"949":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ عَطَاءِ بْنِ يَسَارٍ أَنَّهُ سَأَلَ زَيْدَ بْنَ ثَابِتٍ عَنْ الْقِرَاءَةِ مَعَ الْإِمَامِ فَقَالَ لَا قِرَاءَةَ مَعَ الْإِمَامِ فِي شَيْءٍوَزَعَمَ أَنَّهُ قَرَأَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّجْمِ إِذَا هَوَى فَلَمْ يَسْجُدْ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dia adalah Ibnu Ja'far dari [Yazid bin Khushaifah] dari [Yazid bin Abdullah bin Qusaith] dari ['Atha bin Yasar] bahwa dia pernah bertanya kepada Zaid bin Tsabit tentang membaca bersama imam, maka [Zaid] berkata; \"Tidak ada bacaan saat imam membaca dan dia beranggapan bahwa ia pernah membaca di depan Rasulullah Shallallallahu'alaihi wasallam surat An Najm namun beliau tidak sujud.\""},"950":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِأَنَّ أَبَا هُرَيْرَةَ قَرَأَ بِهِمْ إِذَا السَّمَاءُ انْشَقَّتْ فَسَجَدَ فِيهَا فَلَمَّا انْصَرَفَ أَخْبَرَهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِيهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abdullah bin Yazid] dari [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] pernah membacakan \"Idzas-samaa'un Syaqqat\" (Al Insyiqaaq) kepada mereka, lalu ia sujud. Setelah selesai ia mengatakan bahwa Rasulullah Shallallallahu'alaihi wasallam juga sujud waktu membacanya."},"951":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ قَالَ أَنْبَأَنَا ابْنُ أَبِي ذِئْبٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَيَّاشٍ عَنْ ابْنِ قَيْسٍ وَهُوَ مُحَمَّدٌ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَسَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِذَا السَّمَاءُ انْشَقَّتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] telah memberitakan kepada kami [Ibnu Abu Dzi'ib] dari [Abdul Aziz bin 'Ayyasy] dari [Ibnu Qais] dia adalah Muhammad dari [Umar bin Abdul Aziz] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam pernah sujud pada surat Al Insyiqaaq (Idzas-samaaun syaqqat).\""},"952":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَ قَالَسَجَدْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّ��َ فِي إِذَا السَّمَاءُ انْشَقَّتْ وَاقْرَأْ بِاسْمِ رَبِّكَأَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِي هُرَيْرَةَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Muhamad bin Manshur] dia berkata; telah menceritakan kepada kami [Syufyan] dari [Yahya bin Sa'id] dari [Abu Bakr bin Muhammad bin Amr bin Hazm] dari [Umar bin Abdul Aziz] dari [Abu Bakr bin Abdurrahman bin Harits bin Hisyam] dari [Abu Hurairah] dia berkata; \"Kami pernah sujud bersama Rasulullah Shallallallahu'alaihi wasallam pada surah\" Idzas-samaaun syaqqat\" (Al Insyiqaaq) dan \"Iqra bismi rabbika\" (Al 'Alaq). Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Abu Bakar bin Muhammad] dari [Umar bin Abdul Aziz] dari [Abu Bakar bin Abdurrahman bin Al Harits bin Hisyam] dari [Abu Hurairah] seperti itu juga."},"953":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَسَجَدَ أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا فِي إِذَا السَّمَاءُ انْشَقَّتْ وَمَنْ هُوَ خَيْرٌ مِنْهُمَا","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Qurrah bin Khalid] dari [Muhammad bin Sirin] dari [Abu Hurairah] dia berkata; \"Abu Bakar dan Umar Radliyallahu'anhu pernah sujud pada surat Idzas-samaaun syaqqat. Juga telah sujud orang yang Iebih baik dari keduanya (yakni Rasulullah Shallallahu'alaihi wasallam).\""},"954":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْمُعْتَمِرُ عَنْ قُرَّةَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَسَجَدَ أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا وَمَنْ هُوَ خَيْرٌ مِنْهُمَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِذَا السَّمَاءُ انْشَقَّتْ وَاقْرَأْ بِاسْمِ رَبِّكَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Al Mu'tamir] dari [Qurrah] dari [Muhamad bin Sirin] dari [Abu Hurairah] dia berkata; \"Abu Bakar dan Umar Radliyallahu'anhum juga orang yang lebih baik dari keduanya (yakni Rasulullah Shallallahu'alaihi wasallam) pernah sujud pada surat Idzas-samaaun syaqqat (surat Al Insyiqaaq) dan Iqra bismi rabbika (surat Al 'Alaq).\""},"955":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ عَطَاءِ بْنِ مِينَاءَ عَنْ أَبِي هُرَيْرَةَ وَوَكِيعٌ عَنْ سُفْيَانَ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ عَطَاءِ بْنِ مِينَاءَ عَنْ أَبِي هُرَيْرَةَ قَالَسَجَدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِذَا السَّمَاءُ انْشَقَّتْ وَاقْرَأْ بِاسْمِ رَبِّكَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Syufyan] dari [Ayub bin Musa] dari ['Atha bin Mina] dari [Abu Hurairah]. Dan (menurut jalur periwayatan yang lain) [Waqi'i] dari [Sufyan] dari [Ayyub bin Musa] dari ['Atha bin Mina] dari [Abu Hurairah] dia berkata; \"Kami pernah sujud bersama Rasulullah Shallallallahu'alaihi wasallam pada surat Idzas-samaaun syaqqat -surat al-insyiqaq- dan Iqra' bismi rabbika- surat al'alaq-.\""},"956":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُلَيْمٍ وَهُوَ ابْنُ أَخْضَرَ عَنْ التَّيْمِيِّ قَالَ حَدَّثَنِي بَكْرُ بْنُ عَبْدِ اللَّهِ الْمُزَنِيُّ عَنْ أَبِي رَافِعٍ قَالَصَلَّيْتُ خَلْفَ أَبِي هُرَيْرَةَ صَلَاةَ الْعِشَاءِ يَعْنِي الْعَتَمَةَ فَقَرَأَ سُورَةَ إِذَا السَّمَاءُ انْشَقَّتْ فَسَجَدَ فِيهَا فَلَمَّا فَرَغَ قُلْتُ يَا أَبَا هُرَيْرَةَ هَذِهِ يَعْنِي سَجْدَةً مَا كُنَّا نَسْجُدُهَا قَالَ سَجَدَ بِهَا أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا خَلْفَهُ فَلَا أَزَالُ أَسْجُدُ بِهَا حَتَّى أَلْقَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Sulaim] dia adalah Ibnu Akhdlar dari [At Taimi] dia berkata; telah menceritakan kepadaku [Bakr bin Abdullah Al Muzani] dari [Abu Rafi'] dia berkata; \"Aku pernah shalat Isya' di belakang Abu Hurairah, ia membaca surat Al Insyiqaaq dan ia sujud. Setelah selesai aku berkata, 'Wahai Abu Hurairah, ini (maksudnya sujud) tidak pernah kita lakukan sebelumnya'. la ([Abu Hurairah]) berkata; 'Sujud ini pernah dilakukan oleh Abul Qasim (Rasulullah Shallallahu'alaihi wasallam) dan aku di belakangnya. Aku senantiasa melakukannya hingga aku berjumpa dengan Abul Qasim Shallallahu'alaihi wasallam.\""},"957":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ رَقَبَةَ عَنْ عَطَاءٍ قَالَ قَالَ أَبُو هُرَيْرَةَكُلُّ صَلَاةٍ يُقْرَأُ فِيهَا فَمَا أَسْمَعَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْمَعْنَاكُمْ وَمَا أَخْفَاهَا أَخْفَيْنَا مِنْكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Raqabah] dari ['Atha] dia berkata; [Abu Hurairah] berkata; \"Setiap shalat ada bacaannya. Jika Rasulullah Shallallallahu'alaihi wasallam memperdengarkannya kepadaku, maka aku perdengarkan kepada kalian, dan apa yang tidak beliau perdengarkan maka kami juga tidak memperdengarkan kepada kalian.\""},"958":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَفِي كُلِّ صَلَاةٍ قِرَاءَةٌ فَمَا أَسْمَعَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْمَعْنَاكُمْ وَمَا أَخْفَاهَا أَخْفَيْنَا مِنْكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] dia berkata; telah memberitakan kepada kami [Khalid] dia berkata; Telah mengabarkan kepada kami [Ibnu Jurij] dari ['Atha] dari [Abu Hurairah] \"Setiap shalat ada bacaannya. Jika Rasulullah Shallallallahu'alaihi wasallam memperdengarkannya kepadaku, maka aku perdengarkan kepada kalian, dan apa yang tidak beliau perdengarkan maka kami juga tidak memperdengarkan kepada kalian.\""},"959":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ صُدْرَانَ قَالَ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ قَالَ حَدَّثَنَا هَاشِمُ بْنُ الْبَرِيدِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَكُنَّا نُصَلِّي خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَنَسْمَعُ مِنْهُ الْآيَةَ بَعْدَ الْآيَاتِ مِنْ سُورَةِ لُقْمَانَ وَالذَّارِيَاتِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ibrahim bin Shudran] dia berkata; Telah mengabarkan kepada kami [Salm bin Qutaibah] dia berkata; Telah mengabarkan kepada kami [Hasyim bin Al Barid] dari [Abu Ishaq] dari [Abu Bara'] dia berkata; \"Kami shalat zhuhur di belakang Rasulullah Shallallahu'alaihi wasallam, kemudian kami mendengar satu ayat setelah beberapa ayat dari surat Luqman dan Adzariyat.\""},"960":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ شُجَاعٍ الْمَرُّوذِيُّ قَالَ حَدَّثَنَا أَبُو عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدٍ قَالَ سَمِعْتُ أَبَا بَكْرِ بْنَ النَّضْرِ قَالَكُنَّا بِالطَّفِّ عِنْدَ أَنَسٍ فَصَلَّى بِهِمْ الظُّهْرَ فَلَمَّا فَرَغَ قَالَ إِنِّي صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَقَرَأَ لَنَا بِهَاتَيْنِ السُّورَتَيْنِ فِي الرَّكْعَتَيْنِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Syuhja' Al Marrudzi] dia berkata; Telah mengabarkan kepada kami [Abu Ubaidah] dari [Abdullah bin 'Ubaid] dia berkata; 'Aku mendengar [Abu Bakr bin Nadlr] berkata; 'Kami sedang bersama [Anas]. lalu Anas shalat dluhur bersama jama'ah. Setelah selesai shalat dia berkata; Aku shalat bersama Rasulullah shallallahu 'alaihi wasallam, beliau membacakan untuk kami dengan dua surat ini dalam dua raka'at. Yaitu, Sabihisma Rabbikal A'la (surat al-a'la) dan Hal Ataaka Haditsul Ghaasyiyah (surat alghasyiyah). "},"961":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَطِيَّةَ بْنِ قَيْسٍ عَنْ قَزَعَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَلَقَدْ كَانَتْ صَلَاةُ الظُّهْرِ تُقَامُ فَيَذْهَبُ الذَّاهِبُ إِلَى الْبَقِيعِ فَيَقْضِي حَاجَتَهُ ثُمَّ يَتَوَضَّأُ ثُمَّ يَجِيءُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّكْعَةِ الْأُولَى يُطَوِّلُهَا","id":"Telah mengabarkan kepada kami [Amr bin Utsman] dia berkata; telah menceritakan kepada kami [Al Walid] dari [Sa'id bin Abdul Aziz] dari ['Athiyah bin Qays] dari [Qaza'ah] dari [Abu Sa'id Al Khudri] dia berkata, \"Ketika shalat Zhuhur ditegakkan, ada seseorang yang pergi ke Baqi' lalu ia menyelesaikan hajatnya lalu berwudhu. Kemudian ia datang lagi dan Rasulullah Shalallahu 'Alaihi Wa Sallam masih pada rakaat pertama; beliau melamakannya.\""},"962":{"ar":"أَخْبَرَنِي يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ وَهُوَ الْقَنَّادُ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ عَبْدَ اللَّهِ بْنَ أَبِي قَتَادَةَ حَدَّثَهُ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ يُصَلِّي بِنَا الظُّهْرَ فَيَقْرَأُ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ يُسْمِعُنَا الْآيَةَ كَذَلِكَ وَكَانَ يُطِيلُ الرَّكْعَةَ فِي صَلَاةِ الظُّهْرِ وَالرَّكْعَةَ الْأُولَى يَعْنِي فِي صَلَاةِ الصُّبْحِ","id":"Telah mengabarkan kepadaku [Yahya bin Durust] dia berkata; telah menceritakan kepada kami [Abu Ismail] dia adalah Al Qanad dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepadaku [Yahya bin Abu Katsir] sesungguhnya [Abdullah bin Abu Qatadah] telah menceritakan kepadanya dari [Bapaknya] dari Nabi Shallallahu'alaihi wasallam, dia berkata: \"Rasulullah Shalallahu 'Alaihi Wa Sallam pernah shalat Zhuhur bersama kami, dan pada dua rakaat pertama beliau memperdengarkan ayat kepada kami. Beliau Shalallahu 'Alaihi Wa Sallam memperpanjang rakaat pertama pada shalat Zhuhur dan Subuh.\""},"963":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ بْنِ خَالِدِ بْنِ مُسْلِمٍ يُعْرَفُ بِابْنِ أَبِي جَمِيلٍ الدِّمَشْقِيِّ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَبْدِ اللَّهِ ابْنِ سَمَاعَةَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ قَالَ حَدَّثَنَا أَبِيأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ بِأُمِّ الْقُرْآنِ وَسُورَتَيْنِ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ صَلَاةِ الظُّهْرِ وَصَلَاةِ الْعَصْرِ وَيُسْمِعُنَا الْآيَةَ أَحْيَانًا وَكَانَ يُطِيلُ فِي الرَّكْعَةِ الْأُولَى","id":"Telah mengabarkan kepada kami [Imran bin Yazid bin Khalid bin Muslim] yang dikenal dengan Abu Jamil Ad-Dimasyqi dia berkata; telah menceritakan kepada kami [Ismail bin Abdullah bin Sama'ah] dia berkata; telah menceritakan kepada kami [Al Auza'i] dari [Yahya bin Abu Katsir] dia berkata; telah menceritakan kepadaku [Abdullah bin Abu Qatadah] dia berkata; telah menceritakan kepada kami [Bapakku] bahwa Rasulullah Shallallallahu'alaihi wasallam membaca Ummul Qur'an (Fatihah) dan dua surat pada dua rakaat pertama shalat Zhuhur dan Ashar. Kadang beliau memperdengarkan ayat kepada kami dan memperpanjang rakaat pertama."},"964":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ أَنَّ أَبَاهُ أَخْبَرَهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِنَا فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ صَلَاةِ الظُّهْرِ وَيُسْمِعُنَا الْآيَةَ أَحْيَانًا وَيُطَوِّلُ فِي الْأُولَى وَيُقَصِّرُ فِي الثَّانِيَةِ وَكَانَ يَفْعَلُ ذَلِكَ فِي صَلَاةِ الصُّبْحِ يُطَوِّلُ فِي الْأُولَى وَيُقَصِّرُ فِي الثَّانِيَةِ وَكَانَ يَقْرَأُ بِنَا فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ صَلَاةِ الْعَصْرِ يُطَوِّلُ الْأُولَى وَيُقَصِّرُ الثَّانِيَةَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Muadz bin Hisyam] dia berkata; telah menceritakan kepadaku [Bapakku] dari [Yahya bin Abu Katsir] dia berkata; telah menceritakan kepada ku [Abdullah bin Abu Qatadah] sesungguhnya [Bapaknya] Telah mengabarkan kepadanya dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam pernah membaca - surat - pada dua rakaat pertama dari shalat Zhuhur, dan kadang beliau memperdengarkan ayat kepada kami. Beliau memperpanjang rakaat pertama dan memperpendek rakaat kedua. Beliau Shallallallahu'alaihi wasallam juga melakukan hal tersebut pada shalat Subuh dengan memperpanjang rakaat pertama dan memperpendek rakaat kedua. Demikian juga Rasulullah Shallallallahu'alaihi wasallam pernah membacakan kepada kami pada dua rakaat pertama dalam shalat Ashar dengan memperpanjang rakaat pertama dan memperpendek rakaat kedua.\""},"965":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ بِأُمِّ الْقُرْآنِ وَسُورَتَيْنِ وَفِي الْأُخْرَيَيْنِ بِأُمِّ الْقُرْآنِ وَكَانَ يُسْمِعُنَا الْآيَةَ أَحْيَانًا وَكَانَ يُطِيلُ أَوَّلَ رَكْعَةٍ مِنْ صَلَاةِ الظُّهْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Abdurrahman bin Mahdi] dia berkata; telah menceritakan kepada kami [Aban bin Yazid] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [Bapaknya] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam membaca pada shalat Zhuhur dan Ashar (berjamaah), pada dua rakaat pertama beliau membaca Ummul Qur'an (Fatihah) dan dua surat, sedangkan pada dua rakaat terakhir beliau hanya membaca Ummul Qur'an (Fatihah). Kadang beliau memperdengarkan ayat kepada kami, dan beliau Shallallallahu'alaihi wasallam memperpanjang rakaat pertama pada shalat Zhuhur.\""},"966":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ حَجَّاجٍ الصَّوَّافِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ وَعَنْ أَبِي سَلَمَةَ عَنْ أَبِي قَتَادَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ بِفَاتِحَةِ الْكِتَابِ وَسُورَتَيْنِ وَيُسْمِعُنَا الْآيَةَ أَحْيَانًا وَكَانَ يُطِيلُ الرَّكْعَةَ الْأُولَى فِي الظُّهْرِ وَيُقَصِّرُ فِي الثَّانِيَةِ وَكَذَلِكَ فِي الصُّبْحِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Ibnu Abu Adi] dari [Hajaj Ash Shawaf] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [bapaknya] dan dari [Abu Salamah] dari [Abu Qutadah] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam shalat Zuhur dan Ashar (berjamaah), lalu beliau membaca Ummul Qur'an (Fatihah) dan dua surat pada dua rakaat pertama. Kadang beliau memperdengarkan ayat kepada kami. Beliau Shallallallahu'alaihi wasallam memperpanjang rakaat pertama dan memperpendek rakaat kedua pada shalat Zhuhur. Demikian juga dalam shalat Subuh.\""},"967":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ بِالسَّمَاءِ ذَاتِ الْبُرُوجِ وَالسَّمَاءِ وَالطَّارِقِ وَنَحْوِهِمَا","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; telah menceritakan kepada kami [Abdurrahman] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dia berkata; telah menceritakan kepada kami dari [Simak] dari [Jabir bin Samurah] bahwa Nabi Shallallallahu'alaihi wasallam pernah membaca As Samaai dzaatil buruuj (QS. Al Buruuj) dan Was-samaai wath-thaariq (Qs. Ath-Thaariq) pada shalat Zhuhur dan Ashar. Atau yang sepertinya.\""},"968":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ شُعْبَةَ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَاللَّيْلِ إِذَا يَغْشَى وَفِي الْعَصْرِ نَحْوَ ذَلِكَ وَفِي الصُّبْحِ بِأَطْوَلَ مِنْ ذَلِكَ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami [Abdurrahman] dari [Syu'bah] dari [Simak] dari [Jabir bin Samurah] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam membaca surat Al Lail pada shalat zhuhur dan pada Ashar yang sepertinya. Sedangkan pada shalat Shubuh beliau membaca yang lebih panjang dari itu.\""},"969":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْعَطَّافُ بْنُ خَالِدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ قَالَدَخَلْنَا عَلَى أَنَسِ بْنِ مَالِكٍ فَقَالَ صَلَّيْتُمْ قُلْنَا نَعَمْ قَالَ يَا جَارِيَةُ هَلُمِّي لِي وَضُوءًا مَا صَلَّيْتُ وَرَاءَ إِمَامٍ أَشْبَهَ صَلَاةً بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِمَامِكُمْ هَذَا قَالَ زَيْدٌ وَكَانَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ يُتِمُّ الرُّكُوعَ وَالسُّجُودَ وَيُخَفِّفُ الْقِيَامَ وَالْقُعُودَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Athaf bin Khalid] dari [Zaid bin Aslam] dia berkata; \"kami menemui [Anas bin Malik] lalu dia berkata; 'Apakah kalian sudah shalat? ' Kami menjawab, 'Sudah'. la berkata, 'Wahai Jariyah (budak perempuan), ambilkan air wudhu untukku. Aku belum pernah shalat di belakang imam yang lebih mirip dengan shalatnya Rasulullah Shallallallahu'alaihi wasallam dari imam kalian ini'.\" Zaid berkata; 'Bila Umar bin Abdul Aziz shalat, maka ia menyempurnakan ruku' dan sujudnya, serta tidak memperlama berdiri dan duduknya.\""},"970":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَا صَلَّيْتُ وَرَاءَ أَحَدٍ أَشْبَهَ صَلَاةً بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فُلَانٍ قَالَ سُلَيْمَانُ كَانَ يُطِيلُ الرَّكْعَتَيْنِ الْأُولَيَيْنِ مِنْ الظُّهْرِ وَيُخَفِّفُ الْأُخْرَيَيْنِ وَيُخَفِّفُ الْعَصْرَ وَيَقْرَأُ فِي الْمَغْرِبِ بِقِصَارِ الْمُفَصَّلِ وَيَقْرَأُ فِي الْعِشَاءِ بِوَسَطِ الْمُفَصَّلِ وَيَقْرَأُ فِي الصُّبْحِ بِطُوَلِ الْمُفَصَّلِ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah] dia berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Adl Dlahak bin Utsman] dari [Bukair bin Abdullah] dari [Sulaiman bin Yasar] dari [Abu Hurairah] dia berkata; \"Aku belum pernah shalat di belakang imam yang lebih mirip dengan shalatnya Rasulullah Shallallallahu'alaihi wasallam daripada shalat di belakang si Fulan.\" Sulaiman berkata; 'la memperlama dua rakaat pertama pada shalat Zhuhur dan meringankannya pada dua rakaat terakhir. la juga meringankan shalat Ashar, membaca surat-surat pendek pada shalat Maghrib, membaca surat yang sedang pada shalat Isya dan membaca surat yang panjang pada shalat Subuh.\""},"971":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْحَارِثِ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَا صَلَّيْتُ وَرَاءَ أَحَدٍ أَشْبَهَ صَلَاةً بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فُلَانٍ فَصَلَّيْنَا وَرَاءَ ذَلِكَ الْإِنْسَانِ وَكَانَ يُطِيلُ الْأُولَيَيْنِ مِنْ الظُّهْرِ وَيُخَفِّفُ فِي الْأُخْرَيَيْنِ وَيُخَفِّفُ فِي الْعَصْرِ وَيَقْرَأُ فِي الْمَغْرِبِ بِقِصَارِ الْمُفَصَّلِ وَيَقْرَأُ فِي الْعِشَاءِ بِالشَّمْسِ وَضُحَاهَا وَأَشْبَاهِهَا وَيَقْرَأُ فِي الصُّبْحِ بِسُورَتَيْنِ طَوِيلَتَيْنِ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abdullah bin Al Harits] dari [Adl Dlahak bin 'Utsman] dari [Bukair bin Abdillah bin Al Asyaj] dari [Sulaiman bin Yasar] dari [Abu Hurairah] dia berkata; \"Aku belum pernah shalat di belakang imam yang lebih mirip dengan shalatnya Rasulullah Shallallallahu'alaihi wasallam daripada shalat di belakang si Fulan. Kami shalat di belakang orang tersebut dan dia memperlama dua rakaat pertama shalat zhuhur serta meringankan dua rakaat terakhir. la juga meringankan shalat Ashar dan membaca surat pendek pada shalat Maghrib. Pada shalat Isya' ia membaca sural Wasysamsi wadluhaha (Qs. Asy-Syamsy) dan yang sepadan dengannya, sedangkan pada shalat Subuh ia membaca dua surat yang panjang.\""},"972":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرٍ قَالَمَرَّ رَجُلٌ مِنْ الْأَنْصَارِ بِنَاضِحَيْنِ عَلَى مُعَاذٍ وَهُوَ يُصَلِّي الْمَغْرِبَ فَافْتَتَحَ بِسُورَةِ الْبَقَرَةِ فَصَلَّى الرَّجُلُ ثُمَّ ذَهَبَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَفَتَّانٌ يَا مُعَاذُ أَفَتَّانٌ يَا مُعَاذُ أَلَّا قَرَأْتَ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَالشَّمْسِ وَضُحَاهَا وَنَحْوِهِمَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Muharib bin Ditsar] dari [Jabir] dia berkata; \"Ada seorang laki-laki Anshar melewati Mu'adz dengan membawa dua tempat minum unta, padahal Mu'adz sedang shalat Maghrib. Dia memulai shalat Maghrib dengan membaca surat Al Baqarah. Laki-laki tersebut shalat kemudian pergi, dan hal tersebut sampai kepada Rasulullah Shallallahu'alaihi wasallam, maka beliau Shallallallahu'alaihi wasallam lalu bersabda; ' Wahai Mu'adz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? Wahai Mu'adz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? Kenapa kamu tidak mau membaca Sabbihisma rabbikal a'laa (Qs. Al A'laa) dan Wasysamsi wadluhaha (Qs. Asy-Syamsy), atau yang sejenisnya? '"},"973":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ الْمَاجِشُونُ عَنْ حُمَيْدٍ عَنْ أَنَسٍ عَنْ أُمِّ الْفَضْلِ بِنْتِ الْحَارِثِ قَالَتْصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ الْمَغْرِبَ فَقَرَأَ الْمُرْسَلَاتِ مَا صَلَّى بَعْدَهَا صَلَاةً حَتَّى قُبِضَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dia berkata; telah menceritakan kepada kami [Musa bin Dawud] dia berkata; telah menceritakan kepada kami [Abdul Aziz bin Abu Salamah Al Majisyun] dari [Humaid] dari [Anas] dari [Ummu Al Fadhl binti Al Harits] dia berkata; \"Rasulullah Shallallallahu'alaihi wasallam pernah shalat Maghrib bersama kami di rumahnya, dan beliau Shallallallahu'alaihi wasallam membaca surat Al Mursalaat. Setelah itu tidak pernah lagi shalat bersama umat hingga beliau wafat.\""},"974":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ أُمِّهِ أَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِالْمُرْسَلَاتِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ubaidillah] dari [Ibnu Abbas] dari [Ibunya] bahwa ia pernah mendengar Rasulullah Shallallallahu'alaihi wasallam shalat Maghrib dengan membaca surat Al Mursalaat."},"975":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْمَغْرِبِ بِالطُّورِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [Bapaknya] dia berkata; \"Aku pernah mendengar Rasulullah Shallallallahu'alaihi wasallam shalat Maghrib dengan membaca surat Ath Thuur.\""},"976":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْمُقْرِئُ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا حَيْوَةُ وَذَكَرَ آخَرَ قَالَا حَدَّثَنَا جَعْفَرُ بْنُ رَبِيعَةَ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ هُرْمُزَ حَدَّثَهُ أَنَّ مُعَاوِيَةَ بْنَ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ حَدَّثَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عُتْبَةَ بْنِ مَسْعُودٍ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ فِي صَلَاةِ الْمَغْرِبِ بِ حم الدُّخَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdillah bin Yazid Al Muqri] dia berkata; telah menceritakan kepada kami [bapakku] dia berkata; telah menceritakan kepada kami [Haiwah] dan yang lainnya juga menyebutkan, keduanya berkata; telah menceritakan kepada kami [Ja'far bin Rabi'ah] bahwa [Abdurrahman bin Hurmuz] telah menceritakan kepadanya; [Mu'awiyah bin Abdullah bin Ja'far] telah menceritakan kepadanya, bahwa [Abdullah bin 'Uthbah bin Mas'ud] telah menceritakan kepadanya; \"Rasulullah Shallallallahu'alaihi wasallam pernah membaca surat Ad Dukhan pada shalat magrib.\""},"977":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ أَبِي الْأَسْوَدِ أَنَّهُ سَمِعَ عُرْوَةَ بْنَ الزُّبَيْرِ يُحَدِّثُ عَنْ زَيْدِ بْنِ ثَابِتٍ أَنَّهُقَالَ لِمَرْوَانَ يَا أَبَا عَبْدِ الْمَلِكِ أَتَقْرَأُ فِي الْمَغْرِبِ بِقُلْ هُوَ اللَّهُ أَحَدٌ وَإِنَّا أَعْطَيْنَاكَ الْكَوْثَرَ قَالَ نَعَمْ قَالَ فَمَحْلُوفَةٌ لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِيهَا بِأَطْوَلِ الطُّولَيَيْنِ المص","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari ['Amr bin Al Harits] dari [Abul Aswad] bahwa dia telah mendengar [Urwah bin Az Zubair] berkata; dari [Zaid bin Tsabit] bahwa ia pernah berkata kepada Marwan, \"Wahai Abdul Malik, apakah kamu membaca qul huwallahu ahad (Qs. AI Ikhlash) dan Innaa a'thainaakal kautsaar (Qs. Al Kautsar) saat shalat Maghrib? Dia menjawab, \"Ya.\" la berkata, \"Demi Allah, aku mendengar Rasulullah Shallallallahu'alaihi wasallam membaca surat yang paling panjang dari dua surat yang panjang Aliif laam miim shaad (Qs. Shaad) - dalam shalat Maghrib -.\""},"978":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ مَرْوَانَ بْنَ الْحَكَمِ أَخْبَرَهُ أَنَّ زَيْدَ بْنَ ثَابِتٍ قَالَمَا لِي أَرَاكَ تَقْرَأُ فِي الْمَغْرِبِ بِقِصَارِ السُّوَرِ وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِيهَا بِأَطْوَلِ الطُّولَيَيْنِقُلْتُ يَا أَبَا عَبْدِ اللَّهِ مَا أَطْوَلُ الطُّولَيَيْنِ قَالَ الْأَعْرَافُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Ibnu Juraij] dari [Ibnu Abu Mulaikah] Telah mengabarkan kepadaku ['Urwah Az Zubair] bahwasanya [Marwan bin Al Hakam] Telah mengabarkan kepadanya, sesungguhnya [Zaid bin Tsabit] berkata; \"Kenapa kamu membaca surat pendek pada shalat Maghrib, padahal aku menyaksikan Rasulullah Shallallallahu'alaihi wasallam membaca surat yang paling panjang dari dua surat yang panjang pada shalat Maghrib?\" Aku berkata, \"Wahai Abu Abdullah surat apakah yang paling panjang dari dua surat yang panjang itu?\" la menjawab, \"Surah Al A'raaf.\""},"979":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ وَأَبُو حَيْوَةَ عَنْ ابْنِ أَبِي حَمْزَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ فِي صَلَاةِ الْمَغْرِبِ بِسُورَةِ الْأَعْرَافِ فَرَّقَهَا فِي رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman] dia berkata; [Baqiyah] dan [Abu Haiwah] dari [Ibnu Abu Hamzah] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Bapaknya] dari [Aisyah] bahwa Rasulullah Shallallallahu'alaihi wasallam pernah membaca surat Al A'raf pada shalat Maghrib dengan membaginya dalam dua rakaat. "},"980":{"ar":"أَخْبَرَنَا الْفَضْلُ بْنُ سَهْلٍ قَالَ حَدَّثَنِي أَبُو الْجَوَّابِ قَالَ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ أَبِي إِسْحَقَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَرَمَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِشْرِينَ مَرَّةً يَقْرَأُ فِي الرَّكْعَتَيْنِ بَعْدَ الْمَغْرِبِ وَفِي الرَّكْعَتَيْنِ قَبْلَ الْفَجْرِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Telah mengabarkan kepada kami [Al Fadhl bin Sahl] dia berkata; telah menceritakan kepadaku [Abu Al jawwab] dia berkata; telah menceritakan kepada kami ['Amr bin Ruzaiq] dari [Abu Ishaq] dari [Ibrahim bin Muhajir] dari [Mujahid] dari [Ibnu 'Umar] dia berkata; \"Aku memperhatikan Rasulullah Shallallallahu'alaihi wasallam selama dua puluh kali, beliau Shallallallahu'alaihi wasallam senantiasa membaca qul yaa ayyuhal kaafirun dan qul huwallahu ahad saat shalat dua rakaat setelah Maghrib, juga shalat dua rakaat sebelum Subuh.\""},"981":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ أَنَّ أَبَا الرِّجَالِ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُ عَنْ أُمِّهِ عَمْرَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ رَجُلًا عَلَى سَرِيَّةٍ فَكَانَ يَقْرَأُ لِأَصْحَابِهِ فِي صَلَاتِهِمْ فَيَخْتِمُ بِقُلْ هُوَ اللَّهُ أَحَدٌ فَلَمَّا رَجَعُوا ذَكَرُوا ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَلُوهُ لِأَيِّ شَيْءٍ فَعَلَ ذَلِكَ فَسَأَلُوهُ فَقَالَ لِأَنَّهَا صِفَةُ الرَّحْمَنِ عَزَّ وَجَلَّ فَأَنَا أُحِبُّ أَنْ أَقْرَأَ بِهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبِرُوهُ أَنَّ اللَّهَ عَزَّ وَجَلَّ يُحِبُّهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud] dari [Ibnu Wahab] dia berkata; telah menceritakan kepada kami ['Amr bin Al Harits] dari [Sa'id bin Abu Hilal] sesungguhnya bapaknya para lelaki - [Muhammad bin Abdurrahman] - telah menceritakan kepadanya dari ibuya ['Amrah] dari ['Aisyah] bahwa Rasulullah Shallallallahu'alaihi wasallam mengutus seseorang dalam suatu pasukan (kecil), ia mengimami para sahabatnya dengan mengakhiri bacaan dengan surat qul huwallahu ahad. Setelah pulang, mereka menceritakan hal itu kepada Rasuiullah Shallallallahu'alaihi wasallam dan beliau bersabda; \"Tanyakan kepadanya alasan ia melakukan hal tersebut?\" Lalu para sahabat segera bertanya kepadanya, dan ia menjawab; \"Karena qul huwallahu ahad adalah sifat Ar Rahman -Azza wa Jalla- dan aku sangat suka membacanya.\" Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Beritahukan kepadanya bahwa Allah Azza wa Jalla juga sangat mencintainya.\""},"982":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُبَيْدِ بْنِ حُنَيْنٍ مَوْلَى آلِ زَيْدِ بْنِ الْخَطَّابِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُأَقْبَلْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعَ رَجُلًا يَقْرَأُ{ قُلْ هُوَ اللَّهُ أَحَدٌ اللَّهُ الصَّمَدُ لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ }فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ فَسَأَلْتُهُ مَاذَا يَا رَسُولَ اللَّهِ قَالَ الْجَنَّةُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abdullah bin Abdurrahman] dari ['Ubaid bin Hunain] budak keluarga Zaid bin Al Khaththab dia berkata; Aku telah mendengar [Abu Hurairah] berkata; \"Aku datang bersama Rasulullah Shallallahu'alaihi wasallam, lalu beliau Shallallallahu'alaihi wasallam mendengar seorang laki-laki membaca surat Al Ikhlas: qul huwallahu ahad, allahush-shamad lam yalid walam yulad walam yakullahu kufuwan ahad. Rasulullah Shallallallahu'alaihi wasallam kemudian bersabda: 'Wajib baginya'. Aku bertanya, 'Apa yang wajib bagi dia wahai Rasulullah Shallallallahu'alaihi wasallam? ' Beliau Shallallallahu'alaihi wasallam menjawab: Surga.\""},"983":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي صَعْصَعَةَ عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَجُلًا سَمِعَ رَجُلًا يَقْرَأُ قُلْ هُوَ اللَّهُ أَحَدٌ يُرَدِّدُهَا فَلَمَّا أَصْبَحَ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ إِنَّهَا لَتَعْدِلُ ثُلُثَ الْقُرْآنِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Abdurrahman bin Abdullah bin Abu Sha'sha'ah] dari [Bapaknya] dari [Abu Sa'id Al Khudri] bahwa seorang laki-laki mendengar seseorang membaca qul huwallahu ahad dengan mengulang-ulangnya. Pada pagi harinya, laki-laki itu menemui Rasulullah Shallallallahu'alaihi wasallam dan menceritakan hal itu kepada beliau. Rasulullah Shallallallahu'alaihi wasallam lalu berkata: \"Demi Dzat yang jiwaku ada di Tangan-Nya, surat itu sepadan dengan sepertiga Al Qur'an.\""},"984":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا زَائِدَةُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ رَبِيعِ بْنِ خُثَيْمٍ عَنْ عَمْرِو بْنِ مَيْمُونٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ امْرَأَةٍ عَنْ أَبِي أَيُّوبَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْ هُوَ اللَّهُ أَحَدٌ ثُلُثُ الْقُرْآنِقَالَ أَبُو عَبْد الرَّحْمَنِ مَا أَعْرِفُ إِسْنَادًا أَطْوَلَ مِنْ هَذَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Abdurrahman] dia berkata; telah menceritakan kepada kami [Za'idah] dari [Manshur] dari [Hilal bin Yasaf] dari [Rabi' bin Khutsaim] dari ['Amr bin Maimun] dari [Ibnu Abu Laila] dari [seorang perempuan] dari [Abu Ayyub] dari Nabi Shallallallahu'alaihi wasallam beliau bersabda: \"Qul huwallahu ahad adalah sepertiga AI Qur'an.\" Abu Abdurrahman berkata; 'Aku tidak mengetahui sanad yang lebih panjang dari ini.'"},"985":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرٍ قَالَقَامَ مُعَاذٌ فَصَلَّى الْعِشَاءَ الْآخِرَةَ فَطَوَّلَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَتَّانٌ يَا مُعَاذُ أَفَتَّانٌ يَا مُعَاذُ أَيْنَ كُنْتَ عَنْ سَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَالضُّحَى وَإِذَا السَّمَاءُ انْفَطَرَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Muharib bin Ditsar] dari [Jabir] mengatakan; \"Mu'adz bangkit untuk shalat Isya dan ia memperlama shalatnya. Lalu Rasulullah Shallallallahu'alaihi wasallam bersabda: \"Wahai Mua'dz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? Wahai Mua'dz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? Kenapa kamu tidak membaca Sabbihisma Rabbikal A'laa (Qs. Al A'laa), wadhdhuhaa (Qs. Adh-Dhuhaa), serta Idzas Samaaun fatharat (Qs. Al Infithaar)?\""},"986":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَصَلَّى مُعَاذُ بْنُ جَبَلٍ لِأَصْحَابِهِ الْعِشَاءَ فَطَوَّلَ عَلَيْهِمْ فَانْصَرَفَ رَجُلٌ مِنَّا فَأُخْبِرَ مُعَاذٌ عَنْهُ فَقَالَ إِنَّهُ مُنَافِقٌ فَلَمَّا بَلَغَ ذَلِكَ الرَّجُلَ دَخَلَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِمَا قَالَ مُعَاذٌ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتُرِيدُ أَنْ تَكُونَ فَتَّانًا يَا مُعَاذُ إِذَا أَمَمْتَ النَّاسَ فَاقْرَأْ بِالشَّمْسِ وَضُحَاهَا وَسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَاللَّيْلِ إِذَا يَغْشَى وَاقْرَأْ بِاسْمِ رَبِّكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] dia berkata; \"Mu'adz bin Jabal shalat Isya' bersama para sahabatnya dan ia memperlama shalatnya, sehingga ada salah seorang dari kami yang keluar dari jamaah shalat. Mua'dz lalu segera diberitahu hal itu, lalu ia berkata; 'Dia munafik'. Setelah berita itu sampai kepada orang tersebut, ia segera datang kepada Nabi Shallallallahu'alaihi wasallam dan memberitahukan tentang perkataan Mu'adz. Kemudian Rasulullah Shallallallahu'alaihi wasallam bersabda kepada Mu'adz, 'Wahai Mua'dz, apakah engkau hendak menjadi orang yang menimbulkan fitnah? ' Jika kamu jadi imam, maka bacalah, \"Wasy syamsi wadhuhaha (Qs. Asy-Syamsy) \", \"Sabbihisma Rabbikal A'laa (Qs. Al A'laa), \"Wallaili Idzaa Yaghsyaa (Qs. Al Lail), dan \"Iqra bismi Rabbika (Qs. Al Alaq).\" "},"987":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ الْحَسَنِ بْنِ شَقِيقٍ قَالَ حَدَّثَنَا أَبِي قَالَ أَنْبَأَنَا الْحُسَيْنُ بْنُ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الْعِشَاءِ الْآخِرَةِ بِالشَّمْسِ وَضُحَاهَا وَأَشْبَاهِهَا مِنْ السُّوَرِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ali bin Al Hasan bin Syaqiq] dia berkata; telah menceritakan kepada kami [bapakku] dia berkata; telah bertanya kepada kami [Al Husain bin Waqid] dari [Abdullah bin Buraidah] dari Bapaknya - [Buraidah] -, bahwa Rasulullah Shallallallahu'alaihi wasallam saat pernah shalat Isya' membaca Wasy Syamsi Wadluhaha (Qs. Asy-Syams) dan yang serupa dengannya.\""},"988":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَتَمَةَ فَقَرَأَ فِيهَا بِالتِّينِ وَالزَّيْتُونِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Yahya bin Sa'id] dari ['Adi bin Tsabit] dari [Al Bara' bin 'Azib] dia berkata, \"Aku pernah shalat Isya' bersama Rasulullah Shallallahu'alaihi wasallam, dan beliau Shallallallahu'alaihi wasallam membaca: Wattiini waz-zaituun (Surat. At-Tiin).\""},"989":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَرَأَ فِي الْعِشَاءِ فِي الرَّكْعَةِ الْأُولَى بِالتِّينِ وَالزَّيْتُونِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yazid bin Zura'] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Adi bin Tsabit] dari [Al Bara' bin 'Azib] dia berkata; \"Dalam suatu perjalanan Rasulullah Shallallallahu'alaihi wasallam pernah membaca Wattiini Waz-Zaituun (Qs. At-Tiin) pada shalat Isya' dalam rakaat pertama.\""},"990":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي أَبُو عَوْنٍ قَالَ سَمِعْتُ جَابِرَ بْنَ سَمُرَةَ يَقُولُقَالَ عُمَرُ لِسَعْدٍ قَدْ شَكَاكَ النَّاسُ فِي كُلِّ شَيْءٍ حَتَّى فِي الصَّلَاةِ فَقَالَ سَعْدٌ أَتَّئِدُ فِي الْأُولَيَيْنِ وَأَحْذِفُ فِي الْأُخْرَيَيْنِ وَمَا آلُو مَا اقْتَدَيْتُ بِهِ مِنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ ذَاكَ الظَّنُّ بِكَ","id":"Telah mengabarkan kepada kami [Amr bin Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepadaku [Abu 'Aun] dia berkata; \"Aku mendengar [Jabir bin Samurah] dia berkata; \"Umar berkata kepada Sa'ad, 'Orang-orang (penduduk Kufah) mengeluhkan kamu tentang semua hal, hingga dalam masalah shalat! ' [Sa'ad] berkata; 'Aku tidak buru-buru (agak lama) pada dua rakaat pertama dan meringankan dua rakaat terakhir. Aku tidak mengurangi shalat yang aku teladani dari shalatnya Rasulullah Shallallahu'alaihi wasallam.' Umar berkata; 'Itulah yang dituduhkan kepadamu'.\""},"991":{"ar":"أَخْبَرَنَا حَمَّادُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ ابْنِ عُلَيَّةَ أَبُو الْحَسَنِ قَالَ حَدَّثَنَا أَبِي عَنْ دَاوُدَ الطَّائِيِّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَوَقَعَ نَاسٌ مِنْ أَهْلِ الْكُوفَةِ فِي سَعْدٍ عِنْدَ عُمَرَ فَقَالُوا وَاللَّهِ مَا يُحْسِنُ الصَّلَاةَ فَقَالَ أَمَّا أَنَا فَأُصَلِّي بِهِمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَخْرِمُ عَنْهَا أَرْكُدُ فِي الْأُولَيَيْنِ وَأَحْذِفُ فِي الْأُخْرَيَيْنِقَالَ ذَاكَ الظَّنُّ بِكَ","id":"Telah mengabarkan kepada kami [Hammad bin Ismail bin Ibrahim bin Ulayyah Abu Al Hasan] dia berkata; telah menceritakan kepada kami [Bapakku] dari [Daud Ath Tha'i] dari [Abdul Malik bin Umair] dari [Jabir bin Samurah] dia berkata; \"Orang-orang Kufah mengadukan Sa'ad kepada Umar, mereka berkata; 'Demi Allah, ia tidak baik shalatnya! ' [Sa'ad] berkata; 'Aku shalat dengan mereka sesuai cara shalat Rasulullah Shallallahu'alaihi wasallam, Aku tidak mengurangi shalat, memperlama dua rakaat pertama, dan memperpendek dua rakaat terakhir'. Umar berkata; 'Itulah yang dituduhkan kepadamu'.\""},"992":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَإِنِّي لَأَعْرِفُ النَّظَائِرَ الَّتِي كَانَ يَقْرَأُ بِهِنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِشْرِينَ سُورَةً فِي عَشْرِ رَكَعَاتٍ ثُمَّ أَخَذَ بِيَدِ عَلْقَمَةَ فَدَخَلَ ثُمَّ خَرَجَ إِلَيْنَا عَلْقَمَةُ فَسَأَلْنَاهُ فَأَخْبَرَنَا بِهِنَّ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah memberitakan kepada kami [Isa bin Yunus] dari [Al A'masy] dari [Syaqiq] dari [Abdullah] dia berkata, \"Aku mengetahui surat-surat yang hampir sama panjangnya, yang biasa di baca oleh Rasulullah Shallallahu'alaihi wasallam, yakni dua puluh surat pada sepuluh rakaat (tiap satu rakaat dua surat - penerj).\"Kemudian ia menarik tangan Alqomah dan masuk. Lalu Alqomah keluar kepada kami, dan kami bertanya kepadanya tentang hal itu, maka ia memberitahukan semua hal tersebut kepada kami.\" "},"993":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ أَبَا وَائِلٍ يَقُولُقَالَ رَجُلٌ ع��نْدَ عَبْدِ اللَّهِ قَرَأْتُ الْمُفَصَّلَ فِي رَكْعَةٍ قَالَ هَذًّا كَهَذِّ الشِّعْرِ لَقَدْ عَرَفْتُ النَّظَائِرَ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرُنُ بَيْنَهُنَّ فَذَكَرَ عِشْرِينَ سُورَةً مِنْ الْمُفَصَّلِ سُورَتَيْنِ سُورَتَيْنِ فِي رَكْعَةٍ","id":"Telah mengabarkan kepada kami [Ismail bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Amr bin Murrah] dia berkata; \"Aku mendengar [Abu Wail] berkata; \"Seorang laki-laki berkata kepada Abdullah Ibnu Mas'ud, 'Aku pernah membaca surah-surah Al Mufashshal dalam satu rakaat! ' [Abdullah] berkata; 'Cepat sekali membacanya, seperti cepatnya orang yang membaca syair. Aku mengetahui surah-surah yang panjangnya hampir sama, yang biasa dibaca oleh Rasulullah Shallallallahu'alaihi wasallam dengan bersambung di antara surah-surah tersebut. la menyebutkan dua puluh surat dari surah-surah Al Mufashshal, dan tiap dua surat dibaca pada satu rakaat.'"},"994":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ أَبِي حَصِينٍ عَنْ يَحْيَى بْنِ وَثَّابٍ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِوَأَتَاهُ رَجُلٌ فَقَالَ إِنِّي قَرَأْتُ اللَّيْلَةَ الْمُفَصَّلَ فِي رَكْعَةٍ فَقَالَ هَذًّا كَهَذِّ الشِّعْرِ لَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ النَّظَائِرَ عِشْرِينَ سُورَةً مِنْ الْمُفَصَّلِ مِنْ آلِ حم","id":"Telah mengabarkan kepada kami [Amr bin Manshur] dia berkata; telah menceritakan kepada kami [Abdullah bin Raja'] telah memberitakan kepada kami [Isra'il] dari [Abu Hashin] dari [Yahya bin Watstsab] dari [Masruk] dari [Abdullah] -dia didatangi oleh seorang laki-laki- laki-laki tersebut berkata; \"Suatu malam aku membaca surat Al Mufashshal dalam satu rakaat.' Abdullah berkata; Cepat sekali, seperti cepatnya orang yang membaca syair? Akan tetapi aku mendengar Rasulullah Shallallallahu'alaihi wasallam membaca surat-surat yang panjangnya hampir sama, dua puluh surat dari surah-surah Al Mufashshal dari surat Haa miim'.\""},"995":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبَّادٍ حَدِيثًا رَفَعَهُ إِلَى ابْنِ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ قَالَحَضَرْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ فَصَلَّى فِي قُبُلِ الْكَعْبَةِ فَخَلَعَ نَعْلَيْهِ فَوَضَعَهُمَا عَنْ يَسَارِهِ فَافْتَتَحَ بِسُورَةِ الْمُؤْمِنِينَ فَلَمَّا جَاءَ ذِكْرُ مُوسَى أَوْ عِيسَى عَلَيْهِمَا السَّلَام أَخَذَتْهُ سَعْلَةٌ فَرَكَعَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ali] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Ibnu Juraij] dia berkata; Telah mengabarkan kepadaku [Muhammad bin 'Abbad Rafa'ah] ke [Ibnu Sufyan] dari [Abdullah As Saib] dia berkata; \"Aku datang kepada Rasulullah Shallallallahu'alaihi wasallam saat penaklukan Makkah, beliau Shallallallahu'alaihi wasallam shalat di depan Ka'bah, lalu melepas kedua sandalnya dan meletakkannya di sebelah kirinya. Rasulullah Shallallallahu'alaihi wasallam memulai shalatnya dengan membaca surat Al Mukminun, dan ketika menyebut Musa atau Isa Alaihimassalam beliau batuk, sehingga beliau segera ruku'.\""},"996":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى وَعَبْدُ الرَّحْمَنِ وَابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَأَنَّهُ صَلَّى إِلَى جَنْبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَقَرَأَ فَكَانَ إِذَا مَرَّ بِآيَةِ عَذَابٍ وَقَفَ وَتَعَوَّذَ وَإِذَا مَرَّ بِآيَةِ رَحْمَةٍ وَقَفَ فَدَعَا وَكَانَ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ وَفِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Yahya] dan [Abdurrahman] dan [Ibnu Abu 'Adi] dari [syu'bah] dari [Sulaiman] dari [Sa'd bin Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] dia berkata; bahwa pada suatu malam ia pernah mengerjakan shalat di samping Rasulullah Shallallahu'alaihi wasallam, dan beliau membaca surat. Jika beliau melalui bacaan yang berkenaan tentang adzab maka ia berhenti dan ber-ta'awudz (berlindung), sedangkan jika ia melalui ayat yang berkenaan dengan rahmat maka ia berhenti serta berdoa. Beliau saat ruku' membaca.\"Subhana rabbiyal 'adziim (Maha suci Tuhan yang Maha Agung) \" dan saat sujud membaca, \"Subbhana rabbiyal a'laa (Maha Suci Allah, Tuhan yang Maha Tinggi).\""},"997":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ الْعَلَاءِ بْنِ الْمُسَيَّبِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ طَلْحَةَ بْنِ يَزِيدَ عَنْ حُذَيْفَةَ وَالْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ الْبَقَرَةَ وَآلَ عِمْرَانَ وَالنِّسَاءَ فِي رَكْعَةٍ لَا يَمُرُّ بِآيَةِ رَحْمَةٍ إِلَّا سَأَلَ وَلَا بِآيَةِ عَذَابٍ إِلَّا اسْتَجَارَ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari [Hafsh bin ghiyats] dari [Al A'la bin Al Musayyab] dari [Amr bin Murrah] dari [Thalhah bin Yazid] dari [Hudzaifah] dan [Al A'masy] dari [Sa'd bin Ubaidah] dari [Al Mustawrid Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] bahwa Nabi Shallallallahu'alaihi wasallam pernah membaca surat Al Baqarah, Ali 'Imraan, dan An-Nisaa' dalam satu rakaat. Beliau Shallallallahu'alaihi wasallam tidak melewati (membaca) ayat yang berkenaan dengan rahmat kecuali beliau berdoa, dan tidak melewati (membaca) ayat yang berkenaan dengan adzab kecuali beliau memohon perlindungan kepada-Nya. "},"998":{"ar":"أَخْبَرَنَا نُوحُ بْنُ حَبِيبٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ قَالَ حَدَّثَنَا قُدَامَةُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَتْنِي جَسْرَةُ بِنْتُ دَجَاجَةَ قَالَتْ سَمِعْتُ أَبَا ذَرٍّ يَقُولُقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا أَصْبَحَ بِآيَةٍ وَالْآيَةُ{ إِنْ تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ وَإِنْ تَغْفِرْ لَهُمْ فَإِنَّكَ أَنْتَ الْعَزِيزُ الْحَكِيمُ }","id":"Telah mengabarkan kepada kami [Nuh bin Habib] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dia berkata; telah menceritakan kepada kami [Qudamah bin Abdullah] dia berkata; telah menceritakan kepadaku [Jasrah binti Dajajah] dia berkata; \"Aku mendengar [Abu Dzar], dia berkata, \"Rasulullah Shallallallahu'alaihi wasallam shalat hingga pagi dengan membaca ayat, \"In Tuadzibhum Fainnahum 'Ibaduk wa In Taghfirlahum Fainnaka Antal 'Azizul Hakim\" (Jika Engkau menyiksa mereka, maka sesungguhnya mereka adalah hamba-hamba Engkau, dan jika Engkau mengampuni mereka, maka sesungguhnya Engkaulah Yang Maha Perkasa lagi Maha Bijaksana) (Qs. Al Maa'idah (5): I18) '.\""},"999":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مَنِيعٍ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ قَالَا حَدَّثَنَا هُشَيْمٌ قَالَ حَدَّثَنَا أَبُو بِشْرٍ جَعْفَرُ بْنُ أَبِي وَحْشِيَّةَ وَهُوَ ابْنُ إِيَاسٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا }قَالَ نَزَلَتْ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخْتَفٍ بِمَكَّةَ فَكَانَ إِذَا صَلَّى بِأَصْحَابِهِ رَفَعَ صَوْتَهُ وَقَالَ ابْنُ مَنِيعٍ يَجْهَرُ بِالْقُرْآنِ وَكَانَ الْمُشْرِكُونَ إِذَا سَمِعُوا صَوْتَهُ سَبُّوا الْقُرْآنَ وَمَنْ أَنْزَلَهُ وَمَنْ جَاءَ بِهِ فَقَالَ اللَّهُ عَزَّ وَجَلَّ لِنَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَلَا تَجْهَرْ بِصَلَاتِكَ }أَيْ بِقِرَاءَتِكَ فَيَسْمَعَ الْمُشْرِكُونَ فَيَسُبُّوا الْقُرْآنَ{ وَلَا تُخَافِتْ بِهَا }عَنْ أَصْحَابِكَ فَلَا يَسْمَعُوا{ وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }","id":"Telah mengabarkan kepada kami [Ahmad bin Mani'] dan [Ya'qub bin Ibrahim Ad-Dauraqiy] mereka berdua berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah menceritakan kepada kami [Abu Bisyr Ja'far bin Abu Wahsyiyyah bin Iyas] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] tentang firman Allah Azza wa Jalla, \"Janganlah kamu mengeraskan suaramu dalam shalatmu dan Janganlah pula merendahkannya.\" (Qs. Al Israa' (17): 1 10), dia berkata; \"Ayat ini turun dan Rasulullah Shallallahu'alaihi wasallam masih sembunyi-sembunyi dalam berdakwah di Makkah. Jika beliau mengerjakan shalat dengan para sahabatnya, maka beliau Shallallahu'alaihi wasallam mengeraskan suaranya, Ibnu Mani' berkata, \"Beliau memperdengarkan bacaan Al Qur'annya. Adalah orang-orang musyrik yang mendengar suara Rasulullah Shallallahu'alaihi wasallam (saat membaca Al Qur'an) mencela Al Qur'an, yang menurunkannya (Allah), serta yang membawanya (malaikat Jibril). Oleh karena itu Allah Azza wa Jalla berfirman kepada nabi-Nya, \"Janganlah kamu mengeraskan suaramu dalam shalatmu\" yakni dalam bacaannya. -Jika- Orang musyrik mendengar hal ini, maka mereka mencela Al Qur'an.\"Dan janganlah pula melirihkannya\" dari sahabatmu hingga mereka tidak mendengar.\"Dan carilah jalannya diantara keadaan yang demikian.\" (Qs. Al Israa' (17): 110)."},"1000":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ جَعْفَرِ بْنِ إِيَاسٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ صَوْتَهُ بِالْقُرْآنِ وَكَانَ الْمُشْرِكُونَ إِذَا سَمِعُوا صَوْتَهُ سَبُّوا الْقُرْآنَ وَمَنْ جَاءَ بِهِ فَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْفِضُ صَوْتَهُ بِالْقُرْآنِ مَا كَانَ يَسْمَعُهُ أَصْحَابُهُ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا وَابْتَغِ بَيْنَ ذَلِكَ سَبِيلًا }","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ja'far bin Iyas] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] dia berkata; \"Dahulu Rasulullah Shallallahu'alaihi wasallam mengeraskan suara dalam membaca Al Qur'an, sehingga bila orang-orang musyrik mendengarnya maka mereka segera mencela Al Qur'an dan yang membawanya. Suatu saat Rasulullah Shallallahu'alaihi wasallam membaca dengan suara pelan hingga tidak bisa didengar oleh sahabatnya, maka Allah Azza wa Jalla menurunkan ayat: 'Janganlah kamu mengeraskan suaramu dalam shalatmu dan janganlah pula merendahkannya dan carilah jalannya diantara keadaan yang demikian\""}};
